/// HillClimbing optimization direction (formerly `HillClimbingDirection`).
/// Renamed in #119 (Composable Execution Part A) to live alongside the other
/// strategy-config types. Wire format is unchanged: snake_case `"minimize"` /
/// `"maximize"`.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum HillClimbingDirection {
    Minimize,
    Maximize,
}

// ============================================================================
// Composable Execution Part A (issue #119): recursive LoopStrategy config
// newtypes + per-node collaborator handles + StrategyRef + RunStrategy trait.
// ============================================================================
//
// Types defined in this section:
//   - Handle newtypes: AgentRef, ToolsetRef, SchemaRef (transparent strings).
//   - Config structs: ReactConfig, PlanExecuteConfig, SelfVerifyingConfig,
//     RalphConfig, HillClimbingConfig.
//   - LoopStrategy: closed serde enum of config newtypes (recursive via
//     Box<LoopStrategy> children on the combinator variants).
//   - StrategyRef: adjacently-tagged BuiltIn(LoopStrategy) | Custom(String).
//   - RunStrategy trait + delegation impl on LoopStrategy (the single match
//     site) + stub impls on each *Config.
//   - Placeholder runtime types: ExecutionContext, StrategyOutcome (#123 owns
//     their real shapes).
//
// Trait method: `RunStrategy::run(&self, &mut ExecutionContext) ->
// StrategyOutcome` (native async).
//
// Rules enforced:
//   - `LoopStrategy` is `#[serde(tag = "kind", rename_all = "snake_case")]`;
//     the `ReAct` variant overrides its tag to `"react"` (not `"re_act"`).
//   - Newtype-variant inner structs flatten next to `"kind"` (flat wire form);
//     recursive `Box<LoopStrategy>` children nest as tagged objects.
//   - JSON field order follows struct declaration order (cross-language
//     byte-identity target).
//   - Built-ins stay a closed enum (versioning + `max_steps()`, #122);
//     `StrategyRef::Custom` is the opaque escape hatch (registry: #120).
//   - Per-variant run bodies are REAL (#124): each `*Config::run` owns its loop
//     and recurses via `self.inner.run(cx)` (or `self.plan`/`self.execute`); the
//     model-touching machinery stays on the harness behind [`StrategyExecutor`].
//     The harness entry collapses to `task.loop_strategy.run(cx).await` — the
//     central dispatch `match` is GONE (the only `match` left is the enum→config
//     delegation in `LoopStrategy::run`).
//
// No `// SPEC QUESTION:` markers — the plan is fully pinned.

/// Per-node handle to a named agent definition. Serializes as a bare JSON
/// string. Resolution to a concrete agent lands with the registry slice (#120).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(transparent)]
pub struct AgentRef(pub String);

/// Per-node handle to a named toolset. Serializes as a bare JSON string.
/// Resolution lands with the registry slice (#120). `Default` yields the empty
/// handle (`ToolsetRef("")`) — the global-catalogue fallback — which backs the
/// `#[serde(default)]` on [`PausedState::toolset`] (#140).
#[derive(Debug, Clone, PartialEq, Eq, Default, Serialize, Deserialize)]
#[serde(transparent)]
pub struct ToolsetRef(pub String);

/// Per-node handle to a named output/evaluator schema. Serializes as a bare
/// JSON string. Resolution lands with the registry slice (#120).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(transparent)]
pub struct SchemaRef(pub String);

/// Leaf ReAct node config. `budget` is the renamed `max_iterations`
/// (semantically `PerLoop(n)`). Serializes flat next to `"kind":"react"`.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct ReactConfig {
    pub budget: BudgetPolicy,
    /// What this node does when its `budget` is spent (#129). Canonical position:
    /// IMMEDIATELY after `budget`. A leaf honors its `behavior` ONLY at the
    /// top-level/bare-leaf resolution site (`drive_strategy`); in the normal
    /// NESTED case the leaf still PROPAGATES exhaustion to its parent (#125 rule
    /// 6 — a nested leaf never self-resolves). Always serialized (Q1).
    #[serde(default = "default_budget_behavior")]
    pub behavior: BudgetExhaustedBehavior,
    pub agent: AgentRef,
    pub toolset: ToolsetRef,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub output: Option<SchemaRef>,
}

impl ReactConfig {
    /// A bare ReAct leaf with a `PerLoop { value }` budget and empty agent /
    /// toolset handles (resolution lands with the registry slice, #120). This
    /// is the migration shim for the old `ReAct { max_iterations }` shape.
    pub fn per_loop(value: u32) -> Self {
        Self {
            budget: BudgetPolicy::PerLoop { value },
            behavior: default_budget_behavior(),
            agent: AgentRef(String::new()),
            toolset: ToolsetRef(String::new()),
            output: None,
        }
    }

    /// The `max_iterations` value extracted from a `PerLoop` budget; any other
    /// budget shape yields `u32::MAX` (matching the legacy executor's
    /// "unbounded" fall-through for non-ReAct/non-`PerLoop` strategies).
    pub fn max_iterations(&self) -> u32 {
        match self.budget {
            BudgetPolicy::PerLoop { value } => value,
            _ => u32::MAX,
        }
    }
}

/// PlanExecute combinator: a `plan` sub-strategy feeds an `execute`
/// sub-strategy. `plan_model` stays optional/omittable (as today).
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct PlanExecuteConfig {
    pub plan: Box<LoopStrategy>,
    pub execute: Box<LoopStrategy>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub plan_model: Option<ModelConfig>,
    /// What this combinator does when its execute-phase budget is spent (#129).
    /// Canonical position on a combinator: the LAST field. Always serialized (Q1).
    #[serde(default = "default_budget_behavior")]
    pub behavior: BudgetExhaustedBehavior,
}

impl PlanExecuteConfig {
    /// A PlanExecute whose plan and execute phases are both bare ReAct leaves
    /// (migration shim for the old `PlanExecute { plan_model }` shape; the live
    /// executor does not read the children yet — #124).
    pub fn simple(plan_model: Option<ModelConfig>) -> Self {
        Self {
            plan: Box::new(LoopStrategy::ReAct(ReactConfig::per_loop(u32::MAX))),
            execute: Box::new(LoopStrategy::ReAct(ReactConfig::per_loop(u32::MAX))),
            plan_model,
            behavior: default_budget_behavior(),
        }
    }
}

/// SelfVerifying combinator: run `inner`, then judge it against `evaluator`.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct SelfVerifyingConfig {
    pub inner: Box<LoopStrategy>,
    pub evaluator: SchemaRef,
    /// Optional dedicated reviewer agent for the evaluate phase. `None` ⇒ the
    /// evaluate phase reuses the inner worker's resolved agent (Q1c default).
    /// Set this to a SEPARATE agent so the reviewer is not the same model that
    /// wrote the code (a builder reviewing its own work tends to rubber-stamp).
    /// Omitted from the wire when unset (existing configs stay byte-identical).
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub eval_agent: Option<AgentRef>,
    /// Optional read-only/inspection toolset for the evaluate phase. `None` ⇒
    /// the empty handle (global-catalogue fallback), byte-identical to prior
    /// behavior. The evaluate phase already runs on a read-only sandbox; scoping
    /// the toolset to read-only tools additionally prevents the reviewer from
    /// reaching non-filesystem side-effecting tools (web/MCP) that the sandbox
    /// does not gate. Omitted from the wire when unset.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub eval_toolset: Option<ToolsetRef>,
    /// What this combinator does when its build↔evaluate budget is spent (#129).
    /// Canonical position on a combinator: the LAST field. Always serialized (Q1).
    #[serde(default = "default_budget_behavior")]
    pub behavior: BudgetExhaustedBehavior,
}

/// Ralph combinator: re-run `inner` under a fixed `agent` across context-window
/// resets.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct RalphConfig {
    pub inner: Box<LoopStrategy>,
    pub agent: AgentRef,
    /// What Ralph does when its own scope is spent (#129). Canonical position on
    /// a combinator: the LAST field. Always serialized (Q1). NOTE: Ralph's window
    /// recovery (reset + retry) is independent of this field — it governs Ralph's
    /// OWN budget scope, not the per-window child exhaustion (which Ralph already
    /// absorbs as "window incomplete" and retries).
    #[serde(default = "default_budget_behavior")]
    pub behavior: BudgetExhaustedBehavior,
}

/// HillClimbing combinator: iterate `inner`, keeping/reverting per the metric
/// `evaluator` and `direction`. `max_stagnation` and `min_improvement_delta`
/// are now required (#119).
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct HillClimbingConfig {
    pub inner: Box<LoopStrategy>,
    pub direction: HillClimbingDirection,
    pub max_stagnation: u32,
    pub revert_on_no_improvement: bool,
    pub min_improvement_delta: f64,
    pub evaluator: AgentRef,
    /// What this combinator does when its optimization-loop budget is spent
    /// (#129). Canonical position on a combinator: the LAST field. Always
    /// serialized (Q1).
    #[serde(default = "default_budget_behavior")]
    pub behavior: BudgetExhaustedBehavior,
}

/// Loop strategy — a closed, recursive serde enum of config newtypes. The
/// `ReAct` variant is the leaf; the rest are combinators holding
/// `Box<LoopStrategy>` children. See the section header above for the full
/// type/wire-format/rule documentation.
///
/// Concrete strategy traits (`CompletionCheck`, `Verifier`, `MetricEvaluator`)
/// are owned by their respective component issues. The live `StandardHarness`
/// executes ReAct/PlanExecute via its own dispatch (migrating to the
/// per-`*Config` `run` bodies in #124); the remaining variants still halt with
/// [`HaltReason::StrategyNotYetImplemented`] until then.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
pub enum LoopStrategy {
    #[serde(rename = "react")]
    ReAct(ReactConfig),
    PlanExecute(PlanExecuteConfig),
    SelfVerifying(SelfVerifyingConfig),
    Ralph(RalphConfig),
    HillClimbing(HillClimbingConfig),
}

impl LoopStrategy {
    /// Advisory worst-case **turn** bound for this strategy tree, computed
    /// statically before a run (#122).
    ///
    /// This is an **advisory pre-run figure**, logged at startup — it is NOT
    /// the enforcement mechanism. The actual safety ceiling is the per-node
    /// [`BudgetPolicy`] charged by each `*Config::run` against its own
    /// [`BudgetContext`]; `max_steps` never gates execution.
    ///
    /// The bound is derived **multiplicatively/additively down the tree** and
    /// is Option-monadic: any `Unlimited` node anywhere in the tree collapses
    /// the whole figure to `None` ("no finite advisory bound"). It is a
    /// runtime-only computation and is **never serialized**.
    ///
    /// Per-variant rules:
    /// - `ReAct(c)` ⇒ `c.budget.allowance_value()` (`Unlimited ⇒ None`).
    /// - `SelfVerifying(c)` ⇒ `inner + 1` — the single read-only evaluator
    ///   turn is exactly one extra turn.
    /// - `PlanExecute(c)` ⇒ `plan + execute`. **PER-TASK bound**: a full run's
    ///   total is `plan + execute_per_task × task_count`, where `task_count` is
    ///   data-dependent (the plan phase builds the task graph at runtime), so
    ///   it is intentionally NOT part of this static figure.
    /// - `Ralph(c)` ⇒ `inner` — **PER-WINDOW bound**, mirroring PlanExecute's
    ///   per-task treatment. A full run's total is `per_window × max_windows`,
    ///   where `max_windows` derives from [`HarnessConfig::max_resets`]
    ///   (default 3) at runtime and is intentionally NOT part of this static
    ///   figure.
    /// - `HillClimbing(c)` ⇒ `inner × (max_stagnation + 1)` — the `+1` is the
    ///   one productive pass; `max_stagnation` non-improving passes follow.
    ///   The `max_stagnation == u32::MAX` sentinel means unbounded windows ⇒
    ///   `None` (a semantic unbounded rule, distinct from arithmetic overflow).
    ///
    /// Arithmetic uses `checked_add`/`checked_mul`; an unrepresentable bound
    /// (overflow) yields `None` — an unrepresentable figure is "no finite
    /// advisory bound".
    pub fn max_steps(&self) -> Option<u32> {
        match self {
            LoopStrategy::ReAct(c) => c.budget.allowance_value(),
            LoopStrategy::SelfVerifying(c) => c.inner.max_steps()?.checked_add(1),
            LoopStrategy::PlanExecute(c) => c.plan.max_steps()?.checked_add(c.execute.max_steps()?),
            LoopStrategy::Ralph(c) => c.inner.max_steps(),
            LoopStrategy::HillClimbing(c) => {
                if c.max_stagnation == u32::MAX {
                    return None;
                }
                c.inner
                    .max_steps()?
                    .checked_mul(c.max_stagnation.checked_add(1)?)
            }
        }
    }
}

/// Serializable identity of a strategy: either a closed built-in
/// [`LoopStrategy`] tree or an opaque `Custom` string key resolved at runtime
/// (registry: #120). Adjacently tagged on `kind`/`value` to avoid a tag
/// collision with the nested `LoopStrategy`'s own `kind`:
///   - `{"kind":"built_in","value":{"kind":"react",...}}`
///   - `{"kind":"custom","value":"my-harness::DoubleVerify"}`
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(tag = "kind", content = "value", rename_all = "snake_case")]
pub enum StrategyRef {
    BuiltIn(LoopStrategy),
    Custom(String),
}

impl StrategyRef {
    /// Advisory worst-case turn bound for this strategy reference (#122).
    /// `Custom` is opaque to the framework (it cannot be introspected), so it
    /// yields `None`; `BuiltIn` delegates to [`LoopStrategy::max_steps`].
    pub fn max_steps(&self) -> Option<u32> {
        match self {
            StrategyRef::Custom(_) => None,
            StrategyRef::BuiltIn(s) => s.max_steps(),
        }
    }
}

// ============================================================================
// Composable Execution runtime scaffold (issue #123): StrategyOutcome +
// ExecutionContext / BudgetContext / BudgetStack / SpanStack.
// ============================================================================
//
// SCAFFOLD ONLY. This slice establishes the typed strategy outcome and the
// shared, mutable runtime context that threads through a nested strategy tree.
// `charge` here is PURE ARITHMETIC against a per-scope step allowance — the
// behavior-chain walk, continue-consumption, and persistence are the later
// budget-enforcement slice (#124+).
//
// Types defined in this section:
//   - `StrategyOutcome` — typed result a strategy node returns.
//   - `BudgetExhausted` — the error type `BudgetContext::charge` returns.
//   - `BudgetContext` — one budget scope (`charge`/`remaining`/
//     `continues_remaining`).
//   - `BudgetStack` — runtime push/pop stack of `BudgetContext`, one node per
//     recursion frame (siblings do NOT share).
//   - `SpanStack` — runtime push/pop stack of `observability::SpanId`.
//   - `ExecutionContext<'a>` — the one shared, mutable context for a whole
//     nested tree; borrows the [`ExecutionRegistry`].
//
// Trait methods (updated this slice):
//   - `RunStrategy::run<'a>(&'a self, &'a mut ExecutionContext<'_>) ->
//     BoxFut<'a, StrategyOutcome>` — the `ExecutionContext` now carries the
//     real runtime scaffold and a borrowed registry lifetime.
//
// Rules enforced:
//   - A child's `StrategyOutcome::BudgetExhausted` is an INSPECTABLE value the
//     parent reads; it does NOT auto-propagate.
//   - `charge` is pure arithmetic: it debits `turns` steps; on success
//     increments `steps_taken` and returns `Ok(())`; on overflow returns
//     `Err(BudgetExhausted{..})` from current state. It does NOT walk the
//     behavior chain or consume continues. `BudgetPolicy::Unlimited` never
//     exhausts.
//   - Each `BudgetContext` represents ONE scope; the allowance is the policy's
//     own `value` (Unlimited = no cap → `None`).
//   - All runtime types here are NEVER serialized (no serde derives). Rust
//     cannot assert the *absence* of a `Serialize` impl via a negative trait
//     bound, so this is structural-only, not test-asserted.
//
// Resolved spec ambiguities (DECIDED — see issue #123 plan):
//   1. `ExecutionContext<'a>` borrows the registry (`&'a ExecutionRegistry`);
//      the `RunStrategy` trait + all impls thread the context lifetime.
//      `Arc<dyn RunStrategy>` stays dyn-compatible.
//   2. `charge` is pure arithmetic (above); `BudgetExhausted` is a dedicated
//      struct used as charge's error; `StrategyOutcome::BudgetExhausted` is a
//      struct variant that mirrors those fields and adds `partial_output`
//      (modeled as a struct variant rather than wrapping, so callers can match
//      and read all fields uniformly). `Output` maps to `String`.
//   3. `continues_used` is an IN-MEMORY field ONLY in this slice. Its "rides a
//      Continue/Escalate checkpoint" persistence is DEFERRED to the
//      enforcement slice — it is intentionally NOT added to
//      `BudgetSnapshot`/`PausedState` here.
//   4. `SpanStack` reuses [`observability::SpanId`](crate::observability::SpanId)
//      as its element type.
//
// No `// SPEC QUESTION:` markers — the plan is fully pinned.

/// The typed result a strategy node returns. Runtime-only (NOT serialized): a
/// strategy outcome is an in-process value, never persisted.
///
/// `BudgetExhausted` is distinguishable from `Failed` by callers — a child's
/// `BudgetExhausted` is a value the parent INSPECTS (e.g. to grant a continue
/// or escalate); it does NOT auto-propagate as a failure. `Output` maps to
/// `String` in this codebase (mirrors [`RunResult`]).
#[derive(Debug, Clone, PartialEq)]
pub enum StrategyOutcome {
    /// The strategy completed and produced its final output.
    Complete(String),
    /// The strategy's budget scope ran out of allowance — OR (issue #137) the
    /// ReAct consecutive-tool-error breaker tripped (see `cause`). Mirrors the
    /// [`BudgetExhausted`] charge-error fields and adds `partial_output` — any
    /// output produced before exhaustion. Inspectable, NOT auto-propagating.
    ///
    /// The `cause` discriminant (#137) lets the SINGLE budget-exhaustion
    /// resolution site (`drive_strategy_with_resume_seed`) pick the right
    /// terminal [`HaltReason`]: genuine budget exhaustion →
    /// [`HaltReason::BudgetExceeded`]; an error loop →
    /// [`HaltReason::ToolErrorLoop`]. Both flow through the node's
    /// [`BudgetExhaustedBehavior`] (Fail / Escalate / Continue) identically.
    BudgetExhausted {
        policy: BudgetPolicy,
        behavior: BudgetExhaustedBehavior,
        steps_taken: u32,
        continues_used: u32,
        phase: String,
        partial_output: Option<String>,
        /// What caused this exhaustion (#137): genuine budget vs. an error loop.
        /// Defaults to [`ExhaustionCause::Budget`] for every pre-#137 path.
        cause: ExhaustionCause,
    },
    /// The strategy halted with a harness error.
    Failed(HarnessError),
}

/// Why a [`StrategyOutcome::BudgetExhausted`] was raised (issue #137). The
/// budget-exhaustion resolution site routes BOTH causes through the node's
/// [`BudgetExhaustedBehavior`], but stamps a DIFFERENT terminal
/// [`HaltReason`] on the Fail / Escalate→Fail terminals so a caller can tell a
/// genuine budget exhaustion from an error-grinding circuit-break. Runtime-only
/// (NOT serialized).
#[derive(Debug, Clone, PartialEq, Eq, Default)]
pub enum ExhaustionCause {
    /// The scope's step allowance ran out (the pre-#137 behavior). Resolves to
    /// [`HaltReason::BudgetExceeded`] on a Fail / Escalate→Fail terminal.
    #[default]
    Budget,
    /// The ReAct consecutive-recoverable-tool-error breaker hard-stopped at
    /// `2 * error_loop_threshold` identical-argument errors for `tool` (#137).
    /// Resolves to [`HaltReason::ToolErrorLoop`] on a Fail / Escalate→Fail
    /// terminal — NEVER [`HaltReason::BudgetExceeded`].
    ToolErrorLoop {
        tool: String,
        consecutive_errors: u32,
    },
}

/// The current run of consecutive recoverable tool errors for ONE tool name
/// (issue #137). Tracked per tool name in a loop-local
/// `HashMap<String, ErrorRun>` inside [`StandardHarness::run_react_inner`]:
///
/// - On a recoverable [`ToolOutput::Error`] for tool `T` with args `A`: if the
///   existing run for `T` has `args` STRUCTURALLY equal to `A`, `count` is
///   incremented; otherwise the run is REPLACED with a fresh `{ args: A,
///   count: 1 }` (covers both the first error and the args-changed case).
/// - On ANY success for tool `T`: the entry is REMOVED (AC1 — success resets the
///   run regardless of args).
/// - At `count == N` (`error_loop_threshold`): inject ONE corrective message
///   (AC2). `injected` is set so the message is NOT re-injected between `N` and
///   `2 * N` for the same run.
/// - At `count == 2 * N`: stop looping (AC3).
#[derive(Debug, Clone, PartialEq)]
struct ErrorRun {
    /// The tool-call arguments shared by every error in this run.
    args: serde_json::Value,
    /// How many consecutive identical-argument recoverable errors so far.
    count: u32,
    /// Whether the `N`-threshold corrective message has already been injected
    /// for THIS run (so we inject exactly once between `N` and `2 * N`).
    injected: bool,
}

/// The error [`BudgetContext::charge`] returns when a debit would exceed the
/// scope's step allowance. Captures the budget state at the moment of
/// exhaustion. Runtime-only (NOT serialized).
///
/// Promotes to [`StrategyOutcome::BudgetExhausted`] (which adds
/// `partial_output`) at the strategy boundary.
#[derive(Debug, Clone, PartialEq)]
pub struct BudgetExhausted {
    pub policy: BudgetPolicy,
    pub behavior: BudgetExhaustedBehavior,
    pub steps_taken: u32,
    pub continues_used: u32,
    pub phase: String,
}

/// One budget scope in the strategy tree. Each recursion node gets its OWN
/// `BudgetContext`; siblings do NOT share. Runtime-only (NOT serialized).
///
/// The per-scope step allowance is the policy's own `value`:
/// `TotalSteps`/`PerLoop`/`PerAttempt` all expose `value` as the cap for this
/// scope; `Unlimited` is uncapped (`remaining()` → `None`).
///
/// `continues_used` is an in-memory field ONLY in this slice; its checkpoint
/// persistence is deferred to the enforcement slice (see section header,
/// resolution #3).
#[derive(Debug, Clone, PartialEq)]
pub struct BudgetContext {
    pub policy: BudgetPolicy,
    pub behavior: BudgetExhaustedBehavior,
    pub steps_taken: u32,
    pub continues_used: u32,
    pub phase: String,
}

impl BudgetContext {
    /// Construct a fresh scope (zeroed counters) for `policy`/`behavior`/`phase`.
    pub fn new(
        policy: BudgetPolicy,
        behavior: BudgetExhaustedBehavior,
        phase: impl Into<String>,
    ) -> Self {
        Self {
            policy,
            behavior,
            steps_taken: 0,
            continues_used: 0,
            phase: phase.into(),
        }
    }

    /// Reconstruct a RESUMED scope (#129) whose `continues_used` is seeded from a
    /// cross-process checkpoint — the sole field of [`BudgetContext`] that must
    /// survive a process pause. `steps_taken` starts at 0 (the resumed run
    /// re-enters the loop with a fresh per-round step budget; the checkpoint only
    /// carries how many continues were ALREADY spent so a `Continue` spanning the
    /// pause cannot exceed `max_continues`). Runtime-only — `continues_used` is
    /// read off the `HumanRequest::BudgetExhausted` payload (Q3: NOT a new
    /// serialized `BudgetContext`/`PausedState` field).
    pub fn resumed(
        policy: BudgetPolicy,
        behavior: BudgetExhaustedBehavior,
        phase: impl Into<String>,
        continues_used: u32,
    ) -> Self {
        Self {
            policy,
            behavior,
            steps_taken: 0,
            continues_used,
            phase: phase.into(),
        }
    }

    /// The per-scope step allowance (`None` for `Unlimited`).
    fn allowance(&self) -> Option<u32> {
        self.policy.allowance_value()
    }

    /// Debit `turns` steps against the scope allowance (pure arithmetic — see
    /// section header, resolution #2). On success increments `steps_taken` and
    /// returns `Ok(())`. If the debit would exceed the allowance, returns
    /// `Err(BudgetExhausted{..})` from current state WITHOUT mutating. Does NOT
    /// walk the behavior chain or consume continues. `Unlimited` never exhausts.
    pub fn charge(&mut self, turns: u32) -> Result<(), BudgetExhausted> {
        if let Some(allowance) = self.allowance() {
            if self.steps_taken.saturating_add(turns) > allowance {
                return Err(BudgetExhausted {
                    policy: self.policy.clone(),
                    behavior: self.behavior.clone(),
                    steps_taken: self.steps_taken,
                    continues_used: self.continues_used,
                    phase: self.phase.clone(),
                });
            }
        }
        self.steps_taken = self.steps_taken.saturating_add(turns);
        Ok(())
    }

    /// Steps left in this scope (`allowance - steps_taken`, saturating).
    /// `None` for `Unlimited` (no cap).
    pub fn remaining(&self) -> Option<u32> {
        self.allowance().map(|a| a.saturating_sub(self.steps_taken))
    }

    /// Continues left before fall-through. For a `Continue { max_continues }`
    /// behavior this is `max_continues - continues_used` (saturating); for
    /// `Escalate`/`Fail` there are no continues, so `0`.
    pub fn continues_remaining(&self) -> u32 {
        match self.behavior {
            BudgetExhaustedBehavior::Continue { max_continues, .. } => {
                max_continues.saturating_sub(self.continues_used)
            }
            BudgetExhaustedBehavior::Escalate | BudgetExhaustedBehavior::Fail => 0,
        }
    }

    /// Grant one in-process continue (#125): bump `continues_used` and RESET
    /// `steps_taken` to 0 so the scope's step allowance refreshes for the next
    /// round. This is a purely in-memory reset — the session / messages are
    /// untouched (the loop keeps the same conversation; only the per-scope step
    /// counter rewinds). The `continues_used` persistence across a serialized
    /// checkpoint is DEFERRED to #129.
    pub fn consume_continue(&mut self) {
        self.continues_used = self.continues_used.saturating_add(1);
        self.steps_taken = 0;
    }

    /// Resolve this scope's [`BudgetExhaustedBehavior`] at the moment of
    /// exhaustion (#125), walking the on-continues-exhausted fall-through chain:
    ///
    ///   - `Fail`     → [`ExhaustedResolution::Fail`].
    ///   - `Escalate` → [`ExhaustedResolution::Escalate`].
    ///   - `Continue { max_continues, on_exhausted }` →
    ///       - if [`continues_remaining`](Self::continues_remaining) `> 0`:
    ///         [`consume_continue`](Self::consume_continue) (reset counter, bump
    ///         `continues_used`) and return [`ExhaustedResolution::Continue`];
    ///       - otherwise the continues are spent: ADOPT the boxed `on_exhausted`
    ///         behavior as this scope's behavior and recurse into it (the
    ///         fall-through), so a `Continue { on_exhausted: Escalate }` whose
    ///         continues are spent resolves to `Escalate`.
    ///
    /// Mutates `self`: on a granted continue the counter resets; on fall-through
    /// `self.behavior` is replaced by the boxed inner behavior so subsequent
    /// resolutions see the post-fall-through behavior.
    pub fn resolve_exhausted(&mut self) -> ExhaustedResolution {
        match self.behavior.clone() {
            BudgetExhaustedBehavior::Fail => ExhaustedResolution::Fail,
            BudgetExhaustedBehavior::Escalate => ExhaustedResolution::Escalate,
            BudgetExhaustedBehavior::Continue { on_exhausted, .. } => {
                if self.continues_remaining() > 0 {
                    self.consume_continue();
                    ExhaustedResolution::Continue
                } else {
                    // Continues spent — fall through to the boxed behavior.
                    self.behavior = *on_exhausted;
                    self.resolve_exhausted()
                }
            }
        }
    }
}

/// The runtime-only resolution of a [`BudgetExhaustedBehavior`] chain at the
/// moment of exhaustion (#125). NOT serialized — purely a control-flow signal
/// returned by [`BudgetContext::resolve_exhausted`].
///
///   - `Continue` — the scope was granted an in-process continue (counter reset,
///     `continues_used` bumped); the caller loops again.
///   - `Fail`     — terminate; `partial_output = None` (discarded by contract).
///   - `Escalate` — hand off to the parent; `partial_output = Some(..)` carries
///     the node-concrete partial.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum ExhaustedResolution {
    Continue,
    Fail,
    Escalate,
}

/// Runtime push/pop stack of [`BudgetContext`] scopes — one node per recursion
/// frame, pushed on descent and popped on ascent. Runtime-only (NOT
/// serialized). Siblings get DISTINCT contexts and do not share state.
#[derive(Debug, Default)]
pub struct BudgetStack {
    pub stack: Vec<BudgetContext>,
}

impl BudgetStack {
    /// Push a new scope onto the stack.
    pub fn push(&mut self, cx: BudgetContext) {
        self.stack.push(cx);
    }

    /// Pop the current scope, returning it (if any).
    pub fn pop(&mut self) -> Option<BudgetContext> {
        self.stack.pop()
    }

    /// The current (innermost) scope, mutably.
    pub fn current_mut(&mut self) -> Option<&mut BudgetContext> {
        self.stack.last_mut()
    }

    /// The current stack depth (recursion frames active).
    pub fn depth(&self) -> usize {
        self.stack.len()
    }
}

/// Runtime push/pop stack of [`observability::SpanId`](crate::observability::SpanId)
/// (resolution #4). Runtime-only (NOT serialized).
#[derive(Debug, Default)]
pub struct SpanStack {
    pub stack: Vec<SpanId>,
}

impl SpanStack {
    /// Push a span id onto the stack.
    pub fn push(&mut self, id: SpanId) {
        self.stack.push(id);
    }

    /// Pop the current span id, returning it (if any).
    pub fn pop(&mut self) -> Option<SpanId> {
        self.stack.pop()
    }

    /// The current stack depth.
    pub fn depth(&self) -> usize {
        self.stack.len()
    }
}

/// The one shared, mutable runtime context threaded through a whole nested
/// strategy tree. Borrows the [`ExecutionRegistry`] for the duration of the
/// run (`'a`). Runtime-only — NOT serialized.
///
/// `stream` holds an optional boxed `dyn Fn` [`StreamSink`], which is neither
/// `Debug` nor `Clone`; like [`HarnessRunOptions`] this type therefore does not
/// derive `Debug`.
///
/// ## Recursive executor wiring (#124)
///
/// The per-variant [`RunStrategy::run`] bodies are LOOP OWNERS: a combinator
/// recurses by calling `self.inner.run(cx).await` (or `self.plan`/`self.execute`
/// as applicable). For PlanExecute (#124) this recursion is GENUINE: the plan
/// phase dispatches `self.plan.run(cx)` and the execute phase dispatches
/// `self.execute.run(cx)` once per task, so a non-ReAct execute child really
/// executes its loop per task. The leaf model-touching primitives (the ReAct
/// turn-loop window, the SelfVerifying evaluate phase, the HillClimbing metric
/// machinery, the Ralph `.spore/` reload/completion checks, and the PlanExecute
/// artifact-capture / deep-resume / hook helpers) stay on the harness behind the
/// [`StrategyExecutor`] trait, reachable through `executor` — but the per-task
/// ORCHESTRATION loop lives in `PlanExecuteConfig::run`, where it can call the
/// child `.run(cx)`. The per-run mutable orchestration state (`task`, `on_stream`,
/// `run_session`, `run_budget`) lives in the [`RunScratch`] so it threads across
/// recursion through this one shared context — `ExecutionContext::run_strategy`
/// is the single entry the harness calls instead of the old central dispatch
/// `match`.
pub struct ExecutionContext<'a> {
    /// Borrowed handle registry (agents/toolsets/schemas/custom strategies).
    pub registry: &'a ExecutionRegistry,
    /// Per-scope budget stack, pushed/popped through recursion.
    pub budgets: BudgetStack,
    /// Aggregated token/cost usage across the whole tree.
    pub usage: AggregateUsage,
    /// Conversation/session state round-tripped across the tree.
    pub session: SessionState,
    /// Span stack for observability nesting.
    pub spans: SpanStack,
    /// Optional streaming sink for emitted events.
    pub stream: Option<StreamSink>,
    /// The harness primitives the per-variant run bodies delegate to (#124).
    /// `None` only for the scaffold/unit fixtures that exercise the runtime
    /// context without a real harness (the recursion stub tests).
    pub executor: Option<&'a dyn StrategyExecutor>,
    /// Per-run orchestration scratch threaded across recursion (#124).
    pub scratch: RunScratch,
}

/// Per-run mutable orchestration state threaded through the recursive strategy
/// tree (#124). Runtime-only (NOT serialized). The combinator bodies set up the
/// sub-phase `task` here before recursing, and the leaf ([`ReactConfig::run`])
/// reads it to drive the ReAct window. `on_stream` is moved out of the context
/// only at the harness entry (it is `!Clone`), so it lives here rather than
/// being re-threaded per call.
#[derive(Default)]
pub struct RunScratch {
    /// The task whose strategy is currently executing. Combinators swap in a
    /// per-phase sub-task before recursing and restore it after.
    pub task: Option<Task>,
    /// The conversation/session state the current leaf turn-loop builds on.
    pub run_session: SessionState,
    /// The shared budget snapshot threaded across every sub-loop of this run.
    pub run_budget: BudgetSnapshot,
    /// A non-terminal pause (`WaitingForHuman`/`Consult`/`Escalate`) or a
    /// fully-formed terminal that must propagate up the recursion VERBATIM as a
    /// [`RunResult`] rather than being collapsed into a [`StrategyOutcome`]. The
    /// harness entry returns this directly when set, preserving the pause/escalate
    /// contract through the recursive executor (#124).
    pub terminal_override: Option<RunResult>,
    /// Cross-process Continue checkpoint seed (#129): `(phase, continues_used)`
    /// carried from a resumed [`HumanRequest::BudgetExhausted`]. The FIRST
    /// [`push_budget`](ExecutionContext::push_budget) whose `phase` matches seeds
    /// the reconstructed scope's `continues_used` (via [`BudgetContext::resumed`])
    /// and CLEARS this seed — so a `Continue` spanning a process pause resumes
    /// with the correct continue count (AC2). Runtime-only; the value rides the
    /// request payload, NOT a serialized `BudgetContext`/`PausedState` field (Q3).
    /// `None` on a fresh run and after the seed is consumed (an in-process
    /// Continue never sets it → AC3: no serialization on the in-process path).
    pub resume_continues: Option<(String, u32)>,
    /// Phase-agnostic resume seed (#131 consult re-drive + #138 budget resume):
    /// the stalled worker conversation carried from a resumed pause. For a
    /// CONSULT resume the consult answer is already injected as the pending
    /// call's tool result; for a BUDGET resume (#138) it is the worker's full
    /// post-exhaustion session. When set, a [`PlanExecuteConfig`] walk resumes
    /// its single `InProgress` task from THIS session (instead of a fresh
    /// instruction-seeded session) so the stalled worker continues mid-loop, its
    /// SelfVerifying evaluator still runs, and the ready-set walk proceeds.
    ///
    /// #138 AC3 (plan-phase exhaustion): when the durable task_list has NO
    /// `InProgress` task, the exhaustion happened in the PLAN phase before any
    /// task was authored — the walk seeds the PLAN session from this carried
    /// conversation instead of cloning a fresh base session.
    ///
    /// The FIRST PlanExecute walk consumes and CLEARS it. Runtime-only — the
    /// session itself rides the serialized [`PausedState::session_state`], so a
    /// cross-process resume reconstructs this seed in
    /// [`resume_consult`](Harness::resume_consult) (consult) or
    /// [`resume`](Harness::resume)'s `ContinueWithBudget` arm (#138 budget).
    /// `None` on a fresh run / after the seed is consumed.
    pub resume_seed: Option<SessionState>,
}

impl<'a> ExecutionContext<'a> {
    /// A fresh context bound to `registry`, with empty stacks and default
    /// usage/session and no stream sink.
    pub fn new(registry: &'a ExecutionRegistry) -> Self {
        Self {
            registry,
            budgets: BudgetStack::default(),
            usage: AggregateUsage::default(),
            session: SessionState::default(),
            spans: SpanStack::default(),
            stream: None,
            executor: None,
            scratch: RunScratch::default(),
        }
    }

    /// The current per-run task (panics only in misuse — the harness always sets
    /// it before driving a strategy). Cloned because the recursive bodies borrow
    /// the context mutably while reading the task.
    fn current_task(&self) -> Task {
        self.scratch
            .task
            .clone()
            .expect("ExecutionContext::scratch.task must be set before running a strategy")
    }

    /// The executor primitives, or a typed failure outcome when absent (the
    /// scaffold-only contexts). Real harness runs always wire one.
    fn executor(&self) -> Result<&'a dyn StrategyExecutor, StrategyOutcome> {
        self.executor.ok_or_else(|| {
            StrategyOutcome::Failed(HarnessError::InvalidConfiguration(
                "ExecutionContext has no StrategyExecutor wired".to_string(),
            ))
        })
    }
}

/// The runtime composition seam: every strategy node knows how to run itself
/// given an [`ExecutionContext`]. Implemented once on [`LoopStrategy`] as the
/// ONLY `match` site — one-line delegation per arm to the inner config's `run`
/// (#124 — the central dispatch `match` in `run_inner` is gone). Each `*Config`
/// impl OWNS its loop: a combinator recurses via `self.inner.run(cx)` (or
/// `self.plan`/`self.execute`), and the leaf [`ReactConfig::run`] drives one
/// bounded ReAct window through the [`StrategyExecutor`] primitive. Without a
/// wired executor (the scaffold-only contexts) every body returns a TYPED
/// [`StrategyOutcome::Failed`] — never a panic/unimplemented/todo (CONVENTIONS).
///
/// Uses the hand-rolled [`BoxFut`] return shape (NOT `trait_variant::make`) so
/// that `Arc<dyn RunStrategy>` is dyn-compatible — the
/// [`ExecutionRegistry`](crate::ExecutionRegistry) custom-strategy escape hatch
/// (#120) stores trait objects keyed by `StrategyRef::Custom` key. This trait is
/// never serialized, so the dyn-safe shape has no wire impact.
pub trait RunStrategy: Send + Sync {
    fn run<'a>(&'a self, cx: &'a mut ExecutionContext<'_>) -> BoxFut<'a, StrategyOutcome>;
}

/// The harness-side primitives the per-variant [`RunStrategy::run`] bodies
/// delegate to (#124). Implemented by [`StandardHarness`]. This is the seam that
/// lets the recursive config bodies own their loops while the model-touching
/// machinery (ReAct turn-loop window, evaluate phase, plan phase, metric
/// machinery, `.spore/` checks) stays where it is tested.
///
/// Every primitive returns a terminal [`RunResult`] for its phase; the config
/// bodies translate the terminal into a [`StrategyOutcome`] (or recurse). The
/// trait is dyn-compatible via [`BoxFut`] so [`ExecutionContext`] can hold
/// `&dyn StrategyExecutor`.
pub trait StrategyExecutor: Send + Sync {
    /// Run ONE bounded ReAct turn-loop window over `session_state`, carrying the
    /// shared `budget_used`. This is the leaf primitive (the body of the legacy
    /// `run_react_inner`). Does NOT finalize observability — the caller does.
    #[allow(clippy::too_many_arguments)]
    fn react_window<'a>(
        &'a self,
        task: Task,
        max_iterations: u32,
        session_state: SessionState,
        budget_used: BudgetSnapshot,
        on_stream: Option<StreamSink>,
        agent: Arc<dyn Agent>,
        // Issue 2 (per-node toolset scoping): the leaf's RESOLVED `toolset`
        // handle, threaded alongside `agent`. Empty ⇒ global-catalogue fallback;
        // a non-empty handle with its own catalogue ⇒ strict per-node scoping.
        toolset: ToolsetRef,
        // Issue #139: the leaf's RESOLVED output schema (canonical compact
        // key-sorted JSON) when `enforce_output_schemas` is ON and the leaf
        // carries `output = Some(..)`; `None` otherwise (no delivery, no
        // validation). When `Some`, the window VALIDATES its terminal against it
        // and retries up to `output_schema_max_retries` extra turns, and sets
        // [`ModelParams::output_schema`] on every turn so the Ollama `format`
        // channel constrains decoding.
        output_schema: Option<serde_json::Value>,
        // Issue #139: the `N` extra validation-retry turns (total attempts =
        // `1 + N`). Ignored when `output_schema` is `None`.
        output_schema_max_retries: u32,
    ) -> BoxFut<'a, RunResult>;

    /// Resolve an [`AgentRef`] to its registered agent (#124). The leaf and the
    /// combinators resolve their worker agent through this so a missing handle is
    /// a typed terminal `Failure` rather than a panic. Returns `Err(RunResult)`
    /// carrying the `UnresolvedHandle` failure when the key is absent.
    fn resolve_agent_ref(
        &self,
        r: &AgentRef,
        session_id: &SessionId,
    ) -> Result<Arc<dyn Agent>, Box<RunResult>>;

    /// Run the SelfVerifying evaluate phase (#124): a fresh evaluator RUN over a
    /// read-only sandbox in a never-shared session, on `eval_agent`, scoped to
    /// `eval_toolset` (empty handle ⇒ global-catalogue fallback). Folds the
    /// run's usage into `total_usage`/`carried`; returns its terminal.
    fn evaluate_phase<'a>(
        &'a self,
        task: &'a Task,
        eval_agent: Arc<dyn Agent>,
        eval_toolset: ToolsetRef,
        carried: &'a mut BudgetSnapshot,
        total_usage: &'a mut AggregateUsage,
    ) -> BoxFut<'a, RunResult>;

    /// Append `reason` as a user message on `session_state` (Default-FAIL).
    fn append_user_message<'a>(
        &'a self,
        session_state: &'a mut SessionState,
        text: &'a str,
    ) -> BoxFut<'a, ()>;

    /// The configured sandbox workspace root (#124, for `VerifierInput`).
    fn workspace_root(&self) -> std::path::PathBuf;

    /// The configured HITL-vs-AFK escalation knob (#130). The `*Config::run`
    /// bodies only hold `&dyn StrategyExecutor`, so they consult the
    /// [`EscalationMode`] through this accessor at each
    /// [`ExhaustedResolution::Escalate`] site: `SurfaceToHuman` pauses with a
    /// [`HumanRequest::BudgetExhausted`]; `Autonomous` keeps the existing
    /// propagate-up behavior. Mirrors [`ralph_max_resets`](Self::ralph_max_resets)
    /// / [`workspace_root`](Self::workspace_root).
    fn escalation_mode(&self) -> EscalationMode;

    /// The output-schema enforcement MIGRATION GATE (issue #139). `false` (the
    /// default) means [`ReactConfig::run`] never resolves/delivers/validates a
    /// leaf's `output` schema — byte-identical to pre-#139. The `*Config::run`
    /// bodies only hold `&dyn StrategyExecutor`, so they read it through this
    /// accessor (mirrors [`escalation_mode`](Self::escalation_mode)).
    fn enforce_output_schemas(&self) -> bool;

    /// The number of EXTRA terminal-validation retry turns `N` granted under
    /// output-schema enforcement (issue #139; total attempts = `1 + N`). Read by
    /// [`ReactConfig::run`] to thread into the window. Default `2`.
    fn output_schema_max_retries(&self) -> u32;

    /// Seed a user message onto `session_state` (the `ContextManager` seam).
    fn seed_user_message<'a>(
        &'a self,
        session_state: &'a mut SessionState,
        text: &'a str,
    ) -> BoxFut<'a, ()>;

    /// Capture + persist a [`PlanArtifact`] from the plan sub-strategy's final
    /// output text (#124). The leaf model work (the planner turn) now runs through
    /// `self.plan.run(cx)`; this primitive owns only the harness-side artifact
    /// machinery: parse the response (R3), fire `OnPlanCreated` (R11), and persist
    /// to the RunStore under `PLAN_EXECUTE_EXTRAS_KEY` (R4). Returns the captured
    /// artifact or a terminal failure to propagate.
    fn capture_plan_artifact<'a>(
        &'a self,
        session_id: &'a SessionId,
        plan_output: &'a str,
        usage: AggregateUsage,
        turns: u32,
    ) -> BoxFut<'a, Result<PlanPhaseOutcome, RunResult>>;

    /// The planning directive seeded before the plan sub-strategy runs (R1) — the
    /// "respond with a single JSON plan" instruction wrapped around the task.
    fn plan_directive(&self, instruction: &str) -> String;

    /// Dispatch the plan sub-strategy `plan` for `plan_task` over `plan_session`,
    /// returning its terminal [`RunResult`] (#124). Genuinely recursive — the
    /// child's `.run(cx)` drives its whole loop. Routes the configured
    /// `planner_agent` (R5/R6) by running the child against an agent-swapped child
    /// harness when one is set; otherwise the default agent runs the plan turn.
    fn run_plan_subtree<'a>(
        &'a self,
        plan: &'a LoopStrategy,
        plan_task: Task,
        plan_session: SessionState,
        budget_used: BudgetSnapshot,
        on_stream: Option<StreamSink>,
    ) -> BoxFut<'a, Option<RunResult>>;

    /// Reconcile a freshly-parsed task list against the DURABLE RunStore
    /// checkpoint (A.6 deep-resume): any task already `Completed` on the
    /// checkpoint is marked `Completed` in `task_list` so it is NOT re-run.
    fn reconcile_completed_tasks<'a>(
        &'a self,
        session_id: &'a SessionId,
        task_list: &'a mut crate::tasklist::TaskList,
    ) -> BoxFut<'a, ()>;

    /// Fire the `OnTaskAdvance` hook (pre, mutable) for an execute step. The hook
    /// may rewrite `step_task.instruction`; the (possibly mutated) instruction is
    /// what the execute sub-strategy then runs.
    fn fire_task_advance<'a>(
        &'a self,
        session_id: &'a SessionId,
        step_task: &'a mut Task,
        task_index: usize,
        total_tasks: usize,
    ) -> BoxFut<'a, ()>;

    /// Persist a parsed task list through the RunStore seam (legacy
    /// `persist_task_list`).
    fn persist_task_list<'a>(
        &'a self,
        session_id: &'a SessionId,
        task_list: &'a crate::tasklist::TaskList,
    ) -> BoxFut<'a, ()>;

    /// Load the persisted [`TaskList`](crate::tasklist::TaskList) from the
    /// RunStore seam under
    /// [`TASK_LIST_EXTRAS_KEY`](crate::tasklist::TASK_LIST_EXTRAS_KEY), the one
    /// authoring path (#126, decision C). `None` when no list is persisted for
    /// the session. This is how the DAG executor obtains its task list (with
    /// real blockers) instead of the linear `plan_artifact_to_task_list` bridge.
    fn load_task_list<'a>(
        &'a self,
        session_id: &'a SessionId,
    ) -> BoxFut<'a, Option<crate::tasklist::TaskList>>;

    /// Drain and reset the harness-observed write/edit file-path accumulator
    /// (#126, AC2). The dispatch seam records the `path` of every `write_file` /
    /// `edit_file` tool call here as it happens; the DAG executor calls this on
    /// task completion to attach the OBSERVED `files_touched` to the task's
    /// [`StepLedgerEntry`](crate::tasklist::StepLedgerEntry). Paths are returned
    /// in observation order, de-duplicated (a file written twice in one task
    /// appears once), and the accumulator is cleared so the next task starts
    /// empty. NEVER model-self-reported — observed from the actual tool call.
    fn take_observed_writes(&self) -> Vec<String>;

    /// Clear the harness-observed write accumulator WITHOUT reading it (#126).
    /// Called before each execute step so a step's `files_touched` reflects only
    /// the writes that step issued (no leakage from a prior step).
    fn clear_observed_writes(&self);

    /// Build the per-window Ralph seed session (#124): a fresh
    /// `SessionState::default()` seeded with `instruction`, the `.spore/` reload
    /// context (R3), and the optional VCS history block — exactly the legacy
    /// `run_ralph` window setup, minus the model loop (which now recurses).
    fn ralph_seed_session<'a>(&'a self, instruction: &'a str) -> BoxFut<'a, SessionState>;

    /// Ralph external completion check (#124, legacy `ralph_completion_status`):
    /// `None` ⇒ complete; `Some(reason)` ⇒ tasks remain. ASYNC since #142: the
    /// Ralph checkpoint moved off the `.spore/` filesystem onto the durable
    /// project-id [`RunStore`](crate::storage::RunStore).
    fn ralph_completion_status<'a>(&'a self) -> BoxFut<'a, Option<String>>;

    /// The Ralph outer-loop reset cap (`config.max_resets`, #124).
    fn ralph_max_resets(&self) -> u32;

    /// Resolve the HillClimbing metric evaluator for `key` (#124, Q2), or
    /// `Err(RunResult)` with the misconfiguration failure when absent.
    fn resolve_metric_evaluator(
        &self,
        key: &str,
        session_id: &SessionId,
    ) -> Result<Arc<dyn crate::metric::MetricEvaluator>, Box<RunResult>>;

    /// HillClimbing iteration-0 baseline (#124): evaluate the metric (no agent
    /// turn), record the row + span, and return the baseline value — or
    /// `Err(RunResult)` on a baseline-evaluation failure (already records the
    /// failed row + writes the TSV). Leaf primitive of the legacy
    /// `run_hill_climbing`.
    #[allow(clippy::too_many_arguments)]
    fn hill_baseline<'a>(
        &'a self,
        evaluator: &'a Arc<dyn crate::metric::MetricEvaluator>,
        session_id: &'a SessionId,
        task_id: &'a TaskId,
        direction: HillClimbingDirection,
        rows: &'a mut Vec<crate::metric::ResultsEntry>,
        span_seq: &'a mut u64,
        total_usage: AggregateUsage,
        turns: u32,
    ) -> BoxFut<'a, Result<f64, RunResult>>;

    /// HillClimbing per-iteration metric eval + keep/revert decision (#124): the
    /// agent turn already ran (recursively); this evaluates the metric, applies
    /// `should_keep`, optionally reverts, records the row + span, and returns the
    /// updated `(current_best, stagnation_increment)`. Leaf primitive of the
    /// legacy `run_hill_climbing`.
    #[allow(clippy::too_many_arguments)]
    fn hill_iteration<'a>(
        &'a self,
        evaluator: &'a Arc<dyn crate::metric::MetricEvaluator>,
        session_id: &'a SessionId,
        task_id: &'a TaskId,
        iteration: u32,
        direction: HillClimbingDirection,
        revert_on_no_improvement: bool,
        min_improvement_delta: Option<f64>,
        current_best: f64,
        rows: &'a mut Vec<crate::metric::ResultsEntry>,
        span_seq: &'a mut u64,
    ) -> BoxFut<'a, (f64, bool)>;

    /// Write the HillClimbing results TSV (#124, leaf primitive).
    fn hill_write_tsv<'a>(
        &'a self,
        task_id: &'a TaskId,
        rows: &'a [crate::metric::ResultsEntry],
    ) -> BoxFut<'a, ()>;

    /// Finalize observability for a terminal outcome (legacy
    /// `finalize_observability` routing). No-op for non-terminal results.
    fn finalize<'a>(&'a self, result: &'a RunResult) -> BoxFut<'a, ()>;
}

impl RunResult {
    /// True for the non-terminal pause / clean-handoff variants
    /// (`WaitingForHuman` / `Consult` / `Escalate`) that a combinator must
    /// propagate VERBATIM rather than fold into its own terminal (#124).
    pub fn is_pause(&self) -> bool {
        matches!(
            self,
            RunResult::WaitingForHuman { .. }
                | RunResult::Consult { .. }
                | RunResult::Escalate { .. }
        )
    }
}

impl RunStrategy for LoopStrategy {
    fn run<'a>(&'a self, cx: &'a mut ExecutionContext<'_>) -> BoxFut<'a, StrategyOutcome> {
        // The ONLY `match` site: the enum→config delegation (AC1). No central
        // dispatch match remains — each config owns its loop.
        match self {
            LoopStrategy::ReAct(c) => c.run(cx),
            LoopStrategy::PlanExecute(c) => c.run(cx),
            LoopStrategy::SelfVerifying(c) => c.run(cx),
            LoopStrategy::Ralph(c) => c.run(cx),
            LoopStrategy::HillClimbing(c) => c.run(cx),
        }
    }
}

impl RunStrategy for ReactConfig {
    /// The leaf: a bounded ReAct turn-loop window. Reads the per-run scratch
    /// (`task`, `run_session`, `run_budget`) and drives one ReAct window through
    /// the executor primitive, threading the result back into the shared usage.
    ///
    /// ## Budget enforcement (#125)
    ///
    /// The leaf pushes its OWN [`BudgetContext`] scope for `self.budget` and
    /// charges the turns the window consumed against it. Per Open Q A-2 (rule 6)
    /// the leaf does NOT carry its own behavior and NEVER self-resolves a
    /// Continue/Fail/Escalate at the leaf — on charge exhaustion it PROPAGATES a
    /// `StrategyOutcome::BudgetExhausted` to its parent (which owns the single
    /// recovery site). The propagated `partial_output` is the window's last
    /// FinalResponse text as JSON (fork #2). A clean (non-budget) terminal is
    /// recorded verbatim through [`record_terminal`](ExecutionContext::record_terminal).
    fn run<'a>(&'a self, cx: &'a mut ExecutionContext<'_>) -> BoxFut<'a, StrategyOutcome> {
        Box::pin(async move {
            let executor = match cx.executor() {
                Ok(e) => e,
                Err(o) => return o,
            };
            let task = cx.current_task();
            let max_iterations = self.max_iterations();
            let mut session_state = std::mem::take(&mut cx.scratch.run_session);
            let budget_used = cx.scratch.run_budget.clone();
            // #124: resolve the worker agent from the registry by THIS leaf's
            // handle (genuine recursion — no `config.agent`). A missing handle is
            // a typed terminal failure.
            let agent = match executor.resolve_agent_ref(&self.agent, &task.session_id) {
                Ok(a) => a,
                Err(result) => {
                    let result = *result;
                    executor.finalize(&result).await;
                    return cx.record_terminal(result);
                }
            };
            // Output-schema delivery + enforcement (issue #139). MIGRATION GATE:
            // only when `enforce_output_schemas` is ON AND this leaf carries
            // `output = Some(..)` do we resolve the schema, DELIVER it (directive
            // seed + the constrained-decoding channel), and pass it (plus the
            // retry budget `N`) into the window for terminal validation. When the
            // gate is OFF or there is no `output`, `output_schema` is `None` and
            // the window behaves byte-identically to pre-#139 (no resolve, no
            // delivery, no validation). The schema is canonicalized to compact
            // key-sorted JSON so its delivered/reported bytes are identical
            // across the four language ports.
            let output_schema: Option<serde_json::Value> = if executor.enforce_output_schemas() {
                self.output
                    .as_ref()
                    .and_then(|r| cx.registry.resolve_schema(r))
                    .cloned()
            } else {
                None
            };
            let output_schema_max_retries = executor.output_schema_max_retries();
            if let Some(schema) = output_schema.as_ref() {
                // AC1: append the resolved schema to the leaf's directive/system
                // context as a USER message, key-sorted via `canonicalize_json`
                // so the seeded bytes are identical across languages.
                let directive = format!(
                    "Your final response must be a JSON value that conforms to this \
JSON schema: {}",
                    crate::model::canonicalize_json(schema)
                );
                executor
                    .seed_user_message(&mut session_state, &directive)
                    .await;
            }
            // #125/#129: push this leaf's OWN budget scope carrying its CONFIGURED
            // `behavior`. The leaf still never RESOLVES it in the nested case (rule
            // 6: it PROPAGATES a `BudgetExhausted` to its parent, which owns the
            // single recovery site). Carrying the real `behavior` only means the
            // propagated error reports it, so the TOP-LEVEL/bare-leaf resolution
            // site (`drive_strategy`) can honor it (Q1 — a bare leaf self-resolves,
            // a nested leaf does not).
            cx.push_budget(self.budget.clone(), self.behavior.clone(), "react");
            // The leaf CLONES (not takes) the run's stream sink so sibling phases
            // of a combinator parent still inherit it for their own turns, and
            // WRAPS it so every event this leaf emits is attributed to THIS node
            // (kind `react` + the resolved agent handle). The wrapper is what the
            // live agent adapter forwards to, so token deltas carry attribution too.
            let agent_id = (!self.agent.0.is_empty()).then(|| self.agent.0.clone());
            let on_stream = wrap_node_sink(cx.stream.clone(), "react", agent_id);
            let result = executor
                .react_window(
                    task,
                    max_iterations,
                    session_state,
                    budget_used,
                    on_stream,
                    agent,
                    // Issue 2: thread THIS leaf's toolset handle down so the
                    // window dispatches the per-node scoped catalogue (empty
                    // handle ⇒ global-catalogue fallback). Mirrors `agent`.
                    self.toolset.clone(),
                    // Issue #139: thread the resolved output schema (or `None`)
                    // and the retry budget so the window validates the terminal.
                    output_schema,
                    output_schema_max_retries,
                )
                .await;
            executor.finalize(&result).await;

            // #125: charge the window's turns against this leaf's OWN scope. The
            // leaf POLICY (`self.budget`) — not the global `BudgetLimits` backstop —
            // is the per-node enforcement point. A window stops at
            // `min(max_iterations, task.budget.max_turns)`: when the LEAF cap is the
            // binding constraint (the window consumed >= the leaf policy value), the
            // leaf is exhausted and PROPAGATES a typed `BudgetExhausted` to its
            // parent (rule 6 — the leaf never self-resolves). When the smaller
            // GLOBAL backstop trips first, the legacy `BudgetExceeded` terminal is
            // recorded VERBATIM (the global cap is unchanged, #117 backstop).
            let window_turns = match &result {
                RunResult::Success { turns, .. } | RunResult::Failure { turns, .. } => *turns,
                _ => 0,
            };
            // #137: the window hit the consecutive-tool-error breaker's 2N hard
            // stop. PROPAGATE it through the SAME single budget-exhaustion
            // resolution site (so the node's `behavior` governs Fail/Escalate/
            // Continue), but carry the `ToolErrorLoop` cause so the terminal
            // reports `HaltReason::ToolErrorLoop`, never `BudgetExceeded`. The
            // window's turns are still CHARGED against the leaf scope (accurate
            // accounting), but the breaker stopped EARLY — the remaining budget
            // is NOT burned. Detection is independent of `leaf_cap_binding`.
            if let RunResult::Failure {
                reason:
                    HaltReason::ToolErrorLoop {
                        tool,
                        consecutive_errors,
                    },
                ..
            } = &result
            {
                let tool = tool.clone();
                let consecutive_errors = *consecutive_errors;
                let last_final = last_final_response_text(&result).unwrap_or_default();
                if let RunResult::Failure { session_state, .. } = &result {
                    cx.scratch.run_session = session_state.clone();
                }
                let _ = cx.charge_current(window_turns);
                cx.pop_budget();
                return promote_tool_error_loop(
                    &self.budget,
                    &self.behavior,
                    window_turns,
                    tool,
                    consecutive_errors,
                    Some(react_partial_json(&last_final)),
                );
            }
            let window_hit_budget = matches!(
                &result,
                RunResult::Failure {
                    reason: HaltReason::BudgetExceeded { .. },
                    ..
                }
            );
            // The leaf cap is binding when the window hit a budget terminal AND it
            // consumed at least the leaf's own allowance (so the leaf policy — not a
            // smaller global backstop — is what stopped it).
            let leaf_cap_binding = window_hit_budget
                && matches!(self.budget.allowance_value(), Some(cap) if window_turns >= cap);
            let charge = cx.charge_current(window_turns);
            if leaf_cap_binding || charge.is_err() {
                // The leaf partial is the window's last FinalResponse text.
                let last_final = last_final_response_text(&result).unwrap_or_default();
                // Carry the post-run session so a parent resumes losslessly.
                if let RunResult::Success { session_state, .. }
                | RunResult::Failure { session_state, .. } = &result
                {
                    cx.scratch.run_session = session_state.clone();
                }
                let err = charge.err().unwrap_or_else(|| {
                    // The window itself hit the cap; synthesize the charge error
                    // from the current scope state.
                    cx.budgets
                        .current_mut()
                        .map(|s| BudgetExhausted {
                            policy: s.policy.clone(),
                            behavior: s.behavior.clone(),
                            steps_taken: s.steps_taken,
                            continues_used: s.continues_used,
                            phase: s.phase.clone(),
                        })
                        .unwrap_or_else(|| BudgetExhausted {
                            policy: self.budget.clone(),
                            behavior: self.behavior.clone(),
                            steps_taken: window_turns,
                            continues_used: 0,
                            phase: "react".to_string(),
                        })
                });
                cx.pop_budget();
                // Rule 6: the leaf PROPAGATES — partial carries the last
                // FinalResponse (Escalate semantics, fork #1/#2).
                return promote_budget_exhausted(&err, Some(react_partial_json(&last_final)));
            }
            cx.pop_budget();
            cx.record_terminal(result)
        })
    }
}

impl RunStrategy for PlanExecuteConfig {
    /// Plan→execute DAG executor (#124 recursion seam, #126 ready-set walk).
    ///
    /// GENUINELY recursive: the plan phase dispatches `self.plan.run(cx)` and the
    /// execute phase dispatches `self.execute.run(cx)` ONCE PER TASK. The child
    /// strategy's full loop runs for each phase.
    ///
    /// # #126 — what this body now does
    /// - **Task list source (decision C):** after the plan phase persists the
    ///   captured artifact (so the legacy plan→tasklist replay path is intact),
    ///   the executor LOADS its runnable [`TaskList`] from the persisted
    ///   `task_list` tool store (`load_task_list`) — the ONE authoring path that
    ///   can carry real `blockers`. The plan artifact only seeds an initial
    ///   linear list when nothing was authored via the tool.
    /// - **Cycle re-check (AC5):** `task_list.has_cycle()` is re-checked at
    ///   execute entry (defense in depth — `add_task` already rejects cycles) →
    ///   [`HaltReason::TaskGraphCycle`].
    /// - **Ready-set walk (AC1):** repeatedly pick the LOWEST-id `Pending` task
    ///   whose blockers are all `Completed` (`next_ready`), run it, mark
    ///   `Completed`, repeat — honoring the blocker DAG, deterministic id
    ///   tiebreak. v1 runs ready tasks SEQUENTIALLY.
    /// - **Two-tier context (AC1 isolation):** each step is seeded with Tier-1
    ///   (its TRANSITIVE blockers' final outputs + their ledger rows, decision D)
    ///   plus Tier-2 (the global running ledger, every step). Independent
    ///   branches never appear in a task's seed.
    /// - **Ledger (decision B):** on completion a
    ///   [`StepLedgerEntry`](crate::tasklist::StepLedgerEntry) is appended whose
    ///   `files_touched` is HARNESS-OBSERVED from write/edit tool calls
    ///   (`take_observed_writes`, AC2) — never self-reported. The ledger is
    ///   bounded at [`STEP_LEDGER_MAX_ENTRIES`](crate::tasklist::STEP_LEDGER_MAX_ENTRIES)
    ///   via drop-oldest.
    /// - **Failure cascade (decision A/E, AC3/AC4):** a terminal task failure
    ///   (unrecoverable error OR a `BudgetExhausted` resolving to `Fail`) marks
    ///   its transitive dependents `Blocked` (tracked in the run-local
    ///   `blocked_by_failure` set) and KEEPS scheduling unrelated tasks; at drain
    ///   the run returns [`HaltReason::TasksBlockedByFailure`] with the full
    ///   completed/blocked partition. A run where every task completes is
    ///   `Success`, as before.
    ///
    /// # #138 — resume seeding + skip re-planning
    /// - **AC1 (skip re-planning):** the durable `task_list` (project-scoped, so it
    ///   survives Ralph's per-window session reset, #142) is probed BEFORE the plan
    ///   dispatch. A non-empty list ⇒ the WHOLE plan phase is skipped (no
    ///   `plan_directive` / `run_plan_subtree` / `capture_plan_artifact`); the run
    ///   goes straight to reconcile + the ready-set walk. The plan artifact may be
    ///   ABSENT (AC1-a artifact-optional) — nothing downstream needs it once a list
    ///   exists. `total_usage` starts empty and `carried.turns` stays at the incoming
    ///   `budget_used.turns` when the plan phase is skipped.
    /// - **AC2 (seed the stalled worker):** a budget/consult resume carries the
    ///   stalled worker session in the phase-agnostic [`RunScratch::resume_seed`].
    ///   For execute-phase exhaustion the single `InProgress` task is reset to
    ///   `Pending` and its step is seeded from the carried session (the
    ///   InProgress→Pending→complete machinery), so the worker continues mid-loop.
    /// - **AC3 (plan-phase exhaustion):** when the seed is present AND the durable
    ///   list has NO `InProgress` task (option iii — the exhaustion was the plan
    ///   phase, list still empty per AC3-b), the PLAN session is seeded from the
    ///   carried conversation instead of a fresh base session.
    ///
    /// No `// SPEC QUESTION:` markers — all five forks (A–E) were resolved.
    fn run<'a>(&'a self, cx: &'a mut ExecutionContext<'_>) -> BoxFut<'a, StrategyOutcome> {
        Box::pin(async move {
            use crate::tasklist::{
                push_step_ledger, render_step_ledger, StepLedgerEntry, TaskStatus,
            };
            use std::collections::{HashMap, HashSet};

            let executor = match cx.executor() {
                Ok(e) => e,
                Err(o) => return o,
            };
            let task = cx.current_task();
            let session_id = task.session_id.clone();
            // The incoming shared execute session ( `[user: task.instruction]` ).
            let base_session = std::mem::take(&mut cx.scratch.run_session);
            let budget_used = cx.scratch.run_budget.clone();
            // Save the parent sink and install a node-attributing wrapper for the
            // phases (#stream): children inherit `cx.stream` and stream through it,
            // each event gaining a `plan_execute` hop in its node path. Restored to
            // the parent on every exit (the `cx.stream = on_stream;` sites below).
            let on_stream = cx.stream.take();
            cx.stream = wrap_node_sink(on_stream.clone(), "plan_execute", None);

            // #131/#138: the phase-agnostic resume seed (the stalled worker
            // conversation carried from a resumed consult or budget pause). Taken
            // BEFORE the plan phase so AC3 (plan-phase exhaustion) can seed the
            // plan session from it, and AC2 (execute-phase exhaustion) can
            // re-attach it to the single `InProgress` task.
            let mut resume_seed_session = cx.scratch.resume_seed.take();

            // #138 AC1 (skip re-planning): probe the DURABLE task_list BEFORE the
            // plan phase. If a non-empty list already exists (e.g. a prior window
            // authored it, #142 makes it survive Ralph's per-window session reset),
            // the plan phase is REDUNDANT — go straight to reconcile + the ready-set
            // walk. This is the core fix: a budget/consult re-entry no longer burns
            // its grant re-planning a graph that is already durable. The plan
            // artifact under `PLAN_EXECUTE_EXTRAS_KEY` may be ABSENT in this case
            // (AC1-a artifact-optional) — nothing downstream requires it once a
            // task_list exists.
            let preexisting = executor.load_task_list(&session_id).await;
            let skip_plan = matches!(&preexisting, Some(l) if !l.tasks.is_empty());

            let (mut task_list, mut total_usage, mut carried) = if skip_plan {
                // ── AC1: skip-plan path. The list is the durable source of truth.
                let mut task_list =
                    preexisting.expect("skip_plan implies a non-empty preexisting list");

                // AC5 (defense in depth): re-check the durable graph for cycles.
                if task_list.has_cycle() {
                    cx.stream = on_stream;
                    let result = RunResult::Failure {
                        reason: HaltReason::TaskGraphCycle {
                            reason: "persisted task graph contains a directed cycle".into(),
                        },
                        session_id,
                        usage: AggregateUsage::default(),
                        turns: budget_used.turns,
                        session_state: SessionState::default(),
                    };
                    return cx.finish(executor, task, result).await;
                }

                // A.6 deep-resume: reconcile already-Completed tasks so they are
                // NOT re-run (handles the dedup the plan path would have done).
                executor
                    .reconcile_completed_tasks(&session_id, &mut task_list)
                    .await;
                executor.persist_task_list(&session_id, &task_list).await;

                // No plan turn ran: usage starts empty and the shared budget is
                // carried unchanged (turns stay at the incoming `budget_used.turns`).
                (task_list, AggregateUsage::default(), budget_used.clone())
            } else {
                // ── AC3 / fresh-plan path: run the plan phase. ──────────────────
                // #138 AC3 (plan-phase exhaustion, infer-from-task_list option iii):
                // when a resume seed is present AND the durable list has no
                // `InProgress` task, the exhaustion happened in the PLAN phase
                // before authoring any task (AC3-b: the list is still empty). Seed
                // the PLAN session from the carried conversation so the planner
                // CONTINUES on it instead of starting fresh — and consume the seed
                // here so the execute-phase re-attach below does not also fire.
                let plan_resume = resume_seed_session.is_some()
                    && preexisting
                        .as_ref()
                        .is_none_or(|l| l.tasks.iter().all(|t| t.status != TaskStatus::InProgress));
                let directive = executor.plan_directive(&task.instruction);
                let mut plan_session = if plan_resume {
                    resume_seed_session
                        .take()
                        .unwrap_or_else(|| base_session.clone())
                } else {
                    base_session.clone()
                };
                executor
                    .seed_user_message(&mut plan_session, &directive)
                    .await;
                // The plan phase runs under the plan sub-strategy's OWN declared
                // budget (e.g. a ReAct `PerLoop{4}`); the global `max_turns` is only
                // the outer backstop.
                let plan_task = Task {
                    id: task.id.clone(),
                    instruction: directive,
                    session_id: session_id.clone(),
                    budget: task.budget.clone(),
                    loop_strategy: (*self.plan).clone(),
                };
                let plan_result = executor
                    .run_plan_subtree(
                        &self.plan,
                        plan_task,
                        plan_session,
                        budget_used.clone(),
                        cx.stream.clone(),
                    )
                    .await;
                let (plan_output, plan_usage, plan_turns) = match plan_result {
                    Some(RunResult::Success {
                        output,
                        usage,
                        turns,
                        ..
                    }) => (output, usage, turns),
                    Some(other) => {
                        cx.stream = on_stream;
                        return cx.finish(executor, task, other).await;
                    }
                    None => {
                        cx.stream = on_stream;
                        let result = RunResult::Failure {
                            reason: HaltReason::PlanPhaseFailed {
                                error: crate::plan::PlanPhaseError::PlanningTurnFailed {
                                    message: "plan sub-strategy produced no terminal".into(),
                                },
                            },
                            session_id,
                            usage: AggregateUsage::default(),
                            turns: budget_used.turns,
                            session_state: SessionState::default(),
                        };
                        return cx.finish(executor, task, result).await;
                    }
                };

                // Capture + persist the artifact from the plan child's output (R3/
                // R4/R11) — the harness-side machinery, no model turn.
                let outcome = match executor
                    .capture_plan_artifact(&session_id, &plan_output, plan_usage, plan_turns)
                    .await
                {
                    Ok(outcome) => outcome,
                    Err(failure) => {
                        cx.stream = on_stream;
                        return cx.finish(executor, task, failure).await;
                    }
                };

                // #126 decision C: the runnable task list comes from the persisted
                // `task_list` tool store (the ONE authoring path — it can carry real
                // blockers). Fall back to the linear plan-artifact bridge only when
                // nothing was authored via the tool (back-compat with the #59/#124
                // plan-only path and its replay fixtures).
                let mut task_list = match executor.load_task_list(&session_id).await {
                    Some(persisted) if !persisted.tasks.is_empty() => persisted,
                    _ =>
                    {
                        #[allow(deprecated)]
                        crate::tasklist::plan_artifact_to_task_list(&outcome.artifact)
                    }
                };
                if task_list.tasks.is_empty() {
                    cx.stream = on_stream;
                    let result = RunResult::Failure {
                        reason: HaltReason::EmptyPlan,
                        session_id,
                        usage: outcome.usage,
                        turns: outcome.turns,
                        session_state: SessionState::default(),
                    };
                    return cx.finish(executor, task, result).await;
                }

                // #126 AC5: re-check the WHOLE graph for cycles at execute entry.
                if task_list.has_cycle() {
                    cx.stream = on_stream;
                    let result = RunResult::Failure {
                        reason: HaltReason::TaskGraphCycle {
                            reason: "persisted task graph contains a directed cycle".into(),
                        },
                        session_id,
                        usage: outcome.usage,
                        turns: outcome.turns,
                        session_state: SessionState::default(),
                    };
                    return cx.finish(executor, task, result).await;
                }

                executor.persist_task_list(&session_id, &task_list).await;

                // Carry the shared budget past the plan turn.
                let mut carried = budget_used.clone();
                carried.turns = outcome.turns;
                carried.input_tokens += outcome.usage.input_tokens;
                carried.output_tokens += outcome.usage.output_tokens;

                // A.6 deep-resume (Q2): reconcile against the durable checkpoint so
                // already-Completed tasks are not re-run.
                executor
                    .reconcile_completed_tasks(&session_id, &mut task_list)
                    .await;

                (task_list, outcome.usage, carried)
            };

            // #131 consult / #138 budget re-drive: a resumed pause carries the
            // stalled worker conversation in `resume_seed_session`. The stalled task
            // is the single `InProgress` task in the durable list (PlanExecute marks
            // a task InProgress before running it). Reset it to `Pending` so
            // `next_ready` re-schedules it, and remember its id so its step uses the
            // carried session instead of a fresh one — the worker then continues
            // mid-loop and its evaluator still runs. (When the seed was already
            // consumed by the AC3 plan-resume path above, this is a no-op.)
            let mut consult_resume_session = resume_seed_session;
            let consult_resume_task: Option<u32> = if consult_resume_session.is_some() {
                let in_progress = task_list
                    .tasks
                    .iter()
                    .find(|t| t.status == TaskStatus::InProgress)
                    .map(|t| t.id);
                if let Some(tid) = in_progress {
                    // Reset directly (bypassing `update`'s forward-only transition
                    // guard, which rejects InProgress->Pending): the resume
                    // legitimately re-schedules the in-flight task.
                    if let Some(t) = task_list.tasks.iter_mut().find(|t| t.id == tid) {
                        t.status = TaskStatus::Pending;
                    }
                } else {
                    // No in-progress task to resume (out-of-contract); drop the
                    // seed so the walk proceeds normally rather than stalling.
                    consult_resume_session = None;
                }
                in_progress
            } else {
                None
            };

            let mut last_output = String::new();
            let mut last_state = SessionState::default();

            // #126 Tier-1/Tier-2 + cascade run-local state.
            // - `final_outputs`: each completed task's `Success.output` (Tier-1).
            // - `ledger`: the Tier-2 global running ledger (bounded, drop-oldest).
            // - `ledger_elided`: sticky flag set the first time entries are dropped.
            // - `blocked_by_failure`: tasks cascade-Blocked by a terminal failure
            //   (decision E — the run scratch, NOT a TaskStatus variant).
            let mut final_outputs: HashMap<u32, String> = HashMap::new();
            let mut ledger: Vec<StepLedgerEntry> = Vec::new();
            let mut ledger_elided = false;
            let mut blocked_by_failure: HashSet<u32> = HashSet::new();
            // The first terminal failure that triggered a cascade (decision A).
            let mut first_failure: Option<(u32, String)> = None;

            // #125: PlanExecute owns a budget scope for its execute phase.
            let plan_policy = match task.budget.max_turns {
                Some(max) => BudgetPolicy::TotalSteps { value: max },
                None => BudgetPolicy::Unlimited,
            };
            cx.push_budget(plan_policy, self.behavior.clone(), "plan_execute");

            // Total positional count for the OnTaskAdvance hook (stable).
            let total_tasks = task_list.tasks.len();

            // ── Phase 2: ready-set DAG walk (#126). ─────────────────────────
            //
            // Repeatedly pick the lowest-id Pending task whose blockers are all
            // Completed. A task whose blocker FAILED is cascade-Blocked (so it is
            // no longer Pending and never becomes ready). When no Pending task is
            // ready, the walk drains.
            loop {
                let Some(task_id) = task_list.next_ready() else {
                    break;
                };
                let index = task_list
                    .tasks
                    .iter()
                    .position(|t| t.id == task_id)
                    .unwrap_or(0);
                let instruction = task_list.tasks[index].description.clone();

                // Mark InProgress and re-persist (Q4).
                let _ = task_list.update(task_id, Some(TaskStatus::InProgress), None);
                executor.persist_task_list(&session_id, &task_list).await;

                // Fire OnTaskAdvance (pre, mutable). The hook may rewrite the
                // step instruction; the (possibly mutated) instruction seeds the
                // execute sub-strategy.
                let mut step_task = Task {
                    id: task.id.clone(),
                    instruction,
                    session_id: session_id.clone(),
                    budget: task.budget.clone(),
                    loop_strategy: (*self.execute).clone(),
                };
                executor
                    .fire_task_advance(&session_id, &mut step_task, index, total_tasks)
                    .await;

                // #131 consult re-drive: if THIS is the task that was consulting,
                // resume its worker from the carried conversation (answer already
                // injected) instead of a fresh instruction-seeded session — the
                // worker continues mid-loop and its evaluator still runs. Otherwise
                // build the normal fresh, Tier-1/Tier-2-seeded step session.
                let step_session = if Some(task_id) == consult_resume_task {
                    consult_resume_session
                        .take()
                        .unwrap_or_else(|| base_session.clone())
                } else {
                    // #126 Tier-1 scoped context: seed this step from a FRESH copy
                    // of the base session (NOT a forward-folded shared transcript —
                    // that breaks on a DAG, #126) plus, for THIS task's transitive
                    // blockers only, their final outputs + their ledger rows.
                    // Independent branches never appear (AC1 isolation).
                    let mut step_session = base_session.clone();
                    let blockers = task_list.transitive_blockers(task_id);
                    if !blockers.is_empty() {
                        let blocker_set: HashSet<u32> = blockers.iter().copied().collect();
                        // Tier-1: transitive blockers' final outputs (ascending id).
                        let mut tier1_lines: Vec<String> = Vec::new();
                        for b in &blockers {
                            if let Some(out) = final_outputs.get(b) {
                                tier1_lines.push(format!("#{b} result: {out}"));
                            }
                        }
                        if !tier1_lines.is_empty() {
                            let block =
                                format!("Results from upstream tasks:\n{}", tier1_lines.join("\n"));
                            executor.seed_user_message(&mut step_session, &block).await;
                        }
                        // Tier-1 ledger: the Tier-2 ledger rows for this set.
                        let scoped: Vec<StepLedgerEntry> = ledger
                            .iter()
                            .filter(|e| blocker_set.contains(&e.task_id))
                            .cloned()
                            .collect();
                        if let Some(block) = render_step_ledger(&scoped, false) {
                            executor.seed_user_message(&mut step_session, &block).await;
                        }
                    }

                    // #126 Tier-2: inject the FULL global running ledger into EVERY
                    // step (with the static elision marker once entries dropped).
                    if let Some(block) = render_step_ledger(&ledger, ledger_elided) {
                        executor.seed_user_message(&mut step_session, &block).await;
                    }

                    // Finally seed this step's own instruction.
                    executor
                        .seed_user_message(&mut step_session, &step_task.instruction)
                        .await;
                    step_session
                };

                // #126 AC2: clear the observed-write accumulator so this task's
                // files_touched reflect ONLY the writes this step issues.
                executor.clear_observed_writes();

                cx.scratch.task = Some(step_task);
                cx.scratch.run_session = step_session;
                cx.scratch.run_budget = carried.clone();
                let carried_before = carried.turns;
                let step_outcome = self.execute.run(cx).await;

                // ── BudgetExhausted (#125 rule 4/7) — resolve THIS scope. ────
                if let StrategyOutcome::BudgetExhausted {
                    steps_taken: leaf_steps,
                    ..
                } = &step_outcome
                {
                    // The execute LEAF already counted the worker's true consumed
                    // turns (ABSOLUTE — including the incoming `carried_before`
                    // floor) and carried them in the outcome's `steps_taken`. Use
                    // THAT for the grant accounting, NOT the parent `plan_execute`
                    // scope's `steps_taken`: that scope is `Unlimited` when the Task
                    // has `max_turns = None` (so its `steps_taken` is 0), which made
                    // the resume grant `granted = 0 + steps` a no-op and stalled the
                    // worker on the same window every grant. Everything ELSE on `err`
                    // stays the parent scope's: `phase` must remain "plan_execute" so
                    // the resume-seed `continues_used` restore matches in
                    // `push_budget`, and `continues_used` is the combinator's
                    // (`max_continues`) count, not the leaf's.
                    let leaf_steps = *leaf_steps;
                    let err = cx
                        .budgets
                        .current_mut()
                        .map(|s| BudgetExhausted {
                            policy: s.policy.clone(),
                            behavior: s.behavior.clone(),
                            steps_taken: leaf_steps,
                            continues_used: s.continues_used,
                            phase: s.phase.clone(),
                        })
                        .expect("plan_execute scope pushed above");
                    let resolution = cx.resolve_current();
                    match resolution {
                        // #126 AC4: a budget-`Fail` task cascades IDENTICALLY to an
                        // error-failed one — block its transitive dependents and
                        // keep scheduling unrelated tasks.
                        ExhaustedResolution::Fail => {
                            let _ = task_list.update(task_id, Some(TaskStatus::Blocked), None);
                            for dep in task_list.transitive_dependents(task_id) {
                                let _ = task_list.update(dep, Some(TaskStatus::Blocked), None);
                                blocked_by_failure.insert(dep);
                            }
                            blocked_by_failure.insert(task_id);
                            executor.persist_task_list(&session_id, &task_list).await;
                            if first_failure.is_none() {
                                first_failure = Some((
                                    task_id,
                                    format!("budget exhausted (Fail): {:?}", err.policy),
                                ));
                            }
                            continue;
                        }
                        // #129: a granted `Continue` loops IN-PROCESS — the scope's
                        // `resolve_current` already reset `steps_taken` and bumped
                        // `continues_used`. Reset this task to `Pending` and re-enter
                        // the ready-set walk so it runs again under the refreshed
                        // scope allowance (NO serialization — AC3). `max_continues`
                        // bounds the loop: once continues are spent, the chain falls
                        // through to `Fail`/`Escalate`.
                        ExhaustedResolution::Continue => {
                            let _ = task_list.update(task_id, Some(TaskStatus::Pending), None);
                            executor.persist_task_list(&session_id, &task_list).await;
                            continue;
                        }
                        // Escalate: under `Autonomous`, surface the partial and abort
                        // the run. Under `SurfaceToHuman` (#130) the node PAUSES with
                        // a `BudgetExhausted` request via the `terminal_override`
                        // seam instead of propagating up.
                        ExhaustedResolution::Escalate => {
                            let surface = matches!(
                                executor.escalation_mode(),
                                EscalationMode::SurfaceToHuman
                            );
                            // #138 AC2-b: under SurfaceToHuman the task is NOT
                            // permanently failed — it pauses awaiting a budget grant.
                            // Leave it `InProgress` (the consult path's invariant) so
                            // the resume's seed re-attaches via the SAME
                            // InProgress→Pending→complete machinery. Under Autonomous
                            // the run aborts, so the task is `Blocked` as before.
                            let _ = task_list.update(
                                task_id,
                                Some(if surface {
                                    TaskStatus::InProgress
                                } else {
                                    TaskStatus::Blocked
                                }),
                                None,
                            );
                            executor.persist_task_list(&session_id, &task_list).await;
                            let partial = plan_execute_partial_json(&task_list);
                            // #138 AC2-a: carry the FULL stalled worker session
                            // (the execute child left it in scratch) into the pause
                            // so a budget RESUME re-attaches it as the in-progress
                            // task's seed — parallel to the consult pause — instead
                            // of discarding it for a partial-only stub.
                            let worker_session = std::mem::take(&mut cx.scratch.run_session);
                            let worker_toolset = worker_toolset_of(&self.execute);
                            cx.pop_budget();
                            cx.scratch.task = Some(task.clone());
                            cx.stream = on_stream;
                            // Advance the run-wide turn cursor to the worker's
                            // consumed turns BEFORE building the pause (mirrors the
                            // Success branch's `carried.turns = turns`). Otherwise the
                            // cursor stays frozen at `carried_before`, so the paused
                            // `budget_used` / `turn_number` and the displayed
                            // `TurnStart { turn }` regress, and the resumed window
                            // re-seeds its floor to the same value and re-runs the
                            // same turns. `leaf_steps` is absolute (>= carried_before).
                            carried.turns = leaf_steps;
                            if surface {
                                let waiting = promote_budget_exhausted_to_human(
                                    &err,
                                    Some(partial),
                                    combinator_escalation_actions(&err),
                                    session_id.clone(),
                                    task,
                                    carried.clone(),
                                    carried.turns,
                                    worker_session,
                                    worker_toolset,
                                );
                                return cx.record_terminal(waiting);
                            }
                            return promote_budget_exhausted(&err, Some(partial));
                        }
                    }
                }

                let sub_result = cx.take_child_override();
                match sub_result {
                    Some(RunResult::Success {
                        output,
                        usage,
                        turns,
                        session_state: step_state,
                        ..
                    }) => {
                        carried.turns = turns;
                        last_state = step_state;
                        carried.input_tokens += usage.input_tokens;
                        carried.output_tokens += usage.output_tokens;
                        total_usage.input_tokens += usage.input_tokens;
                        total_usage.output_tokens += usage.output_tokens;
                        total_usage.cache_read_tokens += usage.cache_read_tokens;
                        total_usage.cache_write_tokens += usage.cache_write_tokens;
                        total_usage.cost_usd += usage.cost_usd;
                        last_output = output.clone();

                        let _ = task_list.complete(task_id);
                        executor.persist_task_list(&session_id, &task_list).await;

                        // #126: record this task's final output (Tier-1) and append
                        // a ledger entry whose files_touched is HARNESS-OBSERVED.
                        final_outputs.insert(task_id, output.clone());
                        let files_touched = executor.take_observed_writes();
                        let entry = StepLedgerEntry {
                            task_id,
                            summary: output.clone(),
                            files_touched,
                        };
                        if push_step_ledger(&mut ledger, entry) {
                            ledger_elided = true;
                        }

                        // #stream: emit through the WRAPPED `cx.stream` (not the
                        // saved parent `on_stream`) so this combinator-surfaced step
                        // output is attributed to the `plan_execute` node.
                        StandardHarness::emit(
                            &cx.stream,
                            StreamEvent::FinalResponse {
                                content: last_output.clone(),
                                node: None,
                            },
                        );

                        // #125: charge this step's turns against the PlanExecute scope.
                        if let Err(err) = cx.charge_current(turns.saturating_sub(carried_before)) {
                            let resolution = cx.resolve_current();
                            // #129: a granted `Continue` refreshes the scope and
                            // keeps scheduling the remaining ready tasks IN-PROCESS
                            // (this step already completed). NO serialization (AC3).
                            if matches!(resolution, ExhaustedResolution::Continue) {
                                continue;
                            }
                            let partial = plan_execute_partial_json(&task_list);
                            cx.pop_budget();
                            cx.scratch.task = Some(task.clone());
                            cx.stream = on_stream;
                            return match resolution {
                                ExhaustedResolution::Fail => promote_budget_exhausted(&err, None),
                                ExhaustedResolution::Continue | ExhaustedResolution::Escalate => {
                                    if matches!(
                                        executor.escalation_mode(),
                                        EscalationMode::SurfaceToHuman
                                    ) {
                                        // #138 AC2-a: this step already COMPLETED;
                                        // carry its post-run session (`last_state`)
                                        // so a budget resume re-attaches the real
                                        // worker context, not a partial-only stub.
                                        let waiting = promote_budget_exhausted_to_human(
                                            &err,
                                            Some(partial),
                                            combinator_escalation_actions(&err),
                                            session_id.clone(),
                                            task,
                                            carried.clone(),
                                            carried.turns,
                                            last_state.clone(),
                                            worker_toolset_of(&self.execute),
                                        );
                                        cx.record_terminal(waiting)
                                    } else {
                                        promote_budget_exhausted(&err, Some(partial))
                                    }
                                }
                            };
                        }
                    }
                    // A GLOBAL turn-budget hard stop (#117 backstop) surfaces as a
                    // `BudgetExceeded` Failure from the leaf. That is a WHOLE-RUN
                    // hard stop, NOT a single-task terminal failure — it aborts the
                    // run verbatim (preserving the pre-#126 mid-execute budget
                    // behavior). It is distinct from a per-NODE `BudgetExhausted`
                    // resolving to `Fail`, which DOES cascade (AC4, handled above).
                    Some(RunResult::Failure {
                        reason: reason @ HaltReason::BudgetExceeded { .. },
                        usage,
                        turns,
                        ..
                    }) => {
                        total_usage.input_tokens += usage.input_tokens;
                        total_usage.output_tokens += usage.output_tokens;
                        total_usage.cache_read_tokens += usage.cache_read_tokens;
                        total_usage.cache_write_tokens += usage.cache_write_tokens;
                        total_usage.cost_usd += usage.cost_usd;
                        let _ = task_list.update(task_id, Some(TaskStatus::Blocked), None);
                        executor.persist_task_list(&session_id, &task_list).await;
                        cx.pop_budget();
                        cx.stream = on_stream;
                        let result = RunResult::Failure {
                            reason,
                            session_id,
                            usage: total_usage,
                            turns,
                            session_state: last_state,
                        };
                        return cx.finish(executor, task, result).await;
                    }
                    // #126 AC3: a terminal task FAILURE cascade-blocks its
                    // transitive dependents and KEEPS scheduling unrelated tasks
                    // (replaces the Q5 blanket abort).
                    Some(RunResult::Failure {
                        reason,
                        usage,
                        turns,
                        ..
                    }) => {
                        carried.turns = turns;
                        total_usage.input_tokens += usage.input_tokens;
                        total_usage.output_tokens += usage.output_tokens;
                        total_usage.cache_read_tokens += usage.cache_read_tokens;
                        total_usage.cache_write_tokens += usage.cache_write_tokens;
                        total_usage.cost_usd += usage.cost_usd;

                        let _ = task_list.update(task_id, Some(TaskStatus::Blocked), None);
                        for dep in task_list.transitive_dependents(task_id) {
                            let _ = task_list.update(dep, Some(TaskStatus::Blocked), None);
                            blocked_by_failure.insert(dep);
                        }
                        blocked_by_failure.insert(task_id);
                        executor.persist_task_list(&session_id, &task_list).await;
                        if first_failure.is_none() {
                            first_failure = Some((task_id, format!("{reason:?}")));
                        }
                        continue;
                    }
                    // A pause / consult / escalate propagates the whole run verbatim.
                    Some(pause) => {
                        cx.pop_budget();
                        cx.stream = on_stream;
                        return cx.finish(executor, task, pause).await;
                    }
                    None => {
                        // No terminal from the child: treat as a terminal failure
                        // of this task and cascade (same as a Failure).
                        let _ = task_list.update(task_id, Some(TaskStatus::Blocked), None);
                        for dep in task_list.transitive_dependents(task_id) {
                            let _ = task_list.update(dep, Some(TaskStatus::Blocked), None);
                            blocked_by_failure.insert(dep);
                        }
                        blocked_by_failure.insert(task_id);
                        executor.persist_task_list(&session_id, &task_list).await;
                        if first_failure.is_none() {
                            first_failure = Some((
                                task_id,
                                "execute sub-strategy produced no terminal".to_string(),
                            ));
                        }
                        continue;
                    }
                }
            }

            cx.pop_budget();
            cx.stream = on_stream;

            // ── Drain (#126, decision A). ───────────────────────────────────
            //
            // A run where a terminal failure cascade-blocked any task returns a
            // PARTIAL terminal `Failure` reporting the full partition. A run where
            // every task completed returns `Success` (output = last step's text).
            if let Some((failed_task, reason)) = first_failure {
                let mut completed: Vec<u32> = task_list
                    .tasks
                    .iter()
                    .filter(|t| t.status == TaskStatus::Completed)
                    .map(|t| t.id)
                    .collect();
                completed.sort_unstable();
                let mut blocked: Vec<u32> = blocked_by_failure.into_iter().collect();
                blocked.sort_unstable();
                let result = RunResult::Failure {
                    reason: HaltReason::TasksBlockedByFailure {
                        completed,
                        blocked,
                        failed_task,
                        reason,
                    },
                    session_id,
                    usage: total_usage,
                    turns: carried.turns,
                    session_state: last_state,
                };
                return cx.finish(executor, task, result).await;
            }

            let result = RunResult::Success {
                output: last_output,
                session_id,
                usage: total_usage,
                turns: carried.turns,
                session_state: last_state,
            };
            cx.finish(executor, task, result).await
        })
    }
}

impl RunStrategy for SelfVerifyingConfig {
    /// SelfVerifying (#124): GENUINELY recursive build↔evaluate loop. Each
    /// iteration dispatches `self.inner.run(cx)` for the build phase (a non-ReAct
    /// inner — e.g. PlanExecute — really runs its whole loop per iteration), then
    /// runs a fresh evaluate phase on the inner worker's resolved agent (Q1c) and
    /// consults the verifier resolved from `self.evaluator`'s key (Q1a). Passed ⇒
    /// Success; Failed ⇒ append the reason (Default-FAIL) and loop; exhausted ⇒
    /// `SelfVerifyExhausted`.
    fn run<'a>(&'a self, cx: &'a mut ExecutionContext<'_>) -> BoxFut<'a, StrategyOutcome> {
        Box::pin(async move {
            let executor = match cx.executor() {
                Ok(e) => e,
                Err(o) => return o,
            };
            let task = cx.current_task();
            let build_session_id = task.session_id.clone();
            let mut session_state = std::mem::take(&mut cx.scratch.run_session);
            let mut carried = cx.scratch.run_budget.clone();
            // #stream: save the parent sink, install a `self_verifying`-attributing
            // wrapper so the build (worker) and evaluate phases stream through it;
            // restored to the parent on every exit (`cx.stream = on_stream;`).
            let on_stream = cx.stream.take();
            cx.stream = wrap_node_sink(on_stream.clone(), "self_verifying", None);

            // Q1a: resolve the verifier from `evaluator`'s key (NO wire change).
            let verifier = match cx.registry.resolve_verifier(&self.evaluator.0) {
                Some(v) => v.clone(),
                None => {
                    let result = RunResult::Failure {
                        reason: HaltReason::SelfVerifyMisconfigured {
                            reason: format!(
                                "SelfVerifying requires a verifier registered under key {:?}",
                                self.evaluator.0
                            ),
                        },
                        session_id: build_session_id,
                        usage: AggregateUsage::default(),
                        turns: 0,
                        session_state: SessionState::default(),
                    };
                    cx.stream = on_stream;
                    return cx.finish(executor, task, result).await;
                }
            };
            // Q1c: the evaluate-phase agent defaults to the inner worker's agent;
            // an explicit `eval_agent` override (a dedicated reviewer, distinct
            // from the builder) takes precedence.
            let eval_agent_ref = self
                .eval_agent
                .clone()
                .unwrap_or_else(|| AgentRef(executor_worker_key(self)));
            let eval_agent = match executor.resolve_agent_ref(&eval_agent_ref, &build_session_id) {
                Ok(a) => a,
                Err(result) => {
                    cx.stream = on_stream;
                    return cx.finish(executor, task, *result).await;
                }
            };
            // The evaluate phase runs against `eval_toolset` (a read-only/
            // inspection catalogue) when set; `None` ⇒ the empty handle (global-
            // catalogue fallback), byte-identical to pre-override behavior.
            let eval_toolset = self
                .eval_toolset
                .clone()
                .unwrap_or_else(|| ToolsetRef(String::new()));

            let max_iterations = verifier.max_iterations();
            let mut total_usage = AggregateUsage::default();
            let mut last_reason = String::new();
            let mut last_worker_output = String::new();

            // #125: SelfVerifying owns a budget scope for its build↔evaluate loop.
            // POLICY is the task's global turn ceiling (TotalSteps); behavior is
            // `Escalate` (in-process placeholder; serialized behavior is #129).
            let sv_policy = match task.budget.max_turns {
                Some(max) => BudgetPolicy::TotalSteps { value: max },
                None => BudgetPolicy::Unlimited,
            };
            cx.push_budget(sv_policy, self.behavior.clone(), "self_verifying");

            for iteration in 0..max_iterations {
                // ── Build phase: recurse `self.inner.run(cx)`.
                let build_task = Task {
                    id: task.id.clone(),
                    instruction: task.instruction.clone(),
                    session_id: build_session_id.clone(),
                    budget: task.budget.clone(),
                    loop_strategy: (*self.inner).clone(),
                };
                cx.scratch.task = Some(build_task);
                cx.scratch.run_session = session_state.clone();
                cx.scratch.run_budget = carried.clone();
                let carried_before = carried.turns;
                let build_outcome = self.inner.run(cx).await;
                // #125 rule 4/7: a child's BudgetExhausted reaches THIS parent as
                // a `StrategyOutcome`, never auto-cascaded. SelfVerifying surfaces
                // its own typed BudgetExhausted (partial = last worker result +
                // last verdict) without charging the child's exhaustion against
                // its own scope.
                if let StrategyOutcome::BudgetExhausted { .. } = &build_outcome {
                    let partial = self_verifying_partial_json(&last_worker_output, &last_reason);
                    let err = cx
                        .budgets
                        .current_mut()
                        .map(|s| BudgetExhausted {
                            policy: s.policy.clone(),
                            behavior: s.behavior.clone(),
                            steps_taken: s.steps_taken,
                            continues_used: s.continues_used,
                            phase: s.phase.clone(),
                        })
                        .expect("self_verifying scope pushed above");
                    cx.pop_budget();
                    cx.scratch.task = Some(task);
                    cx.stream = on_stream;
                    return promote_budget_exhausted(&err, Some(partial));
                }
                let build_result = match cx.take_child_override() {
                    Some(r) => r,
                    None => RunResult::Failure {
                        reason: HaltReason::SelfVerifyMisconfigured {
                            reason: "build sub-strategy produced no terminal".into(),
                        },
                        session_id: build_session_id.clone(),
                        usage: AggregateUsage::default(),
                        turns: carried.turns,
                        session_state: session_state.clone(),
                    },
                };
                fold_usage(&mut total_usage, &mut carried, &build_result);

                // A paused / escalated build propagates verbatim.
                match &build_result {
                    RunResult::WaitingForHuman { .. } | RunResult::Consult { .. } => {
                        cx.pop_budget();
                        cx.stream = on_stream;
                        return cx.finish(executor, task, build_result).await;
                    }
                    RunResult::Escalate { .. } => {
                        cx.pop_budget();
                        cx.stream = on_stream;
                        return cx.finish(executor, task, build_result).await;
                    }
                    _ => {}
                }
                // Capture the build's output for the partial (last worker result).
                if let RunResult::Success { output, .. } = &build_result {
                    last_worker_output = output.clone();
                }
                // Carry the build's post-run session forward for the next round.
                if let RunResult::Success {
                    session_state: st, ..
                }
                | RunResult::Failure {
                    session_state: st, ..
                } = &build_result
                {
                    session_state = st.clone();
                }

                // #125: charge this iteration's build turns against the
                // SelfVerifying scope. If the global cap is spent, the node
                // surfaces its OWN typed BudgetExhausted (partial = last worker
                // result + last verdict).
                if let Err(err) = cx.charge_current(carried.turns.saturating_sub(carried_before)) {
                    let partial = self_verifying_partial_json(&last_worker_output, &last_reason);
                    let resolution = cx.resolve_current();
                    // #129: a granted `Continue` resets the scope and RE-RUNS the
                    // build↔evaluate iteration IN-PROCESS (do NOT pop the scope; the
                    // loop continues under the refreshed allowance). NO serialization
                    // (AC3). `max_continues` bounds the loop.
                    if matches!(resolution, ExhaustedResolution::Continue) {
                        continue;
                    }
                    cx.pop_budget();
                    cx.scratch.task = Some(task.clone());
                    cx.stream = on_stream;
                    return match resolution {
                        ExhaustedResolution::Fail => promote_budget_exhausted(&err, None),
                        // #129: the in-process `Continue` is handled above; this arm
                        // is `Escalate`-only now (kept combined for the surface/
                        // propagate shape).
                        ExhaustedResolution::Continue | ExhaustedResolution::Escalate => {
                            if matches!(executor.escalation_mode(), EscalationMode::SurfaceToHuman)
                            {
                                // #138 AC2-a: carry the FULL build (worker) session
                                // — the SelfVerifying loop carries it forward in
                                // `session_state` after each iteration — so a budget
                                // resume re-attaches the real worker context.
                                let waiting = promote_budget_exhausted_to_human(
                                    &err,
                                    Some(partial),
                                    combinator_escalation_actions(&err),
                                    build_session_id.clone(),
                                    task,
                                    carried.clone(),
                                    carried.turns,
                                    session_state.clone(),
                                    worker_toolset_of(&self.inner),
                                );
                                cx.record_terminal(waiting)
                            } else {
                                promote_budget_exhausted(&err, Some(partial))
                            }
                        }
                    };
                }

                // ── Evaluate phase: a fresh evaluator run on `eval_agent`.
                let eval_result = executor
                    .evaluate_phase(
                        &task,
                        eval_agent.clone(),
                        eval_toolset.clone(),
                        &mut carried,
                        &mut total_usage,
                    )
                    .await;

                // #C1: charge the evaluator's OWN turns against the SelfVerifying
                // scope, mirroring the build charge above. `run_evaluate_phase`
                // runs the evaluator in an isolated harness from a fresh
                // `BudgetSnapshot`, so `eval_result.turns` is the evaluator's
                // standalone turn count — and `fold_usage` folds it via `.max()`
                // (NOT a sum), so it never reaches `carried.turns` once build
                // turns dominate. Charging the build delta alone therefore missed
                // the evaluate phase entirely; charge it explicitly here so both
                // phases count against the budget.
                let eval_turns = match &eval_result {
                    RunResult::Success { turns, .. }
                    | RunResult::Failure { turns, .. }
                    | RunResult::Escalate { turns, .. } => *turns,
                    RunResult::WaitingForHuman { .. } | RunResult::Consult { .. } => 0,
                };
                if let Err(err) = cx.charge_current(eval_turns) {
                    let partial = self_verifying_partial_json(&last_worker_output, &last_reason);
                    let resolution = cx.resolve_current();
                    // A granted `Continue` resets the scope and re-runs the
                    // build↔evaluate iteration in-process (mirrors the build path).
                    if matches!(resolution, ExhaustedResolution::Continue) {
                        continue;
                    }
                    cx.pop_budget();
                    cx.scratch.task = Some(task.clone());
                    cx.stream = on_stream;
                    return match resolution {
                        ExhaustedResolution::Fail => promote_budget_exhausted(&err, None),
                        ExhaustedResolution::Continue | ExhaustedResolution::Escalate => {
                            if matches!(executor.escalation_mode(), EscalationMode::SurfaceToHuman)
                            {
                                let waiting = promote_budget_exhausted_to_human(
                                    &err,
                                    Some(partial),
                                    combinator_escalation_actions(&err),
                                    build_session_id.clone(),
                                    task,
                                    carried.clone(),
                                    carried.turns,
                                    session_state.clone(),
                                    worker_toolset_of(&self.inner),
                                );
                                cx.record_terminal(waiting)
                            } else {
                                promote_budget_exhausted(&err, Some(partial))
                            }
                        }
                    };
                }

                let input = VerifierInput {
                    build_result,
                    eval_result,
                    workspace: self.sandbox_root(executor),
                    iteration,
                };
                match verifier.verify(&input).await {
                    VerifierVerdict::Passed => {
                        let (output, turns, final_state) = match input.build_result {
                            RunResult::Success {
                                output,
                                turns,
                                session_state: st,
                                ..
                            } => (output, turns, st),
                            _ => (String::new(), carried.turns, session_state.clone()),
                        };
                        let result = RunResult::Success {
                            output,
                            session_id: build_session_id,
                            usage: total_usage,
                            turns,
                            session_state: final_state,
                        };
                        cx.pop_budget();
                        cx.stream = on_stream;
                        return cx.finish(executor, task, result).await;
                    }
                    VerifierVerdict::Failed { reason } => {
                        last_reason = reason.clone();
                        executor
                            .append_user_message(&mut session_state, &reason)
                            .await;
                    }
                }
            }

            cx.pop_budget();
            let result = RunResult::Failure {
                reason: HaltReason::SelfVerifyExhausted {
                    iterations: max_iterations,
                    last_reason,
                },
                session_id: build_session_id,
                usage: total_usage,
                turns: carried.turns,
                session_state,
            };
            cx.stream = on_stream;
            cx.finish(executor, task, result).await
        })
    }
}

impl SelfVerifyingConfig {
    /// The workspace root for a verifier input. Delegated to the executor so the
    /// config body stays harness-agnostic.
    fn sandbox_root(&self, executor: &dyn StrategyExecutor) -> std::path::PathBuf {
        executor.workspace_root()
    }
}

/// The worker-agent key for a SelfVerifying inner (Q1c: the evaluate-phase agent
/// defaults to the inner worker's resolved agent). Descends to the worker leaf.
fn executor_worker_key(cfg: &SelfVerifyingConfig) -> String {
    worker_agent_key_of(&cfg.inner)
}

/// Descend a [`LoopStrategy`] tree to the worker leaf's agent key (#124).
fn worker_agent_key_of(ls: &LoopStrategy) -> String {
    match ls {
        LoopStrategy::ReAct(c) => c.agent.0.clone(),
        LoopStrategy::PlanExecute(c) => worker_agent_key_of(&c.execute),
        LoopStrategy::SelfVerifying(c) => worker_agent_key_of(&c.inner),
        LoopStrategy::Ralph(c) => {
            if c.agent.0.is_empty() {
                worker_agent_key_of(&c.inner)
            } else {
                c.agent.0.clone()
            }
        }
        LoopStrategy::HillClimbing(c) => worker_agent_key_of(&c.inner),
    }
}

/// Descend a [`LoopStrategy`] tree to the worker (execute) leaf's toolset handle
/// (#138 AC4-a). Mirrors [`worker_agent_key_of`]: a combinator descends into its
/// EXECUTE child (PlanExecute) / inner (SelfVerifying/Ralph/HillClimbing) so a
/// budget-exhausted pause records the same handle #140 would have on the leaf's
/// own pause (e.g. `"exec-tools"`), not the empty default.
fn worker_toolset_of(ls: &LoopStrategy) -> ToolsetRef {
    match ls {
        LoopStrategy::ReAct(c) => c.toolset.clone(),
        LoopStrategy::PlanExecute(c) => worker_toolset_of(&c.execute),
        LoopStrategy::SelfVerifying(c) => worker_toolset_of(&c.inner),
        LoopStrategy::Ralph(c) => worker_toolset_of(&c.inner),
        LoopStrategy::HillClimbing(c) => worker_toolset_of(&c.inner),
    }
}

impl RunStrategy for RalphConfig {
    /// Ralph (#124): GENUINELY recursive continuation wrapper. Each context
    /// window seeds a FRESH session from the `.spore/` checkpoint, then recurses
    /// `self.inner.run(cx)` (a non-ReAct inner — e.g. SelfVerifying — really runs
    /// its whole loop per window). Ralph is an OUTER LOOP that re-runs `inner` as
    /// the architect declared it — it does NOT replace nodes the inner tree
    /// already assigned. When `self.agent` is set it only FILLS a worker leaf that
    /// left its own agent handle EMPTY (the bare-leaf Ralph convenience); an
    /// explicit leaf agent is authoritative and never overwritten.
    /// `ralph_completion_status` drives the OUTER reset loop; exhaustion ⇒
    /// `RalphCompletionUnmet`.
    fn run<'a>(&'a self, cx: &'a mut ExecutionContext<'_>) -> BoxFut<'a, StrategyOutcome> {
        Box::pin(async move {
            let executor = match cx.executor() {
                Ok(e) => e,
                Err(o) => return o,
            };
            let task = cx.current_task();
            // #stream: save the parent sink, install a `ralph`-attributing wrapper
            // so each reset window's turns stream through it; restored on exit.
            let on_stream = cx.stream.take();
            cx.stream = wrap_node_sink(on_stream.clone(), "ralph", None);
            // Ralph discards the incoming session state by design (each window is
            // a fresh start re-seeded from the filesystem checkpoint).
            let _ = std::mem::take(&mut cx.scratch.run_session);
            let max_resets = self.max_resets(executor);

            // Ralph fills — never replaces. When `self.agent` is set it supplies a
            // worker agent ONLY where the inner leaf left its handle empty; an
            // explicitly-declared leaf agent (the architect's node) is authoritative.
            let inner_for_window: LoopStrategy = if self.agent.0.is_empty() {
                (*self.inner).clone()
            } else {
                let mut cloned = (*self.inner).clone();
                fill_empty_worker_agent(&mut cloned, &self.agent);
                cloned
            };

            let mut total_usage = AggregateUsage::default();
            let mut cumulative_turns: u32 = 0;
            let mut last_reason = String::from(".spore/progress.json missing");
            let mut last_session_id = task.session_id.clone();

            for iteration in 0..max_resets.max(1) {
                let window_session_id = if iteration == 0 {
                    task.session_id.clone()
                } else {
                    SessionId::generate()
                };
                last_session_id = window_session_id.clone();

                // R2/R3: a FRESH session seeded from the `.spore/` checkpoint.
                let session_state = executor.ralph_seed_session(&task.instruction).await;

                let window_task = Task {
                    id: task.id.clone(),
                    instruction: task.instruction.clone(),
                    session_id: window_session_id.clone(),
                    budget: task.budget.clone(),
                    loop_strategy: inner_for_window.clone(),
                };
                cx.scratch.task = Some(window_task);
                cx.scratch.run_session = session_state;
                // FRESH per-window budget (the reset discards the turn budget).
                cx.scratch.run_budget = BudgetSnapshot::default();
                let window_outcome = inner_for_window.run(cx).await;
                // #125 rule 4/7: a window child's BudgetExhausted reaches Ralph as
                // a `StrategyOutcome`, never auto-cascaded. Ralph's recovery
                // semantics: a budget-exhausted window is treated as "window
                // incomplete" — RESET the context window and retry (next outer
                // iteration). After `max_resets` this falls through to
                // `RalphCompletionUnmet`. Ralph's own scope is unaffected.
                if let StrategyOutcome::BudgetExhausted { partial_output, .. } = &window_outcome {
                    last_reason = format!(
                        "window {} budget-exhausted: {}",
                        iteration + 1,
                        partial_output.as_deref().unwrap_or("<no partial>")
                    );
                    continue;
                }
                let window_result = match cx.take_child_override() {
                    Some(r) => r,
                    None => RunResult::Failure {
                        reason: HaltReason::RalphCompletionUnmet {
                            iterations: iteration + 1,
                            last_reason: "window sub-strategy produced no terminal".into(),
                        },
                        session_id: window_session_id.clone(),
                        usage: AggregateUsage::default(),
                        turns: 0,
                        session_state: SessionState::default(),
                    },
                };
                let mut window_budget = BudgetSnapshot::default();
                fold_usage(&mut total_usage, &mut window_budget, &window_result);
                cumulative_turns += window_budget.turns;

                // A paused / escalated window propagates verbatim.
                if window_result.is_pause() {
                    cx.stream = on_stream;
                    return cx.finish(executor, task, window_result).await;
                }

                match executor.ralph_completion_status().await {
                    None => {
                        let (output, final_state) = match window_result {
                            RunResult::Success {
                                output,
                                session_state,
                                ..
                            } => (output, session_state),
                            _ => (String::new(), SessionState::default()),
                        };
                        let result = RunResult::Success {
                            output,
                            session_id: window_session_id,
                            usage: total_usage,
                            turns: cumulative_turns,
                            session_state: final_state,
                        };
                        cx.stream = on_stream;
                        return cx.finish(executor, task, result).await;
                    }
                    Some(reason) => {
                        last_reason = reason;
                    }
                }
            }

            let result = RunResult::Failure {
                reason: HaltReason::RalphCompletionUnmet {
                    iterations: max_resets.max(1),
                    last_reason,
                },
                session_id: last_session_id,
                usage: total_usage,
                turns: cumulative_turns,
                session_state: SessionState::default(),
            };
            cx.stream = on_stream;
            cx.finish(executor, task, result).await
        })
    }
}

impl RalphConfig {
    /// The configured `max_resets` (the harness `config.max_resets`).
    fn max_resets(&self, executor: &dyn StrategyExecutor) -> u32 {
        executor.ralph_max_resets()
    }
}

/// Fill the worker leaf's agent handle of `ls` with `agent` ONLY where the leaf
/// left it empty — Ralph's bare-leaf convenience. An explicitly-declared leaf
/// agent is authoritative and is never replaced (the architect's node wins).
/// Descends the worker child chain to the innermost leaf.
fn fill_empty_worker_agent(ls: &mut LoopStrategy, agent: &AgentRef) {
    match ls {
        LoopStrategy::ReAct(c) => {
            if c.agent.0.is_empty() {
                c.agent = agent.clone();
            }
        }
        LoopStrategy::PlanExecute(c) => fill_empty_worker_agent(&mut c.execute, agent),
        LoopStrategy::SelfVerifying(c) => fill_empty_worker_agent(&mut c.inner, agent),
        LoopStrategy::Ralph(c) => fill_empty_worker_agent(&mut c.inner, agent),
        LoopStrategy::HillClimbing(c) => fill_empty_worker_agent(&mut c.inner, agent),
    }
}

impl RunStrategy for HillClimbingConfig {
    /// HillClimbing (#124): GENUINELY recursive optimization loop. Iteration 0 is
    /// a pure baseline (no agent turn). Iterations 1.. recurse `self.inner.run(cx)`
    /// to propose a change (a non-ReAct inner — e.g. PlanExecute — really runs its
    /// whole loop per iteration), then evaluate the metric (resolved via
    /// `resolve_metric_evaluator`, Q2) and keep/revert. Bounded by
    /// `max_stagnation` and the turn budget.
    fn run<'a>(&'a self, cx: &'a mut ExecutionContext<'_>) -> BoxFut<'a, StrategyOutcome> {
        Box::pin(async move {
            let executor = match cx.executor() {
                Ok(e) => e,
                Err(o) => return o,
            };
            let task = cx.current_task();
            let session_id = task.session_id.clone();
            let task_id = task.id.clone();
            // #stream: save the parent sink, install a `hill_climbing`-attributing
            // wrapper so each iteration's turns stream through it; restored on exit.
            let on_stream = cx.stream.take();
            cx.stream = wrap_node_sink(on_stream.clone(), "hill_climbing", None);
            let mut carried = cx.scratch.run_budget.clone();
            let _ = std::mem::take(&mut cx.scratch.run_session);
            let direction = self.direction;
            let revert = self.revert_on_no_improvement;
            let min_delta = Some(self.min_improvement_delta);
            // `u32::MAX` sentinel ⇒ no stagnation cap.
            let max_stagnation = (self.max_stagnation != u32::MAX).then_some(self.max_stagnation);

            // Q2: resolve the metric evaluator from `evaluator`'s key.
            let evaluator = match executor.resolve_metric_evaluator(&self.evaluator.0, &session_id)
            {
                Ok(e) => e,
                Err(result) => {
                    cx.stream = on_stream;
                    return cx.finish(executor, task, *result).await;
                }
            };

            let mut total_usage = AggregateUsage::default();
            let mut rows: Vec<crate::metric::ResultsEntry> = Vec::new();
            let mut span_seq: u64 = 0;

            // #125: HillClimbing owns a budget scope for its optimization loop.
            // POLICY is the task's global turn ceiling (TotalSteps); this REPLACES
            // the ad-hoc `turn_cap` / `carried.turns >= turn_cap` gate that #124
            // used. Behavior is `Escalate` (in-process placeholder; #129).
            let hc_policy = match task.budget.max_turns {
                Some(max) => BudgetPolicy::TotalSteps { value: max },
                None => BudgetPolicy::Unlimited,
            };
            cx.push_budget(hc_policy, self.behavior.clone(), "hill_climbing");

            // ── Iteration 0: pure baseline (no agent turn).
            let mut current_best = match executor
                .hill_baseline(
                    &evaluator,
                    &session_id,
                    &task_id,
                    direction,
                    &mut rows,
                    &mut span_seq,
                    total_usage.clone(),
                    carried.turns,
                )
                .await
            {
                Ok(v) => v,
                Err(result) => {
                    cx.pop_budget();
                    cx.stream = on_stream;
                    return cx.finish(executor, task, result).await;
                }
            };

            let mut stagnation: u32 = 0;
            let mut iteration: u32 = 1;

            loop {
                // #125: charge-based budget gate before the iteration's agent
                // turn. A spent `TotalSteps` cap surfaces this node's OWN typed
                // BudgetExhausted (partial = best candidate + score), resolving its
                // behavior — replacing the legacy `BudgetExceeded` Failure.
                if let Err(err) = cx.charge_current(1) {
                    let resolution = cx.resolve_current();
                    // #129: a granted `Continue` resets the scope and KEEPS ITERATING
                    // the climb IN-PROCESS (do NOT pop; the refreshed allowance lets
                    // the next charge pass). NO serialization (AC3). `max_continues`
                    // bounds the loop.
                    if matches!(resolution, ExhaustedResolution::Continue) {
                        continue;
                    }
                    executor.hill_write_tsv(&task_id, &rows).await;
                    let partial = hill_climbing_partial_json(current_best);
                    cx.pop_budget();
                    cx.scratch.task = Some(task.clone());
                    cx.stream = on_stream;
                    return match resolution {
                        ExhaustedResolution::Fail => promote_budget_exhausted(&err, None),
                        // #129: the in-process `Continue` is handled above; this arm
                        // is `Escalate`-only now (kept combined for the surface/
                        // propagate shape).
                        //
                        // #130: under `SurfaceToHuman`, PAUSE with a
                        // `BudgetExhausted` request instead of propagating up.
                        ExhaustedResolution::Continue | ExhaustedResolution::Escalate => {
                            if matches!(executor.escalation_mode(), EscalationMode::SurfaceToHuman)
                            {
                                // #138 AC2-a: HillClimbing iterates on a METRIC, not
                                // a worker conversation, so there is no richer
                                // session to carry — pass the empty default to fall
                                // back to the partial-only stub (pre-#138 behavior).
                                // The worker leaf's toolset handle is still carried
                                // (#140 parity, AC4-a).
                                let waiting = promote_budget_exhausted_to_human(
                                    &err,
                                    Some(partial),
                                    combinator_escalation_actions(&err),
                                    session_id.clone(),
                                    task,
                                    carried.clone(),
                                    carried.turns,
                                    SessionState::default(),
                                    worker_toolset_of(&self.inner),
                                );
                                cx.record_terminal(waiting)
                            } else {
                                promote_budget_exhausted(&err, Some(partial))
                            }
                        }
                    };
                }
                if let Some(limit_type) =
                    StandardHarness::budget_exceeded(&task.budget, &carried, Instant::now())
                {
                    executor.hill_write_tsv(&task_id, &rows).await;
                    let result = RunResult::Failure {
                        reason: HaltReason::BudgetExceeded { limit_type },
                        session_id,
                        usage: total_usage,
                        turns: carried.turns,
                        session_state: SessionState::default(),
                    };
                    cx.pop_budget();
                    cx.stream = on_stream;
                    return cx.finish(executor, task, result).await;
                }

                // ── One agent turn proposes a change: recurse `self.inner`.
                let iter_task = Task {
                    id: task.id.clone(),
                    instruction: task.instruction.clone(),
                    session_id: session_id.clone(),
                    budget: task.budget.clone(),
                    loop_strategy: (*self.inner).clone(),
                };
                cx.scratch.task = Some(iter_task);
                let mut iter_state = SessionState::default();
                executor
                    .append_user_message(&mut iter_state, &task.instruction)
                    .await;
                cx.scratch.run_session = iter_state;
                cx.scratch.run_budget = carried.clone();
                let iter_outcome = self.inner.run(cx).await;
                // #125 rule 4/7: a child's BudgetExhausted reaches HillClimbing as
                // a `StrategyOutcome`, never auto-cascaded. Surface this node's own
                // typed BudgetExhausted (partial = best candidate + score).
                if let StrategyOutcome::BudgetExhausted { .. } = &iter_outcome {
                    executor.hill_write_tsv(&task_id, &rows).await;
                    let partial = hill_climbing_partial_json(current_best);
                    let err = cx
                        .budgets
                        .current_mut()
                        .map(|s| BudgetExhausted {
                            policy: s.policy.clone(),
                            behavior: s.behavior.clone(),
                            steps_taken: s.steps_taken,
                            continues_used: s.continues_used,
                            phase: s.phase.clone(),
                        })
                        .expect("hill_climbing scope pushed above");
                    cx.pop_budget();
                    cx.scratch.task = Some(task);
                    cx.stream = on_stream;
                    return promote_budget_exhausted(&err, Some(partial));
                }
                let turn_result = match cx.take_child_override() {
                    Some(r) => r,
                    None => RunResult::Failure {
                        reason: HaltReason::BudgetExceeded {
                            limit_type: BudgetLimitType::Turns,
                        },
                        session_id: session_id.clone(),
                        usage: AggregateUsage::default(),
                        turns: carried.turns,
                        session_state: SessionState::default(),
                    },
                };
                fold_usage(&mut total_usage, &mut carried, &turn_result);

                // A paused / escalated turn propagates verbatim.
                if turn_result.is_pause() {
                    executor.hill_write_tsv(&task_id, &rows).await;
                    cx.pop_budget();
                    cx.stream = on_stream;
                    return cx.finish(executor, task, turn_result).await;
                }

                // ── Evaluate the metric + keep/revert decision.
                let (best, non_improvement) = executor
                    .hill_iteration(
                        &evaluator,
                        &session_id,
                        &task_id,
                        iteration,
                        direction,
                        revert,
                        min_delta,
                        current_best,
                        &mut rows,
                        &mut span_seq,
                    )
                    .await;
                current_best = best;
                if non_improvement {
                    stagnation += 1;
                } else {
                    stagnation = 0;
                }

                if let Some(limit) = max_stagnation {
                    if stagnation >= limit {
                        executor.hill_write_tsv(&task_id, &rows).await;
                        let result = RunResult::Failure {
                            reason: HaltReason::StagnationLimitReached {
                                iterations: stagnation,
                                best_metric: current_best,
                            },
                            session_id,
                            usage: total_usage,
                            turns: carried.turns,
                            session_state: SessionState::default(),
                        };
                        cx.pop_budget();
                        cx.stream = on_stream;
                        return cx.finish(executor, task, result).await;
                    }
                }

                iteration = iteration.saturating_add(1);
            }
        })
    }
}

impl ExecutionContext<'_> {
    /// Record a terminal/pause [`RunResult`] from a whole-loop primitive
    /// (ReAct / SelfVerifying / Ralph / HillClimbing): carry the post-run session
    /// into the scratch (so a parent resumes losslessly) and stash the FULL
    /// result in `terminal_override` so the harness entry returns it VERBATIM —
    /// preserving the strategy's typed [`HaltReason`] and accounting. Returns the
    /// matchable [`StrategyOutcome`] for any combinator that recurses into this
    /// node (a wrapping combinator CLEARS the override and builds its own
    /// terminal; see [`take_child_override`](Self::take_child_override)).
    ///
    /// Usage is NOT folded into `self.usage` here: the whole-loop primitive's
    /// RunResult already carries the cumulative usage for its subtree, and it is
    /// returned verbatim as the override, so folding would double-count.
    fn record_terminal(&mut self, result: RunResult) -> StrategyOutcome {
        match &result {
            RunResult::Success { session_state, .. } | RunResult::Failure { session_state, .. } => {
                self.scratch.run_session = session_state.clone();
            }
            RunResult::WaitingForHuman { .. }
            | RunResult::Consult { .. }
            | RunResult::Escalate { .. } => {}
        }
        let outcome = outcome_from_run_result_ref(&result);
        self.scratch.terminal_override = Some(result);
        outcome
    }

    /// Take the FULL terminal [`RunResult`] a child strategy stashed into
    /// `terminal_override` when it returned from `.run(cx)` (#124). A combinator
    /// that recurses per-phase / per-task calls this immediately after each child
    /// `.run(cx)` to fold the child's usage / turns / session back into the shared
    /// execute context. Clearing the override is REQUIRED: the combinator builds
    /// its OWN terminal once the whole loop finishes (via [`finish`](Self::finish)),
    /// and a stale child override would otherwise propagate verbatim and mask it.
    fn take_child_override(&mut self) -> Option<RunResult> {
        self.scratch.terminal_override.take()
    }

    /// A combinator's terminal seam: finalize observability for `result`, restore
    /// the parent `task` into scratch, stash `result` as the override so the
    /// harness entry returns it VERBATIM, and return the matching outcome.
    async fn finish(
        &mut self,
        executor: &dyn StrategyExecutor,
        parent_task: Task,
        result: RunResult,
    ) -> StrategyOutcome {
        executor.finalize(&result).await;
        // #131: a `Consult` propagated from a worker leaf carries the LEAF task,
        // so a host `resume_consult` would resume only that leaf and lose the
        // surrounding walk. As the pause unwinds through each combinator's
        // `finish`, rewrite its `state.task` to the combinator's OWN composed
        // task; by the top it carries the FULL tree, so `resume_consult` re-drives
        // the whole strategy (the in-progress task resumes from `resume_seed`).
        let result = match result {
            RunResult::Consult {
                request,
                mut state,
                session_id,
                usage,
                turns,
            } => {
                state.task = parent_task.clone();
                RunResult::Consult {
                    request,
                    state,
                    session_id,
                    usage,
                    turns,
                }
            }
            other => other,
        };
        self.scratch.task = Some(parent_task);
        match &result {
            RunResult::Success { session_state, .. } | RunResult::Failure { session_state, .. } => {
                self.scratch.run_session = session_state.clone();
            }
            _ => {}
        }
        let outcome = outcome_from_run_result_ref(&result);
        self.scratch.terminal_override = Some(result);
        outcome
    }

    /// Push a fresh per-node [`BudgetContext`] scope for `policy`/`behavior`/
    /// `phase` onto `cx.budgets` (#125). Each node — including a sibling — gets
    /// its OWN scope (`steps_taken = 0`), so a node capped at N never spends a
    /// sibling's allowance (rule 1) and a child's exhaustion never touches the
    /// parent scope (rule 4/7). Returns the depth AFTER the push for symmetry
    /// debugging.
    pub fn push_budget(
        &mut self,
        policy: BudgetPolicy,
        behavior: BudgetExhaustedBehavior,
        phase: impl Into<String>,
    ) -> usize {
        let phase = phase.into();
        // #129 (AC2): if a resumed `Continue` checkpoint seed is waiting for THIS
        // phase, reconstruct the scope with its prior `continues_used` (consuming
        // the seed once) instead of zeroing it. The root resumed node pushes
        // first, and the request's `phase` names that node, so the FIRST matching
        // push restores the count. Any other push (or a fresh run) is unaffected.
        let seeded = match &self.scratch.resume_continues {
            Some((seed_phase, _)) if *seed_phase == phase => {
                self.scratch.resume_continues.take().map(|(_, c)| c)
            }
            _ => None,
        };
        let scope = match seeded {
            Some(continues_used) => BudgetContext::resumed(policy, behavior, phase, continues_used),
            None => BudgetContext::new(policy, behavior, phase),
        };
        self.budgets.push(scope);
        self.budgets.depth()
    }

    /// Pop the current per-node budget scope (#125). Always paired with
    /// [`push_budget`](Self::push_budget) so the stack returns to its parent
    /// baseline on ascent.
    pub fn pop_budget(&mut self) -> Option<BudgetContext> {
        self.budgets.pop()
    }

    /// Charge `turns` steps against the CURRENT (innermost) budget scope (#125):
    /// the real enforcement point. `Ok(())` when within allowance; `Err(..)`
    /// carries the budget state at exhaustion. A node with no pushed scope (the
    /// scaffold contexts) never exhausts — charging is a no-op `Ok(())`.
    pub fn charge_current(&mut self, turns: u32) -> Result<(), BudgetExhausted> {
        match self.budgets.current_mut() {
            Some(scope) => scope.charge(turns),
            None => Ok(()),
        }
    }

    /// Resolve the current scope's exhaustion behavior (#125). Walks the chain
    /// (Continue grants a reset; spent continues fall through). A node with no
    /// pushed scope resolves to `Fail` (defensive — should not happen in a wired
    /// run).
    pub fn resolve_current(&mut self) -> ExhaustedResolution {
        match self.budgets.current_mut() {
            Some(scope) => scope.resolve_exhausted(),
            None => ExhaustedResolution::Fail,
        }
    }
}

// ============================================================================
// Per-node budget enforcement + failure isolation (issue #125)
// ============================================================================
//
// This slice makes `BudgetContext::charge` the REAL per-node enforcement point
// and `StrategyOutcome::BudgetExhausted` a real, isolated, parent-inspectable
// value. #123 built `BudgetContext`/`BudgetStack`/`charge` as pure-arithmetic
// scaffold (dead outside tests); #124 wired enforcement through the LEGACY path
// (`task.budget.max_turns` + `BudgetSnapshot`) and mapped every `BudgetExceeded`
// terminal to `StrategyOutcome::Failed`. #125 replaces that with charge-based
// enforcement at each `*Config::run` and a typed, non-cascading exhaustion.
//
// New methods (this slice):
//   - `BudgetContext::consume_continue` — in-process continue: `continues_used +=
//     1`, `steps_taken = 0` (session/messages untouched).
//   - `BudgetContext::resolve_exhausted` -> `ExhaustedResolution` — walks the
//     behavior chain (Fail→Fail; Escalate→Escalate; Continue→grant-or-fall-through).
//   - `ExecutionContext::push_budget` / `pop_budget` / `charge_current` /
//     `resolve_current` — the per-scope stack ops. There is NO single
//     `charge_step` / `run_with_budget` / `execute_budget` wrapper and NO central
//     Continue-loop: enforcement is INLINED per `*Config::run` body. Each body
//     pushes its own scope (`push_budget`), runs the attempt (recurse / window),
//     charges the turns consumed (`charge_current`), and on exhaustion resolves +
//     promotes to a `StrategyOutcome::BudgetExhausted` before popping. The bodies
//     push an `Escalate` placeholder behavior (the serialized
//     `BudgetExhaustedBehavior` field is a wire change DEFERRED to #129), so a live
//     `resolve_current` returns `Escalate`/`Fail` today — never `Continue` — and
//     the partial follows fork #1 (`Escalate` → `Some(partial)`; `Fail` → `None`).
//     The in-process `Continue`-loop wiring (reset + re-run on a granted Continue)
//     and the serialized behavior field that would make it reachable in a live run
//     are DEFERRED to #129; the Continue chain is exercised today only by the
//     direct `BudgetContext`/`resolve_exhausted` unit tests.
//   - The per-node partial helpers (`react_partial_json`,
//     `plan_execute_partial_json`, `self_verifying_partial_json`,
//     `hill_climbing_partial_json`) build the node-concrete `partial_output` JSON.
//   - `promote_budget_exhausted` — the `BudgetExhausted -> StrategyOutcome`
//     promotion boundary helper that attaches `partial_output`.
//
// Enforcement rules (ALL implemented + tested):
//   1. A node capped at N stops at N WITHOUT killing siblings (each sibling gets
//      a FRESH `BudgetContext`; `steps_taken` starts at 0).
//   2. In-process `Continue` resets the counter and resumes with context intact,
//      honors `max_continues`, then falls through to `on_exhausted`.
//   3. `Fail` yields `partial_output = None` (discarded by contract).
//   4. A child `BudgetExhausted` reaches the parent as a `StrategyOutcome`,
//      NEVER auto-propagated (the parent's OWN `BudgetContext` is unaffected).
//   5. `partial_output` is concrete per node: ReAct → last FinalResponse text;
//      PlanExecute → JSON of task list + per-task statuses + ledger; SelfVerifying
//      → JSON of last worker result + verdict; HillClimbing → JSON of best
//      candidate + score.
//   6. The ReAct LEAF does NOT carry its own behavior — it PROPAGATES exhaustion
//      to its parent (one recovery site per node; Open Q A-2).
//   7. Never auto-cascade a child exhaustion into a parent exhaustion.
//
// Resolved spec forks (DECIDED by the maintainer — do NOT re-litigate):
//   - `Escalate` carries `partial_output = Some(partial)`; `Fail` carries `None`.
//   - `partial_output: Option<String>` is a JSON-serialized string of the
//     structured per-node partial (shapes per rule 5 above).
//   - `continues_used` persistence stays DEFERRED to #129 — in-process Continue
//     ONLY, no serialization, no new fixtures.
//
// No `// SPEC QUESTION:` markers — all three forks are resolved.

/// The last FinalResponse text from a ReAct window terminal (#125, fork #2): the
/// `Success.output`, or for a `Failure` the last assistant text message on its
/// post-run session state (the partial captured before exhaustion). `None` for
/// non-terminal pauses.
fn last_final_response_text(result: &RunResult) -> Option<String> {
    match result {
        RunResult::Success { output, .. } => Some(output.clone()),
        RunResult::Failure { session_state, .. } => {
            session_state
                .messages
                .iter()
                .rev()
                .find_map(|m| match (&m.role, &m.content) {
                    (crate::model::Role::Assistant, crate::model::Content::Text { text }) => {
                        Some(text.clone())
                    }
                    _ => None,
                })
        }
        _ => None,
    }
}

/// The structured per-node partial used to build the `partial_output` JSON
/// attached to a `StrategyOutcome::BudgetExhausted` on `Escalate` (#125, fork
/// #2). Each node serializes its own shape; `Fail` discards the partial entirely
/// (`partial_output = None`).
fn react_partial_json(last_final_response: &str) -> String {
    serde_json::json!({
        "node": "react",
        "last_final_response": last_final_response,
    })
    .to_string()
}

/// PlanExecute partial: the task list + per-task statuses + ledger (#125, fork
/// #2). `ledger` is the per-task `(id, description, status)` rows already walked.
fn plan_execute_partial_json(task_list: &crate::tasklist::TaskList) -> String {
    let ledger: Vec<_> = task_list
        .tasks
        .iter()
        .map(|t| {
            serde_json::json!({
                "id": t.id.to_string(),
                "description": t.description,
                "status": format!("{:?}", t.status),
            })
        })
        .collect();
    serde_json::json!({
        "node": "plan_execute",
        "tasks": task_list.tasks.len(),
        "ledger": ledger,
    })
    .to_string()
}

/// SelfVerifying partial: the last worker result summary + the last verdict
/// reason (#125, fork #2).
fn self_verifying_partial_json(last_worker_output: &str, last_verdict: &str) -> String {
    serde_json::json!({
        "node": "self_verifying",
        "last_worker_result": last_worker_output,
        "last_verdict": last_verdict,
    })
    .to_string()
}

/// HillClimbing partial: the best candidate value + its score (#125, fork #2).
fn hill_climbing_partial_json(best_score: f64) -> String {
    serde_json::json!({
        "node": "hill_climbing",
        "best_candidate": best_score,
        "score": best_score,
    })
    .to_string()
}

/// Promote a charge-time [`BudgetExhausted`] to a [`StrategyOutcome::BudgetExhausted`]
/// (#125 promotion boundary), attaching `partial_output`. Per fork #1: an
/// `Escalate`-resolved exhaustion carries `Some(partial)`; a `Fail`-resolved one
/// carries `None`. The caller supplies the node-concrete partial JSON; this
/// helper threads the budget state from the charge error.
fn promote_budget_exhausted(
    err: &BudgetExhausted,
    partial_output: Option<String>,
) -> StrategyOutcome {
    StrategyOutcome::BudgetExhausted {
        policy: err.policy.clone(),
        behavior: err.behavior.clone(),
        steps_taken: err.steps_taken,
        continues_used: err.continues_used,
        phase: err.phase.clone(),
        partial_output,
        cause: ExhaustionCause::Budget,
    }
}

/// Promote a ReAct tool-error-loop hard-stop (issue #137) to a
/// [`StrategyOutcome::BudgetExhausted`] carrying [`ExhaustionCause::ToolErrorLoop`]
/// so it flows through the SAME single budget-exhaustion resolution site as a
/// real budget exhaustion, but the Fail / Escalate→Fail terminals report
/// [`HaltReason::ToolErrorLoop`] instead of [`HaltReason::BudgetExceeded`]. The
/// leaf's CONFIGURED `behavior` is carried so the resolution site can honor
/// Fail / Escalate / Continue (a granted `Continue` re-drives the window with a
/// fresh per-tool error allowance, since the counter is loop-local to
/// `run_react_inner`). `steps_taken` is the window's turn count at the break, so
/// the terminal's `turns` reflects work actually done — the breaker does NOT
/// burn the rest of the budget.
fn promote_tool_error_loop(
    leaf_budget: &BudgetPolicy,
    leaf_behavior: &BudgetExhaustedBehavior,
    steps_taken: u32,
    tool: String,
    consecutive_errors: u32,
    partial_output: Option<String>,
) -> StrategyOutcome {
    StrategyOutcome::BudgetExhausted {
        policy: leaf_budget.clone(),
        behavior: leaf_behavior.clone(),
        steps_taken,
        continues_used: 0,
        phase: "react".to_string(),
        partial_output,
        cause: ExhaustionCause::ToolErrorLoop {
            tool,
            consecutive_errors,
        },
    }
}

/// The advisory `available_actions` a COMBINATOR offers on a budget-exhaustion
/// pause (#130, fork C): `[ContinueWithBudget, Skip, Fail]`. The suggested
/// `steps` defaults to the scope's own allowance (or 1 for an uncapped scope).
fn combinator_escalation_actions(err: &BudgetExhausted) -> Vec<EscalationAction> {
    let steps = err.policy.allowance_value().unwrap_or(1);
    vec![
        EscalationAction::ContinueWithBudget { steps },
        EscalationAction::Skip,
        EscalationAction::Fail,
    ]
}

/// The advisory `available_actions` a BARE LEAF offers on a budget-exhaustion
/// pause (#130, fork C): `[ContinueWithBudget, Fail]` — a leaf has no sibling
/// tasks to advance to, so `Skip` is OMITTED.
fn leaf_escalation_actions(err: &BudgetExhausted) -> Vec<EscalationAction> {
    let steps = err.policy.allowance_value().unwrap_or(1);
    vec![
        EscalationAction::ContinueWithBudget { steps },
        EscalationAction::Fail,
    ]
}

/// Promote a charge-time [`BudgetExhausted`] to a `RunResult::WaitingForHuman`
/// (#130 HITL pause boundary). Built ONLY when a node's `Escalate` resolution is
/// consulted under [`EscalationMode::SurfaceToHuman`]; it carries the node's
/// `partial_output` and the advisory `available_actions` (combinators pass
/// `[ContinueWithBudget, Skip, Fail]`; a bare leaf passes
/// `[ContinueWithBudget, Fail]` — fork C). The `PausedState` records the node's
/// `steps_taken` / `continues_used` (on the request) so `resume_inner` can
/// reconstruct the node's [`BudgetContext`] from the request alone (fork E).
///
/// #138 AC2-a: the paused `session_state` is the FULL stalled worker session
/// (`worker_session`) — parallel to how the consult pause preserves the worker
/// conversation — so a budget RESUME re-attaches it as the in-progress task's
/// seed and the worker continues with its real context instead of a partial-only
/// stub. When `worker_session` is empty (a bare-leaf propagate site that has no
/// richer conversation to carry, or a legacy caller), it falls back to the
/// single `partial_output` assistant message so the pre-#138 behavior is intact.
/// #138 AC4-a: `toolset` carries the stalled worker leaf's handle (e.g.
/// `"exec-tools"`), consistent with #140, instead of staying `""`.
#[allow(clippy::too_many_arguments)]
fn promote_budget_exhausted_to_human(
    err: &BudgetExhausted,
    partial_output: Option<String>,
    available_actions: Vec<EscalationAction>,
    session_id: SessionId,
    task: Task,
    budget_used: BudgetSnapshot,
    turn_number: u32,
    // #138 AC2-a: the FULL stalled worker session to carry across the pause.
    worker_session: SessionState,
    // #138 AC4-a: the stalled worker leaf's toolset handle (#140 parity).
    toolset: ToolsetRef,
) -> RunResult {
    // #138 AC2-a: prefer the FULL worker conversation; fall back to the
    // partial-only stub when the carried session is empty (back-compat).
    let session_state = if worker_session.messages.is_empty() {
        SessionState {
            messages: partial_output
                .clone()
                .map(|t| {
                    vec![Message {
                        role: crate::model::Role::Assistant,
                        content: crate::model::Content::Text { text: t },
                    }]
                })
                .unwrap_or_default(),
            ..Default::default()
        }
    } else {
        worker_session
    };
    let request = HumanRequest::BudgetExhausted {
        phase: err.phase.clone(),
        policy: err.policy.clone(),
        steps_taken: err.steps_taken,
        continues_used: err.continues_used,
        partial_output,
        available_actions,
    };
    let task_id = task.id.clone();
    let state = PausedState {
        session_id,
        task_id,
        turn_number,
        session_state,
        pending_tool_calls: Vec::new(),
        approved_results: Vec::new(),
        human_request: Some(request.clone()),
        task,
        budget_used,
        child_state: None,
        // #138 AC4-a: carry the stalled worker leaf's toolset handle (#140
        // parity) so a resume routes the re-driven worker through its scoped
        // catalogue.
        toolset,
    };
    RunResult::WaitingForHuman {
        state: Box::new(state),
        request,
    }
}

/// Raise a budget [`BudgetPolicy`]'s per-scope cap to at least `granted` (#130
/// `ContinueWithBudget` grant). `Unlimited` is left untouched (already
/// uncapped); a `TotalSteps`/`PerLoop`/`PerAttempt` value below `granted` is
/// raised to `granted`. Lower grants are no-ops (never SHRINKS an allowance).
fn grant_budget_policy(policy: &mut BudgetPolicy, granted: u32) {
    match policy {
        BudgetPolicy::Unlimited => {}
        BudgetPolicy::TotalSteps { value }
        | BudgetPolicy::PerLoop { value }
        | BudgetPolicy::PerAttempt { value } => {
            if *value < granted {
                *value = granted;
            }
        }
    }
}

/// Reconstruct a resumed task's strategy tree with its budget caps raised to
/// `granted` (#130 `ContinueWithBudget`). The ReAct leaf caps live on each
/// node's own `budget` [`BudgetPolicy`]; the combinator nodes derive their cap
/// from `task.budget.max_turns`, so BOTH are raised. Fork E: `granted` is
/// `request.steps_taken + steps`, so the restored scope has room for `steps`
/// more steps after the checkpoint.
fn grant_task_budget(task: &mut Task, granted: u32) {
    match task.budget.max_turns {
        Some(max) if max < granted => task.budget.max_turns = Some(granted),
        None => task.budget.max_turns = Some(granted),
        _ => {}
    }
    grant_strategy_budget(&mut task.loop_strategy, granted);
}

/// Recurse a [`LoopStrategy`] tree raising every ReAct leaf's `budget` cap to at
/// least `granted` (#130). The combinator nodes carry no inline policy (they
/// derive it from `task.budget.max_turns`, raised by
/// [`grant_task_budget`]), so this only touches the leaves.
fn grant_strategy_budget(ls: &mut LoopStrategy, granted: u32) {
    match ls {
        LoopStrategy::ReAct(c) => grant_budget_policy(&mut c.budget, granted),
        LoopStrategy::PlanExecute(c) => {
            grant_strategy_budget(&mut c.plan, granted);
            grant_strategy_budget(&mut c.execute, granted);
        }
        LoopStrategy::SelfVerifying(c) => grant_strategy_budget(&mut c.inner, granted),
        LoopStrategy::Ralph(c) => grant_strategy_budget(&mut c.inner, granted),
        LoopStrategy::HillClimbing(c) => grant_strategy_budget(&mut c.inner, granted),
    }
}

/// Translate a terminal [`RunResult`] into a [`StrategyOutcome`] (#124, Q5):
/// `Success → Complete(output)`, every non-success terminal → `Failed`. A
/// `BudgetExceeded` failure maps to `Failed` here (the budget-enforcement
/// `StrategyOutcome::BudgetExhausted` value is produced by `BudgetContext::charge`
/// at the boundary; full HITL-through-recursion is #130). Operates over a borrow
/// so the source `RunResult` can also be stashed verbatim as the override; the
/// pause variants are handled separately (the override path) and degrade to a
/// typed failure only if they ever reach this mapping.
fn outcome_from_run_result_ref(result: &RunResult) -> StrategyOutcome {
    match result {
        RunResult::Success { output, .. } => StrategyOutcome::Complete(output.clone()),
        RunResult::Failure { reason, .. } => {
            StrategyOutcome::Failed(HarnessError::InvalidConfiguration(format!("{reason:?}")))
        }
        RunResult::WaitingForHuman { .. }
        | RunResult::Consult { .. }
        | RunResult::Escalate { .. } => {
            StrategyOutcome::Failed(HarnessError::InvalidConfiguration(
                "non-terminal outcome reached strategy boundary".to_string(),
            ))
        }
    }
}

/// Fold a sub-run's token usage / turn count into the cumulative `total_usage`
/// and the shared `carried` budget snapshot (#124, R8). `carried.turns` becomes
/// the running MAX of the sub-runs' absolute turn counts. A non-terminal pause
/// (`WaitingForHuman`/`Consult`) carries no fold.
pub(crate) fn fold_usage(
    total_usage: &mut AggregateUsage,
    carried: &mut BudgetSnapshot,
    r: &RunResult,
) {
    let (usage, turns) = match r {
        RunResult::Success { usage, turns, .. }
        | RunResult::Failure { usage, turns, .. }
        | RunResult::Escalate { usage, turns, .. } => (usage, *turns),
        RunResult::WaitingForHuman { .. } => return,
        RunResult::Consult { .. } => return,
    };
    total_usage.input_tokens += usage.input_tokens;
    total_usage.output_tokens += usage.output_tokens;
    total_usage.cache_read_tokens += usage.cache_read_tokens;
    total_usage.cache_write_tokens += usage.cache_write_tokens;
    total_usage.cost_usd += usage.cost_usd;
    carried.input_tokens += usage.input_tokens;
    carried.output_tokens += usage.output_tokens;
    carried.turns = carried.turns.max(turns);
}

/// Lightweight placeholder for an alternate planner model selection. Full
/// shape lives wherever provider routing lands.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct ModelConfig {
    pub provider: String,
    pub model_id: String,
}

#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct Task {
    pub id: TaskId,
    pub instruction: String,
    pub session_id: SessionId,
    pub budget: BudgetLimits,
    pub loop_strategy: LoopStrategy,
}

impl Task {
    pub fn new(
        instruction: impl Into<String>,
        session_id: SessionId,
        loop_strategy: LoopStrategy,
    ) -> Self {
        Self {
            id: TaskId::generate(),
            instruction: instruction.into(),
            session_id,
            budget: BudgetLimits::default(),
            loop_strategy,
        }
    }
    pub fn with_budget(mut self, budget: BudgetLimits) -> Self {
        self.budget = budget;
        self
    }

    /// A one-shot task from just an instruction: a fresh [`SessionId`] and a
    /// default `ReAct` loop. Use [`new`](Self::new) when you need to control the
    /// session id (e.g. multi-turn) or the loop strategy.
    pub fn simple(instruction: impl Into<String>) -> Self {
        Self::new(
            instruction,
            SessionId::generate(),
            LoopStrategy::ReAct(ReactConfig::per_loop(8)),
        )
    }
}

// ============================================================================
// Streaming events emitted by the harness
// ============================================================================

/// The kind of content block a [`StreamEvent::BlockStart`] opens (issue #103,
/// resolved spec decision **Q2**: a single generic frame marker carrying a
/// `BlockKind` rather than typed-per-kind markers).
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum BlockKind {
    /// A text content block (`model::StreamEvent::ContentBlockDelta`).
    Text,
    /// A reasoning / thinking block (`model::StreamEvent::ThinkingDelta`).
    Reasoning,
    /// A tool-use block whose arguments arrive as
    /// `model::StreamEvent::ToolUseDelta` fragments.
    ToolUse,
}

/// Events the harness surfaces on [`StreamSink`].
///
/// ## Delta-level streaming (issue #103)
///
/// The harness maps each raw [`crate::model::StreamEvent`] produced by the
/// agent through [`Harness::map_model_stream_event`] into zero or one of the
/// delta/frame variants below, alongside the existing coarse lifecycle events.
/// Resolution notes for the six spec ambiguities:
///
/// - **Q2**: frame markers are the generic [`StreamEvent::BlockStart`] /
///   [`StreamEvent::BlockStop`] carrying a [`BlockKind`], NOT typed-per-kind
///   markers.
/// - **Q3**: `model::StreamEvent::MessageStart` / `MessageStop` are DROPPED at
///   the harness boundary (mapped to `None`). `TurnStart` / `TurnEnd` already
///   cover message lifecycle.
/// - **Q5**: the coarse [`StreamEvent::ToolCall`] now also carries the final
///   `args`, and [`StreamEvent::ToolResult`] the result `content`. Both new
///   fields use `#[serde(default)]` so pre-#103 serialized events round-trip.
///
/// Tool lifecycle ordering per call:
/// [`StreamEvent::ToolCallStart`] → [`StreamEvent::ToolArgsDelta`]\* →
/// (`BlockStop`) → coarse [`StreamEvent::ToolCall`].
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
pub enum StreamEvent {
    TurnStart {
        turn: u32,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        node: Option<NodeAttr>,
    },
    TurnEnd {
        turn: u32,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        node: Option<NodeAttr>,
    },
    ToolCall {
        call_id: String,
        name: String,
        /// Final, fully-accumulated tool-call arguments (issue #103, Q5).
        /// `#[serde(default)]` keeps pre-#103 serialized events back-compatible.
        #[serde(default)]
        args: serde_json::Value,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        node: Option<NodeAttr>,
    },
    ToolResult {
        call_id: String,
        is_error: bool,
        /// The tool result content (issue #103, Q5). `#[serde(default)]` keeps
        /// pre-#103 serialized events back-compatible.
        #[serde(default)]
        content: String,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        node: Option<NodeAttr>,
    },
    FinalResponse {
        content: String,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        node: Option<NodeAttr>,
    },
    BudgetWarning {
        limit_type: BudgetLimitType,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        node: Option<NodeAttr>,
    },
    /// Emitted when a tool wants to surface a message to the user out-of-band
    /// (issue #81 — `SendMessageTool`). The harness loop recognizes the
    /// `send_message` tool, emits this event instead of collapsing the content
    /// into a normal tool result, and records a minimal success tool result so
    /// the loop continues.
    UserMessage {
        content: String,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        node: Option<NodeAttr>,
    },
    // ── Delta-level streaming (issue #103) ──────────────────────────────────
    /// Streamed text fragment (`model::StreamEvent::ContentBlockDelta`).
    TextDelta {
        content: String,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        node: Option<NodeAttr>,
    },
    /// Streamed reasoning/thinking fragment
    /// (`model::StreamEvent::ThinkingDelta`). Q4.
    ReasoningDelta {
        content: String,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        node: Option<NodeAttr>,
    },
    /// Streamed tool-argument JSON fragment
    /// (`model::StreamEvent::ToolUseDelta`), correlated to a `call_id` via the
    /// open-block index.
    ToolArgsDelta {
        call_id: String,
        partial_json: String,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        node: Option<NodeAttr>,
    },
    /// A content block opened (Q2). Emitted the first time a delta for an index
    /// is seen.
    BlockStart {
        index: u32,
        block: BlockKind,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        node: Option<NodeAttr>,
    },
    /// A content block closed (`model::StreamEvent::ContentBlockStop`). Q2.
    BlockStop {
        index: u32,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        node: Option<NodeAttr>,
    },
    /// A tool-use block opened (issue #103). Emitted so consumers can correlate
    /// the subsequent [`StreamEvent::ToolArgsDelta`] fragments and the final
    /// coarse [`StreamEvent::ToolCall`] by `call_id`. The `name` may be empty
    /// when the underlying model stream does not surface it before args (a
    /// documented `model::StreamEvent` limitation — name is recovered on the
    /// coarse `ToolCall`).
    ToolCallStart {
        index: u32,
        call_id: String,
        name: String,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        node: Option<NodeAttr>,
    },
    /// The consecutive-recoverable-tool-error breaker DETECTED a loop (issue
    /// #137): a tool hit `error_loop_threshold` (`N`) consecutive
    /// identical-argument recoverable errors and ONE corrective message was
    /// injected. A warning — the loop continues. Carries the tool name and the
    /// consecutive-error count (`= N`).
    ToolErrorLoopDetected {
        tool: String,
        consecutive_errors: u32,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        node: Option<NodeAttr>,
    },
    /// The consecutive-recoverable-tool-error breaker TRIPPED (issue #137): the
    /// same tool reached `2 * error_loop_threshold` (`2 * N`) consecutive
    /// identical-argument errors and the loop STOPPED to resolve the node's
    /// `BudgetExhaustedBehavior`. Carries the tool name and the count (`= 2*N`).
    ToolErrorLoopBroken {
        tool: String,
        consecutive_errors: u32,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        node: Option<NodeAttr>,
    },
    /// Output-schema enforcement (issue #139) fed a validation error back and
    /// RETRIED: the terminal `FinalResponse` failed validation against the
    /// leaf's `output` schema and a retry turn was granted (within budget). A
    /// warning — the loop continues. Carries the extra-retry count so far
    /// (`= attempt`) and the frozen validator error fed back.
    OutputSchemaRetry {
        attempt: u32,
        error: String,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        node: Option<NodeAttr>,
    },
    /// Output-schema enforcement (issue #139) EXHAUSTED its retries: the
    /// terminal still failed validation after `output_schema_max_retries` extra
    /// turns (with budget remaining), so the run terminates with
    /// [`HaltReason::OutputSchemaViolation`]. Carries the total attempt count
    /// (`= 1 + max_retries`) and the final frozen validator error.
    OutputSchemaViolation {
        attempts: u32,
        error: String,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        node: Option<NodeAttr>,
    },
}

impl StreamEvent {
    /// Uniform mutable access to the optional [`NodeAttr`] on any variant — the
    /// single seam the node-wrapping sinks stamp through ([`wrap_node_sink`]).
    /// One or-pattern binds the common `node` field across every variant.
    pub fn node_mut(&mut self) -> &mut Option<NodeAttr> {
        match self {
            StreamEvent::TurnStart { node, .. }
            | StreamEvent::TurnEnd { node, .. }
            | StreamEvent::ToolCall { node, .. }
            | StreamEvent::ToolResult { node, .. }
            | StreamEvent::FinalResponse { node, .. }
            | StreamEvent::BudgetWarning { node, .. }
            | StreamEvent::UserMessage { node, .. }
            | StreamEvent::TextDelta { node, .. }
            | StreamEvent::ReasoningDelta { node, .. }
            | StreamEvent::ToolArgsDelta { node, .. }
            | StreamEvent::BlockStart { node, .. }
            | StreamEvent::BlockStop { node, .. }
            | StreamEvent::ToolCallStart { node, .. }
            | StreamEvent::ToolErrorLoopDetected { node, .. }
            | StreamEvent::ToolErrorLoopBroken { node, .. }
            | StreamEvent::OutputSchemaRetry { node, .. }
            | StreamEvent::OutputSchemaViolation { node, .. } => node,
        }
    }

    /// The emitting node's attribution, if stamped.
    pub fn node(&self) -> Option<&NodeAttr> {
        match self {
            StreamEvent::TurnStart { node, .. }
            | StreamEvent::TurnEnd { node, .. }
            | StreamEvent::ToolCall { node, .. }
            | StreamEvent::ToolResult { node, .. }
            | StreamEvent::FinalResponse { node, .. }
            | StreamEvent::BudgetWarning { node, .. }
            | StreamEvent::UserMessage { node, .. }
            | StreamEvent::TextDelta { node, .. }
            | StreamEvent::ReasoningDelta { node, .. }
            | StreamEvent::ToolArgsDelta { node, .. }
            | StreamEvent::BlockStart { node, .. }
            | StreamEvent::BlockStop { node, .. }
            | StreamEvent::ToolCallStart { node, .. }
            | StreamEvent::ToolErrorLoopDetected { node, .. }
            | StreamEvent::ToolErrorLoopBroken { node, .. }
            | StreamEvent::OutputSchemaRetry { node, .. }
            | StreamEvent::OutputSchemaViolation { node, .. } => node.as_ref(),
        }
    }
}

/// A user-facing stream sink. `Arc` (not `Box`) so the single sink installed at
/// the top of a run can be CLONED into every nested node's context and into the
/// live per-turn agent adapter without being consumed — this is what lets a
/// composed strategy tree stream every node's events to one channel (the API
/// the harness backs subscribes to exactly this sink and forwards over SSE).
pub type StreamSink = Arc<dyn Fn(StreamEvent) + Send + Sync>;

/// Attribution stamped onto every [`StreamEvent`] as it flows up through the
/// node-wrapping sinks (see [`wrap_node_sink`]). Lets a multi-agent UI route a
/// frame to the node that produced it. Optional + `skip_serializing_if` so an
/// un-attributed event (a bare/single-leaf run, or any pre-attribution
/// consumer) serializes byte-identically to before this field existed.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct NodeAttr {
    /// The emitting node's kind: `"react"` (a leaf turn loop), or a combinator
    /// kind (`"plan_execute"`, `"self_verifying"`, `"ralph"`, `"hill_climbing"`).
    /// The leaf's kind is the innermost (most specific) — set first.
    pub kind: String,
    /// The leaf agent's handle (e.g. `"planner"`/`"executor"`/`"ralph-agent"`),
    /// when the emitting node is a `react` leaf. `None` for combinator frames.
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub agent_id: Option<String>,
    /// Nesting depth of the emitting leaf below the root (root combinator's leaf
    /// children are progressively deeper). Accumulated as the event passes
    /// through each combinator wrapper.
    pub depth: u32,
    /// Root→leaf node-kind path, accumulated by the wrapper chain (outermost
    /// first). E.g. `["ralph", "plan_execute", "self_verifying", "react"]`.
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    pub path: Vec<String>,
}

/// Wrap a parent sink so every event passing through is stamped for ONE node.
/// The leaf installs the innermost wrapper (it sets `kind`/`agent_id`/seeds the
/// path); each enclosing combinator's wrapper PREPENDS its kind to `path` and
/// bumps `depth`. Stamping is set-once for `kind`/`agent_id` (the innermost leaf
/// wins) so the event reports who actually spoke, with the full nesting in
/// `path`. Returns `None` when there is no parent sink (no-op, baseline path).
fn wrap_node_sink(
    parent: Option<StreamSink>,
    kind: &str,
    agent_id: Option<String>,
) -> Option<StreamSink> {
    let parent = parent?;
    let kind = kind.to_string();
    Some(Arc::new(move |mut ev: StreamEvent| {
        match ev.node_mut() {
            slot @ None => {
                *slot = Some(NodeAttr {
                    kind: kind.clone(),
                    agent_id: agent_id.clone(),
                    depth: 0,
                    path: vec![kind.clone()],
                });
            }
            Some(attr) => {
                attr.path.insert(0, kind.clone());
                attr.depth += 1;
            }
        }
        parent(ev);
    }))
}

/// Per-turn state threaded through [`Harness::map_model_stream_event`] (issue
/// #103). Tracks which block indices are open and their kind so
/// `ToolUseDelta` / `ContentBlockStop` events can be correlated back to a
/// `call_id`, and so each block's `BlockStart` is emitted exactly once.
#[derive(Debug, Default)]
pub struct TurnStreamState {
    /// Open block index → its [`BlockKind`].
    open_blocks: std::collections::HashMap<u32, BlockKind>,
    /// Tool-use block index → its derived `call_id`. The `call_id` is derived
    /// as `call_{index}`, matching the id synthesized by the agent's streaming
    /// accumulator so the coarse `ToolCall` correlates.
    tool_calls: std::collections::HashMap<u32, String>,
}

impl TurnStreamState {
    fn call_id_for(index: u32) -> String {
        format!("call_{index}")
    }
}

// ============================================================================
// Forward-declared sibling component types
// (full surfaces live in their owning issues)
// ============================================================================

/// Tool Escalation Protocol — the typed channel by which a tool signals the
/// harness to terminate cleanly and pass a *structural* state change up to its
/// caller (issue #80).
///
/// The harness is a pure intermediary: it never acts on a signal itself. Mode
/// switching, plan approval, and graceful abort are the caller's concern. The
/// harness terminates cleanly, surfaces the signal via
/// [`RunResult::Escalate`], and the caller (CLI, chat UI, REST API, parent
/// harness) owns the orchestration. This mirrors the [`RunResult::WaitingForHuman`]
/// model — the harness does not resume itself either.
///
/// ## Variants
/// - [`HarnessSignal::EnterPlanMode`] — agent requests entry into plan mode,
///   carrying accumulated context as a seed for the planning harness.
/// - [`HarnessSignal::ExitPlanMode`] — planning agent's terminal signal,
///   carrying the produced [`PlanArtifact`](crate::plan::PlanArtifact) for
///   human approval before an execution harness is instantiated.
/// - [`HarnessSignal::SwitchMode`] — agent requests a mode switch; carries the
///   target [`Mode`](crate::prompt_chunk_registry::Mode) (the EXISTING mode
///   enum — there is no separate `HarnessMode` type).
/// - [`HarnessSignal::Abort`] — agent requests a graceful, intentional stop
///   with a reason. Distinct from `HaltReason::AgentError` — it surfaces as
///   `RunResult::Escalate`, NOT `RunResult::Failure`.
///
/// Wire format: serde-tagged on `kind`, snake_case, byte-identical across the
/// four language implementations. Round-tripped by
/// `fixtures/harness/escalation_signals.json`.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
pub enum HarnessSignal {
    /// Agent requests entry into plan mode. Carries context the agent has
    /// accumulated so far as seed for the planning harness.
    EnterPlanMode { context: String },
    /// Planning agent has produced a plan and requests exit from plan mode.
    /// Carries the plan artifact for human approval before the execution
    /// harness is instantiated. This is the planning agent's terminal signal.
    ExitPlanMode { plan: crate::plan::PlanArtifact },
    /// Agent requests a mode switch. The caller instantiates the appropriate
    /// harness for the new mode.
    SwitchMode {
        mode: crate::prompt_chunk_registry::Mode,
    },
    /// Agent requests a graceful abort with a reason surfaced to the user.
    /// Distinct from `HaltReason::AgentError` — this is an intentional,
    /// agent-initiated stop and surfaces as `RunResult::Escalate`.
    Abort { reason: String },
}

/// Output of a single tool dispatch. Full type lives in issue #4 (ToolRegistry)
/// / #5 (Tool). The variants below cover what the harness loop needs to
/// route; richer payloads are additive.
///
/// The [`ToolOutput::Escalate`] variant is the tool-side entry point of the
/// Tool Escalation Protocol (issue #80): when a dispatched tool returns it, the
/// harness terminates cleanly (NOT appending the escalation to message
/// history — it is a control signal, not a conversation turn) and returns
/// [`RunResult::Escalate`].
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
pub enum ToolOutput {
    Success {
        content: String,
        /// `true` only when the tool itself clipped its output to fit an inline
        /// budget (large outputs routed through
        /// [`SandboxProvider::handle_large_output`] set this). Plain tool
        /// authors should leave it `false` — use [`ToolOutput::success`].
        #[serde(default)]
        truncated: bool,
    },
    Error {
        message: String,
        /// `true` if the agent may sensibly retry or adapt: the loop appends the
        /// error as a tool result and continues. `false` halts the run. Most
        /// tool failures are recoverable — prefer [`ToolOutput::error`]; reach
        /// for [`ToolOutput::fatal`] only when continuing is pointless.
        recoverable: bool,
    },
    /// Boxed because `ChildPausedState` is significantly larger than the other
    /// variants; keeps `ToolOutput` cheap to clone on the happy path.
    WaitingForHuman {
        child_state: Box<ChildPausedState>,
        request: HumanRequest,
    },
    /// Tool requests a structural state change from the harness's parent
    /// (issue #80). The harness terminates cleanly and passes the signal to
    /// the caller via [`RunResult::Escalate`]. The escalation is NOT appended
    /// to message history.
    Escalate { signal: HarnessSignal },
    /// Tool requests a clarifying answer from the human before it can produce a
    /// result (issue #81, Q4b — `AskUserQuestionTool`). UNLIKE
    /// [`ToolOutput::WaitingForHuman`], there is NO [`ChildPausedState`]: the
    /// harness loop builds a [`PausedState`] directly, sets its `human_request`
    /// to [`HumanRequest::Clarification`], and returns
    /// [`RunResult::WaitingForHuman`]. The clarifying tool call is preserved in
    /// `pending_tool_calls`; on resume the human's [`HumanResponse::Answer`]
    /// text is injected as the tool RESULT for that pending call (not appended
    /// as a free-standing user message) and the loop continues.
    AwaitingClarification {
        question: String,
        #[serde(default, skip_serializing_if = "Option::is_none")]
        options: Option<Vec<String>>,
    },
    /// Mid-loop consult signal (issue #114). A worker-side tool returns it with
    /// `child_state: None`; the worker harness pauses and returns
    /// [`RunResult::Consult`] with the consult call preserved as the head of
    /// `pending_tool_calls` (`human_request: None`). At the subagent boundary,
    /// [`SubagentTool`](crate::tools::SubagentTool) populates `child_state:
    /// Some(..)` — but in the A1 mediation seam it consumes the signal itself
    /// rather than bubbling it, so a parent orchestrator never observes this
    /// variant on the happy path. Mirrors [`ToolOutput::WaitingForHuman`]: the
    /// boxed `ChildPausedState` keeps the common case cheap to clone.
    Consult {
        #[serde(default, skip_serializing_if = "Option::is_none")]
        child_state: Option<Box<ChildPausedState>>,
        request: ConsultRequest,
    },
    /// A tool was denied by the sandbox (e.g. a path escaped the workspace root,
    /// or a command was disallowed). Carries the typed [`SandboxViolation`] so
    /// the harness — not the tool — decides whether it halts the run or is fed
    /// back to the model as a recoverable error, per
    /// [`HarnessConfig::sandbox_violation_policy`]. Produced by the
    /// `From<ToolExecutionError>` conversion; the harness normalizes it into a
    /// halt or a recoverable [`ToolOutput::Error`] immediately after dispatch,
    /// so it never reaches message history.
    SandboxViolation { violation: SandboxViolation },
}

impl ToolOutput {
    /// A successful, non-truncated result. The common case for a tool that
    /// returns its full output — saves spelling out `truncated: false`.
    pub fn success(content: impl Into<String>) -> Self {
        ToolOutput::Success {
            content: content.into(),
            truncated: false,
        }
    }

    /// A **recoverable** error: the harness loop appends it as a tool result and
    /// lets the agent adapt or retry. This is the right default for almost every
    /// tool failure (bad arguments, missing file, transient I/O).
    pub fn error(message: impl Into<String>) -> Self {
        ToolOutput::Error {
            message: message.into(),
            recoverable: true,
        }
    }

    /// A **fatal** error: continuing is pointless, so the run halts. Reserve for
    /// genuinely unrecoverable conditions; prefer [`ToolOutput::error`] when the
    /// agent could reasonably do something different next turn.
    pub fn fatal(message: impl Into<String>) -> Self {
        ToolOutput::Error {
            message: message.into(),
            recoverable: false,
        }
    }

    /// A **worker-side consult** signal (issue #114): the tool asks for mid-loop
    /// help. `child_state` is `None` — the harness loop builds the
    /// [`RunResult::Consult`] pause; only `SubagentTool` populates
    /// `child_state` at the boundary.
    pub fn consult(request: ConsultRequest) -> Self {
        ToolOutput::Consult {
            child_state: None,
            request,
        }
    }
}

#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct ToolResult {
    pub call_id: String,
    pub output: ToolOutput,
}

/// Sandbox-side violation. Full enum lives in issue #6 (SandboxProvider).
/// `PathEscape` and `NetworkViolation` are the halt-ELIGIBLE Layer-1 variants
/// (see [`is_always_halt`](Self::is_always_halt)); whether they actually halt is
/// decided by [`SandboxViolationPolicy`]. The remaining variants are always
/// recoverable.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
#[non_exhaustive]
pub enum SandboxViolation {
    PathEscape {
        path: String,
    },
    NetworkViolation {
        host: String,
    },
    PathDenied {
        path: String,
        #[serde(default)]
        matched_rule: String,
    },
    ReadOnlyViolation {
        path: String,
    },
    ExtensionDenied {
        path: String,
        extension: String,
    },
    FileSizeExceeded {
        path: String,
        size: u64,
        limit: u64,
    },
    DisallowedCommand {
        command: String,
    },
}

impl SandboxViolation {
    /// The halt-ELIGIBLE Layer-1 violations: a path escaping the workspace root
    /// or a blocked network host. Whether such a violation actually halts the
    /// run is governed by [`SandboxViolationPolicy`]; under the default
    /// (`Recoverable`) even these are fed back to the model. The Layer-2
    /// variants (`PathDenied`, `ReadOnlyViolation`, …) are never halt-eligible —
    /// they are always recoverable regardless of policy.
    pub fn is_always_halt(&self) -> bool {
        matches!(
            self,
            SandboxViolation::PathEscape { .. } | SandboxViolation::NetworkViolation { .. }
        )
    }
}

/// How the harness treats a [`SandboxViolation`] surfaced by a tool (or the
/// pre-dispatch `validate` check): coach the model and let it retry, or halt the
/// run outright.
///
/// This is the single switch for sandbox-violation handling, applied uniformly
/// across every tool (filesystem, bash/exec, …) and both surfacing paths. The
/// default is [`Recoverable`](Self::Recoverable): a mis-targeted write or a
/// blocked command is a benign mistake for an agent, so the violation is
/// appended as a recoverable tool error and the model self-corrects (the
/// boundary still holds — the access was refused). Opt into
/// [`Halt`](Self::Halt) to restore the original Layer-1 always-halt behavior for
/// path escapes / network violations.
///
/// Set it via [`HarnessBuilder::sandbox_violation_policy`].
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize, Default)]
#[serde(rename_all = "snake_case")]
pub enum SandboxViolationPolicy {
    /// Surface the violation to the model as a recoverable tool error it can
    /// retry from. Halt-eligible or not, nothing halts the run. The default.
    #[default]
    Recoverable,
    /// Halt the run when a halt-eligible violation
    /// ([`SandboxViolation::is_always_halt`]) is encountered. Layer-2 violations
    /// stay recoverable. Restores the pre-policy Layer-1 behavior.
    Halt,
}

/// Where in the lifecycle a middleware hook fired. Full enum lives in #11.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum HookPoint {
    BeforeTurn,
    BeforeTool,
    AfterTool,
    BeforeCompletion,
}

/// Termination-policy decision. Full enum lives in #13.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
pub enum TerminationDecision {
    Continue,
    Halt { reason: String },
}

/// Session state handed back and forth across pause/resume. The harness does
/// not interpret its contents; it round-trips opaquely so that #7
/// (ContextManager) and #8 (MemoryProvider) own the schema.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize, Default)]
pub struct SessionState {
    #[serde(default)]
    pub messages: Vec<Message>,
    #[serde(default)]
    pub extras: serde_json::Map<String, serde_json::Value>,
}

// ============================================================================
// Forward-declared sibling component traits
// ============================================================================

/// Issue #4 — ToolRegistry: dispatches tool calls.
pub trait ToolRegistry: Send + Sync {
    fn dispatch<'a>(&'a self, call: ToolCall) -> BoxFut<'a, ToolOutput>;

    /// Whether this tool is annotated `always_halt` (e.g. dangerous external
    /// effects). The harness short-circuits on the first such call in a batch.
    fn is_always_halt(&self, tool_name: &str) -> bool {
        let _ = tool_name;
        false
    }

    /// Tool schemas to feed into context assembly.
    fn schemas(&self) -> Vec<ToolSchema> {
        Vec::new()
    }
}

/// A [`ToolRegistry`] with no tools.
///
/// `schemas()` is empty, so the model is offered no tools and replies in plain
/// text; `dispatch` is therefore never reached. This is the registry used by
/// [`HarnessBuilder::conversational`] and the right starting point for any
/// agent that does not act on its environment.
#[derive(Debug, Default, Clone, Copy)]
pub struct EmptyToolRegistry;

impl ToolRegistry for EmptyToolRegistry {
    fn dispatch<'a>(&'a self, _call: ToolCall) -> BoxFut<'a, ToolOutput> {
        Box::pin(async {
            ToolOutput::Error {
                message: "no tools are registered".into(),
                recoverable: false,
            }
        })
    }
}

/// SC-30: a read-only VIEW over an inner harness-loop [`ToolRegistry`]. It
/// advertises ([`schemas`](ToolRegistry::schemas)) and dispatches ONLY tools
/// whose name is in `allow` — the INTERSECTION of the wrapped catalogue with a
/// read-only allow-list (`StandardTools::readonly_set()` names). Used internally
/// for the SelfVerifying evaluate phase so a reviewer cannot reach
/// write / exec / side-effecting tools (web/MCP the read-only sandbox does not
/// gate) even though the work phase could — WITHOUT the consumer registering a
/// scoped read-only toolset. A non-allow-listed dispatch (which the model should
/// never request, since it is never advertised) returns a recoverable
/// [`ToolOutput::error`]. A consumer that wants a different reviewer toolset sets
/// an explicit `eval_toolset` handle, which bypasses this view entirely.
struct ReadOnlyToolView {
    inner: Arc<dyn ToolRegistry>,
    allow: std::collections::HashSet<String>,
}

impl ReadOnlyToolView {
    fn new(inner: Arc<dyn ToolRegistry>, allow: std::collections::HashSet<String>) -> Self {
        Self { inner, allow }
    }
}

impl ToolRegistry for ReadOnlyToolView {
    fn dispatch<'a>(&'a self, call: ToolCall) -> BoxFut<'a, ToolOutput> {
        if self.allow.contains(&call.name) {
            self.inner.dispatch(call)
        } else {
            let name = call.name;
            Box::pin(async move {
                ToolOutput::error(format!(
                    "tool `{name}` is not available in the read-only evaluate phase"
                ))
            })
        }
    }

    fn is_always_halt(&self, tool_name: &str) -> bool {
        self.inner.is_always_halt(tool_name)
    }

    fn schemas(&self) -> Vec<ToolSchema> {
        self.inner
            .schemas()
            .into_iter()
            .filter(|s| self.allow.contains(&s.name))
            .collect()
    }
}

/// Issue #6 — SandboxProvider: validates tool calls against sandbox policy.
///
/// Issue #5 adds default implementations for `execute_command`,
/// `handle_large_output`, and `resolve_path` so the standard tool catalogue
/// can be built before #6 lands its canonical sandbox. **These defaults are
/// NOT production-safe**: `execute_command` spawns processes directly with no
/// sandboxing, `resolve_path` returns the input as-is, and
/// `handle_large_output` truncates inline without offloading. Issue #6 must
/// override these.
pub trait SandboxProvider: Send + Sync {
    fn validate<'a>(&'a self, call: &'a ToolCall) -> BoxFut<'a, Result<(), SandboxViolation>>;

    /// Run a subprocess. **Default impl spawns directly with no sandboxing —
    /// production sandboxes must override.**
    fn execute_command<'a>(
        &'a self,
        command: &'a str,
        args: &'a [String],
        working_dir: Option<&'a std::path::Path>,
        timeout: Option<std::time::Duration>,
    ) -> BoxFut<'a, Result<CommandOutput, SandboxViolation>> {
        Box::pin(async move {
            let mut cmd = tokio::process::Command::new(command);
            cmd.args(args);
            if let Some(dir) = working_dir {
                cmd.current_dir(dir);
            }
            let fut = cmd.output();
            let output_res = if let Some(t) = timeout {
                match tokio::time::timeout(t, fut).await {
                    Ok(r) => r,
                    Err(_) => {
                        return Ok(CommandOutput {
                            stdout: String::new(),
                            stderr: format!("command timed out after {}s", t.as_secs()),
                            exit_code: -1,
                            timed_out: true,
                            truncated: false,
                        });
                    }
                }
            } else {
                fut.await
            };
            match output_res {
                Ok(out) => Ok(CommandOutput {
                    stdout: String::from_utf8_lossy(&out.stdout).to_string(),
                    stderr: String::from_utf8_lossy(&out.stderr).to_string(),
                    exit_code: out.status.code().unwrap_or(-1),
                    timed_out: false,
                    truncated: false,
                }),
                Err(e) => Ok(CommandOutput {
                    stdout: String::new(),
                    stderr: format!("spawn failed: {e}"),
                    exit_code: -1,
                    timed_out: false,
                    truncated: false,
                }),
            }
        })
    }

    /// Truncate large output head+tail. Default treats `head_tokens * 4` as
    /// an approximate char budget per half. Production sandboxes should
    /// offload the full content to a file and return a `FileRef`.
    fn handle_large_output<'a>(
        &'a self,
        content: String,
        _call_id: &'a str,
        head_tokens: u32,
        tail_tokens: u32,
    ) -> BoxFut<'a, TruncatedOutput> {
        Box::pin(async move {
            let head_chars = (head_tokens as usize).saturating_mul(4);
            let tail_chars = (tail_tokens as usize).saturating_mul(4);
            let total = content.chars().count();
            let original_size = content.len() as u64;
            if total <= head_chars + tail_chars {
                return TruncatedOutput {
                    content,
                    truncated: false,
                    full_ref: None,
                    original_size,
                };
            }
            let head: String = content.chars().take(head_chars).collect();
            let tail: String = content.chars().skip(total - tail_chars).collect();
            let elided = total - head_chars - tail_chars;
            let snippet = format!("{head}\n... [{elided} chars elided] ...\n{tail}");
            TruncatedOutput {
                content: snippet,
                truncated: true,
                full_ref: None,
                original_size,
            }
        })
    }

    /// Resolve / canonicalize a path against the sandbox root. Default is
    /// an identity pass-through; production sandboxes must enforce roots.
    ///
    /// `operation` lets implementations distinguish reads from writes so they
    /// can apply `read_only`-style policies and skip canonicalization for
    /// not-yet-existing files on writes.
    fn resolve_path<'a>(
        &'a self,
        path: &'a str,
        operation: Operation,
    ) -> BoxFut<'a, Result<std::path::PathBuf, SandboxViolation>> {
        let _ = operation;
        Box::pin(async move { Ok(std::path::PathBuf::from(path)) })
    }

    /// Active isolation mode. Used by observability and middleware. Default
    /// returns `IsolationMode::WorkspaceScoped` (safe-by-default, issue #34).
    /// A provider that genuinely wants no isolation must override this and opt
    /// in to `IsolationMode::None`, which only exists under the `dangerous`
    /// feature.
    fn isolation_mode(&self) -> IsolationMode {
        IsolationMode::WorkspaceScoped
    }

    /// Workspace root used by `ContextManager` for directory-map injection.
    /// Default returns `/`, which is **not** safe — production sandboxes
    /// must override.
    fn workspace_root(&self) -> &std::path::Path {
        std::path::Path::new("/")
    }

    /// Maximum number of bytes a single write/append may produce, or `None` for
    /// no cap. Write tools consult this BEFORE writing (`resolve_path` only sees
    /// the path, not the payload, so the read-side `max_file_size` cap cannot
    /// cover writes). Default `None` — production sandboxes override to mirror
    /// their read cap.
    fn max_write_size(&self) -> Option<u64> {
        None
    }
}

/// A [`SandboxProvider`] with no filesystem.
///
/// `validate` allows everything because nothing is meant to run against it: it
/// is the sandbox for tool-less agents (e.g. [`HarnessBuilder::conversational`]),
/// where no tool is ever dispatched and the boundary is never exercised. Agents
/// that actually touch the filesystem or shell must use a real sandbox such as
/// [`WorkspaceScopedSandbox`](crate::sandbox::WorkspaceScopedSandbox).
#[derive(Debug, Default, Clone, Copy)]
pub struct NullSandbox;

impl SandboxProvider for NullSandbox {
    fn validate<'a>(&'a self, _call: &'a ToolCall) -> BoxFut<'a, Result<(), SandboxViolation>> {
        Box::pin(async { Ok(()) })
    }
}

/// Filesystem operation being performed on a path. Passed to
/// [`SandboxProvider::resolve_path`] so the sandbox can apply read-only
/// policies and adjust canonicalization behavior for not-yet-existing files.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum Operation {
    Read,
    Write,
    Execute,
}

/// Isolation strategy for sandboxed subprocess execution.
///
/// Lives on the trait so middleware and observability can route on it
/// without depending on the concrete sandbox impl.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
pub enum IsolationMode {
    /// No isolation. Trusted-dev use only; the sandbox must emit a warning
    /// at construction time. Gated behind the `dangerous` feature (issue #34);
    /// absent from the default build. The wire tag stays `"none"`.
    #[cfg(feature = "dangerous")]
    None,
    /// Path enforcement only — no process or network isolation. Default for
    /// the canonical `WorkspaceScopedSandbox`. Commands run UNCONTAINED on the
    /// host (full privileges + network); real process isolation
    /// (`Bubblewrap`/`Docker`) is tracked under issue #6. Do not run untrusted
    /// agents under this mode.
    WorkspaceScoped,
    /// Linux process isolation via bubblewrap. Reserved; not implemented in
    /// the v1 reference sandbox.
    Bubblewrap { profile: BwrapProfile },
    /// Full Docker isolation including network policy. Reserved; not
    /// implemented in the v1 reference sandbox.
    Docker {
        image: String,
        network: NetworkPolicy,
    },
}

/// Network egress policy for `IsolationMode::Docker`.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
pub enum NetworkPolicy {
    /// No network access at all.
    None,
    /// Allow egress to the listed hosts only.
    Allowlist { hosts: Vec<String> },
    /// Unrestricted egress. Use with caution.
    Full,
}

/// Bubblewrap profile descriptor. Opaque in v1 — the bubblewrap backend is
/// not yet implemented, but the shape lives on the public surface so the
/// `IsolationMode` enum can be exhaustive across all four implementations.
#[derive(Debug, Clone, Default, PartialEq, Eq, Serialize, Deserialize)]
pub struct BwrapProfile {}

/// Read-only decorator over any [`SandboxProvider`] (issue #61). Wraps an
/// inner sandbox and additionally rejects every WRITE/EXECUTE-classified tool
/// call in [`validate`](SandboxProvider::validate) with
/// [`SandboxViolation::ReadOnlyViolation`], while delegating reads (and all the
/// other `SandboxProvider` methods) to the inner sandbox unchanged.
///
/// The `SelfVerifying` strategy derives one of these INTERNALLY for its
/// evaluate phase (the Default-FAIL contract: the evaluator must not be able to
/// mutate the workspace it is reviewing). Write-intent is classified by tool
/// name against [`Self::DEFAULT_WRITE_TOOLS`] (the standard catalogue's
/// mutating tools: `write_file`, `edit_file`, `delete_file`, `move_file`,
/// `exec`, `bash_command`, `run_tests`). Callers with bespoke tool names can
/// supply their own set via [`with_write_tools`](Self::with_write_tools).
///
/// `ReadOnlyViolation` is a Layer-2 (recoverable) violation, so in the harness
/// loop a blocked write surfaces to the evaluator agent as a recoverable tool
/// error — it does NOT halt the evaluate run.
pub struct ReadOnlySandbox {
    inner: Arc<dyn SandboxProvider>,
    write_tools: std::collections::HashSet<String>,
}

impl ReadOnlySandbox {
    /// Standard-catalogue tool names that MUTATE the workspace and are therefore
    /// blocked by a read-only sandbox.
    pub const DEFAULT_WRITE_TOOLS: &'static [&'static str] = &[
        "write_file",
        "edit_file",
        "delete_file",
        "move_file",
        "exec",
        "bash_command",
        "run_tests",
    ];

    /// Wrap `inner`, blocking the standard mutating tools.
    pub fn new(inner: Arc<dyn SandboxProvider>) -> Self {
        Self {
            inner,
            write_tools: Self::DEFAULT_WRITE_TOOLS
                .iter()
                .map(|s| s.to_string())
                .collect(),
        }
    }

    /// Wrap `inner`, blocking exactly the supplied tool names (overrides the
    /// default set).
    pub fn with_write_tools(
        inner: Arc<dyn SandboxProvider>,
        write_tools: impl IntoIterator<Item = String>,
    ) -> Self {
        Self {
            inner,
            write_tools: write_tools.into_iter().collect(),
        }
    }

    fn is_write(&self, tool_name: &str) -> bool {
        self.write_tools.contains(tool_name)
    }
}

impl SandboxProvider for ReadOnlySandbox {
    fn validate<'a>(&'a self, call: &'a ToolCall) -> BoxFut<'a, Result<(), SandboxViolation>> {
        Box::pin(async move {
            if self.is_write(&call.name) {
                return Err(SandboxViolation::ReadOnlyViolation {
                    path: call.name.clone(),
                });
            }
            self.inner.validate(call).await
        })
    }

    fn execute_command<'a>(
        &'a self,
        command: &'a str,
        _args: &'a [String],
        _working_dir: Option<&'a std::path::Path>,
        _timeout: Option<std::time::Duration>,
    ) -> BoxFut<'a, Result<CommandOutput, SandboxViolation>> {
        // A read-only sandbox forbids subprocess execution outright (commands
        // may have arbitrary write side effects).
        Box::pin(async move {
            Err(SandboxViolation::ReadOnlyViolation {
                path: command.to_string(),
            })
        })
    }

    fn resolve_path<'a>(
        &'a self,
        path: &'a str,
        operation: Operation,
    ) -> BoxFut<'a, Result<std::path::PathBuf, SandboxViolation>> {
        Box::pin(async move {
            if matches!(operation, Operation::Write | Operation::Execute) {
                return Err(SandboxViolation::ReadOnlyViolation {
                    path: path.to_string(),
                });
            }
            self.inner.resolve_path(path, operation).await
        })
    }

    fn isolation_mode(&self) -> IsolationMode {
        self.inner.isolation_mode()
    }

    fn workspace_root(&self) -> &std::path::Path {
        self.inner.workspace_root()
    }
}

// ============================================================================
// VcsProvider seam (issue #58 v2) — git-log reload for the Ralph loop strategy
// ============================================================================

/// Read-only VCS abstraction the `Ralph` loop strategy uses to reload git
/// history between context windows (issue #58 v2, decision B4).
///
/// The v1 Ralph reload (commit `927cc57`) re-seeded each fresh context window
/// from `.spore/progress.json` + `.spore/feature_list.json` only; the spec's
/// "reload git log" step was deferred (B4) because there was no hermetic,
/// cross-language-testable seam for VCS reads. This trait IS that seam.
///
/// It mirrors how [`SandboxProvider`] abstracts filesystem/shell access:
/// define a trait, ship a real implementation ([`GitVcsProvider`]) and a
/// deterministic fixture double ([`FixtureVcsProvider`]), and inject the chosen
/// one at construction via [`HarnessBuilder::vcs_provider`]. The harness owns an
/// `Arc<dyn VcsProvider>` clone exactly as it does for every other component.
///
/// `Ralph` calls [`log`](Self::log) during its reload phase and injects the
/// output into the next window's seed as a clearly delimited
/// "Recent VCS history:" section. When NO provider is wired
/// (`vcs_provider == None`, the default) the git-log section is OMITTED and
/// Ralph behaves byte-for-byte like v1 — this is the B4→None decision.
pub trait VcsProvider: Send + Sync {
    /// Return the project's commit log, shaped by `args`. The returned string
    /// is the verbatim VCS output (e.g. `git log` stdout); the caller does not
    /// parse it, it is injected into the reloaded context block as-is.
    fn log<'a>(&'a self, args: &'a VcsLogArgs) -> BoxFut<'a, Result<String, VcsError>>;

    /// Return the working-tree status (e.g. `git status` stdout), verbatim.
    fn status<'a>(&'a self) -> BoxFut<'a, Result<String, VcsError>>;
}

/// Parameters shaping a [`VcsProvider::log`] read. Each field maps to a
/// `git log` flag in [`GitVcsProvider`]:
///   - `max_entries` → `-n <N>` (cap the number of commits returned),
///   - `since_ref`   → `<ref>..` (only commits AFTER `<ref>`),
///   - `format`      → `--format=<fmt>` (custom pretty format).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize, Default)]
pub struct VcsLogArgs {
    /// Maximum number of commits to return (`git log -n <max_entries>`).
    pub max_entries: usize,
    /// Only commits reachable after this ref (`git log <since_ref>..`). `None`
    /// returns the full history (subject to `max_entries`).
    pub since_ref: Option<String>,
    /// Custom `git log --format=<format>` string. `None` uses git's default
    /// formatting.
    pub format: Option<String>,
}

/// Error raised by a [`VcsProvider`]. Mirrors the per-component
/// `<Component>Error` convention (`thiserror`, `#[non_exhaustive]`).
#[derive(Debug, Error, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
#[non_exhaustive]
pub enum VcsError {
    /// The underlying VCS command failed (non-zero exit), carrying the captured
    /// stderr.
    #[error("vcs command failed: {message}")]
    CommandFailed { message: String },
    /// The VCS command was blocked or could not be spawned by the sandbox.
    #[error("vcs command blocked by sandbox: {0:?}")]
    Sandbox(SandboxViolation),
}

/// Real [`VcsProvider`] that shells out to `git` THROUGH a [`SandboxProvider`]
/// (issue #58 v2). It wraps the sandbox and calls
/// [`SandboxProvider::execute_command`] — it never bypasses sandboxing to spawn
/// `git` directly. The command line is built from [`VcsLogArgs`] (see that
/// type for the flag mapping); [`status`](VcsProvider::status) runs
/// `git status`. All commands run in `workspace_root`.
pub struct GitVcsProvider {
    sandbox: Arc<dyn SandboxProvider>,
    workspace_root: std::path::PathBuf,
}

impl GitVcsProvider {
    /// Wrap `sandbox`, running `git` invocations in `workspace_root`.
    pub fn new(
        sandbox: Arc<dyn SandboxProvider>,
        workspace_root: impl Into<std::path::PathBuf>,
    ) -> Self {
        Self {
            sandbox,
            workspace_root: workspace_root.into(),
        }
    }

    /// Build the `git log` argument vector from `args` (visible for testing the
    /// flag mapping independently of process execution).
    fn log_args(args: &VcsLogArgs) -> Vec<String> {
        let mut out = vec![
            "log".to_string(),
            "-n".to_string(),
            args.max_entries.to_string(),
        ];
        if let Some(fmt) = &args.format {
            out.push(format!("--format={fmt}"));
        }
        if let Some(since) = &args.since_ref {
            out.push(format!("{since}.."));
        }
        out
    }
}

impl VcsProvider for GitVcsProvider {
    fn log<'a>(&'a self, args: &'a VcsLogArgs) -> BoxFut<'a, Result<String, VcsError>> {
        Box::pin(async move {
            let argv = Self::log_args(args);
            let out = self
                .sandbox
                .execute_command("git", &argv, Some(self.workspace_root.as_path()), None)
                .await
                .map_err(VcsError::Sandbox)?;
            if out.exit_code != 0 {
                return Err(VcsError::CommandFailed {
                    message: out.stderr,
                });
            }
            Ok(out.stdout)
        })
    }

    fn status<'a>(&'a self) -> BoxFut<'a, Result<String, VcsError>> {
        Box::pin(async move {
            let argv = vec!["status".to_string()];
            let out = self
                .sandbox
                .execute_command("git", &argv, Some(self.workspace_root.as_path()), None)
                .await
                .map_err(VcsError::Sandbox)?;
            if out.exit_code != 0 {
                return Err(VcsError::CommandFailed {
                    message: out.stderr,
                });
            }
            Ok(out.stdout)
        })
    }
}

/// Output of a subprocess executed through the sandbox.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct CommandOutput {
    pub stdout: String,
    pub stderr: String,
    pub exit_code: i32,
    #[serde(default)]
    pub timed_out: bool,
    /// `true` if `stdout`/`stderr` were truncated by `handle_large_output`
    /// before being returned. Kept alongside `timed_out` so existing callers
    /// continue to compile.
    #[serde(default)]
    pub truncated: bool,
}

/// Head+tail-truncated output. `full_ref` is `Some` when the sandbox offloads
/// the original content to a backing file.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct TruncatedOutput {
    /// The (possibly truncated) head+tail content surfaced to the agent.
    pub content: String,
    /// `true` if the original content was truncated.
    #[serde(default)]
    pub truncated: bool,
    /// Backing file holding the full original content, if offloaded.
    #[serde(default)]
    pub full_ref: Option<FileRef>,
    /// Original size of the input content in bytes.
    #[serde(default)]
    pub original_size: u64,
}

/// Reference to a file holding offloaded tool output.
///
/// `path` is a string and `byte_len` is a `u64` to keep the wire format
/// portable across the four reference implementations — `PathBuf` serde is
/// platform-specific and `usize` width differs by target.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct FileRef {
    pub path: String,
    pub byte_len: u64,
}

/// Inputs the harness compaction loop (issue #46) needs to run one
/// compaction turn and verify its result.
///
/// The harness loop operates on the opaque [`SessionState`] above; the rich
/// compaction/verification API ([`crate::context::ContextManager`],
/// [`CompactionVerifier`]) operates on [`crate::context::SessionState`]. This
/// struct is the bridge: a [`ContextManager`] that supports compaction
/// projects everything the loop needs into one value, so the loop never has
/// to know which concrete state type its manager uses internally.
///
/// `context` is fed straight to `Agent::turn` to produce the summary;
/// `preserve_hints` and `verification_state` are passed to
/// [`CompactionVerifier::verify`]. On a verification failure the loop re-runs
/// the turn with [`ContextManager::inject_missing_items`] applied to `context`.
pub struct CompactionTurn {
    /// Context to feed `Agent::turn` to elicit the summary.
    pub context: Context,
    /// Preservation hints to hand the verifier.
    pub preserve_hints: CompactionPreserveHints,
    /// Verifier-facing session state (rich `context::SessionState`).
    pub verification_state: ContextSessionState,
    /// Messages about to be removed — used to stamp the compaction span.
    pub messages_removed: u32,
    /// The exact messages this turn will drop, computed once in
    /// `prepare_compaction_turn`. Threaded into [`ContextManager::apply_compaction`]
    /// so the manager reuses this set for token accounting instead of
    /// re-deriving it (one source of truth).
    pub dropped_messages: Vec<Message>,
}

/// Issue #7 — ContextManager: assembles per-turn context.
///
/// Issue #46 adds the optional compaction-loop surface
/// ([`prepare_compaction_turn`](Self::prepare_compaction_turn),
/// [`inject_missing_items`](Self::inject_missing_items),
/// [`apply_compaction`](Self::apply_compaction)). All three have defaults so
/// managers that do not compact (the default `should_compact` returns `false`)
/// need not implement them.
pub trait ContextManager: Send + Sync {
    fn assemble<'a>(&'a self, session: &'a SessionState, task: &'a Task) -> BoxFut<'a, Context>;

    fn append_tool_result<'a>(
        &'a self,
        session: &'a mut SessionState,
        result: &'a ToolResult,
    ) -> BoxFut<'a, ()>;

    /// Append the assistant's turn (model output: text and/or the tool calls it
    /// requested) to the conversation so the next assemble() reflects what the
    /// agent already did. Without this the model loses track of its own actions.
    fn append_assistant_message<'a>(
        &'a self,
        session: &'a mut SessionState,
        message: &'a Message,
    ) -> BoxFut<'a, ()> {
        let _ = (session, message);
        Box::pin(async {})
    }

    fn append_user_message<'a>(
        &'a self,
        session: &'a mut SessionState,
        text: &'a str,
    ) -> BoxFut<'a, ()>;

    fn should_compact(&self, session: &SessionState) -> bool {
        let _ = session;
        false
    }

    /// Build the inputs for one compaction turn (issue #46). Returns `None`
    /// when there is nothing to compact (e.g. history shorter than the
    /// preserve window), in which case the harness skips compaction entirely.
    ///
    /// Default: `None` — managers that never compact need not override this.
    fn prepare_compaction_turn(&self, session: &SessionState) -> Option<CompactionTurn> {
        let _ = session;
        None
    }

    /// Mutate a compaction [`Context`] in place to request a revised summary
    /// on retry (issue #46). The harness calls this with the items the prior
    /// summary failed to preserve. Default: append the standard "missing
    /// these items … please revise" instruction as a user message.
    fn inject_missing_items(&self, context: &mut Context, missing: &[String]) {
        context.messages.push(Message {
            role: crate::model::Role::User,
            content: crate::model::Content::Text {
                text: format!(
                    "Your summary is missing these items: {}. Please revise.",
                    missing.join(", ")
                ),
            },
        });
    }

    /// Accept a verified (or accepted-anyway) summary into the session,
    /// replacing the compacted span (issue #46). `dropped` is the message set
    /// computed by [`prepare_compaction_turn`](Self::prepare_compaction_turn)
    /// (carried on the [`CompactionTurn`]); managers use it for token accounting
    /// instead of re-deriving the dropped set. Default: no-op — only
    /// compaction-capable managers implement it.
    fn apply_compaction(&self, session: &mut SessionState, summary: String, dropped: &[Message]) {
        let _ = (session, summary, dropped);
    }

    /// Current token budget used for this session, if the manager tracks one
    /// (issue #57 — Known Deviation #2 token-accounting fix). The harness reads
    /// this after [`apply_compaction`](Self::apply_compaction) to stamp the
    /// compaction span with the real post-compaction utilization. Default:
    /// `None` — managers that do not track tokens fall back to the pre-value.
    fn token_budget_used(&self, session: &SessionState) -> Option<u32> {
        let _ = session;
        None
    }
}

/// Issue #13 — TerminationPolicy.
pub trait TerminationPolicy: Send + Sync {
    fn evaluate<'a>(
        &'a self,
        session: &'a SessionState,
        budget_used: &'a BudgetSnapshot,
    ) -> BoxFut<'a, TerminationDecision>;
}

/// Termination policy that lets the loop complete as soon as the agent produces
/// a final response (always `Continue`, which the harness interprets as "accept
/// the final response and succeed"). This is the default policy wired by
/// [`HarnessBuilder::conversational`] — a tool-less chat agent halts naturally
/// on its first final response, with no extra completion criteria to satisfy.
pub struct CompleteOnFinalResponse;

impl TerminationPolicy for CompleteOnFinalResponse {
    fn evaluate<'a>(
        &'a self,
        _session: &'a SessionState,
        _budget_used: &'a BudgetSnapshot,
    ) -> BoxFut<'a, TerminationDecision> {
        Box::pin(async { TerminationDecision::Continue })
    }
}

/// Issue #11 — Middleware chain. Full shape (BeforeTool modification,
/// SurfaceToHuman payload) lives in #11; this stub covers what ReAct needs.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
pub enum MiddlewareDecision {
    Continue,
    ContinueWithModification { calls: Vec<ToolCall> },
    Halt { reason: String },
    SurfaceToHuman { request: HumanRequest },
}

pub trait MiddlewareChain: Send + Sync {
    fn fire<'a>(
        &'a self,
        hook: HookPoint,
        session: &'a SessionState,
    ) -> BoxFut<'a, MiddlewareDecision>;
}

// Issue #12 — `ObservabilityProvider` is no longer a no-op stub here. The
// canonical trait lives in [`crate::observability`]; the harness loop emits
// real spans through it (see `run_react`). Re-exported below for ergonomics.
pub use crate::observability::ObservabilityProvider;

// ============================================================================
// Human-in-the-loop
// ============================================================================
//
// ## Budget escalation HITL resume (issue #130)
//
// This section also owns the wiring that connects the `Escalate` budget
// resolution (#123/#125) to the existing HITL pause/resume seam
// (`RunResult::WaitingForHuman` + `PausedState` + `resume_inner`). The
// `escalation_mode` config knob (#120, previously UNCONSUMED) is finally read
// here.
//
// ### New types (#130)
//   - [`EscalationAction`] — the operator's choice on a budget-exhaustion
//     pause: `ContinueWithBudget { steps: u32 }` (grant N more steps, resume
//     from checkpoint) | `Skip` (mark the task skipped, the outer loop
//     advances) | `Fail` (abort the node, propagate `BudgetExceeded`). Named
//     `u32` field on `ContinueWithBudget` (serde internally-tagged enums cannot
//     carry tuple variants — mirrors `BudgetPolicy { value: u32 }`).
//   - [`HumanRequest::BudgetExhausted`] — a new variant carrying the node's
//     phase / policy / `steps_taken` / `continues_used` / `partial_output` and
//     the advisory `available_actions: Vec<EscalationAction>`. The existing
//     `ToolApproval` / `Clarification` / `Review` variants are UNCHANGED.
//   - [`HumanResponse::Escalate`] — a new variant delivering the operator's
//     [`EscalationAction`] on resume. It does NOT overload `Allow` / `Halt` /
//     `Deny`.
//
// ### The `escalation_mode` accessor
//   - [`StrategyExecutor::escalation_mode`] returns the configured
//     [`EscalationMode`]. `StandardHarness` returns `self.config.escalation_mode`
//     (mirrors `ralph_max_resets` / `workspace_root`). The `*Config::run` bodies
//     only hold `&dyn StrategyExecutor`, so this accessor is required to consult
//     the knob from a config body.
//
// ### Rules enforced (#130)
//   - At each `ExhaustedResolution::Escalate` site the body consults
//     `executor.escalation_mode()`:
//       * `EscalationMode::Autonomous`     → EXISTING behavior unchanged
//         (surface the partial, propagate `BudgetExhausted` up).
//       * `EscalationMode::SurfaceToHuman` → build a `PausedState` whose
//         `human_request = Some(HumanRequest::BudgetExhausted { .. })`, stash it
//         as `RunResult::WaitingForHuman` through the `terminal_override` seam so
//         it propagates VERBATIM.
//   - `available_actions` is ADVISORY for v1 (fork D): `resume` does NOT
//     hard-reject an out-of-set action. Combinators offer
//     `[ContinueWithBudget, Skip, Fail]`; a bare leaf OMITS `Skip` and offers
//     `[ContinueWithBudget, Fail]` (fork C).
//   - `resume_inner` reconstructs the node's `BudgetContext` from the request's
//     own `steps_taken` + `continues_used` (fork E — NOT #129's durable
//     cross-process checkpoint). `ContinueWithBudget { steps }` grants `steps`
//     additional allowance and re-enters the loop; `Skip` resolves the node
//     cleanly so the outer loop advances; `Fail` propagates
//     `Failure { BudgetExceeded }` with the partial discarded.
//
// No `// SPEC QUESTION:` markers — all forks are resolved in the #130 plan.

/// The operator's choice on a budget-exhaustion [`HumanRequest::BudgetExhausted`]
/// pause (#130). Tagged on `kind`, snake_case — internally-tagged, so the
/// data-carrying variant uses a NAMED `u32` field (tuple variants are not
/// representable; mirrors [`BudgetPolicy`]'s `value: u32` convention).
///
///   - `ContinueWithBudget { steps }` — grant `steps` additional steps to the
///     node's budget scope and resume from the checkpoint.
///   - `Skip` — mark the current task skipped; a combinator's outer loop
///     advances to its sibling tasks. Offered only by combinators (fork C).
///   - `Fail` — abort the node and propagate `BudgetExceeded` (partial
///     discarded, mirroring the `Fail` resolution contract).
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
pub enum EscalationAction {
    ContinueWithBudget { steps: u32 },
    Skip,
    Fail,
}

#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
pub enum HumanRequest {
    ToolApproval {
        calls: Vec<ToolCall>,
        risk_level: RiskLevel,
    },
    Clarification {
        question: String,
        /// Optional fixed-choice options offered to the human (issue #81, Q4b).
        /// `None` for a free-form clarification. `#[serde(default)]` keeps older
        /// `Clarification` blobs (no `options` field) deserializing.
        #[serde(default, skip_serializing_if = "Option::is_none")]
        options: Option<Vec<String>>,
    },
    Review {
        content: String,
    },
    /// A node's budget scope resolved to `Escalate` under
    /// [`EscalationMode::SurfaceToHuman`] (#130): the run pauses and surfaces the
    /// exhaustion to the operator. Carries the node's `phase`, its `policy`, the
    /// `steps_taken` / `continues_used` counters (so `resume_inner` can
    /// reconstruct the node's [`BudgetContext`] — fork E), any `partial_output`
    /// produced before exhaustion, and the ADVISORY `available_actions` the
    /// author offers (fork C/D). The operator answers with
    /// [`HumanResponse::Escalate`].
    BudgetExhausted {
        phase: String,
        policy: BudgetPolicy,
        steps_taken: u32,
        continues_used: u32,
        partial_output: Option<String>,
        available_actions: Vec<EscalationAction>,
    },
}

#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub enum RiskLevel {
    Low,
    Medium,
    High,
    Critical,
}

#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
pub enum HumanResponse {
    Allow,
    AllowWithModification {
        calls: Vec<ToolCall>,
    },
    Deny {
        reason: String,
    },
    Halt,
    Answer {
        text: String,
    },
    ApproveWithFeedback {
        feedback: String,
    },
    Reject {
        reason: String,
    },
    /// The operator's resolution of a [`HumanRequest::BudgetExhausted`] pause
    /// (#130): the chosen [`EscalationAction`]. Distinct from `Allow`/`Halt`/
    /// `Deny` so the budget-escalation resume path is unambiguous.
    Escalate {
        action: EscalationAction,
    },
}

// ============================================================================
// Mid-loop consult primitive (issue #114)
// ============================================================================
//
// PRIMARY CONSULT LOGIC. This is the doc-hub for the mid-loop consult feature
// (issue #114). The signal/route/resume machinery is tightly coupled to the
// ReAct loop and the subagent boundary, so the implementation is split between
// this module (`harness.rs`) — which owns the worker-side pause, the resume
// seam, and the config — and [`crate::tools::subagent`] — which owns the
// orchestrator-side deterministic mediation.
//
// ## Types (all defined here unless noted)
// - [`ConsultRequest`]            — the worker's free-form ask (kind/situation/
//                                   attempts/question). All fields REQUIRED, no
//                                   serde defaults.
// - [`ConsultResponse`]           — the resume input (parallel to
//                                   [`HumanResponse`]): `Answer` | `BudgetExhausted`.
// - [`ConsultOverflowPolicy`]     — per-kind budget-overflow behaviour:
//                                   `SoftFail` | `EscalateToHuman`.
// - [`ConsultHandlerEntry`]       — a handler harness + budget + overflow policy,
//                                   keyed by `kind` in
//                                   [`HarnessConfig::consult_handlers`].
// - [`ToolOutput::Consult`]       — ONE variant. Worker-side tools emit it with
//                                   `child_state: None`; `SubagentTool`
//                                   populates `Some(..)` at the boundary
//                                   (mirrors [`ToolOutput::WaitingForHuman`]).
// - [`RunResult::Consult`]        — sibling of [`RunResult::WaitingForHuman`];
//                                   its `state.human_request` is `None`.
//
// ## Trait / loop methods touched
// - [`StandardHarness::run_react`] dispatch loop — pauses on
//   `ToolOutput::Consult` (R1, R10), preserving the consult call as the head of
//   `pending_tool_calls` exactly like the `AwaitingClarification` arm.
// - [`Harness::resume_consult`] — NEW trait method (the resume seam, below).
//   `StandardHarness` implements it via [`StandardHarness::resume_consult_inner`],
//   mirroring the `resume_inner` clarification branch.
// - [`crate::tools::subagent::SubagentTool::execute`] — the mediation seam
//   (below).
//
// ## Mediation seam — A1 (DECIDED)
// `SubagentTool::execute` drives the FULL consult cycle internally. On a child
// `RunResult::Consult` it routes by `request.kind` to the matching
// [`ConsultHandlerEntry`], checks/decrements the per-kind budget, runs the
// handler harness, builds a [`ConsultResponse::Answer`], and calls
// `child.resume_consult(..)` to continue the worker loop — repeating until the
// child reaches a terminal result. The parent orchestrator's model NEVER sees
// that a consult happened. Depth-1 holds: the handler is the orchestrator's
// direct child, never the worker's. The handlers reach `SubagentTool` through a
// constructor argument (see `SubagentTool::with_consult_handlers`).
//
// ## Resume seam (DECIDED)
// `ConsultResponse` is a distinct type (parallel to [`HumanResponse`]) and the
// resume entry point is a dedicated [`Harness::resume_consult`] trait method
// (NOT an overload of `resume`, which is typed on `HumanResponse`). It mirrors
// the `resume_inner` clarification branch: it injects the response text as the
// `ToolOutput::Success` RESULT of the head pending (consult) tool call, then
// dispatches any remaining pending calls and resumes the ReAct loop. The
// consult is therefore appended to message history ONLY as a tool result, only
// on resume (R10) — never as a free-standing turn.
//
// ## Rules enforced (see issue #114 / fixtures/harness/consult.json)
// R1, R5b, R6 (empty-map standalone), R10 here; R2–R5a, R6 (no-kind), R7 in
// `subagent.rs`; R8/R9 by the fixture-replay + existing-fixture tests.
//
// No `// SPEC QUESTION:` markers — every ambiguity is resolved in the plan.

/// The worker's free-form ask when it pauses mid-loop to consult a
/// parent-spawned helper (issue #114). `kind` selects the handler;
/// `situation`, `attempts`, and `question` carry the free-form context the
/// handler needs. All fields are REQUIRED — there are deliberately no serde
/// defaults, so a malformed/partial request fails to deserialize rather than
/// silently defaulting.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
pub struct ConsultRequest {
    /// Routing key — selects the [`ConsultHandlerEntry`] in
    /// [`HarnessConfig::consult_handlers`].
    pub kind: String,
    /// Free-form description of where the worker is stuck.
    pub situation: String,
    /// How many times the worker has already tried (advisory; the harness
    /// enforces the per-kind budget independently).
    pub attempts: u32,
    /// The concrete question the worker wants answered.
    pub question: String,
}

/// The resume input handed back to a paused worker after a consult (issue
/// #114). Parallel to [`HumanResponse`]; tagged on `kind`, snake_case.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
pub enum ConsultResponse {
    /// The handler produced an answer; `text` is injected as the tool RESULT
    /// for the pending consult call.
    Answer { text: String },
    /// The per-kind budget is exhausted under a `SoftFail` overflow policy: the
    /// worker is resumed with this message and finishes with what it has.
    BudgetExhausted { message: String },
}

/// Per-kind budget-overflow behaviour (issue #114). Tagged on `kind`,
/// snake_case.
#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
pub enum ConsultOverflowPolicy {
    /// Resume the worker with [`ConsultResponse::BudgetExhausted`] so it
    /// finishes without further help.
    SoftFail,
    /// Convert the over-budget consult into [`RunResult::WaitingForHuman`] so
    /// the host decides.
    EscalateToHuman,
}

/// A registered consult handler: the helper harness to run, the per-kind
/// budget (max consults of this kind before overflow), and the overflow policy
/// (issue #114). Held by `kind` in [`HarnessConfig::consult_handlers`].
///
/// The `handler` is run by `SubagentTool` as the ORCHESTRATOR's direct child
/// (depth-1, R7), never nested under the worker.
#[derive(Clone)]
pub struct ConsultHandlerEntry {
    /// The helper harness run on the [`ConsultRequest`].
    pub handler: Arc<dyn Harness>,
    /// Max number of consults of this kind before the overflow policy applies.
    pub budget: u32,
    /// What to do once the budget is exhausted.
    pub overflow: ConsultOverflowPolicy,
}

impl std::fmt::Debug for ConsultHandlerEntry {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.debug_struct("ConsultHandlerEntry")
            .field("handler", &"<dyn Harness>")
            .field("budget", &self.budget)
            .field("overflow", &self.overflow)
            .finish()
    }
}

// ============================================================================
// PausedState / ChildPausedState
// ============================================================================

/// The durable snapshot of a paused leaf. Carries everything needed to resume:
/// the in-progress session, the pending tool calls, the human/consult request,
/// and — since #140 — the pausing leaf's [`toolset`](Self::toolset) handle, so
/// resume routes pending per-node tool calls back through that leaf's scoped
/// catalogue instead of the global-catalogue fallback.
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct PausedState {
    pub session_id: SessionId,
    pub task_id: TaskId,
    pub turn_number: u32,
    pub session_state: SessionState,
    pub pending_tool_calls: Vec<ToolCall>,
    pub approved_results: Vec<ToolResult>,
    /// `None` for an escalation-derived state (issue #80) — an escalation has
    /// no human request. `WaitingForHuman` construction paths always set
    /// `Some(..)`. `#[serde(default)]` keeps old `WaitingForHuman` blobs
    /// deserializing (field present) while escalation blobs omit it.
    #[serde(default)]
    pub human_request: Option<HumanRequest>,
    pub task: Task,
    pub budget_used: BudgetSnapshot,
    #[serde(default)]
    pub child_state: Option<ChildPausedState>,
    /// The toolset handle of the leaf that paused (#140). Resume routes pending
    /// per-node tool calls through this handle's scoped catalogue via
    /// [`effective_tool_registry`](StandardHarness::effective_tool_registry); an
    /// empty handle (the default) falls back to the global catalogue. `#[serde(default)]`
    /// keeps pre-#140 paused-state blobs (no `toolset` key) deserializing — they
    /// restore as `ToolsetRef("")`. The field ALWAYS serializes (even when empty,
    /// as `"toolset":""`) for cross-language byte-parity; never add
    /// `skip_serializing_if`.
    #[serde(default)]
    pub toolset: ToolsetRef,
}

impl PausedState {
    /// The SHARED durable checkpoint round-trip (#129, AC1). Both cross-process
    /// `Continue` (a `HumanRequest::BudgetExhausted` pause whose request carries
    /// `continues_used`) and Ralph's pause-propagation hand the SAME
    /// [`PausedState`] to the caller for persistence; this is the one seam they
    /// share. It is JUST the `PausedState` serialize/deserialize — NOT a
    /// unification of their CONTEXT policies (Q2): a `Continue` resumes preserving
    /// `session_state.messages`; Ralph re-seeds a fresh window from its
    /// filesystem `.spore/progress.json` checkpoint, which stays Ralph-specific
    /// ([`RalphProgress`]/[`ralph_seed_session`](StrategyExecutor::ralph_seed_session)).
    ///
    /// `serialize_checkpoint` produces the durable blob the caller persists;
    /// [`load_checkpoint`](Self::load_checkpoint) restores it on resume.
    pub fn serialize_checkpoint(&self) -> Result<String, serde_json::Error> {
        serde_json::to_string(self)
    }

    /// Restore a [`PausedState`] from a durable checkpoint blob (#129, AC1). The
    /// resume side of [`serialize_checkpoint`](Self::serialize_checkpoint).
    pub fn load_checkpoint(blob: &str) -> Result<Self, serde_json::Error> {
        serde_json::from_str(blob)
    }
}

/// Child paused state. **Deliberately has no `child_state` field** — the type
/// system enforces a one-level subagent depth (spec rule).
#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct ChildPausedState {
    pub session_id: SessionId,
    pub task_id: TaskId,
    pub turn_number: u32,
    pub session_state: SessionState,
    pub pending_tool_calls: Vec<ToolCall>,
    pub approved_results: Vec<ToolResult>,
    /// `None` for an escalation-derived state (issue #80). `WaitingForHuman`
    /// construction paths always set `Some(..)`.
    #[serde(default)]
    pub human_request: Option<HumanRequest>,
    pub task: Task,
    pub budget_used: BudgetSnapshot,
    pub parent_tool_call_id: String,
    /// The toolset handle of the child leaf that paused (#140); same semantics
    /// and serialization contract as [`PausedState::toolset`]. ALWAYS serializes
    /// (`"toolset":""` when empty); `#[serde(default)]` keeps pre-#140 child
    /// blobs deserializing.
    #[serde(default)]
    pub toolset: ToolsetRef,
}

// ============================================================================
// Halt reasons / RunResult
// ============================================================================

#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
#[non_exhaustive]
pub enum HaltReason {
    BudgetExceeded {
        limit_type: BudgetLimitType,
    },
    TerminationPolicyHalt {
        reason: String,
    },
    MiddlewareHalt {
        hook: HookPoint,
        reason: String,
    },
    AgentError {
        error: AgentError,
    },
    /// A [`ContextError`] surfaced by the [`crate::context::ContextManager`]
    /// during assembly halts the run (e.g. a cache-hash mismatch — both Block 1
    /// `Static` and, as of #32, Block 2 `PerSession` halt mid-session). This is
    /// the routing type; mirrors [`HaltReason::AgentError`]. The live
    /// [`StandardHarness`] loop does not yet trigger it because its placeholder
    /// `ContextManager::assemble` is infallible pending the #7 migration.
    ContextError {
        error: ContextError,
    },
    SandboxViolation {
        violation: SandboxViolation,
    },
    UnrecoverableToolError {
        tool: String,
        error: String,
    },
    HumanHalted,
    StagnationLimitReached {
        iterations: u32,
        best_metric: f64,
    },
    /// Returned by [`StandardHarness`] for [`LoopStrategy`] variants whose
    /// concrete trait dependencies (e.g. `CompletionCheck`, `Verifier`,
    /// `MetricEvaluator`) ship with later component issues. Marker only; will
    /// be removed once those issues land.
    StrategyNotYetImplemented {
        strategy: String,
    },
    /// Returned by [`StandardHarness`] for the `PlanExecute` strategy (issue
    /// #59) when the accepted plan parsed into an EMPTY task list (`tasks: []`).
    /// Per Q3, an empty plan is a failure — the run does NOT silently succeed.
    EmptyPlan,
    /// Returned by [`StandardHarness`] for the `PlanExecute` strategy (issue
    /// #59) when an execute step's bounded ReAct sub-loop errored or the agent
    /// returned a blocked/failed outcome (Q5). A plan is a dependency chain by
    /// assumption, so the whole run aborts at the failing step — execution does
    /// NOT continue to the next task. Carries the failing step's positional
    /// index, its instruction, and a human-readable reason derived from the
    /// underlying [`HaltReason`].
    StepFailed {
        task_index: usize,
        task: String,
        reason: String,
    },
    /// The PlanExecute plan phase (issue #70) failed before producing an
    /// artifact: the planner's response was unparseable, the planner requested
    /// a tool call in the one-shot turn, or the artifact could not be
    /// serialized for storage. Carries the underlying
    /// [`PlanPhaseError`](crate::plan::PlanPhaseError).
    PlanPhaseFailed {
        error: crate::plan::PlanPhaseError,
    },
    /// Returned by [`StandardHarness`] for the `SelfVerifying` strategy (issue
    /// #61, D4) when the build↔evaluate loop ran out of the verifier's
    /// `max_iterations` round-trips without an explicit `Passed` verdict. A
    /// RUNTIME limit — the work was attempted in good faith but never verified;
    /// a caller might retry with a different task decomposition. Carries the
    /// number of round-trips run and the last failure reason the verifier gave.
    /// PEER to [`SelfVerifyMisconfigured`](Self::SelfVerifyMisconfigured) (NOT a
    /// sub-case of it).
    SelfVerifyExhausted {
        iterations: u32,
        last_reason: String,
    },
    /// Returned by [`StandardHarness`] for the `SelfVerifying` strategy (issue
    /// #61, D4) when the strategy cannot run because it is misconfigured — e.g.
    /// `config.verifier` is `None`. Likely a BUILD-TIME bug in the caller's
    /// wiring. Surfaced as a typed halt, NOT a panic. PEER to
    /// [`SelfVerifyExhausted`](Self::SelfVerifyExhausted) (NOT a sub-case of it).
    SelfVerifyMisconfigured {
        reason: String,
    },
    /// Returned by [`StandardHarness`] for the `Ralph` strategy (issue #58, B3)
    /// when the multi-context-window continuation loop reached its `max_resets`
    /// cap with tasks still incomplete (the Ralph analogue of
    /// [`SelfVerifyExhausted`](Self::SelfVerifyExhausted)). A RUNTIME limit — the
    /// work was attempted across `iterations` context windows but the
    /// filesystem-backed completion check (the registered `Stop` hook reading
    /// `.spore/progress.json`) never reported done. Carries the number of
    /// context-window resets performed and the last incompletion reason.
    RalphCompletionUnmet {
        iterations: u32,
        last_reason: String,
    },
    /// Returned by [`StandardHarness`] for the `HillClimbing` strategy (issue
    /// #60) when the strategy cannot run because it is misconfigured — i.e.
    /// `config.metric_evaluator` is `None`. Likely a BUILD-TIME bug in the
    /// caller's wiring. Surfaced as a typed halt, NOT a panic. PEER to
    /// [`SelfVerifyMisconfigured`](Self::SelfVerifyMisconfigured).
    HillClimbingMisconfigured {
        reason: String,
    },
    /// Returned by [`StandardHarness`] when [`ExecutionRegistry::validate`](crate::ExecutionRegistry::validate)
    /// fails at run entry: a handle referenced by the task's strategy tree is
    /// unresolved against the configured registry, or a `StrategyRef::Custom`
    /// key is missing. A STARTUP error surfaced before the first turn (issue
    /// #120). Carries the underlying [`HarnessError`].
    ConfigurationError {
        error: HarnessError,
    },
    /// Returned by the PlanExecute DAG executor (#126, decision A) for a PARTIAL
    /// run: a task failed terminally (unrecoverable error or `BudgetExhausted`
    /// resolving to `Fail`) and its transitive dependents were cascade-`Blocked`,
    /// while unrelated branches still completed. The run as a whole is a
    /// `Failure`, but the full partition is reported: which tasks `completed`,
    /// which were `blocked` by the cascade, the `failed_task` that triggered it,
    /// and the human-readable `reason`. (A run where EVERY task completes is a
    /// `Success`, as before.)
    TasksBlockedByFailure {
        completed: Vec<u32>,
        blocked: Vec<u32>,
        failed_task: u32,
        reason: String,
    },
    /// Returned by the PlanExecute DAG executor (#126) when the persisted task
    /// graph contains a directed cycle, re-checked at EXECUTE ENTRY as
    /// defense-in-depth (`add_task` already rejects cycles, but the `task_list`
    /// tool path could in principle persist a cyclic graph out of band). No task
    /// is run. Carries a human-readable description.
    TaskGraphCycle {
        reason: String,
    },
    /// Returned by [`StandardHarness`] (issue #137) when the ReAct turn loop's
    /// consecutive-recoverable-tool-error breaker tripped: a tool returned
    /// `2 * error_loop_threshold` consecutive recoverable
    /// [`ToolOutput::Error`]s with identical arguments, so the loop STOPPED
    /// grinding and resolved the node's [`BudgetExhaustedBehavior`] WITHOUT
    /// burning the remaining budget. This is DISTINCT from
    /// [`BudgetExceeded`](Self::BudgetExceeded) (genuine budget exhaustion): the
    /// loop halted early on a detected error loop, not because the step budget
    /// ran out. Carries the offending tool name and the consecutive-error count
    /// at the moment of the hard stop (`2 * N`).
    ToolErrorLoop {
        tool: String,
        consecutive_errors: u32,
    },
    /// Returned by [`StandardHarness`] (issue #139) when output-schema
    /// enforcement is ON (`HarnessConfig::enforce_output_schemas`) for a
    /// `ReactConfig` leaf carrying `output = Some(..)`, and the leaf's terminal
    /// `FinalResponse` STILL failed validation after the configured
    /// `output_schema_max_retries` extra turns were exhausted WITH budget
    /// remaining. DISTINCT from [`BudgetExceeded`](Self::BudgetExceeded): a
    /// budget/turn cap that a retry would exceed surfaces the budget terminal
    /// instead (budget-cap-wins precedence) — `OutputSchemaViolation` fires ONLY
    /// on a genuine validation exhaustion. Carries the resolved `schema` (the
    /// canonical compact key-sorted JSON), the total number of `attempts`
    /// (`1 + max_retries`), and the `last_error` (the frozen validator error
    /// string from the final attempt).
    OutputSchemaViolation {
        schema: String,
        attempts: u32,
        last_error: String,
    },
}

#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
#[serde(tag = "kind", rename_all = "snake_case")]
pub enum RunResult {
    Success {
        output: String,
        session_id: SessionId,
        usage: AggregateUsage,
        turns: u32,
        /// The post-run conversation history (issue #102). Carries the full
        /// `SessionState.messages` the loop produced — assistant tool-call turns
        /// and tool-result turns included — so an in-process caller can resume
        /// losslessly via `HarnessRunOptions::with_session_state(..)` without
        /// reconstructing history from `output`. `#[serde(default)]` keeps old
        /// serialized blobs (and other languages mid-migration) deserializing.
        #[serde(default)]
        session_state: SessionState,
    },
    Failure {
        reason: HaltReason,
        session_id: SessionId,
        usage: AggregateUsage,
        turns: u32,
        /// The post-run conversation history at the point of failure (issue
        /// #102). Same contract as on [`Success`](Self::Success): lossless
        /// resume, `#[serde(default)]` for back-compat.
        #[serde(default)]
        session_state: SessionState,
    },
    /// Boxed because `PausedState` is significantly larger than the other
    /// variants; keeps `RunResult` cheap to clone on the happy path.
    WaitingForHuman {
        state: Box<PausedState>,
        request: HumanRequest,
    },
    /// Harness terminated cleanly due to a tool escalation signal (issue #80).
    /// The caller handles the `signal` and decides whether to resume the
    /// original harness, instantiate a new one, or present UI to the user. The
    /// `state` preserves the full [`PausedState`] (with `human_request: None`)
    /// so `harness.resume(state, ..)` continues the original session; the
    /// signal is NOT stored in the state, so it is naturally discarded on
    /// resume — the harness does not re-act on it.
    Escalate {
        signal: HarnessSignal,
        state: Box<PausedState>,
        session_id: SessionId,
        usage: AggregateUsage,
        turns: u32,
    },
    /// Worker paused mid-loop to consult a parent-spawned helper (issue #114).
    /// Sibling of [`WaitingForHuman`](Self::WaitingForHuman), but it stops at
    /// the ORCHESTRATOR (via `SubagentTool`'s A1 mediation), not the human. The
    /// `state` preserves the full [`PausedState`] with `human_request: None`
    /// and the consult call as the head of `pending_tool_calls`, so
    /// `harness.resume_consult(state, response, ..)` continues the worker. With
    /// no consult handlers registered, a standalone worker simply returns this
    /// unchanged to its caller (R6 graceful degradation).
    Consult {
        request: ConsultRequest,
        state: Box<PausedState>,
        session_id: SessionId,
        usage: AggregateUsage,
        turns: u32,
    },
}

/// Result of a successful PlanExecute plan phase (issue #70). Carries the
/// produced artifact plus the run accounting so the caller can build the terminal
/// `RunResult`. Surfaced on the [`StrategyExecutor::capture_plan_artifact`]
/// primitive (#124); the artifact is also persisted under
/// `PLAN_EXECUTE_EXTRAS_KEY` on the RunStore.
#[derive(Debug)]
pub struct PlanPhaseOutcome {
    pub artifact: crate::plan::PlanArtifact,
    pub usage: AggregateUsage,
    pub turns: u32,
}

// ============================================================================
// Ralph loop strategy support types (issue #58)
// ============================================================================

/// Deserialized `.spore/progress.json` for the Ralph loop strategy (issue #58,
/// B1/B2). The handoff artifact between context windows: `complete` is the
/// primary completion signal, `remaining` lists outstanding work so an
/// incompletion reason can name what is left. Tolerant by default (`#[serde]`
/// defaults) so a partially-written file deserializes to "incomplete" rather
/// than erroring.
#[derive(Debug, Clone, Default, Serialize, Deserialize)]
struct RalphProgress {
    #[serde(default)]
    complete: bool,
    #[serde(default)]
    remaining: Vec<String>,
}

/// One `.spore/feature_list.json` entry, mirroring
/// [`FeatureListCheck`](crate::termination::FeatureListCheck)'s schema so the
/// two sources agree (issue #58, B2).
#[derive(Debug, Clone, Deserialize)]
struct RalphFeatureEntry {
    name: String,
    passes: bool,
}

/// The `Stop` lifecycle hook (issue #69) the Ralph loop strategy registers at
/// construction (issue #58, B1). Drives multi-context-window continuation off
/// `.spore/progress.json`: while tasks remain incomplete it returns
/// [`HookDecision::Block`](crate::hooks::HookDecision::Block) (the reason
/// describes what is left) so the harness loops into a new context window; when
/// complete it returns [`Continue`](crate::hooks::HookDecision::Continue) so the
/// loop terminates with success.
///
/// Registration is harmless for non-Ralph strategies: when `.spore/progress.json`
/// is ABSENT the hook returns `Continue` and does not interfere with ReAct /
/// PlanExecute / SelfVerifying runs. It only blocks when a progress file is
/// PRESENT and reports incomplete tasks — the Ralph contract.
struct RalphStopHook {
    /// #142: the Ralph checkpoint moved off `.spore/` onto the durable project-id
    /// [`RunStore`](crate::storage::RunStore). The hook reads the checkpoint from
    /// the store under the stable [`ProjectId`](crate::storage::ProjectId).
    run_store: Arc<dyn crate::storage::RunStore>,
    project_id: crate::storage::ProjectId,
}

impl crate::hooks::Hook for RalphStopHook {
    fn handle<'a>(
        &'a self,
        ctx: &'a mut crate::hooks::HookContext<'a>,
    ) -> BoxFut<'a, Result<crate::hooks::HookDecision, crate::hooks::HookError>> {
        Box::pin(async move {
            // Only act on `Stop`; any other event is a no-op `Continue`.
            if !matches!(ctx, crate::hooks::HookContext::Stop { .. }) {
                return Ok(crate::hooks::HookDecision::Continue);
            }
            // Absent checkpoint ⇒ do not interfere with non-Ralph runs. The
            // checkpoint now lives in the project-id RunStore (#142); when the
            // progress key is UNSET this is not a Ralph run, so `Continue`.
            let present = matches!(
                self.run_store
                    .get(
                        &self.project_id.namespace(),
                        crate::storage::RALPH_PROGRESS_KEY,
                    )
                    .await,
                Ok(Some(_))
            );
            if !present {
                return Ok(crate::hooks::HookDecision::Continue);
            }
            match StandardHarness::ralph_completion_status(&self.run_store, &self.project_id).await
            {
                None => Ok(crate::hooks::HookDecision::Continue),
                Some(reason) => Ok(crate::hooks::HookDecision::Block { reason }),
            }
        })
    }
    fn events(&self) -> Vec<crate::hooks::HookEvent> {
        vec![crate::hooks::HookEvent::Stop]
    }
    fn name(&self) -> String {
        "ralph-stop".into()
    }
}

#[derive(Debug, Clone, Error, PartialEq, Eq, Serialize, Deserialize)]
#[serde(tag = "kind")]
#[non_exhaustive]
pub enum HarnessError {
    #[error("invalid configuration: {0}")]
    InvalidConfiguration(String),
    /// A `StrategyRef::Custom(key)` referenced a custom strategy that is not
    /// registered in [`ExecutionRegistry::custom`](crate::ExecutionRegistry).
    /// RECOVERABLE — returned, never panics (same pattern as a missing
    /// `AgentRef`). Issue #120.
    #[error("custom strategy not found: {key}")]
    StrategyNotFound { key: String },
    /// A serializable handle (`AgentRef`/`ToolsetRef`/`SchemaRef`) referenced an
    /// entry absent from the [`ExecutionRegistry`](crate::ExecutionRegistry).
    /// The STARTUP-validation error: surfaced before the first turn. Issue #120.
    ///
    /// The handle category is the Rust field `kind`, but it serializes as
    /// `handle_kind` to avoid colliding with the enum's `#[serde(tag = "kind")]`
    /// discriminant.
    #[error("unresolved {kind} handle: {key}")]
    UnresolvedHandle {
        #[serde(rename = "handle_kind")]
        kind: String,
        key: String,
    },
}

// ============================================================================
// HarnessRunOptions
// ============================================================================

pub struct HarnessRunOptions {
    pub task: Task,
    pub on_stream: Option<StreamSink>,
    /// Optional starting session state (e.g. resumed conversation history).
    pub session_state: Option<SessionState>,
}

impl HarnessRunOptions {
    pub fn new(task: Task) -> Self {
        Self {
            task,
            on_stream: None,
            session_state: None,
        }
    }

    /// Carry an existing session state into the run (e.g. a resumed
    /// conversation history for multi-turn scenarios — issue #57 S2).
    pub fn with_session_state(mut self, session_state: SessionState) -> Self {
        self.session_state = Some(session_state);
        self
    }

    /// Attach a streaming sink for `StreamEvent`s emitted during the run.
    ///
    /// Generic over `impl Fn` so callers can pass a bare closure, an existing
    /// `Box<dyn Fn>` (which itself implements `Fn` — back-compat for pre-`Arc`
    /// callers), or an `Arc<dyn Fn>`; it is wrapped once into the shared
    /// [`StreamSink`].
    pub fn with_stream<F>(mut self, on_stream: F) -> Self
    where
        F: Fn(StreamEvent) + Send + Sync + 'static,
    {
        self.on_stream = Some(Arc::new(on_stream));
        self
    }
}

// ============================================================================
// The trait
// ============================================================================

pub trait Harness: Send + Sync {
    fn run<'a>(&'a self, options: HarnessRunOptions) -> BoxFut<'a, RunResult>;

    fn resume<'a>(
        &'a self,
        state: PausedState,
        response: HumanResponse,
        on_stream: Option<StreamSink>,
    ) -> BoxFut<'a, RunResult>;

    /// Resume a worker paused by [`RunResult::Consult`] (issue #114). The
    /// resume seam parallel to [`resume`](Self::resume): it injects the
    /// [`ConsultResponse`] as the tool RESULT of the head pending consult call,
    /// dispatches any remaining pending calls, and resumes the loop. A default
    /// impl is provided so callers that never use consults need not implement
    /// it; [`StandardHarness`] overrides it with the real behaviour.
    fn resume_consult<'a>(
        &'a self,
        state: PausedState,
        response: ConsultResponse,
        on_stream: Option<StreamSink>,
    ) -> BoxFut<'a, RunResult> {
        let _ = (response, on_stream);
        Box::pin(async move {
            RunResult::Failure {
                reason: HaltReason::HumanHalted,
                session_id: state.session_id,
                usage: AggregateUsage::default(),
                turns: state.turn_number,
                session_state: state.session_state,
            }
        })
    }
}

// ============================================================================
// StandardHarness — the canonical implementation
// ============================================================================

/// Components injected at construction. Mirrors `HarnessConfig` in the spec.
/// Components not yet covered by their own issue are optional here so the
/// harness can be exercised before #4–#13 land.
///
/// Every component, including the agent, is held erased behind `Arc<dyn _>`.
/// The `Agent` trait (issue #2) is dyn-compatible via the hand-rolled `BoxFut`
/// pattern, so no type parameter is needed (issue #45).
pub struct HarnessConfig {
    pub tool_registry: Arc<dyn ToolRegistry>,
    pub sandbox: Arc<dyn SandboxProvider>,
    /// How a [`SandboxViolation`] surfaced by a tool (or the pre-dispatch
    /// `validate` check) is handled: fed back to the model as a recoverable
    /// error (the default) or halted on. See [`SandboxViolationPolicy`].
    pub sandbox_violation_policy: SandboxViolationPolicy,
    pub context_manager: Arc<dyn ContextManager>,
    pub termination_policy: Arc<dyn TerminationPolicy>,
    pub middleware: Option<Arc<dyn MiddlewareChain>>,
    pub observability: Option<Arc<dyn ObservabilityProvider>>,
    /// Post-compaction verifier (issue #29/#46). The harness runs it after
    /// each compaction turn and retries up to `max_compaction_attempts` before
    /// accepting a failing summary. Defaults to [`KeyTermVerifier`].
    pub compaction_verifier: Arc<dyn CompactionVerifier>,
    /// Maximum compaction-summary attempts before accepting a failing summary
    /// anyway (issue #46). Defaults to `2` (mirrors `CompactionConfig`).
    pub max_compaction_attempts: u32,
    /// Token → USD pricing used to stamp `cost_usd` on emitted [`TurnSpan`]s.
    /// Defaults to [`PricingTable::DEFAULT`] (zero cost) when unset.
    pub pricing: PricingTable,
    /// LLM-native content capture guard + truncation limit (issue #64).
    /// Defaults to [`ContentCaptureConfig::default`] (OFF). When disabled the
    /// harness populates no `gen_ai.*` content and the JSONL stays
    /// byte-identical to the pre-#64 metrics-only output.
    pub content_capture: ContentCaptureConfig,
    /// Optional deterministic tool-call repair provider. When set, recoverable
    /// tool-dispatch errors trigger an argument-coercion + re-dispatch attempt
    /// before falling back to error feedback. `None` (the default) preserves
    /// today's behaviour byte-for-byte.
    pub tool_call_repair: Option<Arc<dyn ToolCallRepair>>,
    /// Maximum number of repair-and-re-dispatch attempts per tool call.
    /// Defaults to `1`. Ignored when `tool_call_repair` is `None`.
    pub max_repair_attempts: u32,
    /// Maximum number of consecutive Stop-hook blocks within a single `run()`
    /// before the loop terminates anyway (issue #69, Decision 4/5). The
    /// counter is PER-RUN — it resets on every `run()` call, so a resumed
    /// session starts fresh. Defaults to `8` (matching Claude Code).
    pub max_stop_blocks: u32,
    /// Consecutive-recoverable-tool-error breaker threshold `N` (issue #137).
    /// The ReAct turn loop tracks, per tool name, the current run of
    /// consecutive recoverable [`ToolOutput::Error`] results keyed on identical
    /// arguments (any SUCCESS for that tool resets the run). At `N` identical
    /// failures it injects ONE corrective message (the [`enrich_tool_error`]
    /// schema+hint, as a USER-role message); at exactly `2 * N` it STOPS
    /// looping and resolves the node's [`BudgetExhaustedBehavior`] via the
    /// single budget-exhaustion resolution site — WITHOUT burning the remaining
    /// budget — terminating with [`HaltReason::ToolErrorLoop`] (never
    /// [`HaltReason::BudgetExceeded`]). The `2×` hard-stop multiplier is FIXED,
    /// not an independent field. Defaults to `3`.
    pub error_loop_threshold: u32,
    /// MIGRATION GATE (issue #139) — NOT a permanent feature flag. When `true`,
    /// a [`ReactConfig`] leaf carrying `output = Some(..)` has its resolved
    /// output schema DELIVERED to the model (directive seed + the
    /// [`ModelParams::output_schema`] constrained-decoding channel) and its
    /// terminal `FinalResponse` VALIDATED against that schema; a validation
    /// failure feeds the error back and retries up to
    /// [`output_schema_max_retries`](Self::output_schema_max_retries) extra turns
    /// (within budget), then terminates with
    /// [`HaltReason::OutputSchemaViolation`]. Enforcement is UNIFORM — it applies
    /// to structured-slot leaves (plan / worker / propose) too, and is additive
    /// to and earlier than any downstream combinator validation.
    ///
    /// Default `false` (OFF) is NON-NEGOTIABLE: it keeps every existing replay
    /// fixture byte-for-byte green during migration. When OFF, `ReactConfig::run`
    /// behaves EXACTLY as before — no resolve, no delivery, no validation.
    pub enforce_output_schemas: bool,
    /// The `N` extra terminal-validation retry turns granted when
    /// [`enforce_output_schemas`](Self::enforce_output_schemas) is ON and a
    /// terminal fails output-schema validation (issue #139). Total attempts =
    /// `1 + N`. Retried turns COUNT against the turn budget; a retry that would
    /// exceed the budget surfaces the budget terminal instead of
    /// [`HaltReason::OutputSchemaViolation`] (budget-cap-wins precedence).
    /// Defaults to `2` (mirrors [`error_loop_threshold`](Self::error_loop_threshold)'s
    /// builder default-handling idiom).
    pub output_schema_max_retries: u32,
    /// Lifecycle hook chain (issue #69). When set, the harness fires the wired
    /// lifecycle events (`PreTurn`, `Stop`, `OnError`, …) through it.
    /// `None` (the default) preserves today's behaviour byte-for-byte.
    pub hooks: Option<Arc<dyn crate::hooks::HookChain>>,
    /// Pluggable per-domain persistence layer (issue #73). Defaults to an
    /// all-no-op [`StorageProvider`] so existing callers/tests compile and
    /// behave unchanged. v1 is expose-only — the run/resume loop is NOT
    /// modified to read/write sessions internally.
    pub storage: Arc<crate::storage::StorageProvider>,
    /// The STABLE project namespace for DURABLE artifacts (issue #142). Where
    /// the per-window [`SessionId`] is regenerated on every Ralph context-window
    /// reset (`SessionId::generate()`), this [`ProjectId`](crate::storage::ProjectId)
    /// stays constant across windows AND process restarts — which is what lets
    /// the `task_list`, plan artifact, and Ralph checkpoint persist across a
    /// window reset instead of being orphaned under a regenerated session.
    /// Defaults (at build) to a project id derived from
    /// `sandbox.workspace_root()` (decision 5 — NOT process cwd). Durable
    /// `RunStore` call sites key by `project_id.namespace()` (namespace-reuse on
    /// the existing `&SessionId` axis); ephemeral session/conversation state
    /// stays keyed by the per-window `SessionId`.
    pub project_id: crate::storage::ProjectId,
    /// Source of conditional prompt chunks (issue #79). Defaults to an empty
    /// [`InMemoryChunkProvider`](crate::prompt_assembly::InMemoryChunkProvider).
    /// The harness loads chunks from it at construction and feeds them through
    /// a [`ContextSourcesBuilder`](crate::prompt_assembly::ContextSourcesBuilder).
    pub chunk_provider: Arc<dyn crate::prompt_assembly::ChunkProvider>,
    /// Outer-loop cap for the `Ralph` loop strategy (issue #58, B3): the maximum
    /// number of context-window RESETS the continuation loop performs before
    /// halting with [`HaltReason::RalphCompletionUnmet`] when tasks are still
    /// incomplete. Independent from `max_turns` (the per-context-window ReAct
    /// turn budget) and from `max_stop_blocks` (the per-sub-loop Stop-block cap).
    /// Defaults to `3` (matching the `SelfVerifying` verifier `max_iterations`
    /// precedent). Irrelevant for every other loop strategy.
    pub max_resets: u32,
    /// Optional VCS read seam for the `Ralph` loop strategy (issue #58 v2). When
    /// `Some`, Ralph's per-window reload phase ALSO calls
    /// [`VcsProvider::log`] and injects the output into the fresh context window
    /// as a delimited "Recent VCS history:" section — alongside the reloaded
    /// `.spore/progress.json` + `.spore/feature_list.json` content. When `None`
    /// (the default) the git-log section is OMITTED and Ralph behaves
    /// byte-for-byte like v1 (the B4→None decision). Irrelevant for every other
    /// loop strategy.
    pub vcs_provider: Option<Arc<dyn VcsProvider>>,
    /// Catalogue tools accumulated via [`HarnessBuilder::tool`] / `tools`
    /// (issue #81), drained into a populated
    /// [`StandardToolRegistry`](crate::tool_registry::StandardToolRegistry) at
    /// [`build`](HarnessBuilder::build). When `Some`, the run loop bridges it
    /// per-run via [`RealToolRegistry`](crate::tool_registry::RealToolRegistry)
    /// — threading the run's `SessionId`, sandbox, and storage into every tool
    /// dispatch — and uses that instead of [`tool_registry`](Self::tool_registry)
    /// (which stays the harness-loop seam for custom slim registries). `None`
    /// (the default) preserves the `tool_registry`-only path byte-for-byte.
    pub catalogue_registry: Option<Arc<crate::tool_registry::StandardToolRegistry>>,
    /// Per-toolset catalogues (Issue 2: per-node toolset scoping), keyed by the
    /// non-empty `ToolsetRef` handle a leaf carries. Populated by
    /// [`HarnessBuilder::toolset_tools`] — each value is a populated
    /// [`StandardToolRegistry`](crate::tool_registry::StandardToolRegistry)
    /// folded from that key's catalogue tools. At dispatch the run loop bridges
    /// the matching catalogue per-run via
    /// [`RealToolRegistry`](crate::tool_registry::RealToolRegistry) (same
    /// sandbox/session/storage wiring as the global
    /// [`catalogue_registry`](Self::catalogue_registry)), so a node with a
    /// non-empty `toolset` handle dispatches ONLY its own tools. A leaf with an
    /// EMPTY handle (`""`) — or a non-empty handle with no entry here — falls
    /// back to the global catalogue / `tool_registry` seam (back-compat with
    /// examples 01–11 that use `.tools()`). Empty (the default) preserves
    /// today's behaviour byte-for-byte.
    pub toolset_catalogues:
        std::collections::HashMap<String, Arc<crate::tool_registry::StandardToolRegistry>>,
    /// Operating system prompt prepended to each turn's assembled context when
    /// the context manager renders none (issue #91). See
    /// [`HarnessBuilder::system_prompt`]. `None` (the default) preserves
    /// today's behaviour byte-for-byte.
    pub system_prompt: Option<String>,
    /// Authoritative per-run model sampling/decoding parameters (issue #93).
    /// The harness replaces each turn's `Context.params` with this value
    /// UNCONDITIONALLY (builder params win) right before the request is built,
    /// so the configured params reach every agent turn that requests tools.
    /// See [`HarnessBuilder::model_params`]. Defaults to
    /// [`ModelParams::default`].
    pub model_params: ModelParams,
    /// Opt-in automatic conversation-history threading via the
    /// [`SessionStore`](crate::storage::SessionStore) (issue #102). When `true`,
    /// the harness:
    /// - **auto-loads** the prior [`SessionState`] for the run's `session_id`
    ///   from the store at the start of a fresh `run()` (ReAct / SelfVerifying
    ///   strategies ONLY — Ralph/HillClimbing discard incoming state by design),
    ///   so a caller can resume by reusing the same `session_id` instead of
    ///   threading messages by hand. An explicit
    ///   [`with_session_state`](HarnessRunOptions::with_session_state) always
    ///   wins (the load is skipped).
    /// - **auto-persists** the post-run [`SessionState`] back to the store at the
    ///   terminal seam (one write per `run()`/`resume()` — Success/Failure
    ///   synthesize a [`PausedState`] with empty pending fields, while
    ///   `WaitingForHuman`/`Escalate` persist their carried `PausedState`).
    ///
    /// Storage errors are swallowed-and-logged (load failure ⇒ start fresh;
    /// persist failure ⇒ continue) — never surfaced as a [`HaltReason`].
    ///
    /// `false` (the default) preserves today's behaviour byte-for-byte: ZERO
    /// `get_session`/`put_session` calls and identical message flow.
    pub auto_persist_sessions: bool,
    /// Session-scoped prompt-based-tool-calling escalation flag, shared with the
    /// [`AdaptiveToolCallModelInterface`](crate::prompt_tool_call::AdaptiveToolCallModelInterface)
    /// installed by [`HarnessBuilder::conversational`]. `Some` only on that path.
    /// The run loop resets it at the start of each turn-loop window and flips it
    /// to `true` on detecting a prose response where a tool call was expected;
    /// the wrapped model reads it to switch into prompt-based mode. `None`
    /// disables adaptive escalation (every non-`conversational` construction).
    pub prompt_tool_call_flag: Option<Arc<std::sync::atomic::AtomicBool>>,
    /// Per-kind consult handlers (issue #114), keyed by `ConsultRequest.kind`.
    /// Empty (the default) means consults are NOT mediated: a worker that pauses
    /// with [`RunResult::Consult`] surfaces it unchanged to its caller (R6
    /// graceful degradation), and existing callers are unaffected byte-for-byte
    /// (R9). When populated, the matching entry's helper harness is run
    /// deterministically by `SubagentTool` (the A1 mediation seam) — the
    /// orchestrator model is never involved.
    pub consult_handlers: std::collections::HashMap<String, ConsultHandlerEntry>,
    /// Runtime resolver for the serializable strategy handles
    /// (`AgentRef`/`ToolsetRef`/`SchemaRef`) and `StrategyRef::Custom` keys held
    /// by a task's `LoopStrategy` tree (issue #120). [`StandardHarness::run`]
    /// calls [`ExecutionRegistry::validate`] at entry, so an unresolved handle is
    /// a startup error before the first turn. This slice is ADDITIVE (Option B):
    /// the registry coexists with the deprecated single-collaborator fields and
    /// is not yet read by the run bodies (that lands in #123/#124). Defaults to
    /// an empty registry.
    pub registry: ExecutionRegistry,
    /// HITL-vs-AFK escalation knob (issue #120, PRD goal #7): whether budget
    /// escalation surfaces to a human or proceeds autonomously. STORED only this
    /// slice — consumed in #130. Builder defaults to
    /// [`EscalationMode::SurfaceToHuman`].
    pub escalation_mode: EscalationMode,
}

impl Clone for HarnessConfig {
    fn clone(&self) -> Self {
        Self {
            tool_registry: self.tool_registry.clone(),
            sandbox: self.sandbox.clone(),
            sandbox_violation_policy: self.sandbox_violation_policy,
            context_manager: self.context_manager.clone(),
            termination_policy: self.termination_policy.clone(),
            middleware: self.middleware.clone(),
            observability: self.observability.clone(),
            compaction_verifier: self.compaction_verifier.clone(),
            max_compaction_attempts: self.max_compaction_attempts,
            pricing: self.pricing.clone(),
            content_capture: self.content_capture,
            tool_call_repair: self.tool_call_repair.clone(),
            max_repair_attempts: self.max_repair_attempts,
            max_stop_blocks: self.max_stop_blocks,
            error_loop_threshold: self.error_loop_threshold,
            enforce_output_schemas: self.enforce_output_schemas,
            output_schema_max_retries: self.output_schema_max_retries,
            hooks: self.hooks.clone(),
            storage: self.storage.clone(),
            project_id: self.project_id.clone(),
            chunk_provider: self.chunk_provider.clone(),
            max_resets: self.max_resets,
            vcs_provider: self.vcs_provider.clone(),
            catalogue_registry: self.catalogue_registry.clone(),
            toolset_catalogues: self.toolset_catalogues.clone(),
            system_prompt: self.system_prompt.clone(),
            model_params: self.model_params.clone(),
            auto_persist_sessions: self.auto_persist_sessions,
            prompt_tool_call_flag: self.prompt_tool_call_flag.clone(),
            consult_handlers: self.consult_handlers.clone(),
            registry: self.registry.clone(),
            escalation_mode: self.escalation_mode,
        }
    }
}

/// Fluent assembler for a [`HarnessConfig`] / [`StandardHarness`].
///
/// The harness follows strict inversion of control: every component is
/// injected. `HarnessBuilder` is the canonical assembly point — it takes the
/// required components up front and exposes fluent setters for the optional
/// ones (middleware, observability, pricing). It is the intended caller that
/// wires the [`ObservabilityProvider`] into the loop, including the durable
/// outbox via [`with_observability_outbox`](Self::with_observability_outbox).
///
/// ```no_run
/// # use std::sync::Arc;
/// # use spore_core::{HarnessBuilder, PricingTable};
/// # fn demo(
/// #     agent: Arc<dyn spore_core::Agent>,
/// #     tools: Arc<dyn spore_core::HarnessToolRegistry>,
/// #     sandbox: Arc<dyn spore_core::SandboxProvider>,
/// #     ctx: Arc<dyn spore_core::HarnessContextManager>,
/// #     term: Arc<dyn spore_core::TerminationPolicy>,
/// # ) {
/// let harness = HarnessBuilder::new(agent, tools, sandbox, ctx, term)
///     .with_observability_outbox(".spore")
///     .pricing(PricingTable::DEFAULT)
///     .build();
/// # }
/// ```
pub struct HarnessBuilder {
    agent: Arc<dyn Agent>,
    tool_registry: Arc<dyn ToolRegistry>,
    sandbox: Arc<dyn SandboxProvider>,
    sandbox_violation_policy: SandboxViolationPolicy,
    context_manager: Arc<dyn ContextManager>,
    termination_policy: Arc<dyn TerminationPolicy>,
    middleware: Option<Arc<dyn MiddlewareChain>>,
    observability: Option<Arc<dyn ObservabilityProvider>>,
    compaction_verifier: Arc<dyn CompactionVerifier>,
    max_compaction_attempts: u32,
    pricing: PricingTable,
    content_capture: ContentCaptureConfig,
    tool_call_repair: Option<Arc<dyn ToolCallRepair>>,
    max_repair_attempts: u32,
    max_stop_blocks: u32,
    /// Consecutive-recoverable-tool-error breaker threshold `N` (issue #137).
    /// Defaults to `3`. See [`HarnessConfig::error_loop_threshold`].
    error_loop_threshold: u32,
    /// MIGRATION GATE (issue #139): deliver + enforce `ReactConfig.output`
    /// schemas. Defaults to `false` (OFF). See
    /// [`HarnessConfig::enforce_output_schemas`].
    enforce_output_schemas: bool,
    /// Extra output-schema validation retry turns `N` (issue #139). Defaults to
    /// `2`. See [`HarnessConfig::output_schema_max_retries`].
    output_schema_max_retries: u32,
    hooks: Option<Arc<dyn crate::hooks::HookChain>>,
    /// #124: the default SelfVerifying verifier, folded into the registry under
    /// the empty key at build (no longer a live `HarnessConfig` field).
    verifier: Option<Arc<dyn crate::verifier::Verifier>>,
    storage: Option<Arc<crate::storage::StorageProvider>>,
    /// The STABLE durable-storage project namespace (issue #142). `None` (the
    /// default) resolves at [`build_config`](HarnessBuilder::build_config) to a
    /// [`ProjectId`](crate::storage::ProjectId) derived from
    /// `sandbox.workspace_root()` (decision 5 — NOT process cwd), canonicalizing
    /// the path first; an explicit [`project_id`](HarnessBuilder::project_id)
    /// always wins. See [`HarnessConfig::project_id`].
    project_id: Option<crate::storage::ProjectId>,
    /// Conditional prompt-chunk source (issue #79). `None` resolves to an empty
    /// [`InMemoryChunkProvider`](crate::prompt_assembly::InMemoryChunkProvider)
    /// at build time.
    chunk_provider: Option<Arc<dyn crate::prompt_assembly::ChunkProvider>>,
    /// Outer-loop reset cap for the `Ralph` loop strategy (issue #58, B3).
    /// Defaults to `3`.
    max_resets: u32,
    /// Optional VCS read seam for the `Ralph` loop strategy (issue #58 v2).
    /// `None` (the default) omits the git-log reload section (v1 behavior).
    vcs_provider: Option<Arc<dyn VcsProvider>>,
    /// Scoring oracle for the `HillClimbing` loop strategy (issue #60). `None`
    /// (the default) makes a `HillClimbing` run halt with
    /// `HillClimbingMisconfigured`.
    metric_evaluator: Option<Arc<dyn crate::metric::MetricEvaluator>>,
    /// Standard catalogue tools accumulated via [`HarnessBuilder::tool`] /
    /// [`HarnessBuilder::tools`] (issue #81). They are drained into a populated
    /// [`StandardToolRegistry`](crate::tool_registry::StandardToolRegistry) by
    /// [`HarnessBuilder::build_tool_registry`], applying last-wins upsert.
    standard_tools: Vec<crate::tools::StandardTool>,
    /// Per-toolset catalogue tools (Issue 2: per-node toolset scoping),
    /// accumulated via [`HarnessBuilder::toolset_tools`] and keyed by the
    /// non-empty toolset handle a leaf carries. Each bucket is folded into a
    /// populated [`StandardToolRegistry`](crate::tool_registry::StandardToolRegistry)
    /// (last-wins upsert) at [`build_config`](HarnessBuilder::build_config) and
    /// stored in [`HarnessConfig::toolset_catalogues`]. Empty (the default)
    /// preserves today's single-catalogue behaviour byte-for-byte.
    toolset_tools: std::collections::HashMap<String, Vec<crate::tools::StandardTool>>,
    /// Optional operating system prompt prepended to each turn's assembled
    /// context (issue #91) when the context manager renders none. `None` (the
    /// default) preserves today's behaviour. See [`system_prompt`](HarnessBuilder::system_prompt).
    system_prompt: Option<String>,
    /// Authoritative per-run model sampling/decoding parameters (issue #93).
    /// Defaults to [`ModelParams::default`]. See
    /// [`model_params`](HarnessBuilder::model_params).
    model_params: ModelParams,
    /// Opt-in automatic session-state threading + auto-persist (issue #102).
    /// `false` (the default) preserves today's behaviour byte-for-byte (ZERO
    /// session-store I/O). See [`auto_persist_sessions`](HarnessBuilder::auto_persist_sessions).
    auto_persist_sessions: bool,
    /// Session-scoped escalation flag shared with an
    /// [`AdaptiveToolCallModelInterface`](crate::prompt_tool_call::AdaptiveToolCallModelInterface)
    /// installed by [`conversational`](HarnessBuilder::conversational). `Some`
    /// only on that path; the run loop flips it on detecting a prose response so
    /// the wrapped model switches to prompt-based tool calling for the rest of
    /// the run. `None` for every other construction (no adaptive wrapping).
    prompt_tool_call_flag: Option<Arc<std::sync::atomic::AtomicBool>>,
    /// Per-kind consult handlers (issue #114). Empty (the default) preserves
    /// today's behaviour byte-for-byte (no mediation). See
    /// [`consult_handler`](HarnessBuilder::consult_handler).
    consult_handlers: std::collections::HashMap<String, ConsultHandlerEntry>,
    /// Runtime strategy-handle resolver (issue #120). Defaults to an empty
    /// [`ExecutionRegistry`]. See [`registry`](HarnessBuilder::registry).
    registry: ExecutionRegistry,
    /// HITL-vs-AFK escalation knob (issue #120). Defaults to
    /// [`EscalationMode::SurfaceToHuman`]. See
    /// [`escalation_mode`](HarnessBuilder::escalation_mode).
    escalation_mode: EscalationMode,
}

impl HarnessBuilder {
    /// Start a builder from the five required components. Optional components
    /// default to `None`/[`PricingTable::DEFAULT`] until set.
    pub fn new(
        agent: Arc<dyn Agent>,
        tool_registry: Arc<dyn ToolRegistry>,
        sandbox: Arc<dyn SandboxProvider>,
        context_manager: Arc<dyn ContextManager>,
        termination_policy: Arc<dyn TerminationPolicy>,
    ) -> Self {
        Self {
            agent,
            tool_registry,
            sandbox,
            sandbox_violation_policy: SandboxViolationPolicy::default(),
            context_manager,
            termination_policy,
            middleware: None,
            observability: None,
            compaction_verifier: Arc::new(KeyTermVerifier),
            max_compaction_attempts: 2,
            pricing: PricingTable::DEFAULT,
            content_capture: ContentCaptureConfig::default(),
            tool_call_repair: None,
            max_repair_attempts: 1,
            max_stop_blocks: 8,
            error_loop_threshold: 3,
            enforce_output_schemas: false,
            output_schema_max_retries: 2,
            hooks: None,
            verifier: None,
            storage: None,
            project_id: None,
            chunk_provider: None,
            max_resets: 3,
            vcs_provider: None,
            metric_evaluator: None,
            standard_tools: Vec::new(),
            toolset_tools: std::collections::HashMap::new(),
            system_prompt: None,
            model_params: ModelParams::default(),
            auto_persist_sessions: false,
            prompt_tool_call_flag: None,
            consult_handlers: std::collections::HashMap::new(),
            registry: ExecutionRegistry::empty(),
            escalation_mode: EscalationMode::SurfaceToHuman,
        }
    }

    /// Assemble a minimal conversational harness from a model — no tools, no
    /// filesystem.
    ///
    /// This is the few-lines path: it defaults every required component so you
    /// can go from a model to a running harness in one call. The defaults are a
    /// [`ModelAgent`](crate::agent::ModelAgent) over `model`, an
    /// [`EmptyToolRegistry`], a [`NullSandbox`], a
    /// [`StandardContextManager`](crate::context::StandardContextManager) with a
    /// null cache provider and default compaction, and
    /// [`CompleteOnFinalResponse`] termination (the model's first final response
    /// is the result).
    ///
    /// Every default is overridable: add catalogue tools with
    /// [`tool`](Self::tool) / [`tools`](Self::tools), or supply your own
    /// component to [`new`](Self::new) directly.
    ///
    /// ```no_run
    /// # use spore_core::{Harness, HarnessBuilder, OllamaModelInterface, HarnessRunOptions, Task};
    /// # async fn run() {
    /// let harness = HarnessBuilder::conversational(OllamaModelInterface::new("llama3.2")).build();
    /// let result = harness
    ///     .run(HarnessRunOptions::new(Task::simple("Reply with a friendly greeting.")))
    ///     .await;
    /// # let _ = result;
    /// # }
    /// ```
    pub fn conversational<M: crate::model::ModelInterface + 'static>(model: M) -> Self {
        use crate::compaction_adapter::HarnessContextManagerExt;
        let model = Arc::new(model);
        // Install the adaptive prompt-based tool-calling wrapper around the
        // agent's model. While its flag is unset it delegates natively
        // (byte-for-byte); the run loop flips the flag on detecting a prose
        // response so the model switches to prompt-based tool calling for the
        // rest of the run. The context manager keeps the *raw* model (its only
        // model use is compaction summarization, which advertises no tools).
        let prompt_tool_call_flag = Arc::new(std::sync::atomic::AtomicBool::new(false));
        let adaptive_model = Arc::new(
            crate::prompt_tool_call::AdaptiveToolCallModelInterface::new(
                model.clone(),
                prompt_tool_call_flag.clone(),
            ),
        );
        let agent: Arc<dyn Agent> = Arc::new(crate::agent::ModelAgent::new(
            crate::agent::AgentId::new("agent"),
            adaptive_model,
        ));
        let tool_registry: Arc<dyn ToolRegistry> = Arc::new(EmptyToolRegistry);
        let sandbox: Arc<dyn SandboxProvider> = Arc::new(NullSandbox);
        let context_manager: Arc<dyn ContextManager> =
            Arc::new(crate::context::StandardContextManager::new(
                model,
                Arc::new(crate::cache_provider::NullCacheProvider),
                crate::context::CompactionConfig::default(),
            ))
            .into_harness_adapter();
        let termination_policy: Arc<dyn TerminationPolicy> = Arc::new(CompleteOnFinalResponse);
        let mut builder = Self::new(
            agent,
            tool_registry,
            sandbox,
            context_manager,
            termination_policy,
        );
        builder.prompt_tool_call_flag = Some(prompt_tool_call_flag);
        builder
    }

    /// Like [`conversational`](Self::conversational), but takes an already-boxed
    /// `Arc<dyn ModelInterface>` (SC-2).
    ///
    /// `ModelInterface` is now object-safe (`BoxFut`), so a consumer can hold a
    /// single `Arc<dyn ModelInterface>` — picking the provider at runtime — and
    /// inject it here without monomorphizing through a concrete model type. This
    /// is the entry point `CONVENTIONS.md` refers to when it says components are
    /// injected as `Arc<dyn ModelInterface>`.
    ///
    /// ```no_run
    /// # use std::sync::Arc;
    /// # use spore_core::{HarnessBuilder, ModelInterface, OllamaModelInterface};
    /// let model: Arc<dyn ModelInterface> = Arc::new(OllamaModelInterface::new("llama3.2"));
    /// let harness = HarnessBuilder::conversational_arc(model).build();
    /// # let _ = harness;
    /// ```
    pub fn conversational_arc(model: Arc<dyn crate::model::ModelInterface>) -> Self {
        // `Arc<dyn ModelInterface>` is itself a `ModelInterface` (blanket impl),
        // so the generic preset accepts it directly — the boxed model is shared
        // by reference-count, never re-minted.
        Self::conversational(model)
    }

    /// Override the harness-loop tool registry (issue #4 seam).
    ///
    /// Use this to supply your own [`ToolRegistry`] implementation — e.g. a set
    /// of custom tools — on top of a preset like [`conversational`](Self::new):
    ///
    /// ```no_run
    /// # use std::sync::Arc;
    /// # use spore_core::{HarnessBuilder, OllamaModelInterface, EmptyToolRegistry};
    /// let harness = HarnessBuilder::conversational(OllamaModelInterface::new("llama3.2"))
    ///     .tool_registry(Arc::new(EmptyToolRegistry))
    ///     .build();
    /// ```
    ///
    /// The registry's [`schemas`](ToolRegistry::schemas) are delivered to the
    /// model automatically each turn, and [`dispatch`](ToolRegistry::dispatch)
    /// is called when the model requests a tool.
    pub fn tool_registry(mut self, tool_registry: Arc<dyn ToolRegistry>) -> Self {
        self.tool_registry = tool_registry;
        self
    }

    /// Override the [`ContextManager`] that assembles per-turn context and drives
    /// compaction. `conversational` installs a `StandardContextManager` with
    /// `CompactionConfig::default()` (compaction at 80% of a 200K window); supply
    /// your own (e.g. a lower `threshold`) to make compaction fire earlier for
    /// models with a smaller context window.
    pub fn context_manager(mut self, context_manager: Arc<dyn ContextManager>) -> Self {
        self.context_manager = context_manager;
        self
    }

    /// Override the [`SandboxProvider`] — the only path tools have to the
    /// environment (filesystem, process exec).
    ///
    /// [`conversational`](Self::conversational) defaults to [`NullSandbox`],
    /// which denies environment access — fine for pure-compute tools, but
    /// catalogue file tools (`read_file` / `write_file` / `list_dir`) operate
    /// *through* the sandbox, so an agent that touches a real directory needs a
    /// workspace-scoped sandbox here:
    ///
    /// ```no_run
    /// # use std::sync::Arc;
    /// # use spore_core::{HarnessBuilder, OllamaModelInterface, StandardTools};
    /// # use spore_core::sandbox::{WorkspaceScopedSandbox, WorkspaceConfig};
    /// # fn demo(workspace: Arc<WorkspaceScopedSandbox>) {
    /// let harness = HarnessBuilder::conversational(OllamaModelInterface::new("llama3.2"))
    ///     .sandbox(workspace)
    ///     .tools(StandardTools::coding_set())
    ///     .build();
    /// # let _ = harness;
    /// # }
    /// ```
    pub fn sandbox(mut self, sandbox: Arc<dyn SandboxProvider>) -> Self {
        self.sandbox = sandbox;
        self
    }

    /// Set how a [`SandboxViolation`] surfaced by a tool is handled — recoverable
    /// feedback to the model (the default) or a hard halt. See
    /// [`SandboxViolationPolicy`].
    ///
    /// ```no_run
    /// # use std::sync::Arc;
    /// # use spore_core::harness::{HarnessBuilder, SandboxViolationPolicy};
    /// # fn ex(b: HarnessBuilder) -> HarnessBuilder {
    /// b.sandbox_violation_policy(SandboxViolationPolicy::Halt)
    /// # }
    /// ```
    pub fn sandbox_violation_policy(mut self, policy: SandboxViolationPolicy) -> Self {
        self.sandbox_violation_policy = policy;
        self
    }

    /// Add a single [`StandardTool`](crate::tools::StandardTool) to the
    /// catalogue accumulated for this harness (issue #81, Q1/Q2).
    ///
    /// At [`build`](Self::build) the accumulated tools are folded into a
    /// populated [`StandardToolRegistry`](crate::tool_registry::StandardToolRegistry)
    /// (via [`drain_tools_into_registry`](Self::drain_tools_into_registry)) and
    /// the run loop bridges them per-run through
    /// [`RealToolRegistry`](crate::tool_registry::RealToolRegistry), so they run
    /// with sandbox + storage wired in — no manual bridging required.
    /// Registration applies LAST-WINS upsert: a later `.tool()` with the same
    /// name overrides an earlier one (e.g. a custom tool registered after a
    /// preset).
    ///
    /// To author a *custom* sandboxed tool, implement
    /// [`Tool`](crate::tool_registry::Tool) and wrap it with
    /// [`StandardTool::new`](crate::tools::StandardTool::new), then pass it here.
    /// Catalogue tools added this way take precedence over a registry supplied
    /// via [`tool_registry`](Self::tool_registry).
    pub fn tool(mut self, tool: crate::tools::StandardTool) -> Self {
        self.standard_tools.push(tool);
        self
    }

    /// Set an operating system prompt prepended to each turn's assembled context
    /// (issue #91).
    ///
    /// The standard compaction context manager renders no system prompt, so
    /// without this the model receives only the task as a user message and no
    /// guidance on how to behave. When set, the run loop inserts this text as a
    /// leading [`Role::System`](crate::model::Role) message each turn — but only
    /// when the assembled context does not already start with one, so a context
    /// manager that renders its own system prompt is preserved. `None` (the
    /// default) preserves today's behaviour.
    pub fn system_prompt(mut self, system_prompt: impl Into<String>) -> Self {
        self.system_prompt = Some(system_prompt.into());
        self
    }

    /// Set the authoritative model sampling/decoding parameters for the whole
    /// run (issue #93).
    ///
    /// These params are authoritative: the harness replaces each turn's
    /// `Context.params` with this value UNCONDITIONALLY (builder params win)
    /// right before the request is built, so the configured params reach every
    /// agent turn that requests tools — the ReAct loop, the PlanExecute plan
    /// phase, the execute sub-loop, and the streaming path alike. (The internal
    /// compaction/summarization turn is intentionally left on defaults; it
    /// requests no tools, so decoding params are a no-op there.)
    ///
    /// Enabling [`structured_tool_calls`](crate::model::ModelParams::structured_tool_calls)
    /// trades interleaved reasoning for one schema-constrained tool call per
    /// turn — useful for small local models that otherwise emit malformed tool
    /// calls. See [`ModelParams::structured_tool_calls`](crate::model::ModelParams::structured_tool_calls)
    /// for the full behaviour contract.
    pub fn model_params(mut self, params: ModelParams) -> Self {
        self.model_params = params;
        self
    }

    /// Add many [`StandardTool`](crate::tools::StandardTool)s at once (e.g. a
    /// preset like [`StandardTools::coding_set`](crate::tools::StandardTools::coding_set)).
    /// Order is preserved, so last-wins upsert still applies across the batch.
    pub fn tools(mut self, tools: impl IntoIterator<Item = crate::tools::StandardTool>) -> Self {
        self.standard_tools.extend(tools);
        self
    }

    /// Register catalogue tools SCOPED to a single named toolset handle (Issue 2:
    /// per-node toolset scoping). Mirrors [`tools`](Self::tools), but instead of
    /// folding into the ONE global catalogue, these tools are folded into a
    /// per-`key` [`StandardToolRegistry`](crate::tool_registry::StandardToolRegistry)
    /// (last-wins upsert across calls and within the batch) and stored in
    /// [`HarnessConfig::toolset_catalogues`].
    ///
    /// At dispatch, a leaf whose `toolset` handle equals `key` resolves ONLY this
    /// catalogue (bridged per-run via
    /// [`RealToolRegistry`](crate::tool_registry::RealToolRegistry) with the run's
    /// sandbox/session/storage), so it cannot reach another node's tools — the
    /// union no longer leaks across nodes. A leaf with an EMPTY (`""`) handle, or
    /// a non-empty handle with no entry here, falls back to the global
    /// [`tools`](Self::tools) catalogue / `tool_registry` seam (back-compat).
    ///
    /// `key` should be a NON-EMPTY handle string; the empty handle is reserved
    /// for the global-catalogue fallback.
    pub fn toolset_tools(
        mut self,
        key: impl Into<String>,
        tools: impl IntoIterator<Item = crate::tools::StandardTool>,
    ) -> Self {
        self.toolset_tools
            .entry(key.into())
            .or_default()
            .extend(tools);
        self
    }

    /// Drain the accumulated catalogue tools into a populated
    /// [`StandardToolRegistry`](crate::tool_registry::StandardToolRegistry),
    /// registering each with last-wins upsert (issue #81, Q1/Q2). Consumes the
    /// accumulated set. The harness-loop [`tool_registry`](Self) seam is
    /// separate (it is the bridged dispatch trait); callers wire the returned
    /// registry into a [`RealToolRegistry`](crate::tool_registry::RealToolRegistry)
    /// per run. Returns an empty registry if no catalogue tools were added.
    pub fn drain_tools_into_registry(&mut self) -> Arc<crate::tool_registry::StandardToolRegistry> {
        use crate::tool_registry::ToolRegistry as _;
        let reg = crate::tool_registry::StandardToolRegistry::new();
        for t in self.standard_tools.drain(..) {
            // Upsert: a duplicate name overwrites (issue #81, Q1). Schema/name
            // validation errors are ignored here since catalogue schemas are
            // well-formed by construction.
            let _ = reg.register(t.implementation, t.schema);
        }
        Arc::new(reg)
    }

    /// Inject a [`StorageProvider`](crate::storage::StorageProvider) (issue #73).
    /// Mirrors [`observability`](Self::observability) — independent injection
    /// point. Defaults to an all-no-op provider so existing callers/tests
    /// compile and behave unchanged.
    pub fn storage(mut self, storage: Arc<crate::storage::StorageProvider>) -> Self {
        self.storage = Some(storage);
        self
    }

    /// Override the STABLE durable-storage project namespace (issue #142). When
    /// unset, [`build_config`](Self::build_config) derives it from
    /// `sandbox.workspace_root()` (decision 5), canonicalizing the path first.
    /// Set this explicitly when the workspace root is not a stable on-disk path
    /// (e.g. a fixture-replay tempdir, or to pin a known project across
    /// processes). See [`HarnessConfig::project_id`].
    pub fn project_id(mut self, project_id: crate::storage::ProjectId) -> Self {
        self.project_id = Some(project_id);
        self
    }

    /// Enable opt-in automatic conversation-history threading via the
    /// [`SessionStore`](crate::storage::SessionStore) (issue #102). Defaults to
    /// `false`, which preserves today's behaviour byte-for-byte (ZERO
    /// session-store I/O). When enabled, the harness auto-loads the prior
    /// session for the run's `session_id` (ReAct / SelfVerifying only; an
    /// explicit [`with_session_state`](HarnessRunOptions::with_session_state)
    /// always wins) and auto-persists the post-run state at the terminal seam.
    /// See [`HarnessConfig::auto_persist_sessions`] for the full contract.
    ///
    /// Pair with [`storage`](Self::storage) to wire a real (in-memory or
    /// filesystem) [`SessionStore`]; without one the default all-no-op store
    /// makes auto-load/persist no-ops.
    pub fn auto_persist_sessions(mut self, enabled: bool) -> Self {
        self.auto_persist_sessions = enabled;
        self
    }

    /// Set the conditional prompt-chunk provider (issue #79). Defaults to an
    /// empty [`InMemoryChunkProvider`](crate::prompt_assembly::InMemoryChunkProvider).
    pub fn chunk_provider(
        mut self,
        provider: Arc<dyn crate::prompt_assembly::ChunkProvider>,
    ) -> Self {
        self.chunk_provider = Some(provider);
        self
    }

    /// Convenience: register chunks inline without constructing a provider
    /// (issue #79). Resolves to an
    /// [`InMemoryChunkProvider`](crate::prompt_assembly::InMemoryChunkProvider).
    pub fn chunks(mut self, chunks: Vec<crate::prompt_assembly::PromptChunk>) -> Self {
        self.chunk_provider = Some(Arc::new(
            crate::prompt_assembly::InMemoryChunkProvider::new(chunks),
        ));
        self
    }

    /// Register a per-kind consult handler (issue #114). When a worker (run via
    /// [`SubagentTool`](crate::tools::SubagentTool)) pauses with a
    /// [`ConsultRequest`] whose `kind` matches `kind`, the orchestrator runs
    /// `handler` on the request deterministically (no orchestrator model turn),
    /// up to `budget` consults of this kind before applying `overflow`. Without
    /// any registered handler, consults degrade gracefully (R6): a standalone
    /// worker surfaces [`RunResult::Consult`] unchanged. Empty by default.
    pub fn consult_handler(
        mut self,
        kind: impl Into<String>,
        handler: Arc<dyn Harness>,
        budget: u32,
        overflow: ConsultOverflowPolicy,
    ) -> Self {
        self.consult_handlers.insert(
            kind.into(),
            ConsultHandlerEntry {
                handler,
                budget,
                overflow,
            },
        );
        self
    }

    /// Replace the whole [`ExecutionRegistry`] (issue #120). The registry
    /// resolves a task's serializable strategy handles
    /// (`AgentRef`/`ToolsetRef`/`SchemaRef`) and `StrategyRef::Custom` keys at
    /// run entry. Defaults to an empty registry.
    pub fn registry(mut self, registry: ExecutionRegistry) -> Self {
        self.registry = registry;
        self
    }

    /// Register a named agent in the [`ExecutionRegistry`] (issue #120,
    /// per-key convenience over [`registry`](Self::registry)).
    pub fn registry_agent(mut self, key: impl Into<String>, agent: Arc<dyn Agent>) -> Self {
        self.registry = std::mem::take(&mut self.registry)
            .into_builder()
            .agent(key, agent)
            .build();
        self
    }

    /// Register a named toolset in the [`ExecutionRegistry`] (issue #120).
    pub fn registry_toolset(
        mut self,
        key: impl Into<String>,
        toolset: Arc<dyn ToolRegistry>,
    ) -> Self {
        self.registry = std::mem::take(&mut self.registry)
            .into_builder()
            .toolset(key, toolset)
            .build();
        self
    }

    /// Register a named JSON schema in the [`ExecutionRegistry`] (issue #120).
    pub fn registry_schema(mut self, key: impl Into<String>, schema: serde_json::Value) -> Self {
        self.registry = std::mem::take(&mut self.registry)
            .into_builder()
            .schema(key, schema)
            .build();
        self
    }

    /// Register a named verifier in the [`ExecutionRegistry`] (issue #120).
    pub fn registry_verifier(
        mut self,
        key: impl Into<String>,
        verifier: Arc<dyn crate::verifier::Verifier>,
    ) -> Self {
        self.registry = std::mem::take(&mut self.registry)
            .into_builder()
            .verifier(key, verifier)
            .build();
        self
    }

    /// Register a custom strategy in the [`ExecutionRegistry`] under `key`
    /// (issue #120). Resolvable later via a `StrategyRef::Custom(key)`.
    pub fn register_strategy(
        mut self,
        key: impl Into<String>,
        strategy: Arc<dyn RunStrategy>,
    ) -> Self {
        self.registry.register_strategy(key, strategy);
        self
    }

    /// Select the HITL-vs-AFK escalation mode (issue #120, PRD goal #7).
    /// Defaults to [`EscalationMode::SurfaceToHuman`].
    pub fn escalation_mode(mut self, mode: EscalationMode) -> Self {
        self.escalation_mode = mode;
        self
    }

    /// Inject the default verification oracle for the `SelfVerifying` loop
    /// strategy (issue #61, #124). Folded into the [`ExecutionRegistry`] under
    /// the default empty key at build, so a `SelfVerifying` whose `evaluator`
    /// key is empty resolves to it. Without any resolvable verifier a
    /// `SelfVerifying` run halts with `SelfVerifyMisconfigured` (D4). Its
    /// [`max_iterations`](crate::verifier::Verifier::max_iterations) caps the
    /// build↔evaluate round-trips (D3).
    pub fn verifier(mut self, verifier: Arc<dyn crate::verifier::Verifier>) -> Self {
        self.verifier = Some(verifier);
        self
    }

    /// Inject a lifecycle hook chain (issue #69).
    pub fn hooks(mut self, hooks: Arc<dyn crate::hooks::HookChain>) -> Self {
        self.hooks = Some(hooks);
        self
    }

    /// Set the per-run cap on consecutive Stop-hook blocks (issue #69).
    /// Defaults to `8`.
    pub fn max_stop_blocks(mut self, max: u32) -> Self {
        self.max_stop_blocks = max;
        self
    }

    /// Set the consecutive-recoverable-tool-error breaker threshold `N`
    /// (issue #137). At `N` identical-argument recoverable errors for one tool
    /// the loop injects ONE corrective message; at `2 * N` it stops looping and
    /// resolves the node's [`BudgetExhaustedBehavior`] with
    /// [`HaltReason::ToolErrorLoop`] (the `2×` multiplier is fixed). Defaults to
    /// `3`.
    pub fn error_loop_threshold(mut self, n: u32) -> Self {
        self.error_loop_threshold = n;
        self
    }

    /// Turn ON output-schema delivery + enforcement for `ReactConfig` leaves
    /// carrying `output = Some(..)` (issue #139 — MIGRATION GATE). Defaults to
    /// `false` (OFF), which keeps existing replay fixtures byte-identical. See
    /// [`HarnessConfig::enforce_output_schemas`].
    pub fn enforce_output_schemas(mut self, enforce: bool) -> Self {
        self.enforce_output_schemas = enforce;
        self
    }

    /// Set the number of EXTRA terminal-validation retry turns `N` granted when
    /// [`enforce_output_schemas`](Self::enforce_output_schemas) is ON (issue
    /// #139). Total attempts = `1 + N`. Defaults to `2`. See
    /// [`HarnessConfig::output_schema_max_retries`].
    pub fn output_schema_max_retries(mut self, n: u32) -> Self {
        self.output_schema_max_retries = n;
        self
    }

    /// Set the outer-loop context-window reset cap for the `Ralph` loop strategy
    /// (issue #58, B3). Defaults to `3`.
    pub fn max_resets(mut self, max: u32) -> Self {
        self.max_resets = max;
        self
    }

    /// Inject a [`VcsProvider`] for the `Ralph` loop strategy (issue #58 v2).
    /// When set, Ralph's per-window reload phase also calls
    /// [`VcsProvider::log`] and injects a delimited "Recent VCS history:"
    /// section into the fresh context window. Defaults to `None`, which omits
    /// the git-log section and preserves v1 Ralph behavior byte-for-byte (the
    /// B4→None decision).
    pub fn vcs_provider(mut self, provider: Arc<dyn VcsProvider>) -> Self {
        self.vcs_provider = Some(provider);
        self
    }

    /// Inject the scoring oracle for the `HillClimbing` loop strategy (issue
    /// #60). Required for that strategy: without it a `HillClimbing` run halts
    /// with `HillClimbingMisconfigured` (no panic). The evaluator is called once
    /// at the iteration-0 baseline (no agent turn) and after every subsequent
    /// agent turn; each result is routed through
    /// [`should_keep`](crate::metric::should_keep). Defaults to `None`.
    pub fn metric_evaluator(mut self, evaluator: Arc<dyn crate::metric::MetricEvaluator>) -> Self {
        self.metric_evaluator = Some(evaluator);
        self
    }

    /// Inject a deterministic tool-call repair provider (e.g.
    /// [`StandardToolCallRepair`](crate::tool_call_repair::StandardToolCallRepair)).
    /// When set, recoverable tool-dispatch errors trigger an argument-coercion
    /// and re-dispatch attempt before falling back to enriched error feedback.
    /// Defaults to `None` (behaviour byte-identical to today).
    pub fn tool_call_repair(mut self, repair: Arc<dyn ToolCallRepair>) -> Self {
        self.tool_call_repair = Some(repair);
        self
    }

    /// Set the maximum number of repair-and-re-dispatch attempts per tool call.
    /// Defaults to `1`. Ignored when no repair provider is set.
    pub fn max_repair_attempts(mut self, attempts: u32) -> Self {
        self.max_repair_attempts = attempts;
        self
    }

    /// Inject a post-compaction verifier (issue #46). Defaults to
    /// [`KeyTermVerifier`].
    pub fn compaction_verifier(mut self, verifier: Arc<dyn CompactionVerifier>) -> Self {
        self.compaction_verifier = verifier;
        self
    }

    /// Set the maximum number of compaction-summary attempts before accepting
    /// a failing summary anyway (issue #46). Defaults to `2`.
    pub fn max_compaction_attempts(mut self, attempts: u32) -> Self {
        self.max_compaction_attempts = attempts;
        self
    }

    /// Inject a middleware chain.
    pub fn middleware(mut self, middleware: Arc<dyn MiddlewareChain>) -> Self {
        self.middleware = Some(middleware);
        self
    }

    /// Inject an observability provider. The harness loop emits real spans
    /// through it (turn spans, tool-call spans) and flushes on terminal outcomes.
    pub fn observability(mut self, observability: Arc<dyn ObservabilityProvider>) -> Self {
        self.observability = Some(observability);
        self
    }

    /// Convenience: construct and inject a durable-outbox observability provider
    /// rooted at `root` (typically the `.spore` directory). Honors the
    /// `SPORE_OTLP_ENDPOINT` env var for OTLP forwarding (issue #33).
    pub fn with_observability_outbox(self, root: impl Into<std::path::PathBuf>) -> Self {
        let provider = Arc::new(OutboxObservabilityProvider::new(OutboxConfig::new(root)));
        self.observability(provider)
    }

    /// Set the token→USD pricing table used to stamp `cost_usd` on turn spans.
    pub fn pricing(mut self, pricing: PricingTable) -> Self {
        self.pricing = pricing;
        self
    }

    /// Set the LLM-native content-capture config (issue #64). Defaults to OFF.
    /// Use [`ContentCaptureConfig::from_env`] to honor `SPORE_TRACE_CONTENT` /
    /// `SPORE_TRACE_CONTENT_MAX_LEN`.
    pub fn content_capture(mut self, content_capture: ContentCaptureConfig) -> Self {
        self.content_capture = content_capture;
        self
    }

    /// Assemble the [`HarnessConfig`] without wrapping it in a harness.
    pub fn build_config(mut self) -> HarnessConfig {
        // Fold catalogue tools accumulated via `.tool()` / `.tools()` into a
        // populated `StandardToolRegistry` (last-wins upsert). The run loop
        // bridges it per-run — `build()` can't, because the `ToolContext` is
        // keyed by the run's `SessionId`, unknown until `run()`.
        let catalogue_registry = if self.standard_tools.is_empty() {
            None
        } else {
            Some(self.drain_tools_into_registry())
        };
        // Issue 2: fold each per-toolset bucket into its own populated
        // `StandardToolRegistry` (last-wins upsert), keyed by the toolset handle.
        // Bridged per-run at dispatch — same as the global catalogue.
        let toolset_catalogues: std::collections::HashMap<
            String,
            Arc<crate::tool_registry::StandardToolRegistry>,
        > = {
            use crate::tool_registry::ToolRegistry as _;
            self.toolset_tools
                .drain()
                .map(|(key, tools)| {
                    let reg = crate::tool_registry::StandardToolRegistry::new();
                    for t in tools {
                        let _ = reg.register(t.implementation, t.schema);
                    }
                    (key, Arc::new(reg))
                })
                .collect()
        };
        // When catalogue tools are present and the caller wired no storage,
        // default to an in-memory provider (not the all-no-op default) so that
        // session-aware tools (todo_write, memory, task_list) actually persist
        // within the run. Pure tools (read_file/write_file via the sandbox) are
        // unaffected either way.
        let storage = self.storage.unwrap_or_else(|| {
            if catalogue_registry.is_some() || !toolset_catalogues.is_empty() {
                Arc::new(crate::storage::StorageProvider::single(Arc::new(
                    crate::storage::InMemoryStorageProvider::new(),
                )))
            } else {
                Arc::new(crate::storage::StorageProvider::no_op())
            }
        });
        // #124: the legacy single-collaborator fields are gone — fold the
        // builder's collaborators into the ExecutionRegistry under the DEFAULT
        // empty-string handle (`ReactConfig::per_loop` uses an empty `AgentRef`/
        // `ToolsetRef`; the default `SelfVerifyingConfig.evaluator` /
        // `HillClimbingConfig.evaluator` likewise use the empty key). Explicitly
        // registered handles (via `registry`) take precedence: only fill a key
        // the caller did not already wire.
        let mut reg_builder = self.registry.into_builder();
        reg_builder = reg_builder.fill_default_agent(self.agent);
        reg_builder = reg_builder.fill_default_toolset(self.tool_registry.clone());
        // Issue 2: a leaf carrying a non-empty `toolset` handle must RESOLVE
        // against the registry (`ExecutionRegistry::validate` runs `check_toolset`
        // at run entry). For every per-key catalogue wired via `.toolset_tools`,
        // ensure the registry has a presence entry under that handle so
        // `validate()` passes WITHOUT the caller manually registering a
        // placeholder toolset. The registry VALUE is never dispatched (dispatch
        // goes through `toolset_catalogues`), so a no-op `EmptyToolRegistry` is
        // sufficient; an explicitly-registered toolset under the same key wins.
        for key in toolset_catalogues.keys() {
            reg_builder = reg_builder.fill_toolset(key.clone(), Arc::new(EmptyToolRegistry));
        }
        if let Some(v) = self.verifier {
            reg_builder = reg_builder.fill_default_verifier(v);
        }
        if let Some(m) = self.metric_evaluator {
            reg_builder = reg_builder.fill_default_metric_evaluator(m);
        }
        let registry = reg_builder.build();
        // #142: derive the STABLE project namespace from `sandbox.workspace_root()`
        // (decision 5 — NOT process cwd) unless the caller pinned one explicitly.
        // The FS-touching `ProjectId::from_path` canonicalizes first; if that
        // fails (e.g. the workspace root does not yet exist on disk) fall back to
        // the PURE derivation over the workspace_root string so a `project_id` is
        // always present and deterministic.
        let project_id = self.project_id.unwrap_or_else(|| {
            let workspace_root = self.sandbox.workspace_root();
            crate::storage::ProjectId::from_path(workspace_root).unwrap_or_else(|_| {
                crate::storage::ProjectId::from_canonical_path(&workspace_root.to_string_lossy())
            })
        });
        HarnessConfig {
            tool_registry: self.tool_registry,
            sandbox: self.sandbox,
            sandbox_violation_policy: self.sandbox_violation_policy,
            context_manager: self.context_manager,
            termination_policy: self.termination_policy,
            middleware: self.middleware,
            observability: self.observability,
            compaction_verifier: self.compaction_verifier,
            max_compaction_attempts: self.max_compaction_attempts,
            pricing: self.pricing,
            content_capture: self.content_capture,
            tool_call_repair: self.tool_call_repair,
            max_repair_attempts: self.max_repair_attempts,
            max_stop_blocks: self.max_stop_blocks,
            error_loop_threshold: self.error_loop_threshold,
            enforce_output_schemas: self.enforce_output_schemas,
            output_schema_max_retries: self.output_schema_max_retries,
            hooks: self.hooks,
            storage,
            project_id,
            chunk_provider: self.chunk_provider.unwrap_or_else(|| {
                Arc::new(crate::prompt_assembly::InMemoryChunkProvider::empty())
            }),
            max_resets: self.max_resets,
            vcs_provider: self.vcs_provider,
            catalogue_registry,
            toolset_catalogues,
            system_prompt: self.system_prompt,
            model_params: self.model_params,
            auto_persist_sessions: self.auto_persist_sessions,
            prompt_tool_call_flag: self.prompt_tool_call_flag,
            consult_handlers: self.consult_handlers,
            registry,
            escalation_mode: self.escalation_mode,
        }
    }

    /// Assemble a ready-to-run [`StandardHarness`].
    pub fn build(self) -> StandardHarness {
        StandardHarness::new(self.build_config())
    }
}

pub struct StandardHarness {
    config: HarnessConfig,
    /// #126: harness-observed write/edit file paths for the CURRENTLY-running
    /// execute step. The tool-dispatch seam pushes the `path` of every
    /// `write_file` / `edit_file` call here as it dispatches; the DAG executor
    /// drains it (`take_observed_writes`) on task completion to build the
    /// observed `files_touched` for that task's
    /// [`StepLedgerEntry`](crate::tasklist::StepLedgerEntry). Interior-mutable
    /// because the executor sees the harness only as `&dyn StrategyExecutor`.
    /// Steps run SEQUENTIALLY (v1 ready-set is sequential), so a single shared
    /// accumulator cleared per step is sufficient and deterministic.
    observed_writes: std::sync::Mutex<Vec<String>>,
}

impl StandardHarness {
    pub fn new(config: HarnessConfig) -> Self {
        // Ralph completion mechanism (issue #58, B1): register a `Stop` hook
        // that drives multi-context-window continuation off the Ralph checkpoint.
        // #142: the checkpoint moved off `.spore/progress.json` onto the durable
        // project-id RunStore. Registration is harmless for non-Ralph runs — the
        // hook only BLOCKS when the progress checkpoint key is PRESENT and reports
        // incomplete tasks; when it is absent (the common case for ReAct / other
        // strategies) it returns `Continue`, so existing strategies are unaffected.
        let chain: Arc<dyn crate::hooks::HookChain> = match config.hooks.clone() {
            Some(c) => c,
            None => Arc::new(crate::hooks::StandardHookChain::new()),
        };
        // Best-effort: a duplicate/invalid registration must never panic the
        // constructor. The hook subscribes only to the can-block `Stop` event.
        let _ = chain.register(Arc::new(RalphStopHook {
            run_store: config.storage.run().clone(),
            project_id: config.project_id.clone(),
        }));
        let mut config = config;
        config.hooks = Some(chain);
        Self {
            config,
            observed_writes: std::sync::Mutex::new(Vec::new()),
        }
    }

    /// #126: record a harness-OBSERVED write/edit at the tool-dispatch seam. Only
    /// `write_file` / `edit_file` calls with a `path` are recorded; de-duplicated
    /// against what is already accumulated for the current step. Called from
    /// `run_react_inner` for the call ACTUALLY dispatched (`effective_call`), so
    /// the path comes from the real tool call — never a model-self-reported field.
    fn observe_write_call(&self, call: &ToolCall) {
        let is_write_edit = matches!(call.name.as_str(), "write_file" | "edit_file");
        if !is_write_edit {
            return;
        }
        if let Some(serde_json::Value::String(path)) = call.input.get("path") {
            if let Ok(mut acc) = self.observed_writes.lock() {
                if !acc.iter().any(|p| p == path) {
                    acc.push(path.clone());
                }
            }
        }
    }

    /// Whether a sandbox violation should HALT the run under the configured
    /// [`SandboxViolationPolicy`]: only when the policy is `Halt` AND the
    /// violation is halt-eligible (`PathEscape` / `NetworkViolation`). Layer-2
    /// violations are never halt-eligible, so they stay recoverable regardless.
    fn sandbox_violation_halts(&self, violation: &SandboxViolation) -> bool {
        self.config.sandbox_violation_policy == SandboxViolationPolicy::Halt
            && violation.is_always_halt()
    }

    /// Flatten a [`ToolOutput::SandboxViolation`] into a plain
    /// [`ToolOutput::Error`] whose `recoverable` flag reflects the policy. Used
    /// on tool-result drain paths (resume / human-approval flushes) that append
    /// results to history but have no place to issue a typed halt; the main loop
    /// handles the variant directly so it can return the typed
    /// [`HaltReason::SandboxViolation`]. A non-violation output passes through.
    fn normalize_sandbox_violation(&self, output: ToolOutput) -> ToolOutput {
        match output {
            ToolOutput::SandboxViolation { violation } => {
                let recoverable = !self.sandbox_violation_halts(&violation);
                ToolOutput::Error {
                    message: format!("sandbox violation: {violation:?}"),
                    recoverable,
                }
            }
            other => other,
        }
    }

    /// Read-only access to the assembled config (used by builder tests).
    pub fn config(&self) -> &HarnessConfig {
        &self.config
    }

    /// The injected [`StorageProvider`](crate::storage::StorageProvider)
    /// (issue #73). Defaults to an all-no-op provider when `.storage(...)` was
    /// never set.
    pub fn storage(&self) -> &Arc<crate::storage::StorageProvider> {
        &self.config.storage
    }

    /// Convenience accessor for the storage layer's
    /// [`SessionStore`](crate::storage::SessionStore) (issue #73, expose-only).
    pub fn session_store(&self) -> &Arc<dyn crate::storage::SessionStore> {
        self.config.storage.session()
    }

    /// Test-only hook: drive the post-compaction verify→retry→warn loop
    /// directly, bypassing the full ReAct loop. Lets out-of-module tests (e.g.
    /// the #55 compaction-adapter tests) exercise the seam end-to-end without
    /// scripting a complete model conversation. `#[doc(hidden)]`: not part of
    /// the stable surface.
    #[doc(hidden)]
    pub async fn run_compaction_for_test(
        &self,
        session_state: &mut SessionState,
        session_id: &SessionId,
        task_id: &TaskId,
        span_seq: &mut u64,
        usage: &mut AggregateUsage,
        agent: Arc<dyn Agent>,
    ) {
        self.run_compaction(session_state, session_id, task_id, span_seq, usage, &agent)
            .await;
    }

    fn emit(stream: &Option<StreamSink>, event: StreamEvent) {
        if let Some(s) = stream.as_ref() {
            s(event);
        }
    }

    /// Map one raw [`crate::model::StreamEvent`] to zero or one harness
    /// [`StreamEvent`] (issue #103), threading [`TurnStreamState`] so blocks and
    /// tool calls are correlated across events.
    ///
    /// Rules enforced here:
    /// - Q2: a block's [`StreamEvent::BlockStart`] is emitted exactly once, the
    ///   first time a delta for that index is observed; `ContentBlockStop` maps
    ///   to [`StreamEvent::BlockStop`].
    /// - Q3: `MessageStart` / `MessageStop` map to `None` (dropped).
    /// - A tool-use block additionally emits [`StreamEvent::ToolCallStart`] on
    ///   open, then each fragment as [`StreamEvent::ToolArgsDelta`] keyed by the
    ///   derived `call_id`.
    ///
    /// Returns a `Vec` because opening a block emits both a `BlockStart` and (for
    /// tool-use blocks) a `ToolCallStart` plus the delta itself.
    fn map_model_stream_event(
        ev: crate::model::StreamEvent,
        state: &mut TurnStreamState,
    ) -> Vec<StreamEvent> {
        use crate::model::StreamEvent as M;
        use std::collections::hash_map::Entry;
        match ev {
            // Q3: dropped at the harness boundary.
            M::MessageStart => Vec::new(),
            M::MessageStop { .. } => Vec::new(),
            M::ContentBlockDelta { index, delta } => {
                let mut out = Vec::new();
                if let Entry::Vacant(e) = state.open_blocks.entry(index) {
                    e.insert(BlockKind::Text);
                    out.push(StreamEvent::BlockStart {
                        index,
                        block: BlockKind::Text,
                        node: None,
                    });
                }
                out.push(StreamEvent::TextDelta {
                    content: delta,
                    node: None,
                });
                out
            }
            M::ThinkingDelta { index, delta } => {
                let mut out = Vec::new();
                if let Entry::Vacant(e) = state.open_blocks.entry(index) {
                    e.insert(BlockKind::Reasoning);
                    out.push(StreamEvent::BlockStart {
                        index,
                        block: BlockKind::Reasoning,
                        node: None,
                    });
                }
                out.push(StreamEvent::ReasoningDelta {
                    content: delta,
                    node: None,
                });
                out
            }
            M::ToolUseStart { index, id, name } => {
                let mut out = Vec::new();
                if let Entry::Vacant(e) = state.open_blocks.entry(index) {
                    e.insert(BlockKind::ToolUse);
                    // Use the real call id from the model; consumers correlate
                    // subsequent ToolArgsDelta by it.
                    state.tool_calls.insert(index, id.clone());
                    out.push(StreamEvent::BlockStart {
                        index,
                        block: BlockKind::ToolUse,
                        node: None,
                    });
                    out.push(StreamEvent::ToolCallStart {
                        index,
                        call_id: id,
                        name,
                        node: None,
                    });
                }
                out
            }
            M::ToolUseDelta {
                index,
                partial_json,
            } => {
                let mut out = Vec::new();
                // Fallback: if a stream omitted ToolUseStart, open the block here
                // with a synthesized id and empty name so args still surface.
                if let Entry::Vacant(e) = state.open_blocks.entry(index) {
                    e.insert(BlockKind::ToolUse);
                    let call_id = TurnStreamState::call_id_for(index);
                    state.tool_calls.insert(index, call_id.clone());
                    out.push(StreamEvent::BlockStart {
                        index,
                        block: BlockKind::ToolUse,
                        node: None,
                    });
                    out.push(StreamEvent::ToolCallStart {
                        index,
                        call_id,
                        name: String::new(),
                        node: None,
                    });
                }
                let call_id = state
                    .tool_calls
                    .get(&index)
                    .cloned()
                    .unwrap_or_else(|| TurnStreamState::call_id_for(index));
                out.push(StreamEvent::ToolArgsDelta {
                    call_id,
                    partial_json,
                    node: None,
                });
                out
            }
            M::ContentBlockStop { index } => {
                state.open_blocks.remove(&index);
                vec![StreamEvent::BlockStop { index, node: None }]
            }
        }
    }

    /// Capture a requested tool call as [`ToolCallContent`], truncating its
    /// arguments to `max` UTF-8 bytes (issue #64). The arguments are measured by
    /// their canonical JSON serialization; when over budget they are clipped and
    /// stored as a JSON string carrying the truncation marker (a structured
    /// `Value` cannot be clipped in place), with `arguments_truncated = true`.
    fn capture_tool_call_args(call: &ToolCall, max: usize) -> ToolCallContent {
        let serialized = call.input.to_string();
        let (clipped, truncated) = truncate_field(&serialized, max);
        let arguments = if truncated {
            serde_json::Value::String(clipped)
        } else {
            call.input.clone()
        };
        ToolCallContent {
            name: call.name.clone(),
            arguments,
            arguments_truncated: truncated,
        }
    }

    /// Snapshot the assembled INPUT messages (the full prompt the model saw)
    /// into [`GenAiMessage`]s for LLM-native tracing (issue #64). Each message's
    /// [`Role`] maps to the conventional [`GenAiRole`]; the [`Content`] is
    /// rendered to a plain string and truncated to `max` bytes:
    ///   - `Text { text }`        → the text verbatim
    ///   - `ToolResult(tr)`       → `tr.content` (role stays `Tool`)
    ///   - `ToolCall(tc)`         → `"<name> <compact-json-args>"` (assistant)
    ///   - `Image { media_type }` → `"[image <media_type>]"` — NEVER the base64
    ///
    /// System-first, then history order is preserved because the assembled
    /// `messages` already lead with the `Role::System` prompt.
    fn capture_input_messages(messages: &[Message], max: usize) -> Vec<GenAiMessage> {
        messages
            .iter()
            .map(|m| {
                let role = match m.role {
                    Role::System => GenAiRole::System,
                    Role::User => GenAiRole::User,
                    Role::Assistant => GenAiRole::Assistant,
                    Role::Tool => GenAiRole::Tool,
                };
                let rendered = match &m.content {
                    Content::Text { text } => text.clone(),
                    Content::ToolResult(tr) => tr.content.clone(),
                    Content::ToolCall(tc) => {
                        format!("{} {}", tc.name, tc.input)
                    }
                    // NEVER dump the base64 `data` — placeholder only.
                    Content::Image { media_type, .. } => format!("[image {media_type}]"),
                };
                let (content, truncated) = truncate_field(&rendered, max);
                GenAiMessage {
                    role,
                    content,
                    truncated,
                }
            })
            .collect()
    }

    /// Enrich a recoverable tool-error message that survived (or was not
    /// eligible for) repair, so the model gets actionable feedback instead of a
    /// bare serde message. Appends the tool's parameter schema (when available)
    /// plus a short hint about supplying correctly-typed JSON arguments.
    fn enrich_tool_error(message: &str, schema: Option<&ToolSchema>) -> ToolOutput {
        let mut enriched = message.to_string();
        if let Some(schema) = schema {
            if let Ok(schema_json) = serde_json::to_string(&schema.input_schema) {
                enriched.push_str("\n\nExpected parameter schema: ");
                enriched.push_str(&schema_json);
            }
        }
        enriched.push_str(
            "\n\nHint: provide arguments as correctly-typed JSON \
             (e.g. true/false as a bool, 42 as a number, [\"a\"] as an array) \
             rather than as quoted strings.",
        );
        ToolOutput::Error {
            message: enriched,
            recoverable: true,
        }
    }

    fn budget_exceeded(
        budget: &BudgetLimits,
        used: &BudgetSnapshot,
        started_at: Instant,
    ) -> Option<BudgetLimitType> {
        if let Some(max) = budget.max_turns {
            if used.turns >= max {
                return Some(BudgetLimitType::Turns);
            }
        }
        if let Some(max) = budget.max_input_tokens {
            if used.input_tokens > max as u64 {
                return Some(BudgetLimitType::InputTokens);
            }
        }
        if let Some(max) = budget.max_output_tokens {
            if used.output_tokens > max as u64 {
                return Some(BudgetLimitType::OutputTokens);
            }
        }
        if let Some(max) = budget.max_wall_time {
            if started_at.elapsed() >= max {
                return Some(BudgetLimitType::WallTime);
            }
        }
        if let Some(max) = budget.max_cost_usd {
            if used.cost_usd > max {
                return Some(BudgetLimitType::CostUsd);
            }
        }
        None
    }

    /// Record the terminal outcome and flush the observability session. Called
    /// at every terminal `run_react` outcome (success or any halt) — never on a
    /// `WaitingForHuman` pause, which is not terminal. No-op when no provider is
    /// configured.
    async fn finalize_observability(&self, session_id: &SessionId, outcome: SessionOutcome) {
        if let Some(obs) = self.config.observability.as_ref() {
            obs.set_session_outcome(session_id, outcome);
            obs.flush_session(session_id).await;
        }
    }

    /// Fire registered `Stop` hooks (issue #69, Decision 5/6). Returns
    /// `Some(reason)` when the loop should continue (a hook blocked and the
    /// per-run `max_stop_blocks` cap has not yet been hit), incrementing
    /// `stop_blocks`. Returns `None` to allow normal termination — either no
    /// hooks blocked, no hook chain is configured, or the cap was reached.
    ///
    /// A Stop-hook error (e.g. a failing command handler) is treated as a
    /// non-blocking outcome: the loop terminates normally rather than looping
    /// forever on a broken hook.
    async fn fire_stop_hooks(
        &self,
        session_id: &SessionId,
        task: &Task,
        turn_number: u32,
        last_output_text: &str,
        stop_blocks: &mut u32,
    ) -> Option<String> {
        let chain = self.config.hooks.as_ref()?;
        // Build the rich SessionState the Stop contract requires from the data
        // the ReAct loop has on hand.
        let rich_state = ContextSessionState::new(
            session_id.clone(),
            task.id.clone(),
            task.instruction.clone(),
        );
        let last_output = crate::hooks::TurnOutput {
            text: last_output_text.to_string(),
            had_tool_calls: false,
        };
        let mut ctx = crate::hooks::HookContext::Stop {
            session_id,
            turn_number,
            last_output: &last_output,
            task_instruction: &task.instruction,
            session_state: &rich_state,
        };
        match chain.fire(&mut ctx).await {
            Ok(crate::hooks::FireOutcome::Block { reason }) => {
                if *stop_blocks >= self.config.max_stop_blocks {
                    // R14: cap reached — terminate anyway.
                    None
                } else {
                    *stop_blocks += 1;
                    Some(reason)
                }
            }
            // Continue / Inject / Deny / errors → allow normal termination.
            _ => None,
        }
    }

    /// Drive the ReAct loop, then finalize observability for terminal outcomes.
    /// A `WaitingForHuman` pause is not terminal, so it is never flushed here —
    /// the eventual `resume` path reaches a terminal outcome and flushes then.
    /// Resolve the worker agent for a [`LoopStrategy`] tree from the
    /// [`ExecutionRegistry`] (#124). The worker is the agent on the LEAF reached
    /// by descending the recursion: a `ReAct` leaf's `agent`; a combinator
    /// descends into its primary worker child (`inner` / `execute`). A `Ralph`
    /// with a non-empty `agent` override resolves THAT (Q3). Returns the resolved
    /// agent, or a typed `UnresolvedHandle` failure carried as `Err`.
    fn resolve_worker_agent(&self, ls: &LoopStrategy) -> Result<Arc<dyn Agent>, HarnessError> {
        let key = self.worker_agent_key(ls);
        self.config
            .registry
            .resolve_agent(&AgentRef(key.clone()))
            .cloned()
            .ok_or(HarnessError::UnresolvedHandle {
                kind: "agent".to_string(),
                key,
            })
    }

    /// The agent key the worker leaf of `ls` references (see
    /// [`resolve_worker_agent`](Self::resolve_worker_agent)).
    fn worker_agent_key(&self, ls: &LoopStrategy) -> String {
        match ls {
            LoopStrategy::ReAct(c) => c.agent.0.clone(),
            LoopStrategy::PlanExecute(c) => self.worker_agent_key(&c.execute),
            LoopStrategy::SelfVerifying(c) => self.worker_agent_key(&c.inner),
            LoopStrategy::Ralph(c) => {
                if c.agent.0.is_empty() {
                    self.worker_agent_key(&c.inner)
                } else {
                    c.agent.0.clone()
                }
            }
            LoopStrategy::HillClimbing(c) => self.worker_agent_key(&c.inner),
        }
    }

    #[allow(clippy::too_many_arguments)]
    async fn run_react(
        &self,
        task: Task,
        max_iterations: u32,
        session_state: SessionState,
        budget_used: BudgetSnapshot,
        on_stream: Option<StreamSink>,
        agent: Arc<dyn Agent>,
        // Issue 2: the RESOLVED per-node toolset handle. Most `run_react`
        // wrappers (PlanExecute/DAG execute steps, single-shot run) pass the
        // empty handle (`ToolsetRef("")`) ⇒ global-catalogue fallback, byte-for-
        // byte with pre-Issue-2 behaviour. The SelfVerifying evaluate phase
        // passes its `eval_toolset` so the reviewer is scoped to read-only tools.
        toolset: ToolsetRef,
    ) -> RunResult {
        let result = self
            .run_react_inner(
                task,
                max_iterations,
                session_state,
                budget_used,
                on_stream,
                agent,
                toolset,
                // Issue #139: the legacy `run_react` wrapper does NOT enforce
                // output schemas (the recursive `ReactConfig::run` is the single
                // enforcement seam). `None`/`0` ⇒ byte-for-byte pre-#139.
                None,
                0,
            )
            .await;
        match &result {
            RunResult::Success { session_id, .. } => {
                self.finalize_observability(session_id, SessionOutcome::Success)
                    .await;
            }
            RunResult::Failure {
                session_id, reason, ..
            } => {
                self.finalize_observability(
                    session_id,
                    SessionOutcome::Failure {
                        reason: format!("{reason:?}"),
                    },
                )
                .await;
            }
            RunResult::WaitingForHuman { .. } => {}
            // Consult (issue #114) is NOT terminal — like WaitingForHuman, the
            // worker is paused awaiting a resume. Do not finalize observability.
            RunResult::Consult { .. } => {}
            // Escalation (issue #80) IS a terminal outcome — the harness has
            // run to a clean stop and handed a signal up. Finalize
            // observability with the dedicated `Escalated` outcome (NOT
            // `Partial`). Contrast WaitingForHuman, which is NOT terminal.
            RunResult::Escalate { session_id, .. } => {
                self.finalize_observability(session_id, SessionOutcome::Escalated)
                    .await;
            }
        }
        result
    }

    /// The harness-loop tool registry to use for a run keyed by `session_id`.
    ///
    /// When catalogue tools were added via [`HarnessBuilder::tool`] / `tools`,
    /// this bridges the folded [`StandardToolRegistry`] through
    /// [`RealToolRegistry`](crate::tool_registry::RealToolRegistry) — built
    /// fresh per run so the run's `SessionId` + storage thread into every tool
    /// dispatch. Otherwise it returns the injected
    /// [`tool_registry`](HarnessConfig::tool_registry) seam unchanged.
    /// Issue 2 (per-node toolset scoping): `toolset` is the resolving leaf's
    /// `ToolsetRef` handle. When it is NON-EMPTY and a per-key catalogue was
    /// registered via [`HarnessBuilder::toolset_tools`], THAT catalogue is
    /// bridged (so the node dispatches ONLY its own tools — strict scoping).
    /// Otherwise (empty handle, or non-empty handle with no per-key catalogue)
    /// the existing global-catalogue / `tool_registry` seam fallback applies, so
    /// examples 01–11 that use `.tools()` keep working byte-for-byte.
    fn effective_tool_registry(
        &self,
        session_id: &SessionId,
        toolset: &ToolsetRef,
    ) -> Arc<dyn ToolRegistry> {
        // Strict per-node scoping: a non-empty handle with its own catalogue.
        if !toolset.0.is_empty() {
            if let Some(catalogue) = self.config.toolset_catalogues.get(&toolset.0) {
                return Arc::new(crate::tool_registry::RealToolRegistry::new(
                    catalogue.clone(),
                    self.config.sandbox.clone(),
                    session_id.clone(),
                    self.config.project_id.clone(),
                    self.config.storage.run().clone(),
                    self.config.storage.memory().clone(),
                ));
            }
        }
        // Fallback: empty handle (back-compat) or unregistered non-empty handle.
        match &self.config.catalogue_registry {
            Some(catalogue) => Arc::new(crate::tool_registry::RealToolRegistry::new(
                catalogue.clone(),
                self.config.sandbox.clone(),
                session_id.clone(),
                self.config.project_id.clone(),
                self.config.storage.run().clone(),
                self.config.storage.memory().clone(),
            )),
            None => self.config.tool_registry.clone(),
        }
    }

    #[allow(clippy::too_many_arguments)]
    #[allow(clippy::too_many_arguments)]
    async fn run_react_inner(
        &self,
        task: Task,
        max_iterations: u32,
        mut session_state: SessionState,
        mut budget_used: BudgetSnapshot,
        on_stream: Option<StreamSink>,
        // #124: the worker agent is RESOLVED by the caller (the recursing
        // `ReactConfig::run` resolves `self.agent` from the registry; Ralph may
        // override it per window). The leaf no longer reads `config.agent`.
        agent: Arc<dyn Agent>,
        // Issue 2: the leaf's RESOLVED `toolset` handle (mirrors `agent`). Empty
        // (`""`) ⇒ global-catalogue fallback; a non-empty handle with its own
        // per-key catalogue ⇒ strict per-node scoping.
        toolset: ToolsetRef,
        // Issue #139: the leaf's RESOLVED output schema (`None` ⇒ no enforcement,
        // identical to pre-#139 behavior). When `Some`, the terminal is validated
        // against it (frozen validator subset) and a validation failure feeds the
        // error back + retries up to `output_schema_max_retries` extra turns
        // WITHIN budget; on exhaustion WITH budget remaining the window returns
        // `HaltReason::OutputSchemaViolation`. The schema is also set on every
        // turn's `ModelParams.output_schema` so the Ollama `format` channel
        // constrains decoding (Anthropic/OpenAI ignore it).
        output_schema: Option<serde_json::Value>,
        output_schema_max_retries: u32,
    ) -> RunResult {
        let session_id = task.session_id.clone();
        // Resolve the effective tool registry once per turn-loop window (all
        // strategies funnel through here). Bridges the per-node toolset catalogue
        // (or the global catalogue when the handle is empty) per-run.
        let tool_registry = self.effective_tool_registry(&session_id, &toolset);
        // Reset the adaptive prompt-based-tool-calling escalation flag at the
        // start of this turn-loop window so detection is scoped to the window
        // and does not leak across `run()` calls (the flag is shared with the
        // model wrapper for the harness's lifetime). No-op unless a
        // `conversational` harness installed the adaptive wrapper.
        if let Some(flag) = self.config.prompt_tool_call_flag.as_ref() {
            flag.store(false, std::sync::atomic::Ordering::Release);
        }
        let started_at = Instant::now();
        let mut usage = AggregateUsage::default();
        // Per-run Stop-hook block counter (issue #69, Decision 4). Resets on
        // every run() — resume starts fresh. After `max_stop_blocks` consecutive
        // blocks the loop terminates anyway (R14).
        let mut stop_blocks: u32 = 0;
        // Consecutive-recoverable-tool-error breaker state (issue #137), keyed
        // by tool name. Loop-local to this window: a fresh `run()`/re-driven
        // `Continue` window starts with a clean N/2N allowance (AC3 Continue
        // reset). `N` is `error_loop_threshold`; the hard stop is at `2 * N`.
        let error_loop_n = self.config.error_loop_threshold;
        let mut error_runs: std::collections::HashMap<String, ErrorRun> =
            std::collections::HashMap::new();
        // Output-schema enforcement state (issue #139), loop-local to this
        // window. `output_schema_retries_used` counts the EXTRA retry turns spent
        // on validation feedback; the budget for them is `output_schema_max_retries`
        // (the `N`). `last_schema_error` holds the most recent frozen validator
        // error so a final exhaustion can report it. Both are inert when
        // `output_schema` is `None` (enforcement OFF / no schema).
        let mut output_schema_retries_used: u32 = 0;
        // Set on every validation failure before it is read in the violation
        // terminal; the initial empty value is never observed.
        #[allow(unused_assignments)]
        let mut last_schema_error: String = String::new();
        // Monotonic per-run span counter for turn / tool-call span ids, and the
        // most recent turn span — parent for the tool-call spans of that turn.
        let mut span_seq: u64 = 0;
        // Set on every turn before any tool dispatch; the initial `None` only
        // covers the (unreachable) case of a tool span with no preceding turn.
        #[allow(unused_assignments)]
        let mut current_turn_base: Option<SpanBase> = None;
        let effective_turn_cap = match task.budget.max_turns {
            Some(t) => t.min(max_iterations),
            None => max_iterations,
        };

        loop {
            // Layer-1 budget gates before the turn.
            if budget_used.turns >= effective_turn_cap {
                return RunResult::Failure {
                    reason: HaltReason::BudgetExceeded {
                        limit_type: BudgetLimitType::Turns,
                    },
                    session_id,
                    usage,
                    turns: budget_used.turns,
                    session_state: session_state.clone(),
                };
            }
            if let Some(limit_type) = Self::budget_exceeded(&task.budget, &budget_used, started_at)
            {
                return RunResult::Failure {
                    reason: HaltReason::BudgetExceeded { limit_type },
                    session_id,
                    usage,
                    turns: budget_used.turns,
                    session_state: session_state.clone(),
                };
            }

            // Middleware: BeforeTurn.
            if let Some(mw) = self.config.middleware.as_ref() {
                match mw.fire(HookPoint::BeforeTurn, &session_state).await {
                    MiddlewareDecision::Continue => {}
                    MiddlewareDecision::ContinueWithModification { .. } => {}
                    MiddlewareDecision::Halt { reason } => {
                        return RunResult::Failure {
                            reason: HaltReason::MiddlewareHalt {
                                hook: HookPoint::BeforeTurn,
                                reason,
                            },
                            session_id,
                            usage,
                            turns: budget_used.turns,
                            session_state: session_state.clone(),
                        };
                    }
                    MiddlewareDecision::SurfaceToHuman { request } => {
                        let state = PausedState {
                            session_id: session_id.clone(),
                            task_id: task.id.clone(),
                            turn_number: budget_used.turns,
                            session_state,
                            pending_tool_calls: vec![],
                            approved_results: vec![],
                            human_request: Some(request.clone()),
                            task,
                            budget_used,
                            child_state: None,
                            // #140: carry this leaf's toolset handle so resume
                            // routes through its scoped catalogue.
                            toolset: toolset.clone(),
                        };
                        return RunResult::WaitingForHuman {
                            state: Box::new(state),
                            request,
                        };
                    }
                }
            }

            // Assemble + invoke agent for one turn.
            let mut context = self
                .config
                .context_manager
                .assemble(&session_state, &task)
                .await;
            // Deliver the registry's tool schemas to the model. Tool schemas are
            // owned by the `ToolRegistry`; the harness wires them into the
            // assembled context so the model knows what it can call. Only fill
            // when the context manager left `tools` empty (the standard
            // compaction adapter does), so a context manager that deliberately
            // sets a phase-specific tool subset is preserved.
            if context.tools.is_empty() {
                context.tools = tool_registry.schemas();
            }
            // Prepend the configured operating system prompt (issue #91). The
            // standard compaction adapter renders none, so without this the
            // model gets only the task and no guidance. Guard against duplicates
            // so a context manager that already leads with a System message (or
            // a resumed/seeded session) isn't given two.
            if let Some(system_prompt) = self.config.system_prompt.as_ref() {
                let has_system = context
                    .messages
                    .first()
                    .is_some_and(|m| matches!(m.role, Role::System));
                if !has_system {
                    context.messages.insert(
                        0,
                        Message {
                            role: Role::System,
                            content: Content::Text {
                                text: system_prompt.clone(),
                            },
                        },
                    );
                }
            }
            // Per-run model params win unconditionally (issue #93). The agent
            // copies `Context.params` verbatim into the `ModelRequest`, so this
            // is the single seam that delivers configured params (e.g.
            // structured tool calls) to every tool-requesting ReAct/execute/
            // streaming turn.
            context.params = self.config.model_params.clone();
            // Issue #139: route the enforced output schema into this turn's
            // constrained-decoding channel (`ModelParams.output_schema`). Ollama
            // honors it via `format`; Anthropic/OpenAI ignore it (no-op, like
            // `structured_tool_calls`). `None` leaves the params byte-identical.
            if output_schema.is_some() {
                context.params.output_schema = output_schema.clone();
            }
            // Whether tools were advertised to the model this turn — a
            // precondition for classifying a prose final response as a missed
            // tool call (adaptive prompt-based escalation). Captured before
            // `context` is moved into the turn.
            let tools_advertised = !context.tools.is_empty();
            Self::emit(
                &on_stream,
                StreamEvent::TurnStart {
                    turn: budget_used.turns + 1,
                    node: None,
                },
            );
            let turn_started_at = Timestamp::now();
            let turn_clock = Instant::now();
            // LLM-native content capture (issue #64): snapshot the assembled
            // INPUT messages (the full prompt the model saw) BEFORE `context`
            // is moved into `agent.turn`. Zero-cost when the guard is off (no
            // clone of the message history).
            let input_messages = if self.config.content_capture.enabled {
                Some(Self::capture_input_messages(
                    &context.messages,
                    self.config.content_capture.max_field_len,
                ))
            } else {
                None
            };
            // Delta-level streaming (issue #103): when a user-facing stream sink
            // is attached, drive the turn through `turn_streaming` and forward each
            // raw `model::StreamEvent` mapped to harness `StreamEvent`s.
            //
            // #stream: the sink is now an `Arc` (cloneable), so the adapter forwards
            // each mapped event to it LIVE — the instant the model emits it — rather
            // than buffering and flushing post-turn (the old `Box`-can't-be-shared
            // workaround). This is what makes token-by-token SSE / mid-turn cancel
            // observable. `TurnStreamState` (block + call-id correlation) lives
            // behind a Mutex shared with the adapter; we map UNDER the lock, RELEASE
            // it, then forward — never running the user sink under the lock (a
            // re-entrant sink would deadlock). Order is preserved: TurnStart (emitted
            // below, before the turn) → live deltas → TurnEnd → coarse events.
            // When no sink is attached we keep the plain `turn` path so the baseline
            // RunResult is byte-identical (back-compat).
            let result = if let Some(sink) = on_stream.clone() {
                let state = std::sync::Arc::new(std::sync::Mutex::new(TurnStreamState::default()));
                let adapter: crate::agent::AgentStreamSink = Box::new(move |ev| {
                    let mapped = {
                        let mut guard = state.lock().expect("stream state poisoned");
                        Self::map_model_stream_event(ev, &mut guard)
                    };
                    for m in mapped {
                        sink(m);
                    }
                });
                agent.turn_streaming(context, adapter).await
            } else {
                agent.turn(context).await
            };
            budget_used.turns += 1;
            // Emit a turn span for every model call (issue #12). Fire-and-forget;
            // it never affects control flow. The span base is retained as the
            // parent for any tool-call spans dispatched this turn.
            {
                let zero = TokenUsage::default();
                let u = match &result {
                    TurnResult::ToolCallRequested { usage, .. }
                    | TurnResult::FinalResponse { usage, .. } => usage,
                    TurnResult::Error { usage, .. } => usage.as_ref().unwrap_or(&zero),
                };
                let (stop_reason, tool_calls_requested) = match &result {
                    TurnResult::FinalResponse { .. } => (StopReason::EndTurn, 0),
                    TurnResult::ToolCallRequested { calls, .. } => {
                        (StopReason::ToolUse, calls.len() as u32)
                    }
                    TurnResult::Error { .. } => (StopReason::EndTurn, 0),
                };
                let mut base = SpanBase::new_root(
                    SpanId::new(format!(
                        "{}-turn-{}",
                        session_id.as_str(),
                        budget_used.turns
                    )),
                    session_id.clone(),
                    task.id.clone(),
                    SpanKind::Turn,
                    turn_started_at,
                );
                let status = match &result {
                    TurnResult::Error { error, .. } => SpanStatus::Error {
                        message: format!("{error:?}"),
                    },
                    _ => SpanStatus::Ok,
                };
                base.finish(
                    Timestamp::now(),
                    status,
                    turn_clock.elapsed().as_millis() as u64,
                );
                if let Some(obs) = self.config.observability.as_ref() {
                    // LLM-native content capture (issue #64): output text +
                    // requested tool calls, ONLY when the guard is enabled.
                    // Decision 4: turn span carries output + tool calls; no
                    // assembled input-message history.
                    let cc = &self.config.content_capture;
                    let (output_text, tool_calls) = if cc.enabled {
                        let output_text = match &result {
                            TurnResult::FinalResponse { content, .. } => {
                                let (content, truncated) =
                                    truncate_field(content, cc.max_field_len);
                                Some(GenAiMessage {
                                    role: GenAiRole::Assistant,
                                    content,
                                    truncated,
                                })
                            }
                            _ => None,
                        };
                        let tool_calls = match &result {
                            TurnResult::ToolCallRequested { calls, .. } => Some(
                                calls
                                    .iter()
                                    .map(|c| Self::capture_tool_call_args(c, cc.max_field_len))
                                    .collect(),
                            ),
                            _ => None,
                        };
                        (output_text, tool_calls)
                    } else {
                        (None, None)
                    };
                    obs.emit_turn(TurnSpan {
                        base: base.clone(),
                        turn_number: budget_used.turns,
                        input_tokens: u.input_tokens,
                        output_tokens: u.output_tokens,
                        cache_read_tokens: u.cache_read_tokens,
                        cache_write_tokens: u.cache_write_tokens,
                        cost_usd: self.config.pricing.cost_for(
                            u.input_tokens,
                            u.output_tokens,
                            u.cache_read_tokens,
                            u.cache_write_tokens,
                        ),
                        stop_reason,
                        tool_calls_requested,
                        output_text,
                        tool_calls,
                        input_messages,
                    });
                }
                span_seq += 1;
                current_turn_base = Some(base);
            }
            Self::emit(
                &on_stream,
                StreamEvent::TurnEnd {
                    turn: budget_used.turns,
                    node: None,
                },
            );

            match result {
                TurnResult::FinalResponse {
                    content, usage: u, ..
                } => {
                    usage.add_turn(&u);
                    budget_used.input_tokens += u.input_tokens as u64;
                    budget_used.output_tokens += u.output_tokens as u64;

                    // Adaptive prompt-based tool-calling escalation. When tools
                    // were advertised but the model answered in prose with
                    // action-intent language (it *meant* to act), classify the
                    // turn as a `ProseResponse` failure and escalate: set the
                    // session flag so the wrapped model switches to prompt-based
                    // tool calling, nudge the model, and force another turn
                    // instead of completing. Guarded on the flag being unset so
                    // it fires at most once per window (bounded — one extra
                    // turn) and only on the `conversational` adaptive path.
                    if let Some(flag) = self.config.prompt_tool_call_flag.as_ref() {
                        let already_escalated = flag.load(std::sync::atomic::Ordering::Acquire);
                        if !already_escalated
                            && crate::tool_call_repair::detect_prose_response(
                                &content,
                                tools_advertised,
                            )
                            .is_some()
                        {
                            flag.store(true, std::sync::atomic::Ordering::Release);
                            // Record the model's prose, then a corrective nudge,
                            // so the next turn has coherent context.
                            let assistant = Message {
                                role: Role::Assistant,
                                content: Content::Text {
                                    text: content.clone(),
                                },
                            };
                            self.config
                                .context_manager
                                .append_assistant_message(&mut session_state, &assistant)
                                .await;
                            let nudge = "You described an action but did not call a \
tool. Use the provided tool-call format to actually invoke the tool."
                                .to_string();
                            self.config
                                .context_manager
                                .append_user_message(&mut session_state, &nudge)
                                .await;
                            continue;
                        }
                    }

                    if let Some(mw) = self.config.middleware.as_ref() {
                        match mw.fire(HookPoint::BeforeCompletion, &session_state).await {
                            MiddlewareDecision::Continue => {}
                            MiddlewareDecision::ContinueWithModification { .. } => {}
                            MiddlewareDecision::Halt { reason } => {
                                return RunResult::Failure {
                                    reason: HaltReason::MiddlewareHalt {
                                        hook: HookPoint::BeforeCompletion,
                                        reason,
                                    },
                                    session_id,
                                    usage,
                                    turns: budget_used.turns,
                                    session_state: session_state.clone(),
                                };
                            }
                            MiddlewareDecision::SurfaceToHuman { request } => {
                                let state = PausedState {
                                    session_id: session_id.clone(),
                                    task_id: task.id.clone(),
                                    turn_number: budget_used.turns,
                                    session_state,
                                    pending_tool_calls: vec![],
                                    approved_results: vec![],
                                    human_request: Some(request.clone()),
                                    task,
                                    budget_used,
                                    child_state: None,
                                    // #140: carry this leaf's toolset handle so
                                    // resume routes through its scoped catalogue.
                                    toolset: toolset.clone(),
                                };
                                return RunResult::WaitingForHuman {
                                    state: Box::new(state),
                                    request,
                                };
                            }
                        }
                    }

                    match self
                        .config
                        .termination_policy
                        .evaluate(&session_state, &budget_used)
                        .await
                    {
                        TerminationDecision::Halt { reason } => {
                            return RunResult::Failure {
                                reason: HaltReason::TerminationPolicyHalt { reason },
                                session_id,
                                usage,
                                turns: budget_used.turns,
                                session_state: session_state.clone(),
                            };
                        }
                        TerminationDecision::Continue => {
                            // Record the assistant's final text in history so a
                            // continued session reflects what the agent said.
                            let msg = Message {
                                role: Role::Assistant,
                                content: Content::Text {
                                    text: content.clone(),
                                },
                            };
                            self.config
                                .context_manager
                                .append_assistant_message(&mut session_state, &msg)
                                .await;

                            // Stop hook (issue #69, Decision 5). The strategy
                            // believes the task is done; fire registered Stop
                            // hooks synchronously. If any blocks (and we are
                            // under `max_stop_blocks`), inject the reason via
                            // the same path `ForceAnotherTurn` uses and continue
                            // the loop instead of terminating.
                            if let Some(reason) = self
                                .fire_stop_hooks(
                                    &session_id,
                                    &task,
                                    budget_used.turns,
                                    &content,
                                    &mut stop_blocks,
                                )
                                .await
                            {
                                self.config
                                    .context_manager
                                    .append_user_message(&mut session_state, &reason)
                                    .await;
                                continue;
                            }

                            // Output-schema enforcement gate (issue #139).
                            // Additive to and EARLIER than the Success terminal:
                            // when a schema is active, validate this terminal
                            // `FinalResponse`. On a validation FAILURE, feed the
                            // frozen error back as a USER message and retry one
                            // more turn (up to `output_schema_max_retries` extra
                            // turns). The retried turn re-enters the loop top,
                            // where the budget gate fires FIRST — so a retry that
                            // would exceed the turn/budget backstop surfaces the
                            // existing `BudgetExceeded` terminal, NOT
                            // `OutputSchemaViolation` (budget-cap-wins, Q2). Only
                            // when the N retries are exhausted WITH budget
                            // remaining does the window terminate with
                            // `OutputSchemaViolation`. `None` schema ⇒ no
                            // validation (migration gate OFF / no `output`), so
                            // the terminal is byte-identical to pre-#139.
                            if let Some(schema) = output_schema.as_ref() {
                                if let Err(verr) =
                                    crate::output_schema::validate_output(&content, schema)
                                {
                                    last_schema_error = verr.clone();
                                    if output_schema_retries_used < output_schema_max_retries {
                                        // Grant one more turn: feed the validator
                                        // error back as a USER message (the
                                        // assistant's invalid text is already in
                                        // history above) and loop. The budget gate
                                        // at the loop top enforces Q2 precedence.
                                        output_schema_retries_used += 1;
                                        Self::emit(
                                            &on_stream,
                                            StreamEvent::OutputSchemaRetry {
                                                attempt: output_schema_retries_used,
                                                error: verr.clone(),
                                                node: None,
                                            },
                                        );
                                        if let Some(obs) = self.config.observability.as_ref() {
                                            let base = SpanBase::new_root(
                                                SpanId::new(format!(
                                                    "{}-output-schema-retry-{}",
                                                    session_id.as_str(),
                                                    span_seq
                                                )),
                                                session_id.clone(),
                                                task.id.clone(),
                                                SpanKind::ContextAssembly,
                                                Timestamp::now(),
                                            );
                                            obs.emit_context(ContextSpan {
                                                base,
                                                operation: ContextOperation::OutputSchemaRetry {
                                                    attempt: output_schema_retries_used,
                                                    error: verr.clone(),
                                                },
                                                tokens_before: 0,
                                                tokens_after: 0,
                                                utilization_before: 0.0,
                                                utilization_after: 0.0,
                                            });
                                        }
                                        let feedback =
                                            crate::output_schema::feedback_message(&verr);
                                        self.config
                                            .context_manager
                                            .append_user_message(&mut session_state, &feedback)
                                            .await;
                                        continue;
                                    }
                                    // Retries exhausted WITH budget remaining
                                    // (the budget gate did not fire) → the typed
                                    // schema-violation terminal (Q2/AC3). Total
                                    // attempts = 1 + max_retries.
                                    let attempts = output_schema_max_retries + 1;
                                    Self::emit(
                                        &on_stream,
                                        StreamEvent::OutputSchemaViolation {
                                            attempts,
                                            error: last_schema_error.clone(),
                                            node: None,
                                        },
                                    );
                                    if let Some(obs) = self.config.observability.as_ref() {
                                        let base = SpanBase::new_root(
                                            SpanId::new(format!(
                                                "{}-output-schema-violation-{}",
                                                session_id.as_str(),
                                                span_seq
                                            )),
                                            session_id.clone(),
                                            task.id.clone(),
                                            SpanKind::ContextAssembly,
                                            Timestamp::now(),
                                        );
                                        obs.emit_context(ContextSpan {
                                            base,
                                            operation: ContextOperation::OutputSchemaViolation {
                                                attempts,
                                                error: last_schema_error.clone(),
                                            },
                                            tokens_before: 0,
                                            tokens_after: 0,
                                            utilization_before: 0.0,
                                            utilization_after: 0.0,
                                        });
                                    }
                                    return RunResult::Failure {
                                        reason: HaltReason::OutputSchemaViolation {
                                            schema: crate::model::canonicalize_json(schema),
                                            attempts,
                                            last_error: last_schema_error.clone(),
                                        },
                                        session_id,
                                        usage,
                                        turns: budget_used.turns,
                                        session_state: session_state.clone(),
                                    };
                                }
                            }

                            Self::emit(
                                &on_stream,
                                StreamEvent::FinalResponse {
                                    content: content.clone(),
                                    node: None,
                                },
                            );
                            return RunResult::Success {
                                output: content,
                                session_id,
                                usage,
                                turns: budget_used.turns,
                                session_state: session_state.clone(),
                            };
                        }
                    }
                }

                TurnResult::ToolCallRequested {
                    calls, usage: u, ..
                } => {
                    usage.add_turn(&u);
                    budget_used.input_tokens += u.input_tokens as u64;
                    budget_used.output_tokens += u.output_tokens as u64;

                    // Always-halt short circuit (Layer 1).
                    if let Some(c) = calls.iter().find(|c| tool_registry.is_always_halt(&c.name)) {
                        return RunResult::Failure {
                            reason: HaltReason::UnrecoverableToolError {
                                tool: c.name.clone(),
                                error: "tool is annotated always_halt".into(),
                            },
                            session_id,
                            usage,
                            turns: budget_used.turns,
                            session_state: session_state.clone(),
                        };
                    }

                    // Record the assistant's turn (the tool calls the model
                    // requested) as soon as the calls are known — BEFORE the
                    // BeforeTool middleware (which may pause via SurfaceToHuman)
                    // and before any tool result. This keeps the conversation
                    // well-formed (assistant tool_use precedes its tool result)
                    // on every path, including human-in-the-loop resume, so
                    // resume_inner never has to append it. The recorded turn
                    // reflects the model's original request; a middleware or
                    // human modification changes only what is dispatched.
                    for call in &calls {
                        let msg = Message {
                            role: Role::Assistant,
                            content: Content::ToolCall(call.clone()),
                        };
                        self.config
                            .context_manager
                            .append_assistant_message(&mut session_state, &msg)
                            .await;
                    }

                    // Middleware: BeforeTool.
                    let calls = match self.config.middleware.as_ref() {
                        None => calls,
                        Some(mw) => match mw.fire(HookPoint::BeforeTool, &session_state).await {
                            MiddlewareDecision::Continue => calls,
                            MiddlewareDecision::ContinueWithModification { calls: modified } => {
                                modified
                            }
                            MiddlewareDecision::Halt { reason } => {
                                return RunResult::Failure {
                                    reason: HaltReason::MiddlewareHalt {
                                        hook: HookPoint::BeforeTool,
                                        reason,
                                    },
                                    session_id,
                                    usage,
                                    turns: budget_used.turns,
                                    session_state: session_state.clone(),
                                };
                            }
                            MiddlewareDecision::SurfaceToHuman { request } => {
                                let state = PausedState {
                                    session_id: session_id.clone(),
                                    task_id: task.id.clone(),
                                    turn_number: budget_used.turns,
                                    session_state,
                                    pending_tool_calls: calls,
                                    approved_results: vec![],
                                    human_request: Some(request.clone()),
                                    task,
                                    budget_used,
                                    child_state: None,
                                    // #140: carry this leaf's toolset handle so
                                    // resume routes through its scoped catalogue.
                                    toolset: toolset.clone(),
                                };
                                return RunResult::WaitingForHuman {
                                    state: Box::new(state),
                                    request,
                                };
                            }
                        },
                    };

                    let mut approved_results: Vec<ToolResult> = Vec::new();
                    for (i, call) in calls.iter().enumerate() {
                        // Sandbox validation. The pre-dispatch `validate` seam
                        // honours the SAME policy as tool-surfaced violations
                        // (`sandbox_violation_halts`): halt only under `Halt` for
                        // an always-halt-eligible violation; otherwise recoverable.
                        if let Err(violation) = self.config.sandbox.validate(call).await {
                            if self.sandbox_violation_halts(&violation) {
                                return RunResult::Failure {
                                    reason: HaltReason::SandboxViolation { violation },
                                    session_id,
                                    usage,
                                    turns: budget_used.turns,
                                    session_state: session_state.clone(),
                                };
                            }
                            // Recoverable — append as tool error.
                            let tr = ToolResult {
                                call_id: call.id.clone(),
                                output: ToolOutput::Error {
                                    message: format!("sandbox: {violation:?}"),
                                    recoverable: true,
                                },
                            };
                            Self::emit(
                                &on_stream,
                                StreamEvent::ToolResult {
                                    call_id: call.id.clone(),
                                    is_error: true,
                                    // Q5: carry the result content.
                                    content: format!("sandbox: {violation:?}"),
                                    node: None,
                                },
                            );
                            self.config
                                .context_manager
                                .append_tool_result(&mut session_state, &tr)
                                .await;
                            approved_results.push(tr);
                            continue;
                        }

                        Self::emit(
                            &on_stream,
                            StreamEvent::ToolCall {
                                call_id: call.id.clone(),
                                name: call.name.clone(),
                                // Q5: carry the final tool-call arguments.
                                args: call.input.clone(),
                                node: None,
                            },
                        );
                        let tool_started_at = Timestamp::now();
                        let tool_clock = Instant::now();
                        // `effective_call` is the call actually dispatched. It
                        // starts as the agent's call and may be replaced by a
                        // repaired variant below. Spans/results are stamped from it.
                        let mut effective_call = call.clone();
                        let mut output = tool_registry.dispatch(effective_call.clone()).await;

                        // Tool-call repair (additive): if the dispatch returned a
                        // recoverable error and a repair provider is configured,
                        // try to coerce the arguments and re-dispatch, bounded by
                        // `max_repair_attempts`. If repair gives up or the retry
                        // still errors, fall through to the existing behaviour but
                        // with an enriched error message (schema + hint).
                        if let Some(repair) = self.config.tool_call_repair.as_ref() {
                            let mut attempts_left = self.config.max_repair_attempts;
                            while attempts_left > 0 {
                                let ToolOutput::Error {
                                    ref message,
                                    recoverable: true,
                                } = output
                                else {
                                    break;
                                };
                                let schema = tool_registry
                                    .schemas()
                                    .into_iter()
                                    .find(|s| s.name == effective_call.name);
                                let Some(repaired_call) =
                                    repair.repair(&effective_call, message, schema.as_ref())
                                else {
                                    // Repair gave up: enrich the error fed back to
                                    // the model with the parameter schema + a hint.
                                    output = Self::enrich_tool_error(message, schema.as_ref());
                                    break;
                                };
                                attempts_left -= 1;
                                effective_call = repaired_call;
                                output = tool_registry.dispatch(effective_call.clone()).await;
                                if !matches!(
                                    output,
                                    ToolOutput::Error {
                                        recoverable: true,
                                        ..
                                    }
                                ) {
                                    break;
                                }
                                // Still a recoverable error and no budget left:
                                // enrich before giving up.
                                if attempts_left == 0 {
                                    if let ToolOutput::Error {
                                        message: ref m,
                                        recoverable: true,
                                    } = output
                                    {
                                        let schema = tool_registry
                                            .schemas()
                                            .into_iter()
                                            .find(|s| s.name == effective_call.name);
                                        output = Self::enrich_tool_error(m, schema.as_ref());
                                    }
                                }
                            }
                        }

                        // Tool-surfaced sandbox violation: the HARNESS decides
                        // halt-vs-recoverable per `sandbox_violation_policy`, not
                        // the tool. Under `Halt` an always-halt-eligible violation
                        // ends the run with a typed `HaltReason::SandboxViolation`;
                        // otherwise (the default) it becomes a recoverable error
                        // the model retries from — uniform across every tool.
                        if let ToolOutput::SandboxViolation { violation } = &output {
                            if self.sandbox_violation_halts(violation) {
                                return RunResult::Failure {
                                    reason: HaltReason::SandboxViolation {
                                        violation: violation.clone(),
                                    },
                                    session_id,
                                    usage,
                                    turns: budget_used.turns,
                                    session_state: session_state.clone(),
                                };
                            }
                            let message = format!("sandbox violation: {violation:?}");
                            output = ToolOutput::Error {
                                message,
                                recoverable: true,
                            };
                        }
                        let call = &effective_call;

                        // #126 (AC2): record harness-OBSERVED write/edit paths
                        // from the call ACTUALLY dispatched. This is the single
                        // file-observation point the PlanExecute DAG executor reads
                        // via `take_observed_writes` to build a task's ledger
                        // `files_touched` — never a model-self-reported field.
                        self.observe_write_call(call);

                        // Pause propagation: WaitingForHuman from a subagent tool.
                        if let ToolOutput::WaitingForHuman {
                            child_state,
                            request,
                        } = output
                        {
                            let remaining = calls[i + 1..].to_vec();
                            let state = PausedState {
                                session_id: session_id.clone(),
                                task_id: task.id.clone(),
                                turn_number: budget_used.turns,
                                session_state,
                                pending_tool_calls: remaining,
                                approved_results,
                                human_request: Some(request.clone()),
                                task,
                                budget_used,
                                child_state: Some(*child_state),
                                // #140: the parent leaf's toolset handle (the
                                // child carries its own inside `child_state`).
                                toolset: toolset.clone(),
                            };
                            return RunResult::WaitingForHuman {
                                state: Box::new(state),
                                request,
                            };
                        }

                        // Escalation propagation (issue #80): a tool requests a
                        // structural state change. The harness is a pure
                        // intermediary — it does NOT act on the signal. It
                        // terminates cleanly, preserves session state for a
                        // possible resume, and returns RunResult::Escalate.
                        // The escalation is a control signal, NOT a conversation
                        // turn: it is never appended to message history, and the
                        // remaining tool calls in this batch are preserved into
                        // pending_tool_calls (mirroring WaitingForHuman). The
                        // signal is NOT stored in PausedState, so it is
                        // discarded on resume — the harness never re-acts on it.
                        if let ToolOutput::Escalate { signal } = output {
                            let remaining = calls[i + 1..].to_vec();
                            let turns = budget_used.turns;
                            let state = PausedState {
                                session_id: session_id.clone(),
                                task_id: task.id.clone(),
                                turn_number: budget_used.turns,
                                session_state,
                                pending_tool_calls: remaining,
                                approved_results,
                                human_request: None,
                                task,
                                budget_used,
                                child_state: None,
                                // #140: carry this leaf's toolset handle so resume
                                // routes pending per-node calls through its catalogue.
                                toolset: toolset.clone(),
                            };
                            return RunResult::Escalate {
                                signal,
                                state: Box::new(state),
                                session_id,
                                usage,
                                turns,
                            };
                        }

                        // Clarification pause (issue #81, Q4b): a tool (e.g.
                        // `ask_user_question`) needs a human answer before it can
                        // produce a result. UNLIKE the subagent `WaitingForHuman`
                        // path, there is NO `ChildPausedState`: the loop builds a
                        // `PausedState` directly with `human_request` set to
                        // `Clarification`. The CLARIFYING call itself is preserved
                        // as the head of `pending_tool_calls` (followed by the
                        // remaining batch) so that, on resume, the human's answer
                        // is injected as the tool RESULT for that pending call.
                        if let ToolOutput::AwaitingClarification { question, options } = output {
                            let mut pending = vec![call.clone()];
                            pending.extend_from_slice(&calls[i + 1..]);
                            let request = HumanRequest::Clarification { question, options };
                            let state = PausedState {
                                session_id: session_id.clone(),
                                task_id: task.id.clone(),
                                turn_number: budget_used.turns,
                                session_state,
                                pending_tool_calls: pending,
                                approved_results,
                                human_request: Some(request.clone()),
                                task,
                                budget_used,
                                child_state: None,
                                // #140: carry this leaf's toolset handle so the
                                // preserved clarifying call resumes against its
                                // scoped catalogue.
                                toolset: toolset.clone(),
                            };
                            return RunResult::WaitingForHuman {
                                state: Box::new(state),
                                request,
                            };
                        }

                        // Consult pause (issue #114, R1/R10): a worker-side tool
                        // returns `ToolOutput::Consult { child_state: None, .. }`
                        // to ask for mid-loop help. Like the
                        // `AwaitingClarification` arm, there is NO
                        // `ChildPausedState` at this level — the loop builds a
                        // `PausedState` directly with `human_request: None` and
                        // preserves the CONSULTING call as the head of
                        // `pending_tool_calls` (followed by the remaining batch),
                        // so that on `resume_consult` the helper's answer is
                        // injected as the tool RESULT for that pending call. The
                        // consult is a control signal, NOT a conversation turn:
                        // it is never appended to message history here (R10).
                        if let ToolOutput::Consult { request, .. } = output {
                            // Observability: lightweight consult-spawn event
                            // alongside `SkillInjected`.
                            if let Some(obs) = self.config.observability.as_ref() {
                                let base = SpanBase::new_root(
                                    SpanId::new(format!(
                                        "{}-consult-spawn-{}",
                                        session_id.as_str(),
                                        span_seq
                                    )),
                                    session_id.clone(),
                                    task.id.clone(),
                                    SpanKind::ContextAssembly,
                                    Timestamp::now(),
                                );
                                obs.emit_context(ContextSpan {
                                    base,
                                    operation: ContextOperation::ConsultSpawned {
                                        consult_kind: request.kind.clone(),
                                    },
                                    tokens_before: 0,
                                    tokens_after: 0,
                                    utilization_before: 0.0,
                                    utilization_after: 0.0,
                                });
                                // No `span_seq += 1` here: we return immediately
                                // below, so the increment would be dead.
                            }
                            let mut pending = vec![call.clone()];
                            pending.extend_from_slice(&calls[i + 1..]);
                            let turns = budget_used.turns;
                            let state = PausedState {
                                session_id: session_id.clone(),
                                task_id: task.id.clone(),
                                turn_number: budget_used.turns,
                                session_state,
                                pending_tool_calls: pending,
                                approved_results,
                                human_request: None,
                                task,
                                budget_used,
                                child_state: None,
                                // #140 (THE load-bearing path): carry this leaf's
                                // toolset handle so `resume_consult` routes the
                                // preserved consulting call through its scoped
                                // catalogue instead of the global fallback.
                                toolset: toolset.clone(),
                            };
                            return RunResult::Consult {
                                request,
                                state: Box::new(state),
                                session_id,
                                usage,
                                turns,
                            };
                        }

                        // SendMessage (issue #81): the `send_message` tool surfaces
                        // an out-of-band message to the user. The loop emits a
                        // `StreamEvent::UserMessage` rather than collapsing the
                        // content into a normal tool result, then records a minimal
                        // success result so the loop continues.
                        let output = if call.name == crate::tools::SendMessageTool::NAME {
                            if let ToolOutput::Success { content, .. } = &output {
                                Self::emit(
                                    &on_stream,
                                    StreamEvent::UserMessage {
                                        content: content.clone(),
                                        node: None,
                                    },
                                );
                            }
                            output
                        } else {
                            output
                        };

                        let is_error = matches!(output, ToolOutput::Error { .. });
                        // Layer-2: unrecoverable tool error halts immediately.
                        if let ToolOutput::Error {
                            ref message,
                            recoverable: false,
                        } = output
                        {
                            return RunResult::Failure {
                                reason: HaltReason::UnrecoverableToolError {
                                    tool: call.name.clone(),
                                    error: message.clone(),
                                },
                                session_id,
                                usage,
                                turns: budget_used.turns,
                                session_state: session_state.clone(),
                            };
                        }

                        // ── Consecutive-recoverable-tool-error breaker (#137) ──
                        // `output` here is either a Success or a RECOVERABLE
                        // Error (every other variant early-returned above). On a
                        // success the tool's error run resets (AC1); on a
                        // recoverable error we increment the identical-args run
                        // (AC1 args-variant) and check the N / 2N thresholds.
                        // At N we stash the corrective USER message here and
                        // append it AFTER the tool result below (well-formed
                        // conversation: assistant tool_use → tool result →
                        // corrective user message).
                        let mut pending_corrective: Option<String> = None;
                        if let ToolOutput::Error {
                            recoverable: true, ..
                        } = &output
                        {
                            let run = match error_runs.get_mut(&call.name) {
                                // Same tool, structurally-identical args → extend
                                // the run.
                                Some(existing) if existing.args == call.input => {
                                    existing.count += 1;
                                    existing
                                }
                                // First error, or the args changed → fresh run.
                                _ => error_runs
                                    .entry(call.name.clone())
                                    .insert_entry(ErrorRun {
                                        args: call.input.clone(),
                                        count: 1,
                                        injected: false,
                                    })
                                    .into_mut(),
                            };
                            let count = run.count;
                            let two_n = error_loop_n.saturating_mul(2);

                            // 2N: HARD STOP (AC3). Do NOT append this last tool
                            // result or continue — return a typed terminal that
                            // `ReactConfig::run` routes through the node's
                            // `BudgetExhaustedBehavior` WITHOUT burning the rest
                            // of the budget. The breaker is disabled when N == 0.
                            if error_loop_n > 0 && count >= two_n {
                                // AC4: emit the "broken" pair (stream + obs).
                                Self::emit(
                                    &on_stream,
                                    StreamEvent::ToolErrorLoopBroken {
                                        tool: call.name.clone(),
                                        consecutive_errors: count,
                                        node: None,
                                    },
                                );
                                if let Some(obs) = self.config.observability.as_ref() {
                                    let base = SpanBase::new_root(
                                        SpanId::new(format!(
                                            "{}-tool-error-loop-broken-{}",
                                            session_id.as_str(),
                                            span_seq
                                        )),
                                        session_id.clone(),
                                        task.id.clone(),
                                        SpanKind::ContextAssembly,
                                        Timestamp::now(),
                                    );
                                    obs.emit_context(ContextSpan {
                                        base,
                                        operation: ContextOperation::ToolErrorLoopBroken {
                                            tool_name: call.name.clone(),
                                            consecutive_errors: count,
                                        },
                                        tokens_before: 0,
                                        tokens_after: 0,
                                        utilization_before: 0.0,
                                        utilization_after: 0.0,
                                    });
                                }
                                return RunResult::Failure {
                                    reason: HaltReason::ToolErrorLoop {
                                        tool: call.name.clone(),
                                        consecutive_errors: count,
                                    },
                                    session_id,
                                    usage,
                                    turns: budget_used.turns,
                                    session_state: session_state.clone(),
                                };
                            }

                            // N: inject ONE corrective message (AC2). Render the
                            // schema+hint via `enrich_tool_error` (reused
                            // verbatim) and inject it as a USER-role message —
                            // the SAME channel the Stop-block breaker uses — once
                            // per run (do not re-inject between N and 2N).
                            if error_loop_n > 0 && count >= error_loop_n && !run.injected {
                                run.injected = true;
                                let schema = tool_registry
                                    .schemas()
                                    .into_iter()
                                    .find(|s| s.name == call.name);
                                // `enrich_tool_error` renders the bare message +
                                // schema + hint; the bare message is this run's
                                // own error text.
                                let bare = match &output {
                                    ToolOutput::Error { message, .. } => message.as_str(),
                                    _ => "",
                                };
                                let corrective =
                                    match Self::enrich_tool_error(bare, schema.as_ref()) {
                                        ToolOutput::Error { message, .. } => message,
                                        // enrich_tool_error always returns Error.
                                        _ => bare.to_string(),
                                    };
                                // AC4: emit the "detected/warning" pair (stream +
                                // obs) BEFORE the corrective message is appended.
                                Self::emit(
                                    &on_stream,
                                    StreamEvent::ToolErrorLoopDetected {
                                        tool: call.name.clone(),
                                        consecutive_errors: count,
                                        node: None,
                                    },
                                );
                                if let Some(obs) = self.config.observability.as_ref() {
                                    let base = SpanBase::new_root(
                                        SpanId::new(format!(
                                            "{}-tool-error-loop-detected-{}",
                                            session_id.as_str(),
                                            span_seq
                                        )),
                                        session_id.clone(),
                                        task.id.clone(),
                                        SpanKind::ContextAssembly,
                                        Timestamp::now(),
                                    );
                                    obs.emit_context(ContextSpan {
                                        base,
                                        operation: ContextOperation::ToolErrorLoopDetected {
                                            tool_name: call.name.clone(),
                                            consecutive_errors: count,
                                        },
                                        tokens_before: 0,
                                        tokens_after: 0,
                                        utilization_before: 0.0,
                                        utilization_after: 0.0,
                                    });
                                }
                                // Append after the normal tool-result append below
                                // so the conversation stays well-formed (assistant
                                // tool_use → tool result → corrective user msg).
                                // Stash it for injection just after the tool
                                // result is recorded.
                                pending_corrective = Some(corrective);
                            }
                        } else {
                            // AC1: ANY success for this tool resets its run.
                            error_runs.remove(&call.name);
                        }

                        // Tool-call span (issue #12), child of the current turn.
                        if let Some(obs) = self.config.observability.as_ref() {
                            // LLM-native content capture (issue #64): tool args +
                            // tool result, ONLY when the guard is enabled.
                            let cc = &self.config.content_capture;
                            let (tool_args_content, tool_result_content) = if cc.enabled {
                                let args = Self::capture_tool_call_args(call, cc.max_field_len);
                                let result = match &output {
                                    ToolOutput::Success { content, .. } => {
                                        let (content, t) =
                                            truncate_field(content, cc.max_field_len);
                                        Some(ToolResultContent {
                                            content,
                                            truncated: t,
                                        })
                                    }
                                    ToolOutput::Error { message, .. } => {
                                        let (content, t) =
                                            truncate_field(message, cc.max_field_len);
                                        Some(ToolResultContent {
                                            content,
                                            truncated: t,
                                        })
                                    }
                                    ToolOutput::WaitingForHuman { .. } => None,
                                    // Escalate / AwaitingClarification / Consult
                                    // are handled and returned above; they never
                                    // reach the capture path.
                                    ToolOutput::Escalate { .. } => None,
                                    ToolOutput::AwaitingClarification { .. } => None,
                                    ToolOutput::Consult { .. } => None,
                                    // Normalized into an `Error` (or a halt)
                                    // before this point; never reaches here.
                                    ToolOutput::SandboxViolation { .. } => None,
                                };
                                (Some(args), result)
                            } else {
                                (None, None)
                            };
                            let (output_size_bytes, truncated) = match &output {
                                ToolOutput::Success { content, truncated } => {
                                    (content.len(), *truncated)
                                }
                                ToolOutput::Error { message, .. } => (message.len(), false),
                                ToolOutput::WaitingForHuman { .. } => (0, false),
                                ToolOutput::Escalate { .. } => (0, false),
                                ToolOutput::AwaitingClarification { .. } => (0, false),
                                ToolOutput::Consult { .. } => (0, false),
                                // Normalized away before this point.
                                ToolOutput::SandboxViolation { .. } => (0, false),
                            };
                            let span_id =
                                SpanId::new(format!("{}-tool-{}", session_id.as_str(), span_seq));
                            let mut base = match &current_turn_base {
                                Some(parent) => SpanBase::new_child(
                                    span_id,
                                    parent,
                                    SpanKind::ToolCall,
                                    tool_started_at,
                                ),
                                None => SpanBase::new_root(
                                    span_id,
                                    session_id.clone(),
                                    task.id.clone(),
                                    SpanKind::ToolCall,
                                    tool_started_at,
                                ),
                            };
                            let status = if is_error {
                                SpanStatus::Error {
                                    message: "tool returned a recoverable error".into(),
                                }
                            } else {
                                SpanStatus::Ok
                            };
                            base.finish(
                                Timestamp::now(),
                                status,
                                tool_clock.elapsed().as_millis() as u64,
                            );
                            obs.emit_tool_call(ToolCallSpan {
                                base,
                                tool_name: call.name.clone(),
                                call_id: call.id.clone(),
                                parameters_size_bytes: call.input.to_string().len(),
                                output_size_bytes,
                                truncated,
                                sandbox_mode: String::new(),
                                sandbox_violations: Vec::new(),
                                arguments: tool_args_content,
                                result: tool_result_content,
                            });
                            span_seq += 1;
                        }

                        let tr = ToolResult {
                            call_id: call.id.clone(),
                            output,
                        };
                        // Q5: surface the result content on the coarse event.
                        let result_content = match &tr.output {
                            ToolOutput::Success { content, .. } => content.clone(),
                            ToolOutput::Error { message, .. } => message.clone(),
                            _ => String::new(),
                        };
                        Self::emit(
                            &on_stream,
                            StreamEvent::ToolResult {
                                call_id: call.id.clone(),
                                is_error,
                                content: result_content,
                                node: None,
                            },
                        );
                        self.config
                            .context_manager
                            .append_tool_result(&mut session_state, &tr)
                            .await;
                        approved_results.push(tr);

                        // #137 (AC2): inject the ONE corrective user message at
                        // the N threshold, AFTER this call's tool result is
                        // recorded — same `append_user_message` channel the
                        // Stop-block breaker uses.
                        if let Some(corrective) = pending_corrective.take() {
                            self.config
                                .context_manager
                                .append_user_message(&mut session_state, &corrective)
                                .await;
                        }
                    }

                    // Middleware: AfterTool.
                    if let Some(mw) = self.config.middleware.as_ref() {
                        if let MiddlewareDecision::Halt { reason } =
                            mw.fire(HookPoint::AfterTool, &session_state).await
                        {
                            return RunResult::Failure {
                                reason: HaltReason::MiddlewareHalt {
                                    hook: HookPoint::AfterTool,
                                    reason,
                                },
                                session_id,
                                usage,
                                turns: budget_used.turns,
                                session_state: session_state.clone(),
                            };
                        }
                    }

                    // Compaction (issue #46): after tool results are appended,
                    // before the loop restarts — matches the concepts-doc loop
                    // diagram's "compact if should_compact()" placement. Runs the
                    // verify→retry→warn loop; never halts the run.
                    if self.config.context_manager.should_compact(&session_state) {
                        self.run_compaction(
                            &mut session_state,
                            &session_id,
                            &task.id,
                            &mut span_seq,
                            &mut usage,
                            &agent,
                        )
                        .await;
                    }

                    continue;
                }

                TurnResult::Error { error, usage: u } => {
                    if let Some(u) = u.as_ref() {
                        usage.add_turn(u);
                        budget_used.input_tokens += u.input_tokens as u64;
                        budget_used.output_tokens += u.output_tokens as u64;
                    }
                    return RunResult::Failure {
                        reason: HaltReason::AgentError { error },
                        session_id,
                        usage,
                        turns: budget_used.turns,
                        session_state: session_state.clone(),
                    };
                }
            }
        }
    }

    // ========================================================================
    // SelfVerifying loop strategy (issue #61)
    // ========================================================================
    //
    // Loop-within-a-loop. Each round-trip runs a bounded BUILD ReAct sub-loop
    // (the agent does work until it claims done), then a fresh EVALUATE run
    // (a separate evaluator agent on a read-only sandbox in a never-shared
    // session), then asks the injected [`Verifier`] to translate
    // `(build_result, eval_result)` into a verdict. `Passed` ⇒ Success;
    // `Failed { reason }` ⇒ inject `reason` into the build context and loop.
    //
    // ## Config fields this strategy reads (both default `None`):
    //   - `config.verifier` — the oracle. REQUIRED: `None` ⇒
    //     `Failure { SelfVerifyMisconfigured }` (D4) — a typed halt, NOT a panic.
    //     Its `max_iterations()` (default 3) caps the round-trips (D3); per-run
    //     `max_stop_blocks` does NOT enter the picture for this strategy.
    //   - `config.evaluator_agent` — the evaluate-phase agent. Defaulting
    //     contract (D2): `config.evaluator_agent.as_ref().unwrap_or(&config.agent)`
    //     (identical to `planner_agent`). The read-only sandbox and the fresh
    //     `SessionId::generate()` for the evaluate phase are derived INTERNALLY.
    //
    // ## Terminal `HaltReason` variants this strategy produces (peers, D4):
    //   - `SelfVerifyExhausted { iterations, last_reason }` — ran out of
    //     `max_iterations` round-trips without a pass (clean exhaustion).
    //   - `SelfVerifyMisconfigured { reason }` — `config.verifier` is `None`.
    //
    // ## Rules enforced (each maps to a test):
    //   - R1  build phase runs a ReAct loop until the agent claims done.
    //   - R2  evaluate phase uses a FRESH SessionId never shared with build.
    //   - R3  evaluate phase uses a read-only sandbox (writes ⇒ ReadOnlyViolation;
    //         the build sandbox is unaffected).
    //   - R4  the evaluator carries the `role-evaluator` chunk. PRESENCE-ONLY:
    //         the chunk's content (if the provider supplies it) is prepended to
    //         the evaluate seed message; the chunk-condition machinery (#79) is
    //         NOT otherwise wired into the harness loop.
    //   - R5  Default-FAIL: an indeterminate evaluator verdict keeps looping.
    //   - R6  on findings, the verdict reason is injected into the build context
    //         and the build loop resumes (same path the Stop-block injection uses).
    //   - R7  stagnation guard: always-Failed ⇒ exactly `max_iterations` cycles ⇒
    //         `Failure { SelfVerifyExhausted }`.
    //   - R8  budgets fold BOTH phases across ALL iterations.
    //   - R9  build vs evaluate are distinguishable in traces (distinct session
    //         ids: the build session vs each evaluate's generated session).
    //   - R11 `verifier == None` ⇒ `Failure { SelfVerifyMisconfigured }`.
    //
    // No `// SPEC QUESTION:` markers — all four forks (D1–D4) are resolved.
    /// Run the SelfVerifying evaluate phase (issue #61): a fresh evaluator RUN
    /// over a read-only sandbox in a never-shared session.
    ///
    /// Builds a child [`StandardHarness`] from a clone of `self.config` with the
    /// `agent` swapped to the evaluator agent (D2 defaulting) and the `sandbox`
    /// wrapped in a [`ReadOnlySandbox`] (R3). The evaluator runs a fresh ReAct
    /// loop seeded with the `role-evaluator` chunk (R4, presence-only) plus a
    /// review directive, in a freshly [`generate`](SessionId::generate)d session
    /// (R2/R9). Folds the evaluate run's usage into `total_usage`/`carried` (R8)
    /// and returns its terminal [`RunResult`].
    async fn run_evaluate_phase(
        &self,
        task: &Task,
        evaluator: Arc<dyn Agent>,
        eval_toolset: ToolsetRef,
        carried: &mut BudgetSnapshot,
        total_usage: &mut AggregateUsage,
    ) -> RunResult {
        // R3: derive a read-only sandbox internally from the build sandbox.
        let read_only_sandbox: Arc<dyn SandboxProvider> =
            Arc::new(ReadOnlySandbox::new(self.config.sandbox.clone()));

        // R2/R9: fresh, never-shared session id for the evaluate run.
        let eval_session_id = SessionId::generate();

        // R4 (presence-only): prepend the `role-evaluator` chunk content (if the
        // configured provider supplies it) to the review directive.
        let role_chunk = self.role_evaluator_chunk().await;
        let directive = match role_chunk {
            Some(content) => format!(
                "{content}\n\nReview the work produced for the following task and \
                 report whether it is correct. You did NOT write this code; default \
                 to FAIL unless you can confirm it is right.\n\nTask:\n{}",
                task.instruction
            ),
            None => format!(
                "Review the work produced for the following task and report whether \
                 it is correct. You did NOT write this code; default to FAIL unless \
                 you can confirm it is right.\n\nTask:\n{}",
                task.instruction
            ),
        };

        let eval_task = Task {
            id: TaskId::generate(),
            instruction: directive.clone(),
            session_id: eval_session_id.clone(),
            budget: task.budget.clone(),
            loop_strategy: LoopStrategy::ReAct(ReactConfig::per_loop(
                task.budget.max_turns.unwrap_or(u32::MAX),
            )),
        };

        // Child harness: clone the config, swap the sandbox to read-only. Cloning
        // shares the same observability/storage seams so the evaluate run's spans
        // land in the SAME trace stream (distinguished by its distinct session
        // id). The evaluate agent is passed to `run_react` directly (#124 — no
        // `config.agent`).
        let mut eval_config = self.config.clone();
        eval_config.sandbox = read_only_sandbox;
        // The evaluate phase is a NON-INTERACTIVE nested review run: the caller
        // never sees its (freshly generated) session id, so an approval/HITL
        // middleware that resolves `SurfaceToHuman` would pause this run with no
        // human able to resume it — the reviewer's first `read_file` would yield
        // `WaitingForHuman`, which the verifier reads as a misconfiguration, and
        // the review half would silently never run. The read-only sandbox already
        // enforces the only safety property a reviewer needs (no writes, no
        // command execution), so the caller's approval middleware is both
        // redundant and harmful here — drop it for the evaluate phase. (Pair with
        // an `eval_toolset` scoped to read-only tools so non-filesystem
        // side-effecting tools the sandbox does not gate stay out of reach.)
        eval_config.middleware = None;
        // SC-30: when the eval phase falls back to the GLOBAL catalogue (empty
        // `eval_toolset`), auto-derive a read-only VIEW of it — advertise +
        // dispatch only the intersection with `StandardTools::readonly_set()`, so
        // the reviewer cannot reach write / exec / side-effecting tools (incl.
        // web/MCP the read-only sandbox does not gate) WITHOUT the consumer
        // registering a scoped read-only toolset. A non-empty `eval_toolset` is an
        // explicit opt-in and is left untouched (it resolves via its own catalogue).
        if eval_toolset.0.is_empty() {
            if let Some(catalogue) = eval_config.catalogue_registry.take() {
                let allow: std::collections::HashSet<String> =
                    crate::tools::StandardTools::readonly_set()
                        .into_iter()
                        .map(|t| t.schema.name)
                        .collect();
                let real: Arc<dyn ToolRegistry> =
                    Arc::new(crate::tool_registry::RealToolRegistry::new(
                        catalogue,
                        eval_config.sandbox.clone(),
                        eval_session_id.clone(),
                        eval_config.project_id.clone(),
                        eval_config.storage.run().clone(),
                        eval_config.storage.memory().clone(),
                    ));
                // `catalogue_registry` is now None (taken), so the empty-handle
                // path of `effective_tool_registry` returns this filtered
                // `tool_registry` for the reviewer's dispatch + schema advertising.
                eval_config.tool_registry = Arc::new(ReadOnlyToolView::new(real, allow));
            }
        }
        let eval_harness = StandardHarness::new(eval_config);

        let mut eval_state = SessionState::default();
        eval_harness
            .config
            .context_manager
            .append_user_message(&mut eval_state, &directive)
            .await;

        let cap = task.budget.max_turns.unwrap_or(u32::MAX);
        let eval_result = eval_harness
            .run_react(
                eval_task,
                cap,
                eval_state,
                BudgetSnapshot::default(),
                None,
                evaluator,
                eval_toolset,
            )
            .await;

        fold_usage(total_usage, carried, &eval_result);
        eval_result
    }

    /// Look up the `role-evaluator` chunk content from the configured
    /// [`ChunkProvider`](crate::prompt_assembly::ChunkProvider) (R4,
    /// presence-only). Returns `None` if the provider has no such chunk or fails
    /// to load.
    async fn role_evaluator_chunk(&self) -> Option<String> {
        let chunks = self.config.chunk_provider.load().await.ok()?;
        chunks
            .into_iter()
            .find(|c| c.id == "role-evaluator")
            .map(|c| c.content)
    }

    // ========================================================================
    // Ralph loop strategy (issue #58)
    // ========================================================================
    //
    // Multi-context-window continuation loop. The model's exit attempt is
    // intercepted — instead of terminating, the harness RESETS the context
    // window (discards the prior `SessionState`, builds a FRESH
    // `SessionState::default()`), RELOADS state from the filesystem (the
    // deterministic `.spore/progress.json` + `.spore/feature_list.json` files —
    // B4: no git-log read in v1), and resumes — until an external completion
    // check passes. The filesystem is what makes multi-context-window work
    // possible: each window starts from nothing but the instruction plus the
    // reloaded `.spore/` state.
    //
    // ## Completion mechanism (B1): driven off the `Stop` hook (issue #69).
    //   At construction [`StandardHarness::new`] registers a [`RalphStopHook`]
    //   that reads `.spore/progress.json` (+ `.spore/feature_list.json`): while
    //   tasks remain incomplete it returns [`HookDecision::Block`] (the reason
    //   describes what is left) and the harness loops into a new context window;
    //   when all tasks are complete it returns [`HookDecision::Continue`] and the
    //   loop terminates with success. There is NO dedicated `completion_check`
    //   config field and the deprecated `CompletionCheck` trait is NOT reused.
    //   The harness fires the Stop hook (`fire_stop_hooks` on `FinalResponse`);
    //   this strategy ALSO evaluates the SAME filesystem check between windows
    //   ([`ralph_completion_status`]) to drive the OUTER reset loop and to decide
    //   the terminal outcome.
    //
    // ## Config fields this strategy reads:
    //   - `config.max_resets` (B3, default 3) — the OUTER loop cap: the maximum
    //     number of context-window RESETS. Independent from `max_turns` (the
    //     per-window ReAct turn budget) and `max_stop_blocks` (the per-sub-loop
    //     Stop-block cap).
    //
    // ## Canonical filesystem paths (B2, `.spore/`-prefixed):
    //   - `{workspace_root}/.spore/progress.json`
    //   - `{workspace_root}/.spore/feature_list.json`
    //   (matches [`FeatureListCheck::new`](crate::termination::FeatureListCheck)).
    //
    // ## Terminal `HaltReason` variant this strategy produces (peer to
    //    [`SelfVerifyExhausted`](HaltReason::SelfVerifyExhausted)):
    //   - [`RalphCompletionUnmet`](HaltReason::RalphCompletionUnmet)
    //     `{ iterations, last_reason }` — reached `max_resets` context windows
    //     with tasks still incomplete.
    //
    // ## Rules enforced (each maps to a test):
    //   - R1  the model's exit attempt RESETS the context window instead of
    //         terminating, while tasks remain incomplete.
    //   - R2  each reset builds a FRESH `SessionState::default()` — no message
    //         carryover between context windows.
    //   - R3  the filesystem reload injects the reloaded `.spore/progress.json` +
    //         `.spore/feature_list.json` content into the fresh seed.
    //   - R4  completion pattern `incomplete,incomplete,complete` ⇒ `Success` at
    //         iteration 3.
    //   - R5  always-incomplete ⇒ exactly `max_resets` iterations ⇒
    //         `Failure { RalphCompletionUnmet }`.
    //   - R6  budgets fold across ALL context windows (`fold_usage`).
    //   - R7  each reset is traceable (a distinct generated session id per
    //         window, finalized via observability).
    //
    // No `// SPEC QUESTION:` markers — B1–B4 are resolved.
    /// Ralph external completion check (issue #58, B1). Reads the deterministic
    /// `.spore/` files under `workspace_root` and reports whether the task is
    /// complete. Returns `None` when complete, `Some(reason)` when tasks remain
    /// (the reason describes what is left). This is the SAME logic the registered
    /// [`RalphStopHook`] applies — one source of truth for the completion
    /// mechanism.
    ///
    /// Contract (#142, decision 3 — the checkpoint MOVED off the `.spore/`
    /// filesystem onto the durable project-id [`RunStore`](crate::storage::RunStore)):
    ///   - [`RALPH_PROGRESS_KEY`](crate::storage::RALPH_PROGRESS_KEY) →
    ///     `{ "complete": bool, "remaining": [string] }`. `complete: true` with an
    ///     empty `remaining` ⇒ progress satisfied. Absent/unreadable/invalid ⇒
    ///     incomplete (so the agent learns to write it).
    ///   - [`RALPH_FEATURE_LIST_KEY`](crate::storage::RALPH_FEATURE_LIST_KEY) → a
    ///     JSON array of `{ "name", "passes" }` (the
    ///     [`FeatureListCheck`](crate::termination::FeatureListCheck) schema). Any
    ///     `passes: false` ⇒ incomplete. An ABSENT feature list is tolerated here
    ///     (progress is the primary signal); an invalid one is not.
    ///
    /// The reason strings stay byte-identical to the legacy `.spore/`-path
    /// messages so the surfaced [`HaltReason::RalphCompletionUnmet`] text is
    /// stable across the storage relocation.
    async fn ralph_completion_status(
        run_store: &Arc<dyn crate::storage::RunStore>,
        project: &crate::storage::ProjectId,
    ) -> Option<String> {
        let ns = project.namespace();
        let progress_value = match run_store.get(&ns, crate::storage::RALPH_PROGRESS_KEY).await {
            Ok(Some(v)) => v,
            // Absent OR a storage error ⇒ incomplete (the agent must write it).
            _ => return Some(".spore/progress.json missing".to_string()),
        };
        let progress: RalphProgress = match serde_json::from_value(progress_value) {
            Ok(p) => p,
            Err(e) => return Some(format!(".spore/progress.json invalid JSON: {e}")),
        };
        if !progress.complete {
            let detail = if progress.remaining.is_empty() {
                "task not marked complete".to_string()
            } else {
                format!("remaining: {}", progress.remaining.join(", "))
            };
            return Some(detail);
        }
        if !progress.remaining.is_empty() {
            return Some(format!("remaining: {}", progress.remaining.join(", ")));
        }

        // Progress says done — corroborate against the feature list when present.
        if let Ok(Some(value)) = run_store
            .get(&ns, crate::storage::RALPH_FEATURE_LIST_KEY)
            .await
        {
            let entries: Vec<RalphFeatureEntry> = match serde_json::from_value(value) {
                Ok(v) => v,
                Err(e) => return Some(format!(".spore/feature_list.json invalid JSON: {e}")),
            };
            let incomplete: Vec<String> = entries
                .into_iter()
                .filter(|e| !e.passes)
                .map(|e| e.name)
                .collect();
            if !incomplete.is_empty() {
                return Some(format!("incomplete features: {}", incomplete.join(", ")));
            }
        }
        None
    }

    /// Build the reload context block injected into each fresh context window
    /// (issue #58, R3). #142: reads the checkpoint from the durable project-id
    /// [`RunStore`](crate::storage::RunStore) (not the `.spore/` filesystem) and
    /// returns the verbatim progress + feature-list JSON (when present) so the
    /// re-seeded window knows what is done and what remains. Returns `None` when
    /// neither checkpoint key is set. The "Reloaded .spore/…" prefix is retained
    /// so the seeded prompt text is byte-stable across the relocation.
    async fn ralph_reload_context(
        run_store: &Arc<dyn crate::storage::RunStore>,
        project: &crate::storage::ProjectId,
    ) -> Option<String> {
        let ns = project.namespace();
        let mut parts: Vec<String> = Vec::new();
        if let Ok(Some(v)) = run_store.get(&ns, crate::storage::RALPH_PROGRESS_KEY).await {
            if let Ok(raw) = serde_json::to_string(&v) {
                parts.push(format!("Reloaded .spore/progress.json:\n{}", raw.trim()));
            }
        }
        if let Ok(Some(v)) = run_store
            .get(&ns, crate::storage::RALPH_FEATURE_LIST_KEY)
            .await
        {
            if let Ok(raw) = serde_json::to_string(&v) {
                parts.push(format!(
                    "Reloaded .spore/feature_list.json:\n{}",
                    raw.trim()
                ));
            }
        }
        if parts.is_empty() {
            None
        } else {
            Some(parts.join("\n\n"))
        }
    }

    /// Write the Ralph progress checkpoint to the durable project-id
    /// [`RunStore`](crate::storage::RunStore) (issue #142, decision 3 — the WRITE
    /// path the relocated checkpoint needs; nothing wrote `progress.json` before).
    /// `complete: true` + empty `remaining` ⇒
    /// [`ralph_completion_status`](Self::ralph_completion_status) reports done.
    pub async fn write_ralph_progress(
        &self,
        complete: bool,
        remaining: Vec<String>,
    ) -> Result<(), crate::storage::StorageError> {
        let progress = RalphProgress {
            complete,
            remaining,
        };
        let value = serde_json::to_value(&progress)
            .map_err(|e| crate::storage::StorageError::Serialization(e.to_string()))?;
        self.config
            .storage
            .run()
            .put(
                &self.config.project_id.namespace(),
                crate::storage::RALPH_PROGRESS_KEY,
                value,
            )
            .await
    }

    /// Write the Ralph feature-list checkpoint to the durable project-id
    /// [`RunStore`](crate::storage::RunStore) (issue #142, decision 3). Each entry
    /// is `{ "name", "passes" }`; any `passes: false` keeps the run incomplete.
    pub async fn write_ralph_feature_list(
        &self,
        features: &[(String, bool)],
    ) -> Result<(), crate::storage::StorageError> {
        let entries: Vec<serde_json::Value> = features
            .iter()
            .map(|(name, passes)| serde_json::json!({ "name": name, "passes": passes }))
            .collect();
        let value = serde_json::Value::Array(entries);
        self.config
            .storage
            .run()
            .put(
                &self.config.project_id.namespace(),
                crate::storage::RALPH_FEATURE_LIST_KEY,
                value,
            )
            .await
    }

    // ========================================================================
    // HillClimbing loop strategy (issue #60)
    // ========================================================================
    //
    // Iterative optimization loop. Establishes a baseline metric over the
    // starting workspace, then repeatedly: runs ONE agent turn proposing a
    // change, evaluates the metric, and KEEPS or REVERTS based on whether the
    // new value strictly beats the running best (per `should_keep`). Generalizes
    // the autoresearch pattern.
    //
    // ## Loop semantics
    //   - Iteration 0 is a PURE baseline measurement of the starting workspace —
    //     NO agent turn. Its `ResultsEntry` has `status: kept`, and its
    //     `duration_secs` is the wall-clock time of the baseline evaluator call
    //     only. It seeds `current_best`. Agent turns begin at iteration 1.
    //   - Iterations 1.. : run one bounded ReAct agent turn (proposes a change),
    //     then evaluate. On a successful evaluation, route through
    //     `should_keep(new, current_best, payload_direction, min_improvement_delta)`:
    //       * keep   → status Kept, update `current_best`, reset the stagnation
    //                  counter to 0.
    //       * no keep → status Discarded; if `revert_on_no_improvement`, run
    //                  `git reset --hard HEAD` via the sandbox; increment the
    //                  stagnation counter.
    //     On a MetricError (Crashed/Timeout/etc.), the iteration status is
    //     `IterationStatus::from_error` (Crashed/Timeout), the metric value is
    //     EMPTY in the TSV, the iteration counts as a non-improvement (increment
    //     the stagnation counter), and the loop continues.
    //   - `max_stagnation: Some(N)` ⇒ after N consecutive non-improvements, halt
    //     `StagnationLimitReached { iterations, best_metric }`. Improvement resets
    //     the counter. `max_stagnation: None` ⇒ run until the budget/turn limit
    //     (no stagnation halt).
    //   - Budget gates (turns/tokens/wall/cost) are honored per iteration exactly
    //     as the other run_* methods do; each iteration emits a fire-and-forget
    //     observability span carrying the metric value/delta.
    //   - The harness writes the TSV after the run to
    //     `{workspace_root}/.spore/results/{task_id}.tsv`.
    //
    // ## Six pinned spec decisions (resolved with the user — NOT relitigated)
    //   1. REVERT: `revert_on_no_improvement: true` reverts via the sandbox
    //      `git reset --hard HEAD` directly from the harness. The harness NEVER
    //      git commits; `commit_hash` in the TSV stays empty unless a VcsProvider
    //      supplies it (default empty). Revert discards uncommitted working-tree
    //      changes back to current HEAD.
    //   2. TSV FLOAT FORMAT: both `metric_value` and `duration_secs` are
    //      formatted with exactly 6 decimal places (`format!("{:.6}", x)`) for
    //      cross-language byte-identity.
    //   3. TSV SCHEMA: written to `{workspace_root}/.spore/results/{task_id}.tsv`,
    //      tab-separated, REQUIRED header then one row per iteration ascending.
    //      Columns: iteration, commit_hash, metric_value, direction, status,
    //      duration_secs, description. `commit_hash` empty when no VCS wired;
    //      `metadata` EXCLUDED; `metric_value` EMPTY on crashed/timeout rows;
    //      `direction` snake_case; `status` snake_case; `duration_secs` is
    //      `MetricResult.duration.as_secs_f64()` formatted `{:.6}`.
    //   4. DIRECTION: the strategy payload `direction` is authoritative for the
    //      keep/revert decision via `should_keep`; the evaluator's `direction()`
    //      is descriptive only. The TSV `direction` column records the payload
    //      direction.
    //   5. BASELINE: iteration 0 is a pure baseline (no agent turn); its row has
    //      `status: kept` and `duration_secs` = the baseline evaluator-call time.
    //   6. MISCONFIGURATION: a `None` `metric_evaluator` ⇒ halt
    //      `HillClimbingMisconfigured { reason }` (peer to SelfVerifyMisconfigured).
    //      No panic.
    //
    // No `// SPEC QUESTION:` markers — all six decisions are resolved.

    /// Revert the working tree to current HEAD for a no-improvement iteration
    /// (issue #60, Decision 1). Runs `git reset --hard HEAD` THROUGH the sandbox;
    /// the harness NEVER spawns git directly. A sandbox rejection / non-zero exit
    /// is best-effort: the loop continues (the next agent turn re-derives state).
    async fn hill_climbing_revert(&self) {
        let args = [
            "reset".to_string(),
            "--hard".to_string(),
            "HEAD".to_string(),
        ];
        let _ = self
            .config
            .sandbox
            .execute_command("git", &args, None, None)
            .await;
    }

    /// Resolve the `commit_hash` recorded on a HillClimbing TSV row (issue #60,
    /// Decision 1). The harness never commits, so this is the EMPTY string unless
    /// a [`VcsProvider`] is wired to supply a hash. v1 has no per-keep commit, so
    /// we always return `None` (serialized as the empty string in the TSV); the
    /// `VcsProvider` seam is reserved for a later revision.
    async fn hill_climbing_commit_hash(&self) -> Option<String> {
        None
    }

    /// Emit one fire-and-forget per-iteration observability span for a
    /// HillClimbing run (issue #60). No-op when no provider is configured.
    #[allow(clippy::too_many_arguments)]
    fn emit_hill_climbing_span(
        &self,
        session_id: &SessionId,
        task_id: &TaskId,
        span_seq: &mut u64,
        iteration: u32,
        metric_value: Option<f64>,
        delta: Option<f64>,
        status: crate::metric::IterationStatus,
        reverted: bool,
    ) {
        if let Some(obs) = self.config.observability.as_ref() {
            let base = SpanBase::new_root(
                SpanId::new(format!("{}-hill-{}", session_id.as_str(), *span_seq)),
                session_id.clone(),
                task_id.clone(),
                SpanKind::Warn,
                Timestamp::now(),
            );
            let status_str = serde_json::to_value(status)
                .ok()
                .and_then(|v| v.as_str().map(str::to_string))
                .unwrap_or_else(|| format!("{status:?}").to_lowercase());
            obs.emit_warn(WarnSpan::new(
                base,
                WarnEvent::HillClimbingIteration {
                    iteration,
                    metric_value,
                    delta,
                    status: status_str,
                    reverted,
                },
            ));
            *span_seq += 1;
        }
    }

    /// Serialize the HillClimbing results log and write it to
    /// `{workspace_root}/.spore/results/{task_id}.tsv` (issue #60, Decisions 2/3).
    /// Tab-separated, REQUIRED header, one row per iteration in ascending order.
    /// Floats use exactly 6 decimal places for cross-language byte-identity.
    /// `metric_value` is the empty string on crashed/timeout rows. `metadata` is
    /// excluded. Best-effort: a filesystem error is swallowed (the run outcome is
    /// authoritative, the TSV is a diagnostic artifact).
    async fn write_hill_climbing_tsv(
        &self,
        workspace_root: &std::path::Path,
        task_id: &TaskId,
        rows: &[crate::metric::ResultsEntry],
    ) {
        let body = Self::render_hill_climbing_tsv(rows);
        let dir = workspace_root.join(".spore/results");
        let _ = tokio::fs::create_dir_all(&dir).await;
        let path = dir.join(format!("{}.tsv", task_id.as_str()));
        let _ = tokio::fs::write(&path, body).await;
    }

    /// Render the HillClimbing results-log TSV body (issue #60, Decisions 2/3).
    /// Pure function over the rows so the exact byte content is unit-testable and
    /// cross-language-comparable. Trailing newline after every row (including the
    /// last) so appends and diffs stay line-oriented.
    fn render_hill_climbing_tsv(rows: &[crate::metric::ResultsEntry]) -> String {
        use crate::metric::IterationStatus;
        let mut out = String::from(
            "iteration\tcommit_hash\tmetric_value\tdirection\tstatus\tduration_secs\tdescription\n",
        );
        for r in rows {
            // Decision 3: metric_value is EMPTY on crashed/timeout rows.
            let metric_value = match r.status {
                IterationStatus::Crashed | IterationStatus::Timeout => String::new(),
                _ => format!("{:.6}", r.metric_value),
            };
            let commit_hash = r.commit_hash.clone().unwrap_or_default();
            let direction = match r.direction {
                HillClimbingDirection::Minimize => "minimize",
                HillClimbingDirection::Maximize => "maximize",
            };
            let status = match r.status {
                IterationStatus::Kept => "kept",
                IterationStatus::Discarded => "discarded",
                IterationStatus::Crashed => "crashed",
                IterationStatus::Timeout => "timeout",
            };
            let duration_secs = format!("{:.6}", r.duration.as_secs_f64());
            out.push_str(&format!(
                "{}\t{}\t{}\t{}\t{}\t{}\t{}\n",
                r.iteration,
                commit_hash,
                metric_value,
                direction,
                status,
                duration_secs,
                r.description
            ));
        }
        out
    }

    /// Persist the parsed [`TaskList`](crate::tasklist::TaskList) for the run
    /// (Q4). The DURABLE write goes through the
    /// [`RunStore`](crate::storage::RunStore) seam under
    /// [`TASK_LIST_EXTRAS_KEY`](crate::tasklist::TASK_LIST_EXTRAS_KEY); the #71
    /// sandbox-filesystem path (`.spore/task_list.json`) is intentionally NOT
    /// used — one source of truth. The RunStore write is the single source of
    /// truth (#76 removed the redundant `SessionState.extras` mirror).
    /// Serialization failures are swallowed: a successful plan must not be lost
    /// to a storage hiccup (the default no-op/in-memory provider never fails).
    async fn persist_task_list(
        &self,
        session_id: &SessionId,
        task_list: &crate::tasklist::TaskList,
    ) {
        // #142: the task_list is DURABLE — key it by the STABLE project namespace
        // (`project_id.namespace()`), NOT the per-window `session_id` the Ralph
        // wrapper regenerates each context window. Namespace-reuse keeps the
        // RunStore trait keyed by `&SessionId` while the value keyed is the
        // stable project id. The incoming `session_id` remains the EPHEMERAL key
        // and is intentionally unused for this durable write.
        let _ = session_id;
        let durable_ns = self.config.project_id.namespace();
        if let Ok(value) = serde_json::to_value(task_list) {
            // Durable write through the storage seam (RunStore).
            let _ = self
                .config
                .storage
                .run()
                .put(&durable_ns, crate::tasklist::TASK_LIST_EXTRAS_KEY, value)
                .await;
        }
    }

    /// The planning directive seeded before the constrained plan turn (R1): the
    /// "respond with a single JSON plan object" instruction wrapped around the
    /// task. Seeded by the recursive [`PlanExecuteConfig::run`] plan dispatch
    /// before `self.plan.run(cx)` (#124).
    fn plan_directive(instruction: &str) -> String {
        format!(
            "Produce a step-by-step plan for the following task. Respond with a \
             single JSON object: {{\"tasks\": [<ordered step strings>], \
             \"rationale\": <string>}}.\n\nTask:\n{instruction}"
        )
    }

    /// Capture + persist a [`PlanArtifact`] from the plan turn's output text
    /// (#124): R3 (parse), R11 (fire `OnPlanCreated`, mutable), R4 (persist to the
    /// RunStore under `PLAN_EXECUTE_EXTRAS_KEY`). The model turn that produced
    /// `plan_output` ran elsewhere — the recursive `self.plan` child via
    /// `self.plan.run(cx)` — so this carries no agent call. Returns the captured
    /// artifact + accounting or a terminal failure to propagate.
    async fn capture_and_persist_plan(
        &self,
        session_id: &SessionId,
        plan_output: &str,
        usage: AggregateUsage,
        turns: u32,
    ) -> Result<PlanPhaseOutcome, RunResult> {
        // R3: capture the artifact from the response text. Uses the prose-repair
        // fallback: a planner that wraps its plan JSON in prose still captures
        // (the strict canonical grammar runs first; repair only rescues a failure).
        let mut artifact = match crate::plan::capture_plan_artifact_with_repair(plan_output) {
            Ok(a) => a,
            Err(e) => {
                return Err(RunResult::Failure {
                    reason: HaltReason::PlanPhaseFailed { error: e },
                    session_id: session_id.clone(),
                    usage,
                    turns,
                    session_state: SessionState::default(),
                });
            }
        };

        // R11: fire OnPlanCreated synchronously; the hook may rewrite `artifact`
        // in place. The stored artifact reflects any mutation.
        if let Some(chain) = self.config.hooks.as_ref() {
            let mut ctx = crate::hooks::HookContext::OnPlanCreated {
                session_id,
                plan: &mut artifact,
            };
            // Errors are non-fatal: an observability/handler error must not lose
            // a successfully-captured plan. The (possibly mutated) artifact is
            // still stored.
            let _ = chain.fire(&mut ctx).await;
        }

        // R4: persist the produced artifact to the RunStore seam under
        // PLAN_EXECUTE_EXTRAS_KEY (#76 — the durable single source of truth;
        // no longer mirrored into SessionState.extras). #142: the plan artifact
        // is DURABLE — key it by the STABLE project namespace, NOT the per-window
        // `session_id` (so a Ralph window reset re-reads the prior window's
        // plan). The put result is swallowed (matching the execute-phase
        // persist): a successfully captured plan must not be lost to a storage
        // hiccup.
        match serde_json::to_value(&artifact) {
            Ok(value) => {
                let _ = self
                    .config
                    .storage
                    .run()
                    .put(
                        &self.config.project_id.namespace(),
                        crate::plan::PLAN_EXECUTE_EXTRAS_KEY,
                        value,
                    )
                    .await;
            }
            Err(e) => {
                return Err(RunResult::Failure {
                    reason: HaltReason::PlanPhaseFailed {
                        error: crate::plan::PlanPhaseError::UnparseablePlan {
                            message: format!("failed to serialize plan artifact: {e}"),
                        },
                    },
                    session_id: session_id.clone(),
                    usage,
                    turns,
                    session_state: SessionState::default(),
                });
            }
        }

        Ok(PlanPhaseOutcome {
            artifact,
            usage,
            turns,
        })
    }

    /// A.6 deep-resume reconcile (#124, Q2): mark every task already `Completed`
    /// on the DURABLE RunStore checkpoint as `Completed` in the freshly-parsed
    /// `task_list` so it is NOT re-run. Tasks are matched positionally by `id`
    /// (the task list is regenerated deterministically from the same artifact).
    /// Extracted from the legacy `run_execute_phase` so the recursive
    /// [`PlanExecuteConfig::run`] owns the per-task loop while the durable-state
    /// reconcile stays here.
    async fn reconcile_deep_resume(
        &self,
        session_id: &SessionId,
        task_list: &mut crate::tasklist::TaskList,
    ) {
        use crate::tasklist::TaskStatus;
        // #142: the durable checkpoint is keyed by the STABLE project namespace,
        // NOT the per-window `session_id` — so deep-resume reads the SAME list a
        // prior Ralph window persisted. The ephemeral `session_id` is unused for
        // this durable read.
        let _ = session_id;
        if let Ok(Some(value)) = self
            .config
            .storage
            .run()
            .get(
                &self.config.project_id.namespace(),
                crate::tasklist::TASK_LIST_EXTRAS_KEY,
            )
            .await
        {
            if let Ok(saved) = serde_json::from_value::<crate::tasklist::TaskList>(value) {
                for t in &mut task_list.tasks {
                    if saved
                        .tasks
                        .iter()
                        .any(|s| s.id == t.id && s.status == TaskStatus::Completed)
                    {
                        t.status = TaskStatus::Completed;
                    }
                }
            }
        }
    }

    /// Run the post-compaction verify→retry→warn loop (issue #46/#29).
    ///
    /// Drives one compaction turn through the agent, verifies the summary,
    /// and either accepts it, retries with the missing items injected, or —
    /// after `max_compaction_attempts` — emits a warn event and accepts the
    /// summary anyway. A blocked compaction is worse than an imperfect one, so
    /// this method NEVER returns an error or halts the run; the worst case is
    /// an accepted-anyway summary plus one warn span.
    ///
    /// Token usage from compaction turns folds into the run-level
    /// [`AggregateUsage`]; each compaction turn that produces a summary is
    /// surfaced as a `Compaction` [`ContextSpan`]. The
    /// `compaction_verification_failures` metric is derived from the emitted
    /// [`WarnSpan`].
    async fn run_compaction(
        &self,
        session_state: &mut SessionState,
        session_id: &SessionId,
        task_id: &TaskId,
        span_seq: &mut u64,
        usage: &mut AggregateUsage,
        // #124: the compaction summary turn runs on the SAME resolved worker
        // agent driving the ReAct window (no `config.agent`).
        agent: &Arc<dyn Agent>,
    ) {
        let Some(mut turn) = self
            .config
            .context_manager
            .prepare_compaction_turn(session_state)
        else {
            // Nothing to compact (e.g. history shorter than preserve window).
            return;
        };
        let tokens_before = turn.verification_state.token_budget_used;
        let max_attempts = self.config.max_compaction_attempts.max(1);
        let mut attempt: u32 = 0;

        loop {
            attempt += 1;
            // Run one compaction turn through the agent to produce a summary.
            let result = agent.turn(turn.context.clone()).await;
            let summary = match result {
                TurnResult::FinalResponse {
                    content, usage: u, ..
                } => {
                    usage.add_turn(&u);
                    content
                }
                TurnResult::ToolCallRequested { usage: u, .. } => {
                    // A compaction turn is expected to yield a summary, not a
                    // tool call. Treat the (empty) response as the summary so
                    // verification can run and the loop terminates predictably.
                    usage.add_turn(&u);
                    String::new()
                }
                TurnResult::Error { usage: u, .. } => {
                    if let Some(u) = u.as_ref() {
                        usage.add_turn(u);
                    }
                    String::new()
                }
            };

            let verification = self.config.compaction_verifier.verify(
                &summary,
                &turn.preserve_hints,
                &turn.verification_state,
            );

            if verification.passed {
                self.accept_compaction(
                    session_state,
                    summary,
                    turn.messages_removed,
                    &turn.dropped_messages,
                    tokens_before,
                    session_id,
                    task_id,
                    span_seq,
                );
                return;
            }

            if attempt < max_attempts {
                // Inject the missing items and retry.
                self.config
                    .context_manager
                    .inject_missing_items(&mut turn.context, &verification.missing_items);
                continue;
            }

            // Exhausted attempts: warn, then accept anyway.
            if let Some(obs) = self.config.observability.as_ref() {
                let base = SpanBase::new_root(
                    SpanId::new(format!("{}-warn-{}", session_id.as_str(), *span_seq)),
                    session_id.clone(),
                    task_id.clone(),
                    SpanKind::Warn,
                    Timestamp::now(),
                );
                obs.emit_warn(WarnSpan::new(
                    base,
                    WarnEvent::CompactionVerificationFailed {
                        missing_items: verification.missing_items.clone(),
                        accepted_anyway: true,
                    },
                ));
                *span_seq += 1;
            }
            self.accept_compaction(
                session_state,
                summary,
                turn.messages_removed,
                &turn.dropped_messages,
                tokens_before,
                session_id,
                task_id,
                span_seq,
            );
            return;
        }
    }

    /// Apply an accepted summary and emit the `Compaction` context span.
    #[allow(clippy::too_many_arguments)]
    fn accept_compaction(
        &self,
        session_state: &mut SessionState,
        summary: String,
        messages_removed: u32,
        dropped: &[Message],
        tokens_before: u32,
        session_id: &SessionId,
        task_id: &TaskId,
        span_seq: &mut u64,
    ) {
        self.config
            .context_manager
            .apply_compaction(session_state, summary, dropped);

        // Real token accounting (issue #57): read the post-compaction budget the
        // manager tracks. Managers that do not track tokens report `None`, in
        // which case we fall back to the pre-compaction value (the old behavior).
        let tokens_after = self
            .config
            .context_manager
            .token_budget_used(session_state)
            .unwrap_or(tokens_before);
        let tokens_reclaimed = tokens_before.saturating_sub(tokens_after);

        if let Some(obs) = self.config.observability.as_ref() {
            let base = SpanBase::new_root(
                SpanId::new(format!("{}-compaction-{}", session_id.as_str(), *span_seq)),
                session_id.clone(),
                task_id.clone(),
                SpanKind::Compaction,
                Timestamp::now(),
            );
            obs.emit_context(crate::observability::ContextSpan {
                base,
                operation: crate::observability::ContextOperation::Compaction {
                    messages_removed,
                    tokens_reclaimed,
                },
                tokens_before,
                tokens_after,
                utilization_before: 0.0,
                utilization_after: 0.0,
            });
            *span_seq += 1;
        }
    }
}

impl Harness for StandardHarness {
    fn run<'a>(&'a self, options: HarnessRunOptions) -> BoxFut<'a, RunResult> {
        Box::pin(async move {
            let result = self.run_inner(options).await;
            self.auto_persist_terminal(&result).await;
            result
        })
    }

    fn resume<'a>(
        &'a self,
        state: PausedState,
        response: HumanResponse,
        on_stream: Option<StreamSink>,
    ) -> BoxFut<'a, RunResult> {
        Box::pin(async move {
            let result = self.resume_inner(state, response, on_stream).await;
            self.auto_persist_terminal(&result).await;
            result
        })
    }

    fn resume_consult<'a>(
        &'a self,
        state: PausedState,
        response: ConsultResponse,
        on_stream: Option<StreamSink>,
    ) -> BoxFut<'a, RunResult> {
        Box::pin(async move {
            let result = self.resume_consult_inner(state, response, on_stream).await;
            self.auto_persist_terminal(&result).await;
            result
        })
    }
}

/// [`StrategyExecutor`] impl (#124): the harness-side primitives the recursive
/// per-variant [`RunStrategy::run`] bodies delegate to. Each primitive wraps an
/// existing, tested orchestration method so behavior stays at parity — the only
/// structural change is that the per-variant bodies now own their loops and the
/// central dispatch `match` is gone.
impl StrategyExecutor for StandardHarness {
    fn react_window<'a>(
        &'a self,
        task: Task,
        max_iterations: u32,
        session_state: SessionState,
        budget_used: BudgetSnapshot,
        on_stream: Option<StreamSink>,
        agent: Arc<dyn Agent>,
        toolset: ToolsetRef,
        output_schema: Option<serde_json::Value>,
        output_schema_max_retries: u32,
    ) -> BoxFut<'a, RunResult> {
        Box::pin(async move {
            self.run_react_inner(
                task,
                max_iterations,
                session_state,
                budget_used,
                on_stream,
                agent,
                toolset,
                output_schema,
                output_schema_max_retries,
            )
            .await
        })
    }

    fn resolve_agent_ref(
        &self,
        r: &AgentRef,
        session_id: &SessionId,
    ) -> Result<Arc<dyn Agent>, Box<RunResult>> {
        self.config
            .registry
            .resolve_agent(r)
            .cloned()
            .ok_or_else(|| {
                Box::new(RunResult::Failure {
                    reason: HaltReason::ConfigurationError {
                        error: HarnessError::UnresolvedHandle {
                            kind: "agent".to_string(),
                            key: r.0.clone(),
                        },
                    },
                    session_id: session_id.clone(),
                    usage: AggregateUsage::default(),
                    turns: 0,
                    session_state: SessionState::default(),
                })
            })
    }

    fn evaluate_phase<'a>(
        &'a self,
        task: &'a Task,
        eval_agent: Arc<dyn Agent>,
        eval_toolset: ToolsetRef,
        carried: &'a mut BudgetSnapshot,
        total_usage: &'a mut AggregateUsage,
    ) -> BoxFut<'a, RunResult> {
        Box::pin(async move {
            self.run_evaluate_phase(task, eval_agent, eval_toolset, carried, total_usage)
                .await
        })
    }

    fn append_user_message<'a>(
        &'a self,
        session_state: &'a mut SessionState,
        text: &'a str,
    ) -> BoxFut<'a, ()> {
        Box::pin(async move {
            self.config
                .context_manager
                .append_user_message(session_state, text)
                .await;
        })
    }

    fn workspace_root(&self) -> std::path::PathBuf {
        self.config.sandbox.workspace_root().to_path_buf()
    }

    fn seed_user_message<'a>(
        &'a self,
        session_state: &'a mut SessionState,
        text: &'a str,
    ) -> BoxFut<'a, ()> {
        Box::pin(async move {
            self.config
                .context_manager
                .append_user_message(session_state, text)
                .await;
        })
    }

    fn capture_plan_artifact<'a>(
        &'a self,
        session_id: &'a SessionId,
        plan_output: &'a str,
        usage: AggregateUsage,
        turns: u32,
    ) -> BoxFut<'a, Result<PlanPhaseOutcome, RunResult>> {
        Box::pin(async move {
            self.capture_and_persist_plan(session_id, plan_output, usage, turns)
                .await
        })
    }

    fn plan_directive(&self, instruction: &str) -> String {
        StandardHarness::plan_directive(instruction)
    }

    fn run_plan_subtree<'a>(
        &'a self,
        plan: &'a LoopStrategy,
        plan_task: Task,
        plan_session: SessionState,
        budget_used: BudgetSnapshot,
        on_stream: Option<StreamSink>,
    ) -> BoxFut<'a, Option<RunResult>> {
        Box::pin(async move {
            // #124 Q1: the planner concept is DROPPED — the plan child's leaf
            // `ReactConfig.agent` is authoritative and resolved by the recursing
            // leaf itself. The child's `.run(cx)` drives the WHOLE plan loop.
            let mut cx = ExecutionContext::new(&self.config.registry);
            cx.executor = Some(self);
            // #stream: thread the (already `plan_execute`-wrapped) sink into the
            // plan sub-drive so the plan leaf's turns stream and stay attributed.
            cx.stream = on_stream;
            cx.scratch.run_session = plan_session;
            cx.scratch.run_budget = budget_used;
            cx.scratch.task = Some(plan_task);
            let _ = plan.run(&mut cx).await;
            cx.scratch.terminal_override.take()
        })
    }

    fn reconcile_completed_tasks<'a>(
        &'a self,
        session_id: &'a SessionId,
        task_list: &'a mut crate::tasklist::TaskList,
    ) -> BoxFut<'a, ()> {
        Box::pin(async move {
            self.reconcile_deep_resume(session_id, task_list).await;
        })
    }

    fn fire_task_advance<'a>(
        &'a self,
        session_id: &'a SessionId,
        step_task: &'a mut Task,
        task_index: usize,
        total_tasks: usize,
    ) -> BoxFut<'a, ()> {
        Box::pin(async move {
            if let Some(chain) = self.config.hooks.as_ref() {
                let mut ctx = crate::hooks::HookContext::OnTaskAdvance {
                    session_id,
                    task: step_task,
                    task_index,
                    total_tasks,
                };
                let _ = chain.fire(&mut ctx).await;
            }
        })
    }

    fn persist_task_list<'a>(
        &'a self,
        session_id: &'a SessionId,
        task_list: &'a crate::tasklist::TaskList,
    ) -> BoxFut<'a, ()> {
        Box::pin(async move {
            // Delegate to the existing private method (same RunStore seam).
            StandardHarness::persist_task_list(self, session_id, task_list).await
        })
    }

    fn load_task_list<'a>(
        &'a self,
        session_id: &'a SessionId,
    ) -> BoxFut<'a, Option<crate::tasklist::TaskList>> {
        // #142: the task_list is DURABLE — read it from the STABLE project
        // namespace, NOT the per-window `session_id` (so the execute phase of a
        // fresh Ralph window sees the prior window's list). The ephemeral
        // `session_id` is unused for this durable read.
        let _ = session_id;
        Box::pin(async move {
            // #126 (decision C): the one authoring path — read the persisted
            // TaskList (with real blockers) from the RunStore under
            // TASK_LIST_EXTRAS_KEY. A storage miss / deserialize failure yields
            // None (the executor then falls back to the plan artifact).
            match self
                .config
                .storage
                .run()
                .get(
                    &self.config.project_id.namespace(),
                    crate::tasklist::TASK_LIST_EXTRAS_KEY,
                )
                .await
            {
                Ok(Some(value)) => serde_json::from_value::<crate::tasklist::TaskList>(value).ok(),
                _ => None,
            }
        })
    }

    fn take_observed_writes(&self) -> Vec<String> {
        match self.observed_writes.lock() {
            Ok(mut acc) => std::mem::take(&mut *acc),
            Err(_) => Vec::new(),
        }
    }

    fn clear_observed_writes(&self) {
        if let Ok(mut acc) = self.observed_writes.lock() {
            acc.clear();
        }
    }

    fn ralph_seed_session<'a>(&'a self, instruction: &'a str) -> BoxFut<'a, SessionState> {
        Box::pin(async move {
            let mut session_state = SessionState::default();
            self.config
                .context_manager
                .append_user_message(&mut session_state, instruction)
                .await;
            // #142: the reload context now comes from the durable project-id
            // RunStore checkpoint, not the `.spore/` filesystem.
            if let Some(reload) =
                Self::ralph_reload_context(self.config.storage.run(), &self.config.project_id).await
            {
                self.config
                    .context_manager
                    .append_user_message(&mut session_state, &reload)
                    .await;
            }
            // R3 (issue #58 v2): inject git history when a `VcsProvider` is wired.
            if let Some(vcs) = &self.config.vcs_provider {
                let args = VcsLogArgs {
                    max_entries: 20,
                    since_ref: None,
                    format: None,
                };
                if let Ok(log) = vcs.log(&args).await {
                    let trimmed = log.trim();
                    if !trimmed.is_empty() {
                        let block = format!("Recent VCS history:\n{trimmed}");
                        self.config
                            .context_manager
                            .append_user_message(&mut session_state, &block)
                            .await;
                    }
                }
            }
            session_state
        })
    }

    fn ralph_completion_status<'a>(&'a self) -> BoxFut<'a, Option<String>> {
        Box::pin(async move {
            // #142: read the checkpoint from the durable project-id RunStore.
            Self::ralph_completion_status(self.config.storage.run(), &self.config.project_id).await
        })
    }

    fn ralph_max_resets(&self) -> u32 {
        self.config.max_resets
    }

    fn escalation_mode(&self) -> EscalationMode {
        self.config.escalation_mode
    }

    fn enforce_output_schemas(&self) -> bool {
        self.config.enforce_output_schemas
    }

    fn output_schema_max_retries(&self) -> u32 {
        self.config.output_schema_max_retries
    }

    fn resolve_metric_evaluator(
        &self,
        key: &str,
        session_id: &SessionId,
    ) -> Result<Arc<dyn crate::metric::MetricEvaluator>, Box<RunResult>> {
        self.config
            .registry
            .resolve_metric_evaluator(key)
            .cloned()
            .ok_or_else(|| {
                Box::new(RunResult::Failure {
                    reason: HaltReason::HillClimbingMisconfigured {
                        reason: format!(
                            "HillClimbing requires a metric evaluator registered under key {key:?}"
                        ),
                    },
                    session_id: session_id.clone(),
                    usage: AggregateUsage::default(),
                    turns: 0,
                    session_state: SessionState::default(),
                })
            })
    }

    #[allow(clippy::too_many_arguments)]
    fn hill_baseline<'a>(
        &'a self,
        evaluator: &'a Arc<dyn crate::metric::MetricEvaluator>,
        session_id: &'a SessionId,
        task_id: &'a TaskId,
        direction: HillClimbingDirection,
        rows: &'a mut Vec<crate::metric::ResultsEntry>,
        span_seq: &'a mut u64,
        total_usage: AggregateUsage,
        turns: u32,
    ) -> BoxFut<'a, Result<f64, RunResult>> {
        Box::pin(async move {
            use crate::metric::{IterationStatus, MetricResult, ResultsEntry};
            use crate::termination::SessionStateSnapshot;
            let workspace_root = self.config.sandbox.workspace_root().to_path_buf();
            let snapshot = SessionStateSnapshot::new(
                session_id.clone(),
                task_id.clone(),
                SessionState::default(),
                workspace_root.clone(),
            );
            let baseline = evaluator
                .evaluate(self.config.sandbox.as_ref(), &snapshot)
                .await;
            match baseline {
                Ok(MetricResult {
                    value, duration, ..
                }) => {
                    rows.push(ResultsEntry {
                        iteration: 0,
                        commit_hash: self.hill_climbing_commit_hash().await,
                        metric_value: value,
                        direction,
                        status: IterationStatus::Kept,
                        duration,
                        description: evaluator.description(),
                        metadata: Default::default(),
                    });
                    self.emit_hill_climbing_span(
                        session_id,
                        task_id,
                        span_seq,
                        0,
                        Some(value),
                        None,
                        IterationStatus::Kept,
                        false,
                    );
                    Ok(value)
                }
                Err(err) => {
                    let status = IterationStatus::from_error(&err);
                    rows.push(ResultsEntry {
                        iteration: 0,
                        commit_hash: self.hill_climbing_commit_hash().await,
                        metric_value: f64::NAN,
                        direction,
                        status,
                        duration: Duration::ZERO,
                        description: evaluator.description(),
                        metadata: Default::default(),
                    });
                    self.emit_hill_climbing_span(
                        session_id, task_id, span_seq, 0, None, None, status, false,
                    );
                    self.write_hill_climbing_tsv(&workspace_root, task_id, rows)
                        .await;
                    Err(RunResult::Failure {
                        reason: HaltReason::HillClimbingMisconfigured {
                            reason: format!("baseline evaluation failed: {err}"),
                        },
                        session_id: session_id.clone(),
                        usage: total_usage,
                        turns,
                        session_state: SessionState::default(),
                    })
                }
            }
        })
    }

    #[allow(clippy::too_many_arguments)]
    fn hill_iteration<'a>(
        &'a self,
        evaluator: &'a Arc<dyn crate::metric::MetricEvaluator>,
        session_id: &'a SessionId,
        task_id: &'a TaskId,
        iteration: u32,
        direction: HillClimbingDirection,
        revert_on_no_improvement: bool,
        min_improvement_delta: Option<f64>,
        current_best: f64,
        rows: &'a mut Vec<crate::metric::ResultsEntry>,
        span_seq: &'a mut u64,
    ) -> BoxFut<'a, (f64, bool)> {
        Box::pin(async move {
            use crate::metric::{should_keep, IterationStatus, MetricResult, ResultsEntry};
            use crate::termination::SessionStateSnapshot;
            let workspace_root = self.config.sandbox.workspace_root().to_path_buf();
            let snapshot = SessionStateSnapshot::new(
                session_id.clone(),
                task_id.clone(),
                SessionState::default(),
                workspace_root,
            );
            let eval = evaluator
                .evaluate(self.config.sandbox.as_ref(), &snapshot)
                .await;
            match eval {
                Ok(MetricResult {
                    value, duration, ..
                }) => {
                    let kept = should_keep(value, current_best, direction, min_improvement_delta);
                    let delta = match direction {
                        HillClimbingDirection::Minimize => current_best - value,
                        HillClimbingDirection::Maximize => value - current_best,
                    };
                    if kept {
                        rows.push(ResultsEntry {
                            iteration,
                            commit_hash: self.hill_climbing_commit_hash().await,
                            metric_value: value,
                            direction,
                            status: IterationStatus::Kept,
                            duration,
                            description: evaluator.description(),
                            metadata: Default::default(),
                        });
                        self.emit_hill_climbing_span(
                            session_id,
                            task_id,
                            span_seq,
                            iteration,
                            Some(value),
                            Some(delta),
                            IterationStatus::Kept,
                            false,
                        );
                        (value, false)
                    } else {
                        let reverted = if revert_on_no_improvement {
                            self.hill_climbing_revert().await;
                            true
                        } else {
                            false
                        };
                        rows.push(ResultsEntry {
                            iteration,
                            commit_hash: self.hill_climbing_commit_hash().await,
                            metric_value: value,
                            direction,
                            status: IterationStatus::Discarded,
                            duration,
                            description: evaluator.description(),
                            metadata: Default::default(),
                        });
                        self.emit_hill_climbing_span(
                            session_id,
                            task_id,
                            span_seq,
                            iteration,
                            Some(value),
                            Some(delta),
                            IterationStatus::Discarded,
                            reverted,
                        );
                        (current_best, true)
                    }
                }
                Err(err) => {
                    let status = IterationStatus::from_error(&err);
                    let reverted = if revert_on_no_improvement {
                        self.hill_climbing_revert().await;
                        true
                    } else {
                        false
                    };
                    rows.push(ResultsEntry {
                        iteration,
                        commit_hash: self.hill_climbing_commit_hash().await,
                        metric_value: f64::NAN,
                        direction,
                        status,
                        duration: Duration::ZERO,
                        description: evaluator.description(),
                        metadata: Default::default(),
                    });
                    self.emit_hill_climbing_span(
                        session_id, task_id, span_seq, iteration, None, None, status, reverted,
                    );
                    (current_best, true)
                }
            }
        })
    }

    fn hill_write_tsv<'a>(
        &'a self,
        task_id: &'a TaskId,
        rows: &'a [crate::metric::ResultsEntry],
    ) -> BoxFut<'a, ()> {
        Box::pin(async move {
            let workspace_root = self.config.sandbox.workspace_root().to_path_buf();
            self.write_hill_climbing_tsv(&workspace_root, task_id, rows)
                .await;
        })
    }

    fn finalize<'a>(&'a self, result: &'a RunResult) -> BoxFut<'a, ()> {
        Box::pin(async move {
            match result {
                RunResult::Success { session_id, .. } => {
                    self.finalize_observability(session_id, SessionOutcome::Success)
                        .await;
                }
                RunResult::Failure {
                    session_id, reason, ..
                } => {
                    self.finalize_observability(
                        session_id,
                        SessionOutcome::Failure {
                            reason: format!("{reason:?}"),
                        },
                    )
                    .await;
                }
                RunResult::Escalate { session_id, .. } => {
                    self.finalize_observability(session_id, SessionOutcome::Escalated)
                        .await;
                }
                // Non-terminal pauses are never finalized.
                RunResult::WaitingForHuman { .. } | RunResult::Consult { .. } => {}
            }
        })
    }
}

impl StandardHarness {
    /// Consult resume seam (issue #114). Mirrors the `resume_inner`
    /// clarification branch: the [`ConsultResponse`] text is injected as the
    /// tool RESULT for the head pending (consult) call — NOT appended as a
    /// free-standing user message (R10) — then any remaining pending calls are
    /// dispatched and the ReAct loop resumes.
    async fn resume_consult_inner(
        &self,
        state: PausedState,
        response: ConsultResponse,
        on_stream: Option<StreamSink>,
    ) -> RunResult {
        let PausedState {
            session_id,
            task_id: _,
            turn_number: _,
            mut session_state,
            pending_tool_calls,
            approved_results: _,
            human_request: _,
            task,
            budget_used,
            child_state: _,
            // #140: the pausing leaf's toolset handle, carried through the pause.
            toolset,
        } = state;

        let (text, answered) = match &response {
            ConsultResponse::Answer { text } => (text.clone(), true),
            ConsultResponse::BudgetExhausted { message } => (message.clone(), false),
        };

        // Observability: lightweight consult-resume event.
        if let Some(obs) = self.config.observability.as_ref() {
            // Recover the consult `kind` from the head pending call's args, if
            // present, else fall back to a generic label.
            let kind = pending_tool_calls
                .first()
                .and_then(|c| c.input.get("kind"))
                .and_then(|v| v.as_str())
                .unwrap_or("")
                .to_string();
            let base = SpanBase::new_root(
                SpanId::new(format!("{}-consult-resume", session_id.as_str())),
                session_id.clone(),
                task.id.clone(),
                SpanKind::ContextAssembly,
                Timestamp::now(),
            );
            obs.emit_context(ContextSpan {
                base,
                operation: ContextOperation::ConsultResumed {
                    consult_kind: kind,
                    answered,
                },
                tokens_before: 0,
                tokens_after: 0,
                utilization_before: 0.0,
                utilization_after: 0.0,
            });
        }

        // #140: resume routes the preserved consulting call (and any remaining
        // pending calls) through the pausing leaf's own toolset handle, restoring
        // its scoped per-node catalogue. An empty handle (the default) still falls
        // back to the global catalogue, so pre-#140 blobs behave unchanged.
        let tool_registry = self.effective_tool_registry(&session_id, &toolset);

        // Inject the consult answer as the RESULT of the head pending (consult)
        // call, then dispatch the remaining pending calls in the same batch.
        let mut pending = pending_tool_calls.into_iter();
        if let Some(consult_call) = pending.next() {
            let tr = ToolResult {
                call_id: consult_call.id.clone(),
                output: ToolOutput::Success {
                    content: text,
                    truncated: false,
                },
            };
            self.config
                .context_manager
                .append_tool_result(&mut session_state, &tr)
                .await;
        }
        for call in pending {
            let output =
                self.normalize_sandbox_violation(tool_registry.dispatch(call.clone()).await);
            let tr = ToolResult {
                call_id: call.id,
                output,
            };
            self.config
                .context_manager
                .append_tool_result(&mut session_state, &tr)
                .await;
        }

        // #131: a consult that surfaced from inside a composed tree carries the
        // FULL strategy in `task.loop_strategy` (each combinator's `finish`
        // rewrote the pause's task on the way up). Re-DRIVE that strategy rather
        // than resuming only the worker leaf: the PlanExecute walk resumes its
        // in-progress task from the injected worker session (`consult_resume`
        // seed), so the worker finishes mid-loop, its SelfVerifying evaluator runs,
        // the task is marked Completed, and the remaining ready-set is walked. A
        // BARE worker leaf (depth-1, e.g. a SubagentTool-mediated consult) has no
        // surrounding walk, so it keeps the original leaf-only resume (back-compat).
        if !matches!(task.loop_strategy, LoopStrategy::ReAct(_)) {
            return self
                .drive_strategy_with_resume_seed(
                    task,
                    // Top-level session starts fresh; the worker conversation is
                    // threaded into the in-progress task via the consult seed.
                    SessionState::default(),
                    budget_used,
                    on_stream,
                    None,
                    Some(session_state),
                )
                .await;
        }

        let max_iterations = match &task.loop_strategy {
            LoopStrategy::ReAct(c) => c.max_iterations(),
            _ => u32::MAX,
        };
        let agent = match self.resolve_worker_agent(&task.loop_strategy) {
            Ok(a) => a,
            Err(error) => {
                return RunResult::Failure {
                    reason: HaltReason::ConfigurationError { error },
                    session_id,
                    usage: AggregateUsage::default(),
                    turns: budget_used.turns,
                    session_state,
                };
            }
        };
        self.run_react(
            task,
            max_iterations,
            session_state,
            budget_used,
            on_stream,
            agent,
            // legacy wrapper: empty handle ⇒ global-catalogue fallback.
            ToolsetRef(String::new()),
        )
        .await
    }

    /// Issue #102 auto-persist seam: write the terminal run state to the
    /// [`SessionStore`](crate::storage::SessionStore) when
    /// [`auto_persist_sessions`](HarnessConfig::auto_persist_sessions) is enabled.
    ///
    /// One write per `run()`/`resume()`, at the same terminal seam as the
    /// observability flush. For `Success`/`Failure` a [`PausedState`] is
    /// synthesized carrying the final `session_state` with empty pending fields
    /// (D4); for `WaitingForHuman`/`Escalate` the carried `PausedState` is
    /// persisted (D6 — the cross-process pause case). Storage errors are
    /// swallowed-and-logged (D8): a put failure must never lose the run nor
    /// surface as a [`HaltReason`].
    ///
    /// When disabled (the default), this returns immediately WITHOUT touching the
    /// store — the off-by-default zero-I/O contract (#102).
    async fn auto_persist_terminal(&self, result: &RunResult) {
        if !self.config.auto_persist_sessions {
            return;
        }
        // Build the `(SessionId, PausedState)` to persist for this terminal.
        let (session_id, state) = match result {
            RunResult::Success {
                session_id,
                session_state,
                turns,
                ..
            }
            | RunResult::Failure {
                session_id,
                session_state,
                turns,
                ..
            } => {
                // Synthesize a completed-run PausedState: empty pending fields,
                // no human request, no child — it carries only the final history
                // so a later `get_session(..).session_state` resumes losslessly.
                let state = PausedState {
                    session_id: session_id.clone(),
                    task_id: TaskId::new(session_id.as_str()),
                    turn_number: *turns,
                    session_state: session_state.clone(),
                    pending_tool_calls: vec![],
                    approved_results: vec![],
                    human_request: None,
                    task: Task::new(
                        String::new(),
                        session_id.clone(),
                        LoopStrategy::ReAct(ReactConfig::per_loop(0)),
                    ),
                    budget_used: BudgetSnapshot::default(),
                    child_state: None,
                    // #140: a synthesized completed-run state has empty pending
                    // fields; the handle is behaviorally irrelevant here.
                    toolset: ToolsetRef::default(),
                };
                (session_id.clone(), state)
            }
            // Persist the carried pause state directly (D6).
            RunResult::WaitingForHuman { state, .. } => {
                (state.session_id.clone(), (**state).clone())
            }
            RunResult::Escalate {
                state, session_id, ..
            } => (session_id.clone(), (**state).clone()),
            // Consult (issue #114) is non-terminal — persist the carried pause
            // state directly (same as WaitingForHuman) so a cross-process host
            // can later `resume_consult` it.
            RunResult::Consult {
                state, session_id, ..
            } => (session_id.clone(), (**state).clone()),
        };
        // Swallow-and-log on Err (D8): a storage hiccup must not lose the run.
        let _ = self
            .config
            .storage
            .session()
            .put_session(&session_id, &state)
            .await;
    }

    async fn run_inner(&self, options: HarnessRunOptions) -> RunResult {
        let HarnessRunOptions {
            task,
            on_stream,
            session_state,
        } = options;

        // #124 startup validation: every serializable handle in the task's
        // strategy tree must resolve against the configured ExecutionRegistry,
        // BEFORE the first turn. The legacy single-collaborator fields are gone —
        // resolution is now the SINGLE path, so validation ALWAYS runs (the
        // `!is_empty()` gate is dropped). An unresolved handle is a startup error.
        if let Err(error) = self.config.registry.validate(&task) {
            return RunResult::Failure {
                reason: HaltReason::ConfigurationError { error },
                session_id: task.session_id.clone(),
                usage: AggregateUsage::default(),
                turns: 0,
                session_state: SessionState::default(),
            };
        }

        // Issue #102 auto-load: when enabled AND no explicit session_state was
        // provided AND the strategy seeds incoming state (ReAct / SelfVerifying —
        // Ralph/HillClimbing discard it by design, D7), load the prior session for
        // this `session_id` from the SessionStore so a caller can resume by id.
        // Explicit `with_session_state` always wins (D5). Errors are
        // swallowed-and-logged: a load failure starts fresh (D8).
        let session_state = match session_state {
            Some(explicit) => Some(explicit),
            None if self.config.auto_persist_sessions
                && matches!(
                    task.loop_strategy,
                    LoopStrategy::ReAct(_) | LoopStrategy::SelfVerifying(_)
                ) =>
            {
                match self
                    .config
                    .storage
                    .session()
                    .get_session(&task.session_id)
                    .await
                {
                    Ok(Some(prior)) => Some(prior.session_state),
                    Ok(None) => None,
                    Err(_e) => {
                        // Swallow-and-log: start fresh on a load failure (D8).
                        // (No logging facade is wired into spore-core; the error
                        // is intentionally dropped rather than surfaced as a
                        // HaltReason.)
                        None
                    }
                }
            }
            None => None,
        };

        let mut session_state = session_state.unwrap_or_default();
        let budget_used = BudgetSnapshot::default();

        // #124: the central dispatch `match` is GONE — the only `match` left is
        // the enum→config delegation inside `LoopStrategy::run`. The harness entry
        // collapses to `task.loop_strategy.run(cx).await` via the recursive
        // executor. Strategies that BUILD ON incoming state (ReAct / PlanExecute /
        // SelfVerifying) get the instruction seeded here on the FRESH run (the
        // compaction adapter ignores `task`, so the harness owns prompt delivery);
        // Ralph / HillClimbing re-seed a fresh window internally (D7), so their
        // incoming state is discarded by the config body.
        if matches!(
            task.loop_strategy,
            LoopStrategy::ReAct(_) | LoopStrategy::PlanExecute(_) | LoopStrategy::SelfVerifying(_)
        ) {
            self.config
                .context_manager
                .append_user_message(&mut session_state, &task.instruction)
                .await;
        }
        self.drive_strategy(task, session_state, budget_used, on_stream)
            .await
    }

    /// The recursive-executor entry (#124): build the shared [`ExecutionContext`],
    /// seed the per-run scratch (task / session / budget), drive
    /// `task.loop_strategy.run(cx)`, and translate the outcome back into a
    /// terminal [`RunResult`] (Q5). A non-terminal pause / escalate stashed in
    /// `scratch.terminal_override` propagates VERBATIM (it never collapses into a
    /// `StrategyOutcome`).
    async fn drive_strategy(
        &self,
        task: Task,
        session_state: SessionState,
        budget_used: BudgetSnapshot,
        on_stream: Option<StreamSink>,
    ) -> RunResult {
        self.drive_strategy_with_resume_seed(
            task,
            session_state,
            budget_used,
            on_stream,
            None,
            None,
        )
        .await
    }

    /// `drive_strategy` with an optional cross-process Continue checkpoint seed
    /// (#129, AC2): `resume_continues = Some((phase, continues_used))` seeds the
    /// FIRST matching budget scope's `continues_used` (via [`BudgetContext::resumed`])
    /// so a `Continue` that spanned a process pause resumes with the correct
    /// continue count instead of a zeroed one. `None` is the fresh-run path.
    ///
    /// `resume_seed = Some(session)` (#131 consult + #138 budget) seeds the FIRST
    /// PlanExecute walk from `session` (the stalled worker conversation). For a
    /// consult resume the consult answer is already injected; for a budget resume
    /// (#138) it is the worker's full post-exhaustion session. The walk re-attaches
    /// it to the single `InProgress` task (execute-phase exhaustion) or, when the
    /// durable task_list has no `InProgress` task, to the PLAN session (#138 AC3
    /// plan-phase exhaustion). `None` on every fresh / non-resume path.
    async fn drive_strategy_with_resume_seed(
        &self,
        task: Task,
        session_state: SessionState,
        budget_used: BudgetSnapshot,
        on_stream: Option<StreamSink>,
        resume_continues: Option<(String, u32)>,
        resume_seed: Option<SessionState>,
    ) -> RunResult {
        // #129: the BARE-LEAF resolution site is `drive_strategy` (a bare leaf
        // never self-resolves inside its own body — rule 6 — it PROPAGATES a typed
        // `BudgetExhausted` here, the single recovery site for a top-level leaf).
        // When the leaf's CONFIGURED `behavior` resolves to `Continue`, grant the
        // leaf one more round IN-PROCESS (bump `continues_used`, refresh the
        // step cap) and re-drive WITHOUT any serialization (AC3) — looping until
        // the behavior resolves to `Fail`/`Escalate` or the strategy completes.
        // `behavior_for_resolution` carries the resolution chain's mutated state
        // across in-process continues so `max_continues` is honored.
        let session_id = task.session_id.clone();
        let mut task = task;
        let mut session_state = session_state;
        let mut budget_used = budget_used;
        // #stream: read-only now — cloned into `cx.stream` each round, never moved.
        let on_stream = on_stream;
        // The Continue resolution state threaded across in-process rounds: the
        // (possibly fallen-through) behavior + how many continues have been spent.
        let mut behavior_for_resolution: Option<(BudgetExhaustedBehavior, u32)> = None;
        // #129 (AC2): the cross-process checkpoint seed is consumed by the FIRST
        // round only (the resumed node's scope); later in-process rounds carry
        // their continue count via `behavior_for_resolution`.
        let mut resume_continues = resume_continues;
        // #131/#138: the resume seed is consumed by the FIRST round's
        // PlanExecute walk only; later in-process rounds run normally.
        let mut resume_seed = resume_seed;

        loop {
            let mut cx = ExecutionContext::new(&self.config.registry);
            cx.executor = Some(self);
            // #stream: CLONE (not take) the Arc sink so the binding survives every
            // in-process re-drive round (a `Continue` rebuilds `cx` at the top of
            // this loop and re-installs the same sink). Nested nodes wrap it.
            cx.stream = on_stream.clone();
            cx.scratch.run_session = std::mem::take(&mut session_state);
            cx.scratch.run_budget = budget_used.clone();
            cx.scratch.task = Some(task.clone());
            cx.scratch.resume_continues = resume_continues.take();
            cx.scratch.resume_seed = resume_seed.take();

            let outcome = task.loop_strategy.run(&mut cx).await;

            // A pause / escalate propagates verbatim (preserves the HITL / consult /
            // escalation contract through the recursive executor).
            if let Some(terminal) = cx.scratch.terminal_override.take() {
                return terminal;
            }
            match outcome {
                StrategyOutcome::Complete(output) => {
                    return RunResult::Success {
                        output,
                        session_id,
                        usage: cx.usage.clone(),
                        turns: cx.scratch.run_budget.turns,
                        session_state: std::mem::take(&mut cx.scratch.run_session),
                    }
                }
                StrategyOutcome::Failed(error) => {
                    return RunResult::Failure {
                        reason: HaltReason::ConfigurationError { error },
                        session_id,
                        usage: cx.usage.clone(),
                        turns: cx.scratch.run_budget.turns,
                        session_state: std::mem::take(&mut cx.scratch.run_session),
                    }
                }
                StrategyOutcome::BudgetExhausted {
                    policy,
                    behavior,
                    steps_taken,
                    continues_used,
                    phase,
                    partial_output,
                    cause,
                } => {
                    // #129: a BARE LEAF exhaustion propagates here carrying its
                    // CONFIGURED `behavior` (Q1 — the bare-leaf resolution site
                    // honors it; the leaf body never did). Resolve it ONCE: a
                    // `Continue` with continues left re-drives in-process; a spent
                    // `Continue` falls through to `Fail`/`Escalate`. Carry the
                    // resolution chain's state across rounds so `max_continues` is
                    // respected. (A combinator under `SurfaceToHuman` never reaches
                    // this arm — it sets `terminal_override`, returned above.)
                    let turns = if steps_taken > 0 {
                        steps_taken
                    } else {
                        cx.scratch.run_budget.turns
                    };
                    // #137: the terminal `HaltReason` for a Fail / Escalate→Fail
                    // resolution depends on the CAUSE — a genuine budget
                    // exhaustion reports `BudgetExceeded`; an error-loop break
                    // reports `ToolErrorLoop`. (A granted `Continue` re-drives
                    // the window, whose loop-local error counter starts fresh —
                    // parallel to how `consume_continue` resets `steps_taken`.)
                    let terminal_reason = match &cause {
                        ExhaustionCause::Budget => HaltReason::BudgetExceeded {
                            limit_type: BudgetLimitType::Turns,
                        },
                        ExhaustionCause::ToolErrorLoop {
                            tool,
                            consecutive_errors,
                        } => HaltReason::ToolErrorLoop {
                            tool: tool.clone(),
                            consecutive_errors: *consecutive_errors,
                        },
                    };
                    // Reconstruct the resolution scope: the FIRST round uses the
                    // leaf's propagated behavior + continues_used; later in-process
                    // rounds reuse the threaded (possibly fallen-through) state.
                    let (resolve_behavior, resolve_continues) = behavior_for_resolution
                        .take()
                        .unwrap_or((behavior, continues_used));
                    let mut scope = BudgetContext::resumed(
                        policy.clone(),
                        resolve_behavior,
                        phase.clone(),
                        resolve_continues,
                    );
                    let resolution = scope.resolve_exhausted();
                    match resolution {
                        ExhaustedResolution::Continue => {
                            // In-process continue (AC3: NO serialization). Refresh
                            // the leaf's step cap and re-enter the loop carrying the
                            // post-run session so the conversation context survives
                            // (Continue PRESERVES context — AC4). The granted cap is
                            // `steps_taken + policy.value` so the leaf gets a fresh
                            // window after the checkpoint.
                            let granted =
                                steps_taken.saturating_add(policy.allowance_value().unwrap_or(1));
                            grant_task_budget(&mut task, granted);
                            session_state = std::mem::take(&mut cx.scratch.run_session);
                            budget_used = cx.scratch.run_budget.clone();
                            // #stream: no reclaim needed — `on_stream` (Arc) is
                            // cloned, never moved, into `cx.stream` each round.
                            // Thread the resolution chain's post-continue state so a
                            // subsequent exhaustion sees the bumped `continues_used`.
                            behavior_for_resolution =
                                Some((scope.behavior.clone(), scope.continues_used));
                            continue;
                        }
                        ExhaustedResolution::Escalate => {
                            if matches!(self.config.escalation_mode, EscalationMode::SurfaceToHuman)
                            {
                                let err = BudgetExhausted {
                                    policy,
                                    behavior: scope.behavior.clone(),
                                    steps_taken,
                                    continues_used: scope.continues_used,
                                    phase,
                                };
                                let actions = leaf_escalation_actions(&err);
                                // #138 AC2-a: carry the FULL stalled leaf session
                                // (it propagated into scratch with its conversation)
                                // and the leaf's own toolset handle (#140/AC4-a).
                                let worker_session = std::mem::take(&mut cx.scratch.run_session);
                                let worker_toolset = worker_toolset_of(&task.loop_strategy);
                                return promote_budget_exhausted_to_human(
                                    &err,
                                    partial_output,
                                    actions,
                                    session_id,
                                    task,
                                    cx.scratch.run_budget.clone(),
                                    turns,
                                    worker_session,
                                    worker_toolset,
                                );
                            }
                            return RunResult::Failure {
                                // #137: ToolErrorLoop vs BudgetExceeded per cause.
                                reason: terminal_reason,
                                session_id,
                                usage: cx.usage.clone(),
                                turns,
                                session_state: SessionState {
                                    messages: partial_output
                                        .map(|t| {
                                            vec![Message {
                                                role: crate::model::Role::Assistant,
                                                content: crate::model::Content::Text { text: t },
                                            }]
                                        })
                                        .unwrap_or_default(),
                                    ..Default::default()
                                },
                            };
                        }
                        ExhaustedResolution::Fail => {
                            // Fail contract: the partial is DISCARDED.
                            return RunResult::Failure {
                                // #137: ToolErrorLoop vs BudgetExceeded per cause.
                                reason: terminal_reason,
                                session_id,
                                usage: cx.usage.clone(),
                                turns,
                                session_state: SessionState::default(),
                            };
                        }
                    }
                }
            }
        }
    }

    async fn resume_inner(
        &self,
        state: PausedState,
        response: HumanResponse,
        on_stream: Option<StreamSink>,
    ) -> RunResult {
        let PausedState {
            session_id,
            task_id: _,
            turn_number,
            mut session_state,
            pending_tool_calls,
            approved_results: _approved_results,
            human_request: hr,
            task,
            budget_used,
            child_state,
            // #140: the pausing leaf's toolset handle, carried through the pause.
            toolset,
        } = state;

        // Budget-escalation resume (#130/#129): if this pause came from
        // `HumanRequest::BudgetExhausted`, map the operator's `EscalationAction`
        // BEFORE the generic `match response` (mirrors the Clarification branch).
        // The node's `BudgetContext` is reconstructed from the request fields:
        // `steps_taken` raises the granted cap, and `continues_used` (#129, AC2)
        // is the SOLE `BudgetContext` field that rides a process pause — it is
        // seeded back into the rebuilt scope so a `Continue` spanning the pause
        // resumes with the correct continue count (it cannot exceed
        // `max_continues`). Q3: `continues_used` rides the REQUEST payload, NOT a
        // new serialized `BudgetContext`/`PausedState` field.
        if let Some(HumanRequest::BudgetExhausted {
            steps_taken,
            continues_used,
            phase,
            ..
        }) = &hr
        {
            let steps_taken = *steps_taken;
            let resume_continues = (phase.clone(), *continues_used);
            match &response {
                // Grant `steps` ADDITIONAL allowance and re-enter the loop from the
                // restored checkpoint. The strategy tree is rebuilt with the node's
                // budget policy raised to `steps_taken + steps` so the restored
                // scope has room for `steps` more steps, and the resumed scope's
                // `continues_used` is seeded from the request (#129, AC2).
                HumanResponse::Escalate {
                    action: EscalationAction::ContinueWithBudget { steps },
                } => {
                    let granted = steps_taken.saturating_add(*steps);
                    let mut resumed_task = task.clone();
                    grant_task_budget(&mut resumed_task, granted);
                    // #138 AC2-b: for a COMPOSED task (PlanExecute etc.) thread the
                    // carried worker session through the phase-agnostic resume seed
                    // and start the TOP-LEVEL session EMPTY — exactly mirroring
                    // `resume_consult_inner`. The PlanExecute walk re-attaches the
                    // seed to the single `InProgress` task (execute-phase
                    // exhaustion) via the InProgress→Pending→complete machinery, or
                    // to the PLAN session (AC3 plan-phase exhaustion) — so the
                    // stalled worker continues mid-loop instead of re-planning. A
                    // BARE leaf has no surrounding walk, so it resumes from
                    // `session_state` directly (the seed has nowhere to attach).
                    let (top_session, resume_seed) =
                        if matches!(resumed_task.loop_strategy, LoopStrategy::ReAct(_)) {
                            (session_state, None)
                        } else {
                            (SessionState::default(), Some(session_state))
                        };
                    return self
                        .drive_strategy_with_resume_seed(
                            resumed_task,
                            top_session,
                            budget_used,
                            on_stream,
                            Some(resume_continues),
                            resume_seed,
                        )
                        .await;
                }
                // Skip: the node is marked skipped and the outer loop advances. For
                // a combinator (PlanExecute) the per-task partial already recorded
                // the blocked task and persisted the list; re-entering the loop from
                // the checkpoint advances to the remaining ready tasks. For a leaf
                // there is no sibling, so a skip resolves to a clean (empty)
                // Success carrying whatever partial history was captured.
                HumanResponse::Escalate {
                    action: EscalationAction::Skip,
                } => {
                    if matches!(task.loop_strategy, LoopStrategy::PlanExecute(_)) {
                        return self
                            .drive_strategy(task, session_state, budget_used, on_stream)
                            .await;
                    }
                    return RunResult::Success {
                        output: String::new(),
                        session_id,
                        usage: AggregateUsage::default(),
                        turns: turn_number,
                        session_state,
                    };
                }
                // Fail: abort the node and propagate `BudgetExceeded`; the partial
                // is discarded (the `Fail` resolution contract).
                HumanResponse::Escalate {
                    action: EscalationAction::Fail,
                } => {
                    return RunResult::Failure {
                        reason: HaltReason::BudgetExceeded {
                            limit_type: BudgetLimitType::Turns,
                        },
                        session_id,
                        usage: AggregateUsage::default(),
                        turns: turn_number,
                        session_state: SessionState::default(),
                    };
                }
                // A non-`Escalate` response to a budget pause is out of contract;
                // treat it conservatively as a `Fail` (abort + propagate).
                _ => {
                    return RunResult::Failure {
                        reason: HaltReason::BudgetExceeded {
                            limit_type: BudgetLimitType::Turns,
                        },
                        session_id,
                        usage: AggregateUsage::default(),
                        turns: turn_number,
                        session_state: SessionState::default(),
                    };
                }
            }
        }

        // Resolve the effective tool registry for this resumed session — bridges
        // catalogue tools the same way the turn loop does, so pending tool calls
        // dispatched during resume thread the run's storage + sandbox. #140:
        // resume now routes through the pausing leaf's own toolset handle,
        // restoring its scoped per-node catalogue. An empty handle (the default)
        // still falls back to the global catalogue, so pre-#140 blobs and root
        // pauses behave unchanged. NOTE: the budget-escalation branch above
        // returned early via `drive_strategy_with_resume_seed`, which re-resolves
        // per-leaf toolsets during the re-drive — so this line is only reached by
        // the Clarification / direct-resume paths whose pending calls need the
        // carried handle.
        let tool_registry = self.effective_tool_registry(&session_id, &toolset);

        // Clarification resume (issue #81, Q4b): if this pause came from
        // `ToolOutput::AwaitingClarification`, the human's answer is injected as
        // the tool RESULT for the clarifying call (the head of
        // `pending_tool_calls`) — NOT appended as a free-standing user message.
        // Any remaining pending calls after the clarifying one are then
        // dispatched normally before the loop resumes.
        if matches!(hr, Some(HumanRequest::Clarification { .. })) {
            if let HumanResponse::Answer { text }
            | HumanResponse::ApproveWithFeedback { feedback: text } = &response
            {
                let mut pending = pending_tool_calls.into_iter();
                if let Some(clarifying_call) = pending.next() {
                    let tr = ToolResult {
                        call_id: clarifying_call.id.clone(),
                        output: ToolOutput::Success {
                            content: text.clone(),
                            truncated: false,
                        },
                    };
                    self.config
                        .context_manager
                        .append_tool_result(&mut session_state, &tr)
                        .await;
                }
                // Dispatch any remaining pending calls from the same batch.
                for call in pending {
                    let output = self
                        .normalize_sandbox_violation(tool_registry.dispatch(call.clone()).await);
                    let tr = ToolResult {
                        call_id: call.id,
                        output,
                    };
                    self.config
                        .context_manager
                        .append_tool_result(&mut session_state, &tr)
                        .await;
                }
                let max_iterations = match &task.loop_strategy {
                    LoopStrategy::ReAct(c) => c.max_iterations(),
                    _ => u32::MAX,
                };
                let agent = match self.resolve_worker_agent(&task.loop_strategy) {
                    Ok(a) => a,
                    Err(error) => {
                        return RunResult::Failure {
                            reason: HaltReason::ConfigurationError { error },
                            session_id,
                            usage: AggregateUsage::default(),
                            turns: budget_used.turns,
                            session_state,
                        };
                    }
                };
                return self
                    .run_react(
                        task,
                        max_iterations,
                        session_state,
                        budget_used,
                        on_stream,
                        agent,
                        // legacy wrapper: empty handle ⇒ global-catalogue fallback.
                        ToolsetRef(String::new()),
                    )
                    .await;
            }
        }

        // Subagent depth: if there's a child, route the response through it.
        // The actual child harness is owned by the caller-installed
        // `SubagentTool`; without a tool registry hook for `resume_child`,
        // the harness surfaces a tool result indicating the child's outcome
        // is the caller's responsibility. Wiring lands with #4/#5.
        if child_state.is_some() {
            // Append a synthetic tool result and continue the parent loop.
            // The full child.resume() dispatch lives with SubagentTool (#5).
        }

        match response {
            HumanResponse::Halt => {
                return RunResult::Failure {
                    reason: HaltReason::HumanHalted,
                    session_id,
                    usage: AggregateUsage::default(),
                    turns: turn_number,
                    session_state,
                };
            }
            HumanResponse::Deny { reason } => {
                // Append failed tool results for each pending call, continue loop.
                for call in &pending_tool_calls {
                    let tr = ToolResult {
                        call_id: call.id.clone(),
                        output: ToolOutput::Error {
                            message: reason.clone(),
                            recoverable: true,
                        },
                    };
                    self.config
                        .context_manager
                        .append_tool_result(&mut session_state, &tr)
                        .await;
                }
            }
            HumanResponse::Reject { reason } => {
                self.config
                    .context_manager
                    .append_user_message(&mut session_state, &reason)
                    .await;
            }
            HumanResponse::Answer { text }
            | HumanResponse::ApproveWithFeedback { feedback: text } => {
                self.config
                    .context_manager
                    .append_user_message(&mut session_state, &text)
                    .await;
            }
            HumanResponse::Allow => {
                // Dispatch remaining pending calls before resuming the loop.
                // Mirror the turn-loop's stream events (ToolCall before dispatch,
                // ToolResult after) so an approved tool's execution and output
                // render in the UI sink. Without these emits the resume path runs
                // silently, leaving every human-gated tool (bash, writes, gated
                // reads) with an approval line but no visible result.
                for call in pending_tool_calls {
                    Self::emit(
                        &on_stream,
                        StreamEvent::ToolCall {
                            call_id: call.id.clone(),
                            name: call.name.clone(),
                            args: call.input.clone(),
                            node: None,
                        },
                    );
                    let output = self
                        .normalize_sandbox_violation(tool_registry.dispatch(call.clone()).await);
                    Self::emit(
                        &on_stream,
                        StreamEvent::ToolResult {
                            call_id: call.id.clone(),
                            is_error: matches!(output, ToolOutput::Error { .. }),
                            content: match &output {
                                ToolOutput::Success { content, .. } => content.clone(),
                                ToolOutput::Error { message, .. } => message.clone(),
                                _ => String::new(),
                            },
                            node: None,
                        },
                    );
                    let tr = ToolResult {
                        call_id: call.id,
                        output,
                    };
                    self.config
                        .context_manager
                        .append_tool_result(&mut session_state, &tr)
                        .await;
                }
            }
            HumanResponse::AllowWithModification { calls } => {
                // Same stream-event mirroring as `Allow` (see above) so the
                // modified-and-approved calls render their output in the UI sink.
                for call in calls {
                    Self::emit(
                        &on_stream,
                        StreamEvent::ToolCall {
                            call_id: call.id.clone(),
                            name: call.name.clone(),
                            args: call.input.clone(),
                            node: None,
                        },
                    );
                    let output = self
                        .normalize_sandbox_violation(tool_registry.dispatch(call.clone()).await);
                    Self::emit(
                        &on_stream,
                        StreamEvent::ToolResult {
                            call_id: call.id.clone(),
                            is_error: matches!(output, ToolOutput::Error { .. }),
                            content: match &output {
                                ToolOutput::Success { content, .. } => content.clone(),
                                ToolOutput::Error { message, .. } => message.clone(),
                                _ => String::new(),
                            },
                            node: None,
                        },
                    );
                    let tr = ToolResult {
                        call_id: call.id,
                        output,
                    };
                    self.config
                        .context_manager
                        .append_tool_result(&mut session_state, &tr)
                        .await;
                }
            }
            // An `Escalate` response delivered to a non-budget pause is out of
            // contract (#130): the budget-escalation resume is handled by the
            // dedicated `HumanRequest::BudgetExhausted` branch ABOVE, which
            // returns early. Reaching here means the operator sent an
            // `EscalationAction` for a `ToolApproval`/`Review`/`None` pause —
            // halt cleanly rather than mis-resuming the loop.
            HumanResponse::Escalate { .. } => {
                return RunResult::Failure {
                    reason: HaltReason::HumanHalted,
                    session_id,
                    usage: AggregateUsage::default(),
                    turns: turn_number,
                    session_state,
                };
            }
        }

        // Resume the ReAct loop from where we left off.
        let max_iterations = match &task.loop_strategy {
            LoopStrategy::ReAct(c) => c.max_iterations(),
            _ => u32::MAX,
        };
        let agent = match self.resolve_worker_agent(&task.loop_strategy) {
            Ok(a) => a,
            Err(error) => {
                return RunResult::Failure {
                    reason: HaltReason::ConfigurationError { error },
                    session_id,
                    usage: AggregateUsage::default(),
                    turns: budget_used.turns,
                    session_state,
                };
            }
        };
        self.run_react(
            task,
            max_iterations,
            session_state,
            budget_used,
            on_stream,
            agent,
            // legacy wrapper: empty handle ⇒ global-catalogue fallback.
            ToolsetRef(String::new()),
        )
        .await
    }
}

// ============================================================================
// Test-only stubs of the sibling traits (cover ReAct paths in the unit tests
// before the canonical impls land in #4–#13).
// ============================================================================

#[cfg(any(test, feature = "test-utils"))]
pub mod testing {
    use super::*;
    use std::sync::Mutex;

    pub struct NoopContextManager;
    impl ContextManager for NoopContextManager {
        fn assemble<'a>(
            &'a self,
            session: &'a SessionState,
            _task: &'a Task,
        ) -> BoxFut<'a, Context> {
            let messages = session.messages.clone();
            Box::pin(async move {
                Context {
                    messages,
                    tools: vec![],
                    params: crate::model::ModelParams::default(),
                }
            })
        }
        fn append_tool_result<'a>(
            &'a self,
            session: &'a mut SessionState,
            result: &'a ToolResult,
        ) -> BoxFut<'a, ()> {
            Box::pin(async move {
                let text = match &result.output {
                    ToolOutput::Success { content, .. } => content.clone(),
                    ToolOutput::Error { message, .. } => format!("[error] {message}"),
                    ToolOutput::SandboxViolation { violation } => {
                        format!("[error] sandbox violation: {violation:?}")
                    }
                    ToolOutput::WaitingForHuman { .. } => "[waiting]".into(),
                    ToolOutput::Escalate { .. } => "[escalate]".into(),
                    ToolOutput::AwaitingClarification { .. } => "[clarification]".into(),
                    ToolOutput::Consult { .. } => "[consult]".into(),
                };
                session.messages.push(Message {
                    role: crate::model::Role::Tool,
                    content: crate::model::Content::Text { text },
                });
            })
        }
        fn append_assistant_message<'a>(
            &'a self,
            session: &'a mut SessionState,
            message: &'a Message,
        ) -> BoxFut<'a, ()> {
            let message = message.clone();
            Box::pin(async move {
                session.messages.push(message);
            })
        }
        fn append_user_message<'a>(
            &'a self,
            session: &'a mut SessionState,
            text: &'a str,
        ) -> BoxFut<'a, ()> {
            Box::pin(async move {
                session.messages.push(Message {
                    role: crate::model::Role::User,
                    content: crate::model::Content::Text { text: text.into() },
                });
            })
        }
    }

    pub struct AllowAllSandbox;
    impl SandboxProvider for AllowAllSandbox {
        fn validate<'a>(&'a self, _call: &'a ToolCall) -> BoxFut<'a, Result<(), SandboxViolation>> {
            Box::pin(async { Ok(()) })
        }
    }

    /// Deterministic [`VcsProvider`] double for tests and fixture replay (issue
    /// #58 v2). It returns pre-loaded strings VERBATIM with no process spawning,
    /// so multi-context-window Ralph continuation can be exercised hermetically.
    /// [`log`](VcsProvider::log) ignores its [`VcsLogArgs`] and yields
    /// `log_output`; [`status`](VcsProvider::status) yields `status_output`.
    pub struct FixtureVcsProvider {
        log_output: String,
        status_output: String,
    }

    impl FixtureVcsProvider {
        /// Construct a fixture provider returning `log_output` from `log` and
        /// `status_output` from `status`.
        pub fn new(log_output: impl Into<String>, status_output: impl Into<String>) -> Self {
            Self {
                log_output: log_output.into(),
                status_output: status_output.into(),
            }
        }
    }

    impl VcsProvider for FixtureVcsProvider {
        fn log<'a>(&'a self, _args: &'a VcsLogArgs) -> BoxFut<'a, Result<String, VcsError>> {
            Box::pin(async move { Ok(self.log_output.clone()) })
        }

        fn status<'a>(&'a self) -> BoxFut<'a, Result<String, VcsError>> {
            Box::pin(async move { Ok(self.status_output.clone()) })
        }
    }

    pub struct ScriptedSandbox {
        outcomes: Mutex<std::collections::VecDeque<Result<(), SandboxViolation>>>,
    }
    impl Default for ScriptedSandbox {
        fn default() -> Self {
            Self::new()
        }
    }
    impl ScriptedSandbox {
        pub fn new() -> Self {
            Self {
                outcomes: Mutex::new(Default::default()),
            }
        }
        pub fn push(&self, r: Result<(), SandboxViolation>) -> &Self {
            self.outcomes.lock().unwrap().push_back(r);
            self
        }
    }
    impl SandboxProvider for ScriptedSandbox {
        fn validate<'a>(&'a self, _call: &'a ToolCall) -> BoxFut<'a, Result<(), SandboxViolation>> {
            let r = self.outcomes.lock().unwrap().pop_front().unwrap_or(Ok(()));
            Box::pin(async move { r })
        }
    }

    pub struct ScriptedToolRegistry {
        outputs: Mutex<std::collections::VecDeque<ToolOutput>>,
        pub call_count: std::sync::atomic::AtomicUsize,
        always_halt: Mutex<Vec<String>>,
        /// Optional advertised tool schemas (issue #137: lets the error-loop
        /// breaker's `enrich_tool_error` render a real parameter schema). Empty
        /// by default — preserving every existing caller's behavior.
        schemas: Mutex<Vec<ToolSchema>>,
        /// When non-empty, `dispatch` returns the SAME recoverable error for
        /// EVERY call regardless of the queued `outputs` (issue #137 — models a
        /// tool that always rejects a malformed call, e.g. `add_task` missing a
        /// required `description`). Used by the tool-error-loop replay/tests.
        sticky_error: Mutex<Option<String>>,
    }
    impl Default for ScriptedToolRegistry {
        fn default() -> Self {
            Self::new()
        }
    }
    impl ScriptedToolRegistry {
        pub fn new() -> Self {
            Self {
                outputs: Mutex::new(Default::default()),
                call_count: Default::default(),
                always_halt: Mutex::new(vec![]),
                schemas: Mutex::new(vec![]),
                sticky_error: Mutex::new(None),
            }
        }
        pub fn push(&self, o: ToolOutput) -> &Self {
            self.outputs.lock().unwrap().push_back(o);
            self
        }
        pub fn mark_always_halt(&self, name: &str) {
            self.always_halt.lock().unwrap().push(name.into());
        }
        /// Advertise a tool schema (issue #137). Returns `&Self` for chaining.
        pub fn with_schema(&self, schema: ToolSchema) -> &Self {
            self.schemas.lock().unwrap().push(schema);
            self
        }
        /// Make every dispatch return the same recoverable error message,
        /// regardless of arguments (issue #137 error-loop scenario).
        pub fn always_recoverable_error(&self, message: &str) -> &Self {
            *self.sticky_error.lock().unwrap() = Some(message.into());
            self
        }
    }
    impl ToolRegistry for ScriptedToolRegistry {
        fn dispatch<'a>(&'a self, _call: ToolCall) -> BoxFut<'a, ToolOutput> {
            self.call_count
                .fetch_add(1, std::sync::atomic::Ordering::SeqCst);
            if let Some(message) = self.sticky_error.lock().unwrap().clone() {
                return Box::pin(async move {
                    ToolOutput::Error {
                        message,
                        recoverable: true,
                    }
                });
            }
            let out = self
                .outputs
                .lock()
                .unwrap()
                .pop_front()
                .unwrap_or(ToolOutput::Success {
                    content: "ok".into(),
                    truncated: false,
                });
            Box::pin(async move { out })
        }
        fn is_always_halt(&self, tool_name: &str) -> bool {
            self.always_halt
                .lock()
                .unwrap()
                .iter()
                .any(|n| n == tool_name)
        }
        fn schemas(&self) -> Vec<ToolSchema> {
            self.schemas.lock().unwrap().clone()
        }
    }

    /// Tool registry that models a single tool taking one `flag: bool`
    /// parameter. Dispatch deserializes `flag` strictly: a real JSON bool
    /// succeeds, anything else (e.g. the string `"false"`) returns a
    /// recoverable error — exactly the weak-model failure tool-call repair
    /// targets. Exposes the tool's schema via [`ToolRegistry::schemas`] so the
    /// repair provider can read expected types.
    pub struct BoolToolRegistry {
        pub call_count: std::sync::atomic::AtomicUsize,
    }
    impl Default for BoolToolRegistry {
        fn default() -> Self {
            Self::new()
        }
    }
    impl BoolToolRegistry {
        pub fn new() -> Self {
            Self {
                call_count: Default::default(),
            }
        }
    }
    impl ToolRegistry for BoolToolRegistry {
        fn dispatch<'a>(&'a self, call: ToolCall) -> BoxFut<'a, ToolOutput> {
            self.call_count
                .fetch_add(1, std::sync::atomic::Ordering::SeqCst);
            let out = match call.input.get("flag") {
                Some(serde_json::Value::Bool(b)) => ToolOutput::Success {
                    content: format!("flag={b}"),
                    truncated: false,
                },
                other => ToolOutput::Error {
                    message: format!("invalid parameters: expected bool `flag`, got {other:?}"),
                    recoverable: true,
                },
            };
            Box::pin(async move { out })
        }
        fn schemas(&self) -> Vec<ToolSchema> {
            vec![ToolSchema {
                name: "set_flag".into(),
                description: "set a boolean flag".into(),
                input_schema: serde_json::json!({
                    "type": "object",
                    "properties": { "flag": { "type": "boolean" } },
                    "required": ["flag"],
                }),
            }]
        }
    }

    pub struct AlwaysContinuePolicy;
    impl TerminationPolicy for AlwaysContinuePolicy {
        fn evaluate<'a>(
            &'a self,
            _session: &'a SessionState,
            _budget_used: &'a BudgetSnapshot,
        ) -> BoxFut<'a, TerminationDecision> {
            Box::pin(async { TerminationDecision::Continue })
        }
    }

    pub struct ScriptedTerminationPolicy {
        decisions: Mutex<std::collections::VecDeque<TerminationDecision>>,
    }
    impl Default for ScriptedTerminationPolicy {
        fn default() -> Self {
            Self::new()
        }
    }
    impl ScriptedTerminationPolicy {
        pub fn new() -> Self {
            Self {
                decisions: Mutex::new(Default::default()),
            }
        }
        pub fn push(&self, d: TerminationDecision) -> &Self {
            self.decisions.lock().unwrap().push_back(d);
            self
        }
    }
    impl TerminationPolicy for ScriptedTerminationPolicy {
        fn evaluate<'a>(
            &'a self,
            _session: &'a SessionState,
            _budget_used: &'a BudgetSnapshot,
        ) -> BoxFut<'a, TerminationDecision> {
            let d = self
                .decisions
                .lock()
                .unwrap()
                .pop_front()
                .unwrap_or(TerminationDecision::Continue);
            Box::pin(async move { d })
        }
    }

    pub struct ScriptedMiddleware {
        decisions: Mutex<std::collections::VecDeque<(HookPoint, MiddlewareDecision)>>,
    }
    impl Default for ScriptedMiddleware {
        fn default() -> Self {
            Self::new()
        }
    }
    impl ScriptedMiddleware {
        pub fn new() -> Self {
            Self {
                decisions: Mutex::new(Default::default()),
            }
        }
        pub fn push(&self, h: HookPoint, d: MiddlewareDecision) -> &Self {
            self.decisions.lock().unwrap().push_back((h, d));
            self
        }
    }
    impl MiddlewareChain for ScriptedMiddleware {
        fn fire<'a>(
            &'a self,
            hook: HookPoint,
            _session: &'a SessionState,
        ) -> BoxFut<'a, MiddlewareDecision> {
            let mut q = self.decisions.lock().unwrap();
            let d = if let Some(front) = q.front() {
                if front.0 == hook {
                    q.pop_front().unwrap().1
                } else {
                    MiddlewareDecision::Continue
                }
            } else {
                MiddlewareDecision::Continue
            };
            Box::pin(async move { d })
        }
    }
}

